def case_summary_report(db: Database, case_id: str) -> dict[str, Any]:
    status = db.case_status(case_id)
    warnings = db.activity_for_case(case_id, level="warning", limit=1000)
    errors = db.activity_for_case(case_id, level="error", limit=1000)
    return {
        "case": status["case"],
        "computers": status["computers"],
        "images": status["images"],
        "counts": {
            "computers": len(status["computers"]),
            "images": len(status["images"]),
            "jobs": len(status["jobs"]),
            "artifacts": len(status["artifacts"]),
            "outputs": len(status["outputs"]),
            "warnings": len(warnings),
            "errors": len(errors),
        },
        "tool_outputs": status["outputs"],
        "parsed_row_counts": status["parsed_row_counts"],
        "artifact_counts": _artifact_counts(status["artifacts"]),
        "evtx_recovery": _evtx_recovery_counts(db, case_id),
    }


def case_overview_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 25,
    memory_disk_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    db.get_case(case_id)
    summary = case_summary_report(db, case_id)
    gaps = evidence_gaps_report(db, case_id, limit=limit)
    memory = memory_analysis_report(db, case_id, limit=limit)
    credentials = memory_credentials_report(db, case_id, limit=limit)
    crash_dumps = crash_dump_analysis_report(db, case_id, limit=limit)
    suspicious = suspicious_executions_report(db, case_id, limit=limit)
    cloud_mounts = cloud_mounts_report(db, case_id, limit=limit)
    memory_disk = memory_disk_report or memory_disk_correlations_report(db, case_id, limit=limit)
    return {
        "case_id": case_id,
        "case": summary.get("case"),
        "case_context": {
            "description": ((summary.get("case") or {}).get("description") if isinstance(summary.get("case"), dict) else None) or "",
            "notes_path": ((summary.get("case") or {}).get("notes_path") if isinstance(summary.get("case"), dict) else None) or "",
        },
        "summary": {
            "computers": (summary.get("counts") or {}).get("computers", 0),
            "images": (summary.get("counts") or {}).get("images", 0),
            "tool_outputs": (summary.get("counts") or {}).get("outputs", 0),
            "warnings": (summary.get("counts") or {}).get("warnings", 0),
            "errors": (summary.get("counts") or {}).get("errors", 0),
            "evidence_gaps": (gaps.get("summary") or {}).get("gap_count", 0),
            "memory_artifacts": (memory.get("summary") or {}).get("memory_artifact_count", 0),
            "memory_string_hits": (memory.get("summary") or {}).get("memory_string_hit_count", 0),
            "memory_disk_correlations": (memory_disk.get("summary") or {}).get("correlation_count", 0),
            "credential_likely_usable": (credentials.get("summary") or {}).get("likely_usable_count", 0),
            "crash_dumps": (crash_dumps.get("summary") or {}).get("dump_count", 0),
            "suspicious_executions": (suspicious.get("summary") or {}).get("finding_count", 0),
            "cloud_virtual_mounts": (cloud_mounts.get("summary") or {}).get("cloud_mount_count", 0),
            "cloud_mount_inference_note": "Cloud virtual mounts are inferred from path artifacts unless evidence_basis says explicit configuration.",
        },
        "cloud_mount_summary": cloud_mounts.get("summary") or {},
        "cloud_mounts": (cloud_mounts.get("cloud_mounts") or [])[:limit],
        "top_evidence_gaps": (gaps.get("gaps") or [])[:limit],
        "memory_findings": (memory.get("findings") or [])[:limit],
        "credential_summary": credentials.get("summary") or {},
        "crash_dump_summary": crash_dumps.get("summary") or {},
        "top_suspicious_executions": (suspicious.get("findings") or [])[:limit],
        "memory_disk_correlation_summary": memory_disk.get("summary") or {},
        "report_paths": {
            "memory": "report memory-analysis",
            "credentials": "report memory-credentials",
            "crash_dumps": "report crash-dump-analysis",
            "suspicious_executions": "report suspicious-executions",
            "evidence_gaps": "report evidence-gaps",
            "memory_disk_correlations": "report memory-disk-correlations",
            "cloud_mounts": "report cloud-mounts",
        },
    }


def case_overview_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    context = report.get("case_context") if isinstance(report.get("case_context"), dict) else {}
    lines = [
        "# Case Overview",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
    ]
    if context.get("description") or context.get("notes_path"):
        lines.extend(["## Case Context", ""])
        if context.get("description"):
            lines.append(str(context.get("description")))
            lines.append("")
        if context.get("notes_path"):
            lines.append(f"Notes: `{context.get('notes_path')}`")
            lines.append("")
    lines.extend(["## Summary", ""])
    for key in (
        "computers",
        "images",
        "tool_outputs",
        "warnings",
        "errors",
        "evidence_gaps",
        "memory_artifacts",
        "memory_string_hits",
        "memory_disk_correlations",
        "credential_likely_usable",
        "crash_dumps",
        "suspicious_executions",
        "cloud_virtual_mounts",
    ):
        lines.append(f"- {key.replace('_', ' ').title()}: `{summary.get(key, 0)}`")
    if summary.get("cloud_mount_inference_note"):
        lines.append(f"- Cloud mount caveat: {summary.get('cloud_mount_inference_note')}")
    cloud_mounts = report.get("cloud_mounts") if isinstance(report.get("cloud_mounts"), list) else []
    if cloud_mounts:
        lines.extend(["", "## Cloud Virtual Mounts", ""])
        for mount in cloud_mounts[:10]:
            lines.append(
                "- "
                f"computer `{mount.get('computer_label') or mount.get('computer_id') or ''}` "
                f"user `{mount.get('user_profile') or ''}` "
                f"provider `{mount.get('provider') or ''}` "
                f"root `{mount.get('cloud_root') or ''}` "
                f"confidence `{mount.get('confidence') or ''}` "
                f"basis `{mount.get('basis') or ''}`"
            )
    lines.extend(["", "## High Priority", ""])
    suspicious = report.get("top_suspicious_executions") if isinstance(report.get("top_suspicious_executions"), list) else []
    if not suspicious:
        lines.append("- No suspicious execution findings in this overview window.")
    for row in suspicious[:10]:
        lines.append(
            f"- `{row.get('severity') or ''}` `{row.get('category') or ''}` "
            f"`{row.get('application') or ''}` `{row.get('display_path') or ''}`"
        )
    lines.extend(["", "## Evidence Gaps", ""])
    gaps = report.get("top_evidence_gaps") if isinstance(report.get("top_evidence_gaps"), list) else []
    if not gaps:
        lines.append("- No evidence gaps in this overview window.")
    for row in gaps[:10]:
        lines.append(f"- `{row.get('severity') or ''}` `{row.get('category') or ''}` {row.get('title') or ''}")
    lines.extend(["", "## Report Commands", ""])
    for label, command in (report.get("report_paths") or {}).items():
        lines.append(f"- `{label}`: `{command}`")
    return "\n".join(lines).rstrip() + "\n"


def regression_smoke_report(db: Database, case_id: str, *, limit: int = 10) -> dict[str, Any]:
    checks: list[dict[str, Any]] = []
    report_specs = [
        ("summary", lambda: case_summary_report(db, case_id)),
        ("evidence_gaps", lambda: evidence_gaps_report(db, case_id, limit=limit)),
        ("memory_artifacts", lambda: memory_artifacts_report(db, case_id, limit=limit)),
        ("memory_support_files", lambda: memory_support_files_report(db, case_id, limit=limit)),
        ("memory_analysis", lambda: memory_analysis_report(db, case_id, limit=limit)),
        ("memory_credentials", lambda: memory_credentials_report(db, case_id, limit=limit)),
        ("memory_disk_correlations", lambda: memory_disk_correlations_report(db, case_id, limit=limit)),
        ("crash_dump_analysis", lambda: crash_dump_analysis_report(db, case_id, limit=limit)),
        ("deep_recovery_status", lambda: deep_recovery_status_report(db, case_id, limit=limit)),
        ("suspicious_executions", lambda: suspicious_executions_report(db, case_id, limit=limit)),
        ("case_overview", lambda: case_overview_report(db, case_id, limit=limit)),
    ]
    for name, builder in report_specs:
        try:
            payload = builder()
            checks.append({"name": name, "status": "passed", "summary": payload.get("summary") if isinstance(payload, dict) else {}})
        except Exception as exc:
            checks.append({"name": name, "status": "failed", "error": str(exc)})
    return {
        "case_id": case_id,
        "summary": {
            "check_count": len(checks),
            "passed": sum(1 for row in checks if row.get("status") == "passed"),
            "failed": sum(1 for row in checks if row.get("status") == "failed"),
        },
        "checks": checks,
    }


def case_executive_summary_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 25,
    memory_disk_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    memory_disk = memory_disk_report or memory_disk_correlations_report(db, case_id, limit=max(limit * 10, 250))
    overview = case_overview_report(db, case_id, limit=limit, memory_disk_report=memory_disk)
    suspicious = overview.get("top_suspicious_executions") if isinstance(overview.get("top_suspicious_executions"), list) else []
    gaps = overview.get("top_evidence_gaps") if isinstance(overview.get("top_evidence_gaps"), list) else []
    memory_findings = overview.get("memory_findings") if isinstance(overview.get("memory_findings"), list) else []
    conclusions: list[dict[str, Any]] = []
    if suspicious:
        conclusions.append(
            {
                "priority": "high",
                "topic": "Suspicious execution",
                "summary": f"{len(suspicious)} suspicious execution finding(s) are present in the overview window.",
                "evidence_strength": _evidence_strength_for_category("execution"),
            }
        )
    if (overview.get("credential_summary") or {}).get("likely_usable_count", 0):
        conclusions.append(
            {
                "priority": "high",
                "topic": "Memory credentials",
                "summary": "Likely usable credential-looking memory strings were identified and need controlled validation.",
                "evidence_strength": "lead",
            }
        )
    if (overview.get("crash_dump_summary") or {}).get("dump_count", 0):
        conclusions.append(
            {
                "priority": "medium",
                "topic": "Crash dumps",
                "summary": "Crash dump artifacts are available and should be reviewed as process/kernel memory snapshots.",
                "evidence_strength": "supporting",
            }
        )
    if gaps:
        conclusions.append(
            {
                "priority": "medium",
                "topic": "Evidence gaps",
                "summary": f"{len(gaps)} evidence gap(s) need disclosure or follow-up collection.",
                "evidence_strength": "limitation",
            }
        )
    recommendations = [
        "Review suspicious executions with timeline context and source-specific caveats.",
        "Validate any likely credential memory hits before reporting them as active credentials.",
        "Use combined artifact-family reports to disclose both disk evidence and memory corroboration.",
        "Collect live RAM when encrypted user-session databases must be decrypted and offline memory did not recover keys.",
    ]
    return {
        "case_id": case_id,
        "summary": overview.get("summary") or {},
        "conclusions": conclusions[:limit],
        "top_suspicious_executions": suspicious[:limit],
        "memory_findings": memory_findings[:limit],
        "evidence_gaps": gaps[:limit],
        "recommendations": recommendations,
        "evidence_strength_guide": evidence_strength_guide(),
    }


def case_executive_summary_markdown(report: dict[str, Any]) -> str:
    lines = ["# Executive Summary", "", f"Case: `{report.get('case_id') or ''}`", "", "## Conclusions", ""]
    conclusions = report.get("conclusions") if isinstance(report.get("conclusions"), list) else []
    if not conclusions:
        lines.append("- No high-priority conclusions were generated from the current report set.")
    for row in conclusions:
        lines.append(
            f"- `{row.get('priority') or ''}` `{row.get('evidence_strength') or ''}` "
            f"{row.get('topic') or ''}: {row.get('summary') or ''}"
        )
    lines.extend(["", "## Recommendations", ""])
    for recommendation in report.get("recommendations") or []:
        lines.append(f"- {recommendation}")
    lines.extend(["", "## Evidence Strength Guide", ""])
    for row in report.get("evidence_strength_guide") or []:
        lines.append(f"- `{row.get('strength')}`: {row.get('meaning')}")
    return "\n".join(lines).rstrip() + "\n"


def issues_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    rows = db.conn.execute(
        """
        SELECT * FROM activity_log
        WHERE case_id = ? AND level IN ('warning', 'error')
        ORDER BY created_at DESC
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()
    return {"case_id": case_id, "issues": [dict(row) for row in reversed(rows)]}


def operation_manifest_report(db: Database, case_id: str, *, limit: int = 500) -> dict[str, Any]:
    db.get_case(case_id)
    outputs = [dict(row) for row in db.conn.execute(
        """
        SELECT tool_outputs.*, jobs.exit_code, jobs.dry_run, jobs.start_time, jobs.end_time,
               jobs.stdout_path, jobs.stderr_path, jobs.output_folder
        FROM tool_outputs
        LEFT JOIN jobs ON jobs.id = tool_outputs.job_id
        WHERE tool_outputs.case_id = ?
        ORDER BY COALESCE(jobs.start_time, tool_outputs.created_at), tool_outputs.tool_name, tool_outputs.path
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()]
    jobs = [dict(row) for row in db.conn.execute(
        """
        SELECT id, computer_id, image_id, tool_name, tool_version, command_json, dry_run,
               start_time, end_time, exit_code, stdout_path, stderr_path, output_folder
        FROM jobs
        WHERE case_id = ?
        ORDER BY start_time, tool_name
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()]
    skipped = [dict(row) for row in db.conn.execute(
        """
        SELECT event, level, message, COUNT(*) AS count,
               MIN(created_at) AS first_seen, MAX(created_at) AS last_seen
        FROM activity_log
        WHERE case_id = ?
          AND (
            event LIKE '%skipped%' OR message LIKE '%skipped%'
            OR event LIKE '%missing%' OR message LIKE '%missing%'
            OR level IN ('warning', 'error')
          )
        GROUP BY event, level, message
        ORDER BY last_seen DESC
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()]
    attempts = _artifact_attempts(db, case_id)
    return {
        "case_id": case_id,
        "summary": {
            "jobs": len(jobs),
            "tool_outputs_returned": len(outputs),
            "completed_jobs": sum(1 for row in jobs if row.get("exit_code") == 0),
            "failed_or_unfinished_jobs": sum(1 for row in jobs if row.get("exit_code") not in (0,)),
            "skip_warning_error_groups": len(skipped),
        },
        "artifact_attempts": attempts,
        "jobs": jobs,
        "tool_outputs": outputs,
        "skips_warnings_errors": skipped,
    }


def database_storage_report(
    db: Database,
    case_id: str | None = None,
    *,
    limit: int = 100,
    include_object_sizes: bool = False,
) -> dict[str, Any]:
    page_count = db.conn.execute("PRAGMA page_count").fetchone()[0]
    page_size = db.conn.execute("PRAGMA page_size").fetchone()[0]
    freelist_count = db.conn.execute("PRAGMA freelist_count").fetchone()[0]
    table_rows = _database_table_rows(db, case_id=case_id)
    sizes = _database_object_sizes(db) if include_object_sizes else {}
    tables = []
    for row in table_rows:
        table_size = sizes.get(row["table"], {})
        tables.append(
            {
                **row,
                "table_bytes": table_size.get("bytes"),
                "table_pages": table_size.get("pages"),
                "index_bytes": sum(
                    item["bytes"]
                    for name, item in sizes.items()
                    if name.startswith(f"idx_{row['table']}") or name.startswith(f"sqlite_autoindex_{row['table']}")
                ),
            }
        )
    tables.sort(key=lambda row: (row.get("table_bytes") or 0, row.get("row_count") or 0), reverse=True)
    return {
        "case_id": case_id,
        "database": {
            "path": str(db.path),
            "page_count": page_count,
            "page_size": page_size,
            "file_bytes_estimate": page_count * page_size,
            "freelist_pages": freelist_count,
            "freelist_bytes": freelist_count * page_size,
            "object_sizes_included": include_object_sizes,
        },
        "largest_tables": tables[:limit],
        "content_heavy_tables": _content_heavy_storage(db, case_id),
        "duplicate_tool_outputs": _duplicate_tool_outputs(db, case_id),
    }


def cleanup_candidates_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    storage = database_storage_report(db, case_id, limit=limit)
    candidates = []
    for item in storage["content_heavy_tables"]:
        if item["row_count"]:
            candidates.append(
                {
                    "category": "content_heavy_sqlite",
                    "table": item["table"],
                    "row_count": item["row_count"],
                    "large_columns": item["large_columns"],
                    "recommendation": "Keep metadata in SQLite, move/rebuild large text bodies in OpenSearch or external content store.",
                }
            )
    for duplicate in storage["duplicate_tool_outputs"]:
        candidates.append(
            {
                "category": "duplicate_tool_output",
                "tool_name": duplicate["tool_name"],
                "content_sha256": duplicate["content_sha256"],
                "copies": duplicate["copies"],
                "recommendation": "Preserve provenance, but avoid reimporting duplicate normalized rows unless operator accepts replacement.",
            }
        )
    parsed_rows = _table_count(db, "parsed_rows", case_id)
    if parsed_rows:
        candidates.append(
            {
                "category": "generic_raw_rows",
                "table": "parsed_rows",
                "row_count": parsed_rows,
                "recommendation": "Legacy generic row imports should be purged after confirming normalized tables and raw output files cover the evidence.",
            }
        )
    return {
        "case_id": case_id,
        "database": storage["database"],
        "candidates": candidates[:limit],
    }


def prefetch_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    report = _table_report(db, case_id, "prefetch_items", "prefetch", limit)
    rows = report.get("prefetch") if isinstance(report.get("prefetch"), list) else []
    matched = [
        row for row in rows
        if isinstance(row, dict) and row.get("resolved_reference_path")
    ]
    report["summary"] = {
        "rows_returned": len(rows),
        "reference_matches_returned": len(matched),
        "reference_sources": sorted(
            {
                str(row.get("resolved_reference_source"))
                for row in matched
                if row.get("resolved_reference_source")
            }
        ),
        "reference_caveat": (
            "Prefetch hash reference matches are resolver enrichment only. "
            "They are not proof that the resolved path existed on this system unless corroborated by case artifacts."
        ),
    }
    return report


def cd_burning_activity_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    db.get_case(case_id)
    items: list[dict[str, Any]] = []
    items.extend(_cd_burning_mft_items(db, case_id, limit=limit))
    items.extend(_cd_burning_usn_items(db, case_id, limit=limit))
    items.extend(_cd_burning_logfile_items(db, case_id, limit=limit))
    items.sort(
        key=lambda item: (
            _timestamp_sort_key(item.get("timestamp_utc")),
            item.get("source_table") or "",
            item.get("path") or "",
        )
    )
    if len(items) > limit:
        items = items[:limit]
    source_counts: dict[str, int] = {}
    indicator_counts: dict[str, int] = {}
    for item in items:
        source = str(item.get("source_table") or "unknown")
        indicator = str(item.get("indicator") or "unknown")
        source_counts[source] = source_counts.get(source, 0) + 1
        indicator_counts[indicator] = indicator_counts.get(indicator, 0) + 1
    return {
        "case_id": case_id,
        "summary": {
            "items_returned": len(items),
            "source_counts": source_counts,
            "indicator_counts": indicator_counts,
            "limit": limit,
        },
        "caveats": [
            "Windows burn staging artifacts indicate CD/DVD burning preparation or staging activity; corroborate with filesystem transactions and user context before concluding media was successfully burned.",
            "DAT/FIL/POST temporary burn files are pattern-based indicators and should be reviewed with surrounding $LogFile, USN, and MFT activity.",
        ],
        "items": items,
        "total_returned": len(items),
    }


def cd_burning_activity_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    rows = report.get("items") if isinstance(report.get("items"), list) else []
    lines = [
        "# CD/DVD Burning Activity Report",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Items returned: `{summary.get('items_returned', 0)}`",
        f"- Limit: `{summary.get('limit', '')}`",
        "",
    ]
    caveats = report.get("caveats") if isinstance(report.get("caveats"), list) else []
    if caveats:
        lines.extend(["## Caveats", ""])
        for caveat in caveats:
            lines.append(f"- {caveat}")
        lines.append("")
    for heading, key in (("Sources", "source_counts"), ("Indicators", "indicator_counts")):
        counts = summary.get(key) if isinstance(summary.get(key), dict) else {}
        if counts:
            lines.extend([f"## {heading}", ""])
            for value, count in sorted(counts.items()):
                lines.append(f"- `{value}`: `{count}`")
            lines.append("")
    lines.extend(["## Timeline", ""])
    if not rows:
        lines.append("- No CD/DVD burning indicators were found.")
    for row in rows:
        if not isinstance(row, dict):
            continue
        lines.append(
            f"- `{row.get('timestamp_utc') or ''}` `{row.get('indicator') or ''}` "
            f"`{row.get('source_table') or ''}` `{row.get('display_path') or row.get('path') or ''}`"
        )
        detail_values = {
            "operation": row.get("operation"),
            "reason": row.get("reason"),
            "file_name": row.get("file_name"),
            "source_file": row.get("source_file"),
            "row_number": row.get("row_number"),
        }
        details = [f"{key}={value}" for key, value in detail_values.items() if value not in (None, "")]
        if details:
            lines.append(f"  - {', '.join(details)}")
    lines.append("")
    return "\n".join(lines)


def _cd_burning_mft_items(db: Database, case_id: str, *, limit: int) -> list[dict[str, Any]]:
    rows = _query_report_rows(
        db,
        case_id,
        "mft_entries",
        """
        SELECT id, computer_id, image_id, tool_name, source_csv, row_number,
               parent_path, file_name, extension, in_use, is_directory,
               created_si, modified_si, record_changed_si, accessed_si, source_file
        FROM mft_entries
        WHERE case_id = ?
          AND (
            LOWER(COALESCE(parent_path, '')) LIKE '%/appdata/local/microsoft/windows/burn/burn%'
            OR LOWER(COALESCE(parent_path, '')) LIKE '%\\appdata\\local\\microsoft\\windows\\burn\\burn%'
            OR (
              LOWER(COALESCE(parent_path, '')) LIKE '%/appdata/local/temp%'
              AND _cd_tmp_name_predicate_sql()
            )
            OR (
              LOWER(COALESCE(parent_path, '')) LIKE '%\\appdata\\local\\temp%'
              AND _cd_tmp_name_predicate_sql()
            )
          )
        ORDER BY COALESCE(record_changed_si, modified_si, created_si, accessed_si, '') DESC, row_number
        LIMIT ?
        """.replace("_cd_tmp_name_predicate_sql()", _cd_tmp_name_predicate_sql()),
        (case_id, limit),
    )
    items: list[dict[str, Any]] = []
    for row in rows:
        path = _join_path(row.get("parent_path"), row.get("file_name"))
        items.append(
            {
                "source_table": "mft_entries",
                "source_row_id": row.get("id"),
                "timestamp_utc": row.get("record_changed_si") or row.get("modified_si") or row.get("created_si") or row.get("accessed_si"),
                "indicator": _cd_indicator_for_path(path, row.get("file_name")),
                "path": path,
                "display_path": _display_evidence_path(path),
                "file_name": row.get("file_name"),
                "operation": "mft_metadata",
                "reason": None,
                "tool": row.get("tool_name"),
                "source_file": row.get("source_file") or row.get("source_csv"),
                "row_number": row.get("row_number"),
                "details": {
                    "in_use": row.get("in_use"),
                    "is_directory": row.get("is_directory"),
                    "created_si": row.get("created_si"),
                    "modified_si": row.get("modified_si"),
                    "record_changed_si": row.get("record_changed_si"),
                    "accessed_si": row.get("accessed_si"),
                },
            }
        )
    return items


