def ntfs_namespace_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    status_rows = db.conn.execute(
        """
        SELECT index_status, legit_active_file, header_type, zero_prefix, COUNT(*) AS count
        FROM ntfs_namespace_reconciliation
        WHERE case_id = ?
        GROUP BY index_status, legit_active_file, header_type, zero_prefix
        ORDER BY count DESC, index_status
        """,
        (case_id,),
    ).fetchall()
    access_rows = db.conn.execute(
        """
        SELECT parent_access_status, mounted_present, COUNT(*) AS count
        FROM ntfs_namespace_reconciliation
        WHERE case_id = ?
        GROUP BY parent_access_status, mounted_present
        ORDER BY count DESC, parent_access_status
        """,
        (case_id,),
    ).fetchall()
    rows = db.conn.execute(
        """
        SELECT ntfs_namespace_reconciliation.*, computers.label AS computer_label, images.path AS image_path
        FROM ntfs_namespace_reconciliation
        LEFT JOIN computers ON ntfs_namespace_reconciliation.computer_id = computers.id
        LEFT JOIN images ON ntfs_namespace_reconciliation.image_id = images.id
        WHERE ntfs_namespace_reconciliation.case_id = ?
        ORDER BY ntfs_namespace_reconciliation.original_path
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()
    return {
        "case_id": case_id,
        "summary": {
            "status_counts": [dict(row) for row in status_rows],
            "mount_access_counts": [dict(row) for row in access_rows],
        },
        "ntfs_namespace_reconciliation": [dict(row) for row in rows],
        "total_returned": len(rows),
    }


def filesystem_review_report(
    db: Database,
    case_id: str,
    *,
    contains: str | None = None,
    event_type: str | None = None,
    status: str | None = None,
    source_table: str | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    db.get_case(case_id)
    duplicate_condition = (
        _artifact_duplicate_condition("filesystem_review")
        if db.analytics_mode == "sqlite"
        else "1=1"
    )
    where = ["filesystem_review.case_id = ?", duplicate_condition]
    params: list[Any] = [case_id]
    if contains:
        where.append(
            "(filesystem_review.file_path LIKE ? OR filesystem_review.file_name LIKE ? OR filesystem_review.reason LIKE ?)"
        )
        params.extend([f"%{contains}%", f"%{contains}%", f"%{contains}%"])
    if event_type:
        where.append("filesystem_review.event_type = ?")
        params.append(event_type)
    if status:
        where.append("filesystem_review.status = ?")
        params.append(status)
    if source_table:
        where.append("filesystem_review.source_table = ?")
        params.append(source_table)
    clause = " AND ".join(where)
    total_rows = _query_report_rows(
        db,
        case_id,
        "filesystem_review",
        f"SELECT COUNT(*) AS count FROM filesystem_review WHERE {clause}",
        params,
    )
    total = int((total_rows[0] if total_rows else {}).get("count") or 0)
    source_counts = _query_report_rows(
        db,
        case_id,
        "filesystem_review",
        f"""
        SELECT source_table, event_type, status, COUNT(*) AS count
        FROM filesystem_review
        WHERE {clause}
        GROUP BY source_table, event_type, status
        ORDER BY count DESC, source_table, event_type
        LIMIT 50
        """,
        params,
    )
    rows = _query_report_rows(
        db,
        case_id,
        "filesystem_review",
        f"""
        SELECT filesystem_review.*
        FROM filesystem_review
        WHERE {clause}
        ORDER BY COALESCE(filesystem_review.event_time, '') DESC,
                 filesystem_review.file_path,
                 filesystem_review.source_table
        LIMIT ?
        """,
        [*params, limit],
    )
    source_counts_by_id = _source_counts(db, "filesystem_review")
    _fill_computer_image_fields(db, case_id, rows)
    items = []
    for row in rows:
        item = dict(row)
        item["source_count"] = source_counts_by_id.get(str(item.get("id")), 0)
        item["details"] = _json_details(item.pop("details_json", None))
        items.append(item)
    return {
        "case_id": case_id,
        "total_matching_rows": total,
        "summary": {"source_event_status_counts": [dict(row) for row in source_counts]},
        "filesystem_review": items,
        "total_returned": len(items),
    }


def user_file_references_report(
    db: Database,
    case_id: str,
    *,
    provider: str | None = None,
    scope: str | None = None,
    user: str | None = None,
    contains: str | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    db.get_case(case_id)
    where = ["user_controlled_file_references.case_id = ?"]
    params: list[Any] = [case_id]
    if provider:
        where.append("LOWER(user_controlled_file_references.storage_provider) = LOWER(?)")
        params.append(provider)
    if scope:
        where.append("LOWER(user_controlled_file_references.path_scope) = LOWER(?)")
        params.append(scope)
    if user:
        where.append("LOWER(user_controlled_file_references.owning_user) = LOWER(?)")
        params.append(user)
    if contains:
        where.append(
            "(user_controlled_file_references.normalized_path LIKE ? OR "
            "user_controlled_file_references.display_path LIKE ? OR "
            "user_controlled_file_references.resolved_provider_path LIKE ? OR "
            "user_controlled_file_references.resolved_file_name LIKE ? OR "
            "user_controlled_file_references.artifact_meaning LIKE ? OR "
            "user_controlled_file_references.context LIKE ?)"
        )
        params.extend([f"%{contains}%"] * 6)
    clause = " AND ".join(where)
    total = db.conn.execute(
        f"SELECT COUNT(*) AS count FROM user_controlled_file_references WHERE {clause}",
        params,
    ).fetchone()["count"]
    scope_rows = db.conn.execute(
        f"""
        SELECT path_scope, storage_provider, artifact_meaning, COUNT(*) AS count
        FROM user_controlled_file_references
        WHERE {clause}
        GROUP BY path_scope, storage_provider, artifact_meaning
        ORDER BY count DESC, storage_provider, path_scope
        """,
        params,
    ).fetchall()
    user_rows = db.conn.execute(
        f"""
        SELECT owning_user, storage_provider, COUNT(*) AS count
        FROM user_controlled_file_references
        WHERE {clause}
        GROUP BY owning_user, storage_provider
        ORDER BY count DESC, owning_user
        LIMIT 50
        """,
        params,
    ).fetchall()
    rows = db.conn.execute(
        f"""
        SELECT user_controlled_file_references.*, computers.label AS computer_label, images.path AS image_path
        FROM user_controlled_file_references
        LEFT JOIN computers ON user_controlled_file_references.computer_id = computers.id
        LEFT JOIN images ON user_controlled_file_references.image_id = images.id
        WHERE {clause}
        ORDER BY COALESCE(user_controlled_file_references.event_time_utc, '') DESC,
                 user_controlled_file_references.normalized_path
        LIMIT ?
        """,
        [*params, limit],
    ).fetchall()
    items = []
    for row in rows:
        item = dict(row)
        item["details"] = _json_details(item.pop("details_json", None))
        items.append(item)
    return {
        "case_id": case_id,
        "total_matching_rows": total,
        "summary": {
            "scope_provider_counts": [dict(row) for row in scope_rows],
            "user_provider_counts": [dict(row) for row in user_rows],
        },
        "user_file_references": items,
        "total_returned": len(items),
    }


def user_file_reference_source_report(
    db: Database,
    case_id: str,
    *,
    reference_id: str,
) -> dict[str, Any]:
    db.get_case(case_id)
    ref_row = db.conn.execute(
        """
        SELECT *
        FROM user_controlled_file_references
        WHERE case_id = ? AND id = ?
        """,
        (case_id, reference_id),
    ).fetchone()
    if ref_row is None:
        raise KeyError(f"User-controlled file reference not found: {reference_id}")
    reference = dict(ref_row)
    reference["details"] = _json_details(reference.pop("details_json", None))
    source_table = reference["source_table"]
    if source_table not in {"windows_defender_events", "windows_error_reports", "etl_events"}:
        raise KeyError(f"Unsupported source table for user file reference: {source_table}")
    source_row = _analytics_query_one(
        db,
        source_table,
        f"""
        SELECT *
        FROM {source_table}
        WHERE case_id = ? AND id = ?
        """,
        (case_id, reference["source_row_id"]),
    )
    source = dict(source_row) if source_row is not None else None
    if source:
        for key in ("raw_json", "details_json", "loaded_modules_json", "payload_strings_json"):
            if key in source:
                source[f"{key}_decoded"] = _json_details(source.get(key))
    return {
        "case_id": case_id,
        "reference": reference,
        "source": source,
        "source_found": source is not None,
    }


def srum_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    report = _table_report(db, case_id, "srum_records", "srum_records", limit)
    counts = db.conn.execute(
        """
        SELECT record_type, provider_guid, provider_name, COUNT(*) AS count
        FROM srum_records
        WHERE case_id = ?
        GROUP BY record_type, provider_guid, provider_name
        ORDER BY count DESC, record_type
        """,
        (case_id,),
    ).fetchall()
    report["summary"] = {"provider_counts": [dict(row) for row in counts]}
    return report


def ual_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    timeline_sql = """
        SELECT *
        FROM (
          SELECT id AS source_record_id, case_id, computer_id, image_id, tool_name,
                 source_csv, row_number, database_file, source_table, role_name,
                 product_name, user_sid, user_name, client_name, client_ip,
                 access_count, activity_count, first_seen AS event_time_utc,
                 'ual_first_seen' AS event_type
          FROM ual_records
          WHERE case_id = ? AND COALESCE(first_seen, '') != ''
          UNION ALL
          SELECT id AS source_record_id, case_id, computer_id, image_id, tool_name,
                 source_csv, row_number, database_file, source_table, role_name,
                 product_name, user_sid, user_name, client_name, client_ip,
                 access_count, activity_count, last_seen AS event_time_utc,
                 'ual_last_seen' AS event_type
          FROM ual_records
          WHERE case_id = ? AND COALESCE(last_seen, '') != ''
          UNION ALL
          SELECT id AS source_record_id, case_id, computer_id, image_id, tool_name,
                 source_csv, row_number, database_file, source_table, role_name,
                 product_name, user_sid, user_name, client_name, client_ip,
                 access_count, activity_count, last_access AS event_time_utc,
                 'ual_last_access' AS event_type
          FROM ual_records
          WHERE case_id = ? AND COALESCE(last_access, '') != ''
          UNION ALL
          SELECT id AS source_record_id, case_id, computer_id, image_id, tool_name,
                 source_csv, row_number, database_file, source_table, role_name,
                 product_name, user_sid, user_name, client_name, client_ip,
                 access_count, activity_count, insert_date AS event_time_utc,
                 'ual_insert_date' AS event_type
          FROM ual_records
          WHERE case_id = ? AND COALESCE(insert_date, '') != ''
        )
        ORDER BY event_time_utc, event_type, role_name, client_name, user_name
        LIMIT ?
    """
    timeline = _query_report_rows(db, case_id, "ual_records", timeline_sql, [case_id, case_id, case_id, case_id, limit])
    records_sql = """
        SELECT *
        FROM ual_records
        WHERE case_id = ?
        ORDER BY COALESCE(first_seen, insert_date, last_seen, last_access, ''),
                 role_name, client_name, user_name, row_number
        LIMIT ?
    """
    records = _query_report_rows(db, case_id, "ual_records", records_sql, [case_id, limit])
    summary_sql = """
        SELECT COALESCE(NULLIF(role_name, ''), '(unknown)') AS role_name,
               COALESCE(NULLIF(client_name, ''), NULLIF(client_ip, ''), NULLIF(client_id, ''), '(unknown)') AS client,
               COALESCE(NULLIF(user_name, ''), NULLIF(user_sid, ''), '(unknown)') AS user,
               MIN(COALESCE(NULLIF(first_seen, ''), NULLIF(insert_date, ''), NULLIF(last_seen, ''), NULLIF(last_access, ''))) AS first_logged_utc,
               MAX(COALESCE(NULLIF(last_seen, ''), NULLIF(last_access, ''), NULLIF(first_seen, ''), NULLIF(insert_date, ''))) AS last_logged_utc,
               COUNT(*) AS record_count,
               SUM(CAST(COALESCE(NULLIF(access_count, ''), '0') AS BIGINT)) AS total_access_count
        FROM ual_records
        WHERE case_id = ?
        GROUP BY role_name, client, user
        ORDER BY first_logged_utc, role_name, client, user
        LIMIT ?
    """
    grouped = _query_report_rows(db, case_id, "ual_records", summary_sql, [case_id, limit])
    return {
        "case_id": case_id,
        "summary": {
            "timeline_events": len(timeline),
            "access_records_returned": len(records),
            "grouped_access_returned": len(grouped),
            "caveats": [
                "UAL/SUM records are usually aggregated by role/client/user and are not precise per-access event logs.",
                "Use first/last timestamps and counts as server-role access context; corroborate with EVTX, SMB, RDP, firewall, and authentication logs.",
            ],
        },
        "timeline": timeline,
        "access_records": records,
        "grouped_access": grouped,
        "total_returned": len(timeline),
    }


def srum_networks_report(db: Database, case_id: str, *, include_zero: bool = False, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    filters = ["case_id = ?", "record_type = 'network_connectivity'"]
    params: list[Any] = [case_id]
    if not include_zero:
        filters.append("COALESCE(TRY_CAST(connected_time AS BIGINT), 0) > 0")
    rows = _query_report_rows(
        db,
        case_id,
        "srum_records",
        f"""
        SELECT
          CASE
            WHEN interface_type = '23'
              THEN COALESCE(NULLIF(vpn_profile_name, ''), NULLIF(l2_profile_name, ''), '(unknown)')
            ELSE COALESCE(NULLIF(l2_profile_name, ''), '(unknown)')
          END AS network_name,
          CASE interface_type
            WHEN '23' THEN 'PPP/VPN'
            WHEN '71' THEN 'Wi-Fi'
            WHEN '6' THEN 'Ethernet'
            ELSE COALESCE(NULLIF(interface_type, ''), '(unknown)')
          END AS connection_type,
          vpn_server,
          vpn_device,
          vpn_protocol,
          vpn_phonebook_path,
          vpn_match_method,
          interface_type,
          l2_profile_id,
          interface_luid,
          MIN(connect_start_time) AS first_connected_utc,
          MAX(timestamp) AS last_observed_utc,
          MAX(COALESCE(TRY_CAST(connected_time AS BIGINT), 0)) AS max_connected_seconds,
          COUNT(*) AS observation_count,
          GROUP_CONCAT(DISTINCT user_name) AS users,
          GROUP_CONCAT(DISTINCT app_name) AS applications,
          MIN(source_csv) AS source_csv
        FROM srum_records
        WHERE {' AND '.join(filters)}
        GROUP BY network_name, connection_type, vpn_server, vpn_device, vpn_protocol,
          vpn_phonebook_path, vpn_match_method, interface_type, l2_profile_id, interface_luid
        ORDER BY first_connected_utc, network_name, connection_type
        LIMIT ?
        """,
        [*params, limit],
    )
    summary = _query_report_rows(
        db,
        case_id,
        "srum_records",
        f"""
        SELECT
          CASE interface_type
            WHEN '23' THEN 'PPP/VPN'
            WHEN '71' THEN 'Wi-Fi'
            WHEN '6' THEN 'Ethernet'
            ELSE COALESCE(NULLIF(interface_type, ''), '(unknown)')
          END AS connection_type,
          COUNT(*) AS observation_count,
          COUNT(DISTINCT CASE
            WHEN interface_type = '23'
              THEN COALESCE(NULLIF(vpn_profile_name, ''), NULLIF(l2_profile_name, ''), '(unknown)')
            ELSE COALESCE(NULLIF(l2_profile_name, ''), '(unknown)')
          END) AS network_count
        FROM srum_records
        WHERE {' AND '.join(filters)}
        GROUP BY connection_type
        ORDER BY observation_count DESC
        """,
        params,
    )
    return {
        "case_id": case_id,
        "summary": {"connection_type_counts": [dict(row) for row in summary]},
        "networks": [dict(row) for row in rows],
        "total_returned": len(rows),
    }


def wifi_activity_report(
    db: Database,
    case_id: str,
    *,
    start: str | None = None,
    end: str | None = None,
    ssid: str | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    db.get_case(case_id)
    limit = max(1, min(int(limit), 1000))
    ssid = (ssid or "").strip()
    normalized_start = _normalize_report_timestamp(start)
    normalized_end = _normalize_report_timestamp(end)
    start_bound = _timestamp_sql_bound(start)
    end_bound = _timestamp_sql_bound(end)
    if ssid:
        source_limit = max(limit * 10, 1000)
    elif start_bound or end_bound:
        source_limit = max(limit * 50, 5000)
    else:
        source_limit = max(limit * 100, 100_000)
    event_filters = [
        "case_id = ?",
        "("
        "lower(coalesce(provider, '')) like '%wlan%' OR "
        "lower(coalesce(channel, '')) like '%wlan%' OR "
        "lower(coalesce(provider, '')) like '%networkprofile%' OR "
        "lower(coalesce(channel, '')) like '%networkprofile%' OR "
        "lower(coalesce(map_description, '')) like '%wifi%' OR "
        "lower(coalesce(payload, '')) like '%wifi%' OR "
        "lower(coalesce(payload, '')) like '%wireless%'"
        ")",
    ]
    event_params: list[Any] = [case_id]
    if start_bound:
        event_filters.append(f"{_timestamp_sql_expr('time_created')} >= ?")
        event_params.append(start_bound)
    if end_bound:
        event_filters.append(f"{_timestamp_sql_expr('time_created')} < ?")
        event_params.append(end_bound)
    if ssid:
        event_filters.append(
            "("
            "lower(coalesce(map_description, '')) like ? OR "
            "lower(coalesce(payload_data1, '')) like ? OR "
            "lower(coalesce(payload_data2, '')) like ? OR "
            "lower(coalesce(payload_data3, '')) like ? OR "
            "lower(coalesce(payload, '')) like ?"
            ")"
        )
        event_params.extend([f"%{ssid.casefold()}%"] * 5)
    evtx_rows = _query_report_rows(
        db,
        case_id,
        "evtx_events",
        f"""
        SELECT id, case_id, computer_id, image_id, tool_output_id, time_created, provider, event_id, channel,
               computer, map_description, payload_data1, payload_data2, payload_data3,
               payload_data4, source_file, payload, NULL AS computer_label, NULL AS image_path
        FROM evtx_events
        WHERE {' AND '.join(event_filters)}
        ORDER BY time_created, event_id
        LIMIT ?
        """,
        [*event_params, source_limit],
    )
    for row in evtx_rows:
        row["network_name"] = _wifi_network_name_from_row(row)
        row["wifi_event_class"] = _wifi_event_class(row)
        row["source_table"] = "evtx_events"
        if row.get("payload") and len(str(row["payload"])) > 1000:
            row["payload"] = str(row["payload"])[:1000]

    srum_filters = ["case_id = ?", "record_type = 'network_connectivity'", "(interface_type = '71' OR coalesce(l2_profile_name, '') != '')"]
    srum_params: list[Any] = [case_id]
    if start_bound:
        srum_filters.append(f"({_timestamp_sql_expr('timestamp')} >= ? OR {_timestamp_sql_expr('connect_start_time')} >= ?)")
        srum_params.extend([start_bound, start_bound])
    if end_bound:
        srum_filters.append(f"({_timestamp_sql_expr('timestamp')} < ? OR {_timestamp_sql_expr('connect_start_time')} < ?)")
        srum_params.extend([end_bound, end_bound])
    if ssid:
        srum_filters.append("lower(coalesce(l2_profile_name, '')) like ?")
        srum_params.append(f"%{ssid.casefold()}%")
    srum_rows = _query_report_rows(
        db,
        case_id,
        "srum_records",
        f"""
        SELECT id, case_id, computer_id, image_id, timestamp, l2_profile_name, interface_type,
               l2_profile_id, interface_luid, connected_time, connect_start_time, connect_end_time,
               user_name, app_name, source_csv, NULL AS computer_label, NULL AS image_path
        FROM srum_records
        WHERE {' AND '.join(srum_filters)}
        ORDER BY COALESCE(timestamp, connect_start_time), l2_profile_name
        LIMIT ?
        """,
        [*srum_params, source_limit],
    )
    for row in srum_rows:
        row["network_name"] = row.get("l2_profile_name") or "(unknown)"
        row["connection_type"] = "Wi-Fi" if str(row.get("interface_type") or "") == "71" else str(row.get("interface_type") or "(unknown)")
        row["source_table"] = "srum_records"

    registry_filters = ["case_id = ?", "artifact = 'connected_networks'"]
    registry_params: list[Any] = [case_id]
    if start_bound:
        registry_filters.append(f"{_timestamp_sql_expr('COALESCE(event_time_utc, key_last_write_utc)')} >= ?")
        registry_params.append(start_bound)
    if end_bound:
        registry_filters.append(f"{_timestamp_sql_expr('COALESCE(event_time_utc, key_last_write_utc)')} < ?")
        registry_params.append(end_bound)
    if ssid:
        registry_filters.append(
            "("
            "lower(coalesce(display_name, '')) like ? OR "
            "lower(coalesce(value_data, '')) like ? OR "
            "lower(coalesce(key_path, '')) like ?"
            ")"
        )
        registry_params.extend([f"%{ssid.casefold()}%"] * 3)
    registry_rows = _query_report_rows(
        db,
        case_id,
        "registry_artifacts",
        f"""
        SELECT id, case_id, computer_id, image_id, key_last_write_utc, event_time_utc,
               user_profile, key_path, value_name, value_type, value_data, display_name,
               source_path, NULL AS computer_label, NULL AS image_path
        FROM registry_artifacts
        WHERE {' AND '.join(registry_filters)}
        ORDER BY COALESCE(event_time_utc, key_last_write_utc), display_name, value_name
        LIMIT ?
        """,
        [*registry_params, source_limit],
    )
    for row in registry_rows:
        row["network_name"] = _wifi_network_name_from_row(row)
        row["source_table"] = "registry_artifacts"

    _fill_computer_image_fields(db, case_id, evtx_rows)
    _fill_computer_image_fields(db, case_id, srum_rows)
    _fill_computer_image_fields(db, case_id, registry_rows)
    reconciled = _reconcile_wifi_networks(evtx_rows, srum_rows, registry_rows)
    all_connection_sessions = _public_wifi_connection_sessions(evtx_rows, ssid=ssid or None, limit=max(limit, 1000))
    _attach_wifi_sessions_to_networks(reconciled, all_connection_sessions)
    connection_sessions = all_connection_sessions[:limit]
    session_activity_plan = _wifi_session_activity_plan(connection_sessions, case_id=case_id)
    return {
        "case_id": case_id,
        "filters": {"start": normalized_start, "end": normalized_end, "ssid": ssid or None, "limit": limit},
        "activity_scope": {
            "matching_session_count": len(all_connection_sessions),
            "default_for_network_activity_questions": "all_matching_sessions",
            "selection_rule": "If the user asks what happened while connected to this network, evaluate every connection_session unless they specify one session or exact start/end.",
            "warning": "Do not answer from only the first connection_session when multiple sessions are present.",
        },
        "session_activity_plan": session_activity_plan,
        "summary": {
            "network_count": len(reconciled),
            "connection_session_count": len(all_connection_sessions),
            "evtx_event_count": len(evtx_rows),
            "srum_observation_count": len(srum_rows),
            "registry_row_count": len(registry_rows),
            "returned_evtx_event_count": min(len(evtx_rows), limit),
            "returned_srum_observation_count": min(len(srum_rows), limit),
            "returned_registry_row_count": min(len(registry_rows), limit),
            "interpretation_notes": [
                "EVTX WLAN 8001 and NetworkProfile 10000 are stronger evidence of a successful connection than SRUM alone.",
                "SRUM network_connectivity can show historical or cumulative network state; use EVTX and NetworkList rows to anchor a specific connection date.",
                "EVTX WLAN 8002 is failure evidence and should not be counted as a successful connection.",
                "For questions about what happened while connected to a network, use every connection_sessions row unless the user specifies one session or exact start/end.",
            ],
        },
        "reconciled_networks": reconciled,
        "connection_sessions": connection_sessions,
        "evtx_wifi_events": evtx_rows[:limit],
        "srum_wifi_connectivity": srum_rows[:limit],
        "registry_connected_networks": registry_rows[:limit],
    }


def _wifi_network_name_from_row(row: dict[str, Any]) -> str:
    for key in ("l2_profile_name", "display_name", "value_data"):
        value = str(row.get(key) or "").strip()
        if value and value not in {"(default)"}:
            return value
    if str(row.get("provider") or "").casefold().endswith("networkprofile"):
        value = str(row.get("payload_data1") or "").strip()
        if value and ":" not in value and len(value) < 100:
            return value
    for key in ("payload_data3", "payload_data2", "payload_data1", "map_description", "payload"):
        value = str(row.get(key) or "")
        match = re.search(r"(?:SSID|ProfileName|Name|NetworkHintString)[:\"#= ]+([^,\"}\r\n]+)", value, flags=re.IGNORECASE)
        if match:
            candidate = match.group(1).strip()
            candidate = re.sub(r"^(?:#text|text)[:\"= ]+", "", candidate, flags=re.IGNORECASE).strip()
            if candidate:
                return candidate
    return "(unknown)"


def _wifi_event_class(row: dict[str, Any]) -> str:
    event_id = str(row.get("event_id") or "")
    text = " ".join(str(row.get(key) or "") for key in ("map_description", "payload_data1", "payload_data2", "payload_data3", "payload")).casefold()
    if event_id == "8001" or "connection was successful" in text or "connect to the internet" in text:
        return "connected"
    if event_id == "8002" or "connection was failed" in text or "failed to connect" in text:
        return "failed"
    if event_id == "8000" or "connection was attempted" in text:
        return "attempted"
    if event_id in {"8011", "11000", "11001", "11005", "11010", "50067"}:
        return "diagnostic"
    return "observed"


def _reconcile_wifi_networks(
    evtx_rows: list[dict[str, Any]],
    srum_rows: list[dict[str, Any]],
    registry_rows: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    grouped: dict[str, dict[str, Any]] = {}

    def bucket(name: str) -> dict[str, Any]:
        normalized = (name or "(unknown)").strip() or "(unknown)"
        key = normalized.casefold()
        if key not in grouped:
            grouped[key] = {
                "network_name": normalized,
                "first_seen_utc": None,
                "last_seen_utc": None,
                "sources": [],
                "successful_connection_events": 0,
                "failed_connection_events": 0,
                "attempted_connection_events": 0,
                "diagnostic_events": 0,
                "srum_observations": 0,
                "registry_observations": 0,
                "assessment": "observed",
            }
        return grouped[key]

    def observe(item: dict[str, Any], when: Any, source: str) -> None:
        if when:
            text = str(when)
            if item["first_seen_utc"] is None or text < item["first_seen_utc"]:
                item["first_seen_utc"] = text
            if item["last_seen_utc"] is None or text > item["last_seen_utc"]:
                item["last_seen_utc"] = text
        if source not in item["sources"]:
            item["sources"].append(source)

    for row in evtx_rows:
        network_name = str(row.get("network_name") or "(unknown)")
        event_class = str(row.get("wifi_event_class") or "observed")
        if not _meaningful_wifi_network_name(network_name) and event_class not in {"connected", "failed", "attempted"}:
            continue
        item = bucket(network_name)
        if event_class == "connected":
            item["successful_connection_events"] += 1
        elif event_class == "failed":
            item["failed_connection_events"] += 1
        elif event_class == "attempted":
            item["attempted_connection_events"] += 1
        elif event_class == "diagnostic":
            item["diagnostic_events"] += 1
        observe(item, row.get("time_created"), "evtx_events")
    for row in srum_rows:
        network_name = str(row.get("network_name") or "(unknown)")
        if not _meaningful_wifi_network_name(network_name):
            continue
        item = bucket(network_name)
        item["srum_observations"] += 1
        observe(item, row.get("timestamp") or row.get("connect_start_time"), "srum_records")
    for row in registry_rows:
        network_name = str(row.get("network_name") or "(unknown)")
        if not _meaningful_wifi_network_name(network_name):
            continue
        item = bucket(network_name)
        item["registry_observations"] += 1
        observe(item, row.get("event_time_utc") or row.get("key_last_write_utc"), "registry_artifacts")
    for item in grouped.values():
        if item["successful_connection_events"]:
            item["assessment"] = "connected"
        elif item["failed_connection_events"] and not item["successful_connection_events"]:
            item["assessment"] = "attempted_failed"
        elif item["srum_observations"] or item["registry_observations"]:
            item["assessment"] = "historical_or_observed"
        item["sources"] = sorted(item["sources"])
        item["first_seen"] = item["first_seen_utc"]
        item["last_seen"] = item["last_seen_utc"]
    return sorted(
        grouped.values(),
        key=lambda row: (
            _wifi_assessment_rank(row.get("assessment")),
            0 if _meaningful_wifi_network_name(row.get("network_name")) else 1,
            row.get("network_name") or "",
            row.get("first_seen_utc") or "",
        ),
    )


def _wifi_assessment_rank(value: Any) -> int:
    return {
        "connected": 0,
        "attempted_failed": 1,
        "historical_or_observed": 2,
        "observed": 3,
    }.get(str(value or ""), 9)


def _public_wifi_connection_sessions(
    evtx_rows: list[dict[str, Any]],
    *,
    ssid: str | None = None,
    limit: int = 100,
) -> list[dict[str, Any]]:
    ssid_text = (ssid or "").strip().casefold()
    sessions: list[dict[str, Any]] = []
    for session in _wifi_session_rows(evtx_rows):
        network_name = str(session.get("network_name") or "").strip()
        if ssid_text and ssid_text not in network_name.casefold() and ssid_text not in json.dumps(session, default=str).casefold():
            continue
        start = normalize_timestamp(session.get("start"))
        end = normalize_timestamp(session.get("end"))
        if not start:
            continue
        start_row = session.get("start_row") if isinstance(session.get("start_row"), dict) else {}
        end_row = session.get("end_row") if isinstance(session.get("end_row"), dict) else {}
        row = {
            "network_name": network_name or start_row.get("network_name") or "(unknown)",
            "start": start,
            "end": end,
            "duration_ms": _timeline_duration_ms(start, end),
            "start_event_id": start_row.get("event_id"),
            "end_event_id": end_row.get("event_id"),
            "start_basis": start_row.get("map_description") or start_row.get("provider") or "wifi_connected",
            "end_basis": end_row.get("map_description") or session.get("end_basis"),
            "supporting_event_count": session.get("supporting_event_count"),
            "source_table": "evtx_events",
            "timeline_window_tool": {
                "tool": "perceptor_timeline_window",
                "arguments": {
                    "start": start,
                    "end": end,
                    "limit": 250,
                },
            },
            "guidance": "Use perceptor_timeline_window with this start/end to answer what happened during the connection.",
        }
        sessions.append(row)
        if len(sessions) >= limit:
            break
    return sessions


def _wifi_session_activity_plan(sessions: list[dict[str, Any]], *, case_id: str) -> dict[str, Any]:
    calls = []
    windows = []
    for index, session in enumerate(sessions, start=1):
        start = session.get("start")
        end = session.get("end")
        if not start:
            continue
        windows.append({"label": f"{session.get('network_name') or 'Wi-Fi'} session {index}", "start": start, "end": end})
        calls.append(
            {
                "session_index": index,
                "network_name": session.get("network_name"),
                "start": start,
                "end": end,
                "tool": "perceptor_timeline_window",
                "arguments": {
                    "case_id": case_id,
                    "start": start,
                    "end": end,
                    "limit": 250,
                },
            }
        )
    return {
        "mode": "all_matching_sessions",
        "session_count": len(calls),
        "aggregate_tool": {
            "tool": "perceptor_activity_windows",
            "arguments": {
                "case_id": case_id,
                "windows": windows,
                "limit": 250,
            },
        },
        "calls": calls,
        "aggregation_guidance": "Call aggregate_tool first. Use per-session calls only for drilldown. Combine browser, file, email, USB, execution, communication, direct_activity, and timeline findings across sessions before answering.",
    }


def _attach_wifi_sessions_to_networks(networks: list[dict[str, Any]], sessions: list[dict[str, Any]]) -> None:
    sessions_by_name: dict[str, list[dict[str, Any]]] = {}
    for session in sessions:
        key = str(session.get("network_name") or "").strip().casefold()
        if not key:
            continue
        sessions_by_name.setdefault(key, []).append(session)
    for network in networks:
        key = str(network.get("network_name") or "").strip().casefold()
        matched = sessions_by_name.get(key, [])
        network["connection_session_count"] = len(matched)
        network["connection_sessions"] = matched[:10]
        network["timeline_window_tools"] = [row.get("timeline_window_tool") for row in matched[:10] if row.get("timeline_window_tool")]


def _meaningful_wifi_network_name(value: Any) -> bool:
    text = str(value or "").strip()
    if not text or text in {"(unknown)", "<none>", "(none)"}:
        return False
    lowered = text.casefold()
    if lowered in {
        "adapter",
        "ansistringtemplate",
        "callerusersid",
        "interfaceguid",
        "message1",
        "networkhintstring",
        "newconsentvalue",
        "newinternetconnectionprofile",
        "usersid",
        "id",
    }:
        return False
    if re.fullmatch(r"\{[0-9a-f-]{32,40}\}", lowered):
        return False
    if re.fullmatch(r"[0-9a-f]{12,}", lowered):
        return False
    if re.fullmatch(r"\d+\s+\(0x[0-9a-f]+\)", lowered):
        return False
    if re.fullmatch(r"\d+", lowered):
        return False
    return True


def srum_app_network_usage_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    rows = _query_report_rows(
        db,
        case_id,
        "srum_records",
        """
        SELECT
          COALESCE(NULLIF(app_name, ''), NULLIF(app_path, ''), '(unknown)') AS application,
          app_path,
          app_description,
          user_name,
          user_sid,
          COALESCE(NULLIF(l2_profile_name, ''), '(unknown)') AS network_name,
          SUM(COALESCE(TRY_CAST(bytes_received AS BIGINT), 0)) AS total_bytes_received,
          SUM(COALESCE(TRY_CAST(bytes_sent AS BIGINT), 0)) AS total_bytes_sent,
          SUM(COALESCE(TRY_CAST(bytes_received AS BIGINT), 0))
            + SUM(COALESCE(TRY_CAST(bytes_sent AS BIGINT), 0)) AS total_bytes,
          MIN(timestamp) AS first_observed_utc,
          MAX(timestamp) AS last_observed_utc,
          COUNT(*) AS observation_count
        FROM srum_records
        WHERE case_id = ?
          AND record_type = 'network_usage'
        GROUP BY application, app_path, app_description, user_name, user_sid, network_name
        HAVING total_bytes > 0
        ORDER BY total_bytes DESC, application
        LIMIT ?
        """,
        (case_id, limit),
    )
    totals = db.conn.execute(
        """
        SELECT
          SUM(CAST(COALESCE(NULLIF(bytes_received, ''), '0') AS INTEGER)) AS total_bytes_received,
          SUM(CAST(COALESCE(NULLIF(bytes_sent, ''), '0') AS INTEGER)) AS total_bytes_sent,
          COUNT(*) AS observation_count,
          COUNT(DISTINCT COALESCE(NULLIF(app_name, ''), NULLIF(app_path, ''), '(unknown)')) AS application_count
        FROM srum_records
        WHERE case_id = ?
          AND record_type = 'network_usage'
        """,
        (case_id,),
    ).fetchone()
    return {
        "case_id": case_id,
        "summary": dict(totals) if totals else {},
        "applications": [dict(row) for row in rows],
        "total_returned": len(rows),
    }


def srum_context_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    db.get_case(case_id)
    rows = _query_report_rows(
        db,
        case_id,
        "srum_records",
        """
        SELECT
          id,
          computer_id,
          image_id,
          record_type,
          source_table,
          COALESCE(NULLIF(timestamp, ''), NULLIF(connect_start_time, ''), NULLIF(start_time, '')) AS event_time_utc,
          app_name,
          app_path,
          app_description,
          user_name,
          user_sid,
          l2_profile_name,
          interface_type,
          vpn_profile_name,
          vpn_server,
          vpn_protocol,
          bytes_received,
          bytes_sent,
          connected_time,
          source_csv,
          row_number
        FROM srum_records
        WHERE case_id = ?
          AND (
            lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%onedrive%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%dropbox%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%drivefs%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%google drive%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%icloud%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%mstsc%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%remote desktop%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%chrome%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%firefox%'
            OR lower(coalesce(app_name, '') || ' ' || coalesce(app_path, '') || ' ' || coalesce(app_description, '')) LIKE '%msedge%'
            OR interface_type = '23'
            OR lower(coalesce(vpn_profile_name, '') || ' ' || coalesce(vpn_server, '') || ' ' || coalesce(vpn_protocol, '')) LIKE '%vpn%'
          )
        ORDER BY event_time_utc DESC, record_type
        LIMIT ?
        """,
        (case_id, limit),
    )
    for row in rows:
        row["context"] = _srum_context_label(row)
        row["total_bytes"] = _int_or_zero(row.get("bytes_received")) + _int_or_zero(row.get("bytes_sent"))
        row["source_table"] = row.get("source_table") or "srum_records"
    by_context: dict[str, int] = {}
    for row in rows:
        by_context[row["context"]] = by_context.get(row["context"], 0) + 1
    return {
        "case_id": case_id,
        "summary": {
            "context_counts": [
                {"context": key, "count": value}
                for key, value in sorted(by_context.items(), key=lambda item: (-item[1], item[0]))
            ],
            "interpretation_note": "SRUM timestamps and counters are contextual telemetry, not precise process execution times.",
        },
        "items": rows,
        "total_returned": len(rows),
    }


def _srum_context_label(row: dict[str, Any]) -> str:
    text = " ".join(
        str(row.get(key) or "")
        for key in ("app_name", "app_path", "app_description", "vpn_profile_name", "vpn_server", "vpn_protocol")
    ).lower()
    if row.get("interface_type") == "23" or "vpn" in text:
        return "vpn_context"
    if any(token in text for token in ("onedrive", "dropbox", "drivefs", "google drive", "icloud")):
        return "cloud_sync_context"
    if any(token in text for token in ("mstsc", "remote desktop", "terminal services")):
        return "rdp_context"
    if any(token in text for token in ("chrome", "firefox", "msedge", "edge")):
        return "browser_network_context"
    return "srum_context"


def _int_or_zero(value: Any) -> int:
    try:
        return int(str(value or "0"))
    except ValueError:
        return 0


