def _vpn_evtx_rows(db: Database, case_id: str, limit: int) -> list[dict[str, Any]]:
    return [
        _vpn_event_log_row(row)
        for row in _query_report_rows(
            db,
            case_id,
            "evtx_events",
            f"""
            SELECT *
            FROM evtx_events
            WHERE case_id = ?
              AND (
                event_id IN (
                  '20220', '20221', '20222', '20223', '20224', '20225',
                  '20226', '20227', '20228', '20268', '20269', '20270',
                  '20271', '20272', '20275'
                )
              )
            LIMIT ?
            """,
            (case_id, limit),
        )
    ]


def _vpn_event_log_row(row: Any) -> dict[str, Any]:
    activity_type, event_name = RASCLIENT_EVENT_MEANINGS.get(
        str(_row_value(row, "event_id") or ""),
        ("connection_observation", _row_value(row, "map_description") or f"Event ID {_row_value(row, 'event_id')}"),
    )
    text = " ".join(str(_row_value(row, key) or "") for key in ("payload", "payload_data1", "payload_data2", "payload_data3", "map_description"))
    return _vpn_row(
        source_type="event_log",
        activity_type=activity_type,
        event_time_utc=_row_value(row, "time_created"),
        profile_name=_vpn_profile_from_text(text),
        server=_vpn_server_from_text(text),
        protocol=_vpn_protocol_from_text(f"{text} {_row_value(row, 'provider')} {_row_value(row, 'channel')}"),
        event=event_name,
        user=_row_value(row, "user_name") or _row_value(row, "user_id"),
        path_or_process=_row_value(row, "executable_info"),
        source_file=_row_value(row, "source_file"),
        details={
            "provider": _row_value(row, "provider"),
            "channel": _row_value(row, "channel"),
            "event_id": _row_value(row, "event_id"),
        },
    )


def _vpn_registry_rows(db: Database, case_id: str, limit: int) -> list[dict[str, Any]]:
    text = (
        "coalesce(key_path, '') || ' ' || coalesce(value_name, '') || ' ' || "
        "coalesce(value_data, '') || ' ' || coalesce(normalized_path, '') || ' ' || coalesce(notes, '')"
    )
    return [
        _vpn_row(
            source_type=f"registry_{row['artifact']}",
            activity_type=_vpn_registry_activity_type(row["artifact"]),
            event_time_utc=row["event_time_utc"] or row["key_last_write_utc"],
            profile_name=_vpn_registry_profile_name(row),
            server=_vpn_server_from_text(f"{row['value_name']} {row['value_data']} {row['key_path']}"),
            protocol=_vpn_protocol_from_text(f"{row['value_name']} {row['value_data']} {row['key_path']}"),
            event=row["artifact"],
            user=row["user_profile"] or row["user_sid"],
            path_or_process=row["normalized_path"] or row["value_name"],
            source_file=row["source_path"],
            details={"key_path": row["key_path"], "value_name": row["value_name"], "notes": row["notes"]},
        )
        for row in _query_report_rows(
            db,
            case_id,
            "registry_artifacts",
            f"""
            SELECT *
            FROM registry_artifacts
            WHERE case_id = ?
              AND (
                (
                  artifact = 'connected_networks'
                  AND (
                    lower(coalesce(key_path, '')) LIKE '%networklist/profiles/%'
                    OR lower(coalesce(key_path, '')) LIKE '%networklist/signatures/%'
                  )
                  AND (
                    value_name IN ('Description', 'ProfileName', 'FirstNetwork')
                    OR (value_name = 'DnsSuffix' AND value_data NOT IN ('', '<none>'))
                    OR (value_name = 'NameType' AND value_data LIKE '23%')
                  )
                )
                OR (
                  (
                    artifact IN (
                      'ras_connection_manager', 'ras_phonebook_registry',
                      'bam', 'dam', 'autostart', 'installed_applications',
                      'amcache', 'userassist'
                    )
                  )
                  AND {VPN_TEXT_MATCH.format(text)}
                )
              )
            ORDER BY COALESCE(event_time_utc, key_last_write_utc)
            LIMIT ?
            """,
            (case_id, limit),
        )
    ]


def _vpn_registry_activity_type(artifact: str) -> str:
    if artifact in {"bam", "dam", "autostart"}:
        return "supporting_execution"
    if artifact == "connected_networks":
        return "network_profile_observation"
    return "configured"


def _vpn_registry_profile_name(row: Any) -> str:
    artifact = _row_value(row, "artifact") or ""
    value_name = _row_value(row, "value_name") or ""
    value_data = _row_value(row, "value_data") or ""
    if artifact == "connected_networks" and value_name == "NameType" and str(value_data).startswith("23"):
        profile_guid = _network_profile_guid(_row_value(row, "key_path") or "")
        return f"NetworkList VPN profile {profile_guid}".strip()
    return _row_value(row, "display_name") or value_data or value_name


def _network_profile_guid(key_path: str) -> str:
    match = re.search(r"\{[0-9a-fA-F-]{36}\}", key_path)
    return match.group(0) if match else ""


def _vpn_prefetch_rows(db: Database, case_id: str, limit: int) -> list[dict[str, Any]]:
    text = "coalesce(prefetch_name, '') || ' ' || coalesce(executable_name, '') || ' ' || coalesce(referenced_strings, '')"
    return [
        _vpn_row(
            source_type="prefetch",
            activity_type="supporting_execution",
            event_time_utc=row["last_run_time_utc"],
            server=_vpn_server_from_text(row["referenced_strings"] or ""),
            protocol=_vpn_protocol_from_text(row["referenced_strings"] or row["executable_name"] or ""),
            event="VPN-related executable prefetch",
            path_or_process=row["executable_name"] or row["prefetch_name"],
            source_file=row["artifact_path"] or row["source_csv"],
            details={"run_count": row["run_count"], "last_run_times_utc": row["last_run_times_utc"]},
        )
        for row in _query_report_rows(
            db,
            case_id,
            "prefetch_items",
            f"""
            SELECT *
            FROM prefetch_items
            WHERE case_id = ? AND {VPN_TEXT_MATCH.format(text)}
            ORDER BY last_run_time_utc
            LIMIT ?
            """,
            (case_id, limit),
        )
    ]


def _vpn_shortcut_rows(db: Database, case_id: str, limit: int) -> list[dict[str, Any]]:
    columns = _report_table_columns(db, case_id, "shortcut_items")
    text = " || ' ' || ".join(
        f"coalesce({name}, '')"
        for name in [
            "artifact_name",
            "artifact_path",
            "file_name",
            "file_location",
            "command_line_arguments",
            "working_directory",
            "network_path",
            "app_id",
            "app_id_description",
            "source_csv",
        ]
        if name in columns
    )
    text = text or "''"
    return [
        _vpn_row(
            source_type=f"shortcut_items_{row['artifact_type']}",
            activity_type="supporting_file_or_app_use",
            event_time_utc=row["event_time_utc"],
            profile_name=_vpn_profile_from_text(
                f"{row['file_name']} {row['file_location']} {row['artifact_name']} {row['app_id_description']}"
            ),
            server=_vpn_server_from_text(f"{row['file_name']} {row['file_location']} {row['command_line_arguments']}"),
            protocol=_vpn_protocol_from_text(
                f"{row['file_name']} {row['file_location']} {row['command_line_arguments']} {row['app_id_description']}"
            ),
            event=f"VPN-related {row['artifact_type']} shortcut/Jump List evidence",
            path_or_process=row["file_location"] or row["file_name"] or row["artifact_path"],
            source_file=row["source_csv"],
            details={
                "artifact_type": row["artifact_type"],
                "artifact_name": row["artifact_name"],
                "artifact_path": row["artifact_path"],
                "app_id": row["app_id"],
                "app_id_description": row["app_id_description"],
                "jumplist_item_number": row["jumplist_item_number"],
                "command_line_arguments": row["command_line_arguments"],
                "working_directory": row["working_directory"],
                "row_number": row["row_number"],
            },
        )
        for row in _query_report_rows(
            db,
            case_id,
            "shortcut_items",
            f"""
            SELECT {_shortcut_select_sql(columns)},
                   COALESCE(NULLIF(target_accessed, ''), NULLIF(target_modified, ''), NULLIF(target_created, ''), NULLIF(lnk_accessed, ''), NULLIF(lnk_modified, ''), NULLIF(lnk_created, '')) AS event_time_utc
            FROM shortcut_items
            WHERE case_id = ?
              AND {VPN_TEXT_MATCH.format(text)}
            ORDER BY event_time_utc
            LIMIT ?
            """,
            (case_id, limit),
        )
    ]


def _vpn_execution_cache_rows(db: Database, case_id: str, limit: int) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for table, time_col in (("amcache_entries", "modified_utc"), ("shimcache_entries", "last_modified_utc")):
        path_col = "path"
        for row in db.conn.execute(
            f"""
            SELECT *
            FROM {table}
            WHERE case_id = ? AND {VPN_TEXT_MATCH.format(path_col)}
            ORDER BY {time_col}
            LIMIT ?
            """,
            (case_id, limit),
        ).fetchall():
            rows.append(_vpn_row(
                source_type=table.replace("_entries", ""),
                activity_type="supporting_execution",
                event_time_utc=row[time_col],
                protocol=_vpn_protocol_from_text(row["path"] or ""),
                event="VPN-related executable artifact",
                path_or_process=row["path"],
                source_file=row["source_file"] or row["source_csv"],
            ))
    return rows


def _vpn_etl_rows(db: Database, case_id: str, limit: int) -> list[dict[str, Any]]:
    text = "coalesce(source_name, '') || ' ' || coalesce(provider_name, '') || ' ' || coalesce(event_name, '') || ' ' || coalesce(command_line, '')"
    return [
        _vpn_row(
            source_type="etl",
            activity_type="connection_observation",
            event_time_utc=row["timestamp_utc"],
            profile_name=_vpn_profile_from_text(row["command_line"] or ""),
            server=_vpn_server_from_text(row["command_line"] or ""),
            protocol=_vpn_protocol_from_text(f"{row['provider_name']} {row['event_name']} {row['command_line']}"),
            event=row["event_name"] or row["event_category"],
            user=row["user_sid"],
            path_or_process=row["image_name"] or row["command_line"],
            source_file=row["source_file"],
            details={"provider": row["provider_name"], "source_name": row["source_name"]},
        )
        for row in db.conn.execute(
            f"""
            SELECT *
            FROM etl_events
            WHERE case_id = ? AND {VPN_TEXT_MATCH.format(text)}
            ORDER BY timestamp_utc
            LIMIT ?
            """,
            (case_id, limit),
        ).fetchall()
    ]


def _vpn_wer_defender_rows(db: Database, case_id: str, limit: int) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for row in _query_report_rows(
        db,
        case_id,
        "windows_error_reports",
        """
        SELECT *
        FROM windows_error_reports
        WHERE case_id = ?
          AND lower(coalesce(app_name, '') || ' ' || coalesce(original_filename, '') || ' ' || coalesce(ui_path, '')) LIKE '%vpn%'
        ORDER BY event_time_utc
        LIMIT ?
        """,
        (case_id, limit),
    ):
        rows.append(_vpn_row(
            source_type="windows_error_reporting",
            activity_type="supporting_execution",
            event_time_utc=row["event_time_utc"],
            protocol=_vpn_protocol_from_text(f"{row['app_name']} {row['original_filename']} {row['ui_path']}"),
            event=row["event_type"] or "WER report",
            path_or_process=row["app_name"] or row["ui_path"],
            source_file=row["source_file"],
            details={"report_identifier": row["report_identifier"]},
        ))
    for row in _query_report_rows(
        db,
        case_id,
        "windows_defender_events",
        """
        SELECT *
        FROM windows_defender_events
        WHERE case_id = ?
          AND lower(coalesce(event_type, '') || ' ' || coalesce(path, '') || ' ' || coalesce(resource, '') || ' ' || coalesce(message, '')) LIKE '%vpn%'
        ORDER BY event_time_utc
        LIMIT ?
        """,
        (case_id, limit),
    ):
        rows.append(_vpn_row(
            source_type="windows_defender",
            activity_type="supporting_execution",
            event_time_utc=row["event_time_utc"],
            protocol=_vpn_protocol_from_text(f"{row['event_type']} {row['path']} {row['message']}"),
            event=row["event_type"] or row["component"],
            path_or_process=row["path"] or row["resource"],
            source_file=row["source_file"],
            details={"threat_name": row["threat_name"]},
        ))
    return rows


def _vpn_server_from_text(text: str) -> str:
    for match in re.finditer(r"\b(?:[a-z0-9-]+\.)+[a-z]{2,}(?::\d{2,5})?\b", text, re.IGNORECASE):
        host = match.group(0)
        tld = host.split(":")[0].rsplit(".", 1)[-1].lower()
        if tld in {"exe", "dll", "sys", "pf", "nls", "mui", "dat", "ini", "log", "tmp", "cat", "inf", "sdb"}:
            continue
        return host
    return ""


def _vpn_protocol_from_text(text: str) -> str:
    lowered = text.lower()
    for protocol in ("sstp", "ikev2", "l2tp", "pptp", "wireguard", "openvpn"):
        if protocol in lowered:
            return protocol.upper()
    return ""


def _vpn_profile_from_text(text: str) -> str:
    match = re.search(r"(?:profile name|connection name|entry name|vpn name)[=:\s]+([A-Za-z0-9 _.-]{3,80})", text, re.IGNORECASE)
    return match.group(1).strip() if match else ""


def _vpn_evidence_group(*, profile_name: Any = "", server: Any = "", protocol: Any = "") -> str:
    profile = str(profile_name or "").strip().lower()
    host = str(server or "").strip().lower()
    vpn_protocol = str(protocol or "").strip().lower()
    if host:
        return "|".join(part for part in (f"server:{host}", f"protocol:{vpn_protocol}" if vpn_protocol else "") if part)
    if profile and profile not in {"(unknown)", "unknown"}:
        return "|".join(part for part in (f"profile:{profile}", f"protocol:{vpn_protocol}" if vpn_protocol else "") if part)
    if vpn_protocol:
        return f"protocol:{vpn_protocol}"
    return "unknown"


def windows_search_report(db: Database, case_id: str, *, report_type: str = "files", limit: int = 100) -> dict[str, Any]:
    tables = {
        "files": ("windows_search_files", "files"),
        "internet": ("windows_search_internet_history", "internet_history"),
        "activity": ("windows_search_activity_history", "activity_history"),
        "emails": ("windows_search_email_indicators", "email_indicators"),
        "content": ("windows_search_indexed_content", "indexed_content"),
        "properties": ("windows_search_properties", "properties"),
    }
    table, key = tables[report_type]
    report = _table_report(db, case_id, table, key, limit)
    report["parser_status"] = _windows_search_parser_status(db, case_id)
    return report


def windows_search_combined_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    parser_status = _windows_search_parser_status(db, case_id)
    disk_files = _query_report_rows(
        db,
        case_id,
        "windows_search_files",
        """
        SELECT 'disk_index' AS source, 'file' AS artifact_type,
               gather_time AS timestamp, item_path AS path, file_name AS name,
               COALESCE(is_deleted, '') AS status,
               COALESCE(item_type, '') AS details
        FROM windows_search_files
        WHERE case_id = ?
        ORDER BY COALESCE(gather_time, ''), COALESCE(item_path, '')
        LIMIT ?
        """,
        (case_id, limit),
    )
    gather_logs = _query_report_rows(
        db,
        case_id,
        "windows_search_gather_logs",
        """
        SELECT 'disk_gather_log' AS source, COALESCE(log_type, 'gather') AS artifact_type,
               timestamp_utc AS timestamp, item_path AS path, source_name AS name,
               CASE WHEN is_deleted_path = 'true' THEN 'deleted_path' ELSE '' END AS status,
               'document_id=' || COALESCE(document_id, '') || ' scope_id=' || COALESCE(scope_id, '') AS details
        FROM windows_search_gather_logs
        WHERE case_id = ?
        ORDER BY COALESCE(timestamp_utc, ''), COALESCE(item_path, '')
        LIMIT ?
        """,
        (case_id, limit),
    )
    memory_carves = _query_report_rows(
        db,
        case_id,
        "windows_search_memory_carves",
        """
        SELECT 'memory_carve' AS source, detected_format AS artifact_type,
               '' AS timestamp, carve_path AS path, carve_name AS name,
               parser_status AS status,
               'tables=' || COALESCE(table_count, '0') ||
                 ' objects=' || COALESCE(object_count, '0') ||
                 ' rows=' || COALESCE(extractable_row_count, '0') AS details
        FROM windows_search_memory_carves
        WHERE case_id = ?
        ORDER BY row_number
        LIMIT ?
        """,
        (case_id, limit),
    )
    memory_objects = _query_report_rows(
        db,
        case_id,
        "windows_search_memory_objects",
        """
        SELECT 'memory_schema' AS source, object_type AS artifact_type,
               '' AS timestamp, carve_path AS path, object_name AS name,
               parser_status AS status,
               COALESCE(sql_text, '') AS details
        FROM windows_search_memory_objects
        WHERE case_id = ?
        ORDER BY row_number
        LIMIT ?
        """,
        (case_id, limit),
    )
    memory_rows = _query_report_rows(
        db,
        case_id,
        "windows_search_memory_rows",
        """
        SELECT 'memory_row' AS source, table_name AS artifact_type,
               '' AS timestamp, carve_path AS path, table_name AS name,
               parser_status AS status,
               COALESCE(row_text, parser_error, '') AS details
        FROM windows_search_memory_rows
        WHERE case_id = ?
        ORDER BY row_number
        LIMIT ?
        """,
        (case_id, limit),
    )
    combined = _dedupe_windows_search_combined_rows([*disk_files, *gather_logs, *memory_carves, *memory_objects, *memory_rows])
    combined.sort(
        key=lambda row: (
            _windows_search_combined_source_rank(row.get("source")),
            str(row.get("timestamp") or "9999"),
            str(row.get("source") or ""),
            str(row.get("path") or ""),
            str(row.get("name") or ""),
        )
    )
    combined = combined[:limit]
    counts = {
        "windows_search_files": _report_table_count(db, case_id, "windows_search_files"),
        "windows_search_gather_logs": _report_table_count(db, case_id, "windows_search_gather_logs"),
        "windows_search_indexed_content": _report_table_count(db, case_id, "windows_search_indexed_content"),
        "windows_search_properties": _report_table_count(db, case_id, "windows_search_properties"),
        "windows_search_memory_carves": _report_table_count(db, case_id, "windows_search_memory_carves"),
        "windows_search_memory_objects": _report_table_count(db, case_id, "windows_search_memory_objects"),
        "windows_search_memory_rows": _report_table_count(db, case_id, "windows_search_memory_rows"),
    }
    memory_parsed_rows = _report_table_count_where(
        db,
        case_id,
        "windows_search_memory_rows",
        "parser_status = ?",
        ("parsed",),
    )
    return {
        "case_id": case_id,
        "summary": {
            **counts,
            "windows_search_memory_parsed_rows": memory_parsed_rows,
            "combined_returned": len(combined),
            "parser_status": parser_status.get("summary_status"),
            "memory_carves_with_schema": sum(1 for row in memory_carves if str(row.get("details") or "").find("objects=0") < 0),
            "dedupe_basis": "normalized source/artifact/path/name/status/details",
        },
        "parser_status": parser_status,
        "combined_artifacts": combined,
        "memory_carves": memory_carves,
        "memory_schema_objects": memory_objects,
        "memory_rows": memory_rows,
        "disk_files": disk_files,
        "gather_logs": gather_logs,
        "caveats": [
            "Memory SQLite carves may be partial or malformed; schema-only recovery is still useful evidence that SearchIndexer held decrypted Search pages.",
            "Disk gather logs provide crawl/indexing context but are not equivalent to full indexed Search rows.",
            "Encrypted AesGcm1 SQLite databases remain unsupported unless a usable key or live plaintext cache is recovered.",
        ],
    }


def _dedupe_windows_search_combined_rows(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, str, str, str, str, str]] = set()
    output: list[dict[str, Any]] = []
    for row in rows:
        key = (
            str(row.get("source") or "").lower(),
            str(row.get("artifact_type") or "").lower(),
            _normalize_windows_search_path(row.get("path")),
            str(row.get("name") or "").lower(),
            str(row.get("status") or "").lower(),
            hashlib.sha256(str(row.get("details") or "").encode("utf-8", errors="replace")).hexdigest(),
        )
        if key in seen:
            continue
        seen.add(key)
        output.append(row)
    return output


def _windows_search_combined_source_rank(value: Any) -> int:
    source = str(value or "")
    return {
        "disk_index": 0,
        "memory_carve": 1,
        "memory_schema": 2,
        "memory_row": 3,
        "disk_gather_log": 4,
    }.get(source, 9)


def _normalize_windows_search_path(value: Any) -> str:
    text = str(value or "").replace("/", "\\").strip().lower()
    text = re.sub(r"^file:\\+", "", text)
    text = re.sub(r"\\+", r"\\", text)
    return text.rstrip("\\")


def windows_search_combined_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Combined Windows Search Artifacts",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Parser status: `{summary.get('parser_status') or ''}`",
        f"- Disk Search file rows: `{summary.get('windows_search_files', 0)}`",
        f"- Disk gather log rows: `{summary.get('windows_search_gather_logs', 0)}`",
        f"- Indexed content rows: `{summary.get('windows_search_indexed_content', 0)}`",
        f"- Property rows: `{summary.get('windows_search_properties', 0)}`",
        f"- Memory carves: `{summary.get('windows_search_memory_carves', 0)}`",
        f"- Memory schema objects: `{summary.get('windows_search_memory_objects', 0)}`",
        f"- Memory parsed rows: `{summary.get('windows_search_memory_parsed_rows', 0)}`",
        f"- Memory row-attempt records: `{summary.get('windows_search_memory_rows', 0)}`",
        "",
        "## Parser Status",
        "",
    ]
    status = report.get("parser_status") if isinstance(report.get("parser_status"), dict) else {}
    lines.append(f"- {status.get('summary_note') or ''}")
    inventories = status.get("inventories") if isinstance(status.get("inventories"), list) else []
    for item in inventories[:10]:
        lines.append(
            f"- `{item.get('detected_format') or ''}` `{item.get('parser_status') or ''}` "
            f"{item.get('source_path') or ''}"
        )
    lines.extend(["", "## Combined View", ""])
    combined = report.get("combined_artifacts") if isinstance(report.get("combined_artifacts"), list) else []
    if not combined:
        lines.append("- No Windows Search disk or memory rows were available.")
    for row in combined[:50]:
        details = str(row.get("details") or "").replace("\n", " ")
        if len(details) > 220:
            details = details[:217] + "..."
        lines.append(
            f"- `{row.get('source') or ''}` `{row.get('artifact_type') or ''}` "
            f"`{row.get('status') or ''}` {row.get('timestamp') or ''} "
            f"{row.get('path') or row.get('name') or ''} {details}"
        )
    lines.extend(["", "## Caveats", ""])
    for caveat in report.get("caveats") or []:
        lines.append(f"- {caveat}")
    return "\n".join(lines).rstrip() + "\n"


def _windows_search_parser_status(db: Database, case_id: str) -> dict[str, Any]:
    db.get_case(case_id)
    outputs = [
        dict(row)
        for row in db.conn.execute(
            """
            SELECT tool_outputs.*, jobs.exit_code, jobs.stdout_path, jobs.stderr_path, jobs.output_folder,
                   jobs.start_time, jobs.end_time
            FROM tool_outputs
            LEFT JOIN jobs ON jobs.id = tool_outputs.job_id
            WHERE tool_outputs.case_id = ?
              AND tool_outputs.tool_name IN ('SIDR', 'WindowsSearchESEParser', 'WindowsSearchGatherParser')
            ORDER BY COALESCE(jobs.start_time, tool_outputs.created_at), tool_outputs.tool_name
            """,
            (case_id,),
        ).fetchall()
    ]
    inventories: list[dict[str, Any]] = []
    for output in outputs:
        if output.get("tool_name") != "WindowsSearchESEParser":
            continue
        inventory_path = Path(str(output.get("path") or "")).parent / "WindowsSearchParserInventory.json"
        if not inventory_path.exists():
            continue
        try:
            data = json.loads(inventory_path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError) as exc:
            inventories.append(
                {
                    "source_path": "",
                    "detected_format": "inventory_unreadable",
                    "parser_status": "inventory_unreadable",
                    "parser_note": str(exc),
                    "inventory_path": display_evidence_path(inventory_path),
                }
            )
            continue
        for item in data if isinstance(data, list) else [data]:
            if not isinstance(item, dict):
                continue
            normalized = dict(item)
            if normalized.get("source_path"):
                normalized["source_path"] = _windows_search_display_path(normalized.get("source_path"))
            normalized["inventory_path"] = display_evidence_path(inventory_path)
            inventories.append(normalized)

    table_counts = {
        "windows_search_files": _report_table_count(db, case_id, "windows_search_files"),
        "windows_search_properties": _report_table_count(db, case_id, "windows_search_properties"),
        "windows_search_indexed_content": _report_table_count(db, case_id, "windows_search_indexed_content"),
        "windows_search_gather_logs": _report_table_count(db, case_id, "windows_search_gather_logs"),
    }
    statuses = {str(item.get("parser_status") or "") for item in inventories}
    formats = {str(item.get("detected_format") or "") for item in inventories}
    if "unsupported_encrypted_sqlite" in statuses:
        summary_status = "partial_unsupported_encrypted_sqlite"
        summary_note = "Windows Search database was found but is encrypted AesGcm1 SQLite; full index rows were not parsed. Gather logs may still provide limited context."
    elif "unsupported_sqlite" in statuses:
        summary_status = "partial_unsupported_sqlite"
        summary_note = "Windows Search SQLite database was found but no SQLite schema parser is available. Gather logs may still provide limited context."
    elif "parsed" in statuses:
        summary_status = "parsed"
        summary_note = "Windows Search index parser produced normalized rows."
    elif "not_found" in statuses:
        summary_status = "not_found"
        summary_note = "Windows Search index database was not found in the extracted artifact path."
    elif inventories:
        summary_status = "unknown_or_unparsed"
        summary_note = "Windows Search parser inventory exists but did not report a parsed index."
    else:
        summary_status = "no_parser_inventory"
        summary_note = "No Windows Search parser inventory was found for this case."

    return {
        "summary_status": summary_status,
        "summary_note": summary_note,
        "detected_formats": sorted(item for item in formats if item),
        "fallback_context": {
            "gather_logs_available": table_counts["windows_search_gather_logs"] > 0,
            "gather_log_value": "Gather logs can provide crawl/indexing timestamps, document IDs, and occasional item URLs or paths, but they are not equivalent to full indexed file/property/content rows.",
        },
        "inventories": inventories,
        "table_counts": table_counts,
        "tool_outputs": [
            {
                "tool_name": output.get("tool_name"),
                "path": display_evidence_path(output.get("path")),
                "row_count": output.get("row_count"),
                "exit_code": output.get("exit_code"),
                "start_time": output.get("start_time"),
                "end_time": output.get("end_time"),
            }
            for output in outputs
        ],
    }


def _windows_search_display_path(path: Any) -> str:
    text = str(path or "").replace("\\", "/")
    marker = "/WindowsSearch/Applications/Windows/"
    index = text.lower().find(marker.lower())
    if index >= 0:
        return "/ProgramData/Microsoft/Search/Data/Applications/Windows/" + text[index + len(marker):].lstrip("/")
    return display_evidence_path(path)


def file_metadata_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 100,
    extension: str | None = None,
    property_name: str | None = None,
    path_contains: str | None = None,
    tool_name: str | None = None,
    source_folder: str | None = None,
    user_only: bool = False,
    exclude_system: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    filters = ["file_internal_metadata.case_id = ?"]
    params: list[Any] = [case_id]
    if extension:
        normalized_extension = extension if extension.startswith(".") else f".{extension}"
        filters.append("LOWER(file_internal_metadata.extension) = LOWER(?)")
        params.append(normalized_extension)
    if property_name:
        filters.append("LOWER(file_internal_metadata.property_name) = LOWER(?)")
        params.append(property_name)
    if path_contains:
        filters.append("file_internal_metadata.original_path LIKE ?")
        params.append(f"%{path_contains}%")
    if source_folder:
        normalized_folder = source_folder.strip("/").replace("\\", "/")
        filters.append("file_internal_metadata.original_path LIKE ?")
        params.append(f"{normalized_folder}/%")
    if tool_name:
        filters.append("file_internal_metadata.tool_name = ?")
        params.append(tool_name)
    if user_only:
        filters.append("file_internal_metadata.original_path LIKE 'Users/%'")
    if exclude_system:
        filters.append(
            """
            file_internal_metadata.original_path NOT LIKE 'Windows/%'
            AND file_internal_metadata.original_path NOT LIKE 'Windows.old/Windows/%'
            AND file_internal_metadata.original_path NOT LIKE 'Windows.old/Program Files/%'
            AND file_internal_metadata.original_path NOT LIKE 'Windows.old/Program Files (x86)/%'
            AND file_internal_metadata.original_path NOT LIKE 'Windows.old/ProgramData/%'
            AND file_internal_metadata.original_path NOT LIKE 'Program Files/%'
            AND file_internal_metadata.original_path NOT LIKE 'Program Files (x86)/%'
            AND file_internal_metadata.original_path NOT LIKE 'ProgramData/%'
            """
        )
    params.append(limit)
    rows = _query_report_rows(
        db,
        case_id,
        "file_internal_metadata",
        f"""
        SELECT file_internal_metadata.*
        FROM file_internal_metadata
        WHERE {' AND '.join(filters)}
        ORDER BY file_internal_metadata.created_at, file_internal_metadata.row_number
        LIMIT ?
        """,
        params,
    )
    computer_labels = _computer_labels(db, case_id)
    image_paths = _image_paths(db, case_id)
    for row in rows:
        computer_id = row.get("computer_id")
        image_id = row.get("image_id")
        row["computer_label"] = computer_labels.get(str(computer_id)) if computer_id else None
        row["image_path"] = image_paths.get(str(image_id)) if image_id else None
    return {
        "case_id": case_id,
        "filters": {
            "extension": extension,
            "property": property_name,
            "path": path_contains,
            "source_folder": source_folder,
            "tool_name": tool_name,
            "user_only": user_only,
            "exclude_system": exclude_system,
        },
        "file_internal_metadata": rows,
        "total_returned": len(rows),
    }


def file_metadata_folders_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 100,
    depth: int = 3,
    tool_name: str | None = None,
    extension: str | None = None,
    user_only: bool = False,
    exclude_system: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    rows = file_metadata_report(
        db,
        case_id,
        limit=1_000_000,
        extension=extension,
        tool_name=tool_name,
        user_only=user_only,
        exclude_system=exclude_system,
    )["file_internal_metadata"]
    folders: dict[str, dict[str, Any]] = {}
    for row in rows:
        original_path = str(row.get("original_path") or "")
        parts = [part for part in original_path.replace("\\", "/").split("/") if part]
        folder = "/".join(parts[:depth]) if len(parts) >= depth else "/".join(parts[:-1])
        if not folder:
            folder = "."
        item = folders.setdefault(
            folder,
            {"folder": folder, "metadata_rows": 0, "files": set(), "properties": set()},
        )
        item["metadata_rows"] += 1
        item["files"].add(original_path)
        if row.get("property_name"):
            item["properties"].add(row["property_name"])
    folder_rows = []
    for item in folders.values():
        folder_rows.append(
            {
                "folder": item["folder"],
                "metadata_rows": item["metadata_rows"],
                "file_count": len(item["files"]),
                "property_count": len(item["properties"]),
            }
        )
    folder_rows.sort(key=lambda row: (-row["file_count"], row["folder"]))
    return {
        "case_id": case_id,
        "filters": {
            "depth": depth,
            "tool_name": tool_name,
            "extension": extension,
            "user_only": user_only,
            "exclude_system": exclude_system,
        },
        "folders": folder_rows[:limit],
        "total_returned": min(len(folder_rows), limit),
        "total_folders": len(folder_rows),
    }


def file_metadata_skipped_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 100,
    tool_name: str | None = None,
    since: str | None = None,
    latest: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    filters = ["activity_log.case_id = ?", "activity_log.event = 'artifact.skipped_reparse'"]
    params: list[Any] = [case_id]
    if since:
        filters.append("activity_log.created_at >= ?")
        params.append(since)
    params.append(limit * 10 if latest else limit)
    rows = db.conn.execute(
        f"""
        SELECT activity_log.*, computers.label AS computer_label, images.path AS image_path
        FROM activity_log
        LEFT JOIN computers ON activity_log.computer_id = computers.id
        LEFT JOIN images ON activity_log.image_id = images.id
        WHERE {' AND '.join(filters)}
        ORDER BY activity_log.created_at DESC
        LIMIT ?
        """,
        params,
    ).fetchall()
    skipped = []
    seen_latest: set[str] = set()
    for row in rows:
        details = json.loads(row["details_json"] or "{}")
        row_tool_name = details.get("tool_name")
        if tool_name and row_tool_name != tool_name:
            continue
        latest_key = str(row_tool_name or details.get("artifact") or row["message"])
        if latest and latest_key in seen_latest:
            continue
        seen_latest.add(latest_key)
        skipped.append(
            {
                "created_at": row["created_at"],
                "tool_name": row_tool_name,
                "computer_id": row["computer_id"],
                "computer_label": row["computer_label"],
                "image_id": row["image_id"],
                "image_path": row["image_path"],
                "message": row["message"],
                "count": details.get("count"),
                "sample": details.get("sample", []),
            }
        )
        if len(skipped) >= limit:
            break
    return {"case_id": case_id, "skipped_reparse": skipped, "total_returned": len(skipped)}


