def _timeline_preset_matches(row: dict[str, Any], preset: str) -> bool:
    text = " ".join(str(value or "") for value in row.values()).casefold()
    name = preset.casefold()
    if name == "memory":
        return "memory" in text or row.get("source_table") == "memory_string_hits"
    if name == "suspicious":
        return any(token in text for token in ("suspicious", "prefetch", "bam", "runmru", "wevtutil", "rundll32", "powershell"))
    if name == "cloud":
        return any(token in text for token in ("cloud", "onedrive", "google drive", "drivefs", "dropbox", "icloud"))
    if name == "usb":
        return any(token in text for token in ("usb", "removable", "setupapi", "volume serial"))
    if name == "remote_access":
        return any(token in text for token in ("rdp", "vpn", "remote", "mstsc", "terminal services"))
    if name == "execution":
        return any(token in text for token in ("prefetch", "bam", "dam", "runmru", "amcache", "shimcache", "execution", "process"))
    if name == "file_identity":
        return any(token in text for token in ("droid", "object_id", "object id", "file_reference", "usn_file_lifecycle", "shortcut_object_id_match"))
    return True


def validation_report(db: Database, case_id: str) -> dict[str, Any]:
    db.get_case(case_id)
    expected_tools = [
        "MFTECmd", "MFTECmdUSN", "MFTECmdI30", "SAMParser", "RegistryParser", "RECmd",
        "RegistryArtifactParser", "SrumECmd", "AmcacheParser", "AppCompatCacheParser",
        "SBECmd", "PrefetchParser", "RecycleParser", "FirefoxParser", "ChromiumParser",
        "WebCacheParser", "JLECmd", "LECmd", "SIDR",
    ]
    outputs = db.conn.execute(
        """
        SELECT tool_name, COUNT(*) AS output_count, COALESCE(SUM(row_count), 0) AS row_count
        FROM tool_outputs
        WHERE case_id = ?
        GROUP BY tool_name
        """,
        (case_id,),
    ).fetchall()
    output_by_tool = {row["tool_name"]: dict(row) for row in outputs}
    failed_jobs = db.conn.execute(
        """
        SELECT jobs.id, jobs.tool_name, jobs.start_time, jobs.end_time, jobs.exit_code, jobs.stderr_path
        FROM jobs
        LEFT JOIN activity_log AS error_activity
          ON error_activity.job_id = jobs.id
         AND error_activity.level = 'error'
        WHERE jobs.case_id = ? AND (jobs.exit_code IS NULL OR jobs.exit_code != 0)
          AND (jobs.exit_code IS NULL OR error_activity.id IS NOT NULL)
        ORDER BY start_time
        """,
        (case_id,),
    ).fetchall()
    anticipated_nonzero_jobs = db.conn.execute(
        """
        SELECT jobs.id, jobs.tool_name, jobs.start_time, jobs.end_time, jobs.exit_code, jobs.stderr_path
        FROM jobs
        JOIN activity_log
          ON activity_log.job_id = jobs.id
         AND activity_log.level = 'warning'
         AND activity_log.details_json LIKE '%"anticipated_nonzero": true%'
        WHERE jobs.case_id = ? AND jobs.exit_code IS NOT NULL AND jobs.exit_code != 0
        ORDER BY jobs.start_time
        """,
        (case_id,),
    ).fetchall()
    issue_counts = db.conn.execute(
        """
        SELECT level, COUNT(*) AS count
        FROM activity_log
        WHERE case_id = ? AND level IN ('warning', 'error')
        GROUP BY level
        """,
        (case_id,),
    ).fetchall()
    skipped = db.conn.execute(
        """
        SELECT event, message, COUNT(*) AS count
        FROM activity_log
        WHERE case_id = ? AND (event LIKE '%skipped%' OR message LIKE '%skipped%')
        GROUP BY event, message
        ORDER BY count DESC
        """,
        (case_id,),
    ).fetchall()
    missing = [tool for tool in expected_tools if tool not in output_by_tool]
    return {
        "case_id": case_id,
        "tools_with_outputs": list(output_by_tool.values()),
        "expected_tools_without_outputs": missing,
        "failed_or_unfinished_jobs": [dict(row) for row in failed_jobs],
        "anticipated_nonzero_jobs": [dict(row) for row in anticipated_nonzero_jobs],
        "issue_counts": {row["level"]: row["count"] for row in issue_counts},
        "skipped_activity": [dict(row) for row in skipped],
        "evtx_recovery": _evtx_recovery_counts(db, case_id),
        "artifact_integrity": _artifact_integrity_checks(db, case_id),
    }


def _artifact_integrity_checks(db: Database, case_id: str) -> list[dict[str, Any]]:
    checks: list[dict[str, Any]] = []
    checks.extend(_zone_identifier_ads_integrity(db, case_id))
    return checks


def _zone_identifier_ads_integrity(db: Database, case_id: str) -> list[dict[str, Any]]:
    mft_rows = _query_report_rows(
        db,
        case_id,
        "mft_entries",
        """
        SELECT id, image_id, parent_path, file_name
        FROM mft_entries
        WHERE case_id = ?
          AND COALESCE(is_ads, '') = 'True'
          AND LOWER(COALESCE(file_name, '')) LIKE '%:zone.identifier'
        """,
        (case_id,),
    )
    zone_rows = _query_report_rows(
        db,
        case_id,
        "zone_identifier_ads",
        """
        SELECT image_id, file_path
        FROM zone_identifier_ads
        WHERE case_id = ?
        """,
        (case_id,),
    )
    zone_paths = {
        (str(row.get("image_id") or ""), _integrity_path_key(row.get("file_path")))
        for row in zone_rows
    }
    missing = []
    for row in mft_rows:
        host_name = _strip_zone_identifier_stream(row.get("file_name"))
        expected = _integrity_path_key(f"{row.get('parent_path') or ''}\\{host_name}")
        if (str(row.get("image_id") or ""), expected) not in zone_paths:
            missing.append(
                {
                    "mft_id": row.get("id"),
                    "image_id": row.get("image_id"),
                    "expected_file_path": expected,
                    "mft_file_name": row.get("file_name"),
                }
            )
    return [
        {
            "check": "zone_identifier_ads_mft_coverage",
            "status": "pass" if not missing else "warning",
            "mft_ads_count": len(mft_rows),
            "parsed_zone_identifier_count": len(zone_rows),
            "matched_count": len(mft_rows) - len(missing),
            "missing_count": len(missing),
            "missing_examples": missing[:25],
        }
    ]


def _strip_zone_identifier_stream(value: object) -> str:
    text = str(value or "")
    suffix = ":zone.identifier"
    if text.lower().endswith(suffix):
        return text[: -len(suffix)]
    return text


def _integrity_path_key(value: object) -> str:
    text = str(value or "").replace("/", "\\").strip()
    text = re.sub(r"^\.\\+", "", text)
    text = text.lstrip("\\")
    if len(text) > 2 and text[1] == ":":
        text = text[2:].lstrip("\\")
    return text.rstrip("\\").casefold()


