def shellbag_external_storage_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    rows = _query_report_rows(
        db,
        case_id,
        "shellbag_entries",
        """
        SELECT shellbag_entries.*, NULL AS computer_label, NULL AS image_path
        FROM shellbag_entries
        WHERE shellbag_entries.case_id = ?
          AND (
            COALESCE(shellbag_entries.volume_serial_number, '') <> ''
            OR COALESCE(shellbag_entries.volume_guid, '') <> ''
            OR COALESCE(shellbag_entries.drive_letter, '') <> ''
          )
        ORDER BY COALESCE(last_interacted, first_interacted, modified_on, created_on, last_write_time, '') DESC,
                 absolute_path
        LIMIT ?
        """,
        (case_id, limit),
    )
    _fill_computer_image_fields(db, case_id, rows)
    devices = _external_storage_devices(db, case_id, limit=10000)
    _annotate_external_storage_devices(db, case_id, devices)
    items = []
    for row in rows:
        item = dict(row)
        matches = [
            _shellbag_device_match(item, device)
            for device in devices
            if _shellbag_matches_external_device(item, device)
        ]
        item["matched_devices"] = matches
        item["match_count"] = len(matches)
        items.append(item)
    items.sort(key=lambda item: (-int(item.get("match_count") or 0), str(item.get("absolute_path") or "")))
    return {"case_id": case_id, "shellbag_external_storage": items, "total_returned": len(items)}


def _shellbag_matches_external_device(shellbag: dict[str, Any], device: dict[str, Any]) -> bool:
    shell_vsn = _norm_vsn(shellbag.get("volume_serial_number"))
    device_vsns = {
        _norm_vsn(value)
        for value in _split_external_storage_values(device.get("observed_volume_serial_numbers") or device.get("volume_serial_number"))
        if _norm_vsn(value)
    }
    if shell_vsn and shell_vsn in device_vsns:
        return True
    shell_guid = str(shellbag.get("volume_guid") or "").strip("{}").casefold()
    device_guids = {
        value.strip("{}").casefold()
        for value in _split_external_storage_values(device.get("observed_volume_guids") or device.get("volume_guid"))
        if value
    }
    if shell_guid and shell_guid in device_guids:
        return True
    shell_drive = _normalize_external_storage_drive_letters(shellbag.get("drive_letter"))
    device_drives = _normalize_external_storage_drive_letters(device.get("observed_drive_letters") or device.get("drive_letter"))
    return bool(shell_drive and device_drives and shell_drive in _split_external_storage_values(device_drives))


def _shellbag_device_match(shellbag: dict[str, Any], device: dict[str, Any]) -> dict[str, Any]:
    bases = []
    if _norm_vsn(shellbag.get("volume_serial_number")) and _norm_vsn(shellbag.get("volume_serial_number")) in {
        _norm_vsn(value)
        for value in _split_external_storage_values(device.get("observed_volume_serial_numbers") or device.get("volume_serial_number"))
    }:
        bases.append("volume_serial")
    if str(shellbag.get("volume_guid") or "").strip("{}").casefold() in {
        value.strip("{}").casefold()
        for value in _split_external_storage_values(device.get("observed_volume_guids") or device.get("volume_guid"))
    }:
        bases.append("volume_guid")
    if _normalize_external_storage_drive_letters(shellbag.get("drive_letter")):
        bases.append("drive_letter")
    return {
        "serial": device.get("serial"),
        "device_identity": device.get("device_identity") or _external_storage_device_label(device),
        "volume_serial_number": device.get("observed_volume_serial_numbers") or device.get("volume_serial_number"),
        "volume_guid": device.get("observed_volume_guids") or device.get("volume_guid"),
        "drive_letter": device.get("observed_drive_letters") or device.get("drive_letter"),
        "match_basis": ", ".join(_ordered_unique(bases)),
        "identity_confidence_tier": device.get("identity_confidence_tier"),
    }


def usb_report(db: Database, case_id: str, *, limit: int = 100, raw: bool = False) -> dict[str, Any]:
    if raw:
        return _table_report(db, case_id, "usb_devices", "usb_devices", limit)
    db.get_case(case_id)
    rows = _query_report_rows(
        db,
        case_id,
        "usb_storage_devices",
        """
        SELECT *
        FROM usb_storage_devices
        WHERE usb_storage_devices.case_id = ?
        ORDER BY COALESCE(last_removal_utc, last_arrival_utc, first_install_date_utc, serial), serial
        LIMIT ?
        """,
        (case_id, limit),
    )
    _fill_computer_image_fields(db, case_id, rows)
    devices = []
    for row in rows:
        item = dict(row)
        item["first_connection_utc"] = item.get("first_install_date_utc")
        devices.append(item)
    return {"case_id": case_id, "usb_storage_devices": devices, "total_returned": len(devices)}


def usb_breakdown_report(db: Database, case_id: str) -> dict[str, Any]:
    db.get_case(case_id)
    raw_rows = _query_report_rows(
        db,
        case_id,
        "usb_devices",
        "SELECT COUNT(*) AS count FROM usb_devices WHERE case_id = ?",
        (case_id,),
    )
    total_raw = int((raw_rows[0] if raw_rows else {}).get("count") or 0)
    storage_rows = _query_report_rows(
        db,
        case_id,
        "usb_storage_devices",
        "SELECT COUNT(*) AS count FROM usb_storage_devices WHERE case_id = ?",
        (case_id,),
    )
    total_storage = int((storage_rows[0] if storage_rows else {}).get("count") or 0)
    artifact_counts = _query_report_rows(
        db,
        case_id,
        "usb_devices",
            """
            SELECT artifact, COUNT(*) AS row_count
            FROM usb_devices
            WHERE case_id = ?
            GROUP BY artifact
            ORDER BY row_count DESC, artifact
            """,
            (case_id,),
    )
    device_type_counts = _query_report_rows(
        db,
        case_id,
        "usb_devices",
            """
            SELECT device_type, COUNT(*) AS row_count
            FROM usb_devices
            WHERE case_id = ?
            GROUP BY device_type
            ORDER BY row_count DESC, device_type
            """,
            (case_id,),
    )
    storage_evidence_counts = _query_report_rows(
        db,
        case_id,
        "usb_devices",
            """
            SELECT artifact, device_type, COUNT(*) AS row_count
            FROM usb_devices
            WHERE case_id = ?
              AND device_type IN (
                'usb_storage',
                'scsi_storage',
                'usb_volume',
                'portable_device_volume',
                'mounted_device',
                'usb_partition_diagnostic'
              )
            GROUP BY artifact, device_type
            ORDER BY row_count DESC, artifact, device_type
            """,
            (case_id,),
    )
    return {
        "case_id": case_id,
        "raw_usb_evidence_rows": total_raw,
        "summarized_usb_storage_devices": total_storage,
        "artifact_counts": artifact_counts,
        "device_type_counts": device_type_counts,
        "storage_evidence_counts": storage_evidence_counts,
    }


def usb_verbose_report(
    db: Database,
    case_id: str,
    *,
    serial: str | None = None,
    volume_serial_number: str | None = None,
    volume_guid: str | None = None,
    limit: int = 250,
) -> dict[str, Any]:
    db.get_case(case_id)
    rebuild_usb_file_correlations(db, case_id)
    device = _find_usb_storage_device(
        db,
        case_id,
        serial=serial,
        volume_serial_number=volume_serial_number,
        volume_guid=volume_guid,
    )
    device_id = {
        "serial": device["serial"],
        "volume_serial_number": device["volume_serial_number"],
        "volume_guid": device["volume_guid"],
    }
    raw_rows = _usb_verbose_raw_rows(db, case_id, device_id)
    file_rows = _usb_verbose_file_rows(db, case_id, device, limit=limit)
    _annotate_usb_verbose_candidate_volume_serials(device, file_rows)
    return {
        "case_id": case_id,
        "query": {
            "serial": serial,
            "volume_serial_number": volume_serial_number,
            "volume_guid": volume_guid,
        },
        "device": device,
        "description_attributes": _usb_verbose_description_attributes(device, raw_rows),
        "connection_times": _usb_verbose_connection_times(device, raw_rows),
        "volume_attributes": _usb_verbose_volume_attributes(device, raw_rows),
        "mbr_vbr_details": _usb_verbose_mbr_vbr_details(raw_rows),
        "other_details": _usb_verbose_other_details(raw_rows),
        "files_opened_accessed": file_rows,
        "raw_evidence_counts": _usb_verbose_counts(raw_rows),
        "raw_evidence_rows": [_usb_verbose_raw_summary(row) for row in raw_rows],
        "total_files_returned": len(file_rows),
        "total_raw_evidence_rows": len(raw_rows),
    }


def _annotate_usb_verbose_candidate_volume_serials(device: dict[str, Any], file_rows: list[dict[str, Any]]) -> None:
    confirmed = {
        _norm_vsn(value)
        for value in str(device.get("volume_serial_number") or "").split(",")
        if _norm_vsn(value)
    }
    candidates: set[str] = set()
    sources: set[str] = set()
    for row in file_rows:
        vsn = _norm_vsn(row.get("usb_volume_serial_number") or row.get("matched_volume_serial_number") or row.get("artifact_volume_serial_number"))
        if not vsn or vsn in confirmed:
            continue
        candidates.add(vsn)
        for value in str(row.get("source_artifact_types") or row.get("source_artifact_type") or "").split(","):
            if value.strip():
                sources.add(value.strip())
    device["candidate_volume_serial_numbers"] = ", ".join(sorted(candidates))
    device["candidate_volume_serial_sources"] = ", ".join(sorted(sources))
    if candidates:
        if confirmed:
            device["candidate_volume_serial_note"] = (
                "File activity artifacts reference additional volume serial(s) not present in the storage-device row; "
                "treat as lower-confidence context unless corroborated by device, registry, Partition Diagnostic, or VBR evidence."
            )
        else:
            device["candidate_volume_serial_note"] = (
                "No device-derived volume serial was recovered; these candidate serial(s) come from LNK/Jump List/Shellbag file activity."
            )
    else:
        device["candidate_volume_serial_note"] = ""


def rebuild_usb_file_correlations(db: Database, case_id: str) -> int:
    db.get_case(case_id)
    enrich_usb_storage_device_volume_serials(db, case_id=case_id)
    rows = _usb_file_correlation_rows(db, case_id, limit=None)
    connection_rows = _query_report_rows(
        db,
        case_id,
        "usb_connection_events",
        "SELECT * FROM usb_connection_events WHERE case_id = ? ORDER BY event_time_utc",
        (case_id,),
    )
    connection_rows.extend(_usb_event_log_connection_observations(db, case_id))
    created_at = utc_now()
    correlation_rows = []
    for row in rows:
        item = dict(row)
        _normalize_usb_file_access_precision(item)
        item.update(_usb_file_temporal_context(item, connection_rows))
        item["usb_serial"] = item.get("usb_serial") or ""
        item["usb_volume_serial_number"] = item.get("usb_volume_serial_number") or ""
        item["source_artifact_type"] = item.get("source_artifact_type") or ""
        item["volume_serial_match"] = item.get("volume_serial_match") or ""
        item["confidence"] = item.get("confidence") or ""
        item["target_accessed_precision"] = item.get("target_accessed_precision") or ""
        item["target_accessed_note"] = item.get("target_accessed_note") or ""
        item["id"] = str(uuid.uuid4())
        item["created_at"] = created_at
        if not item.get("user_profile"):
            item["user_profile"] = _user_profile_from_artifact_path(item.get("source_artifact_path"))
        correlation_rows.append(item)
    with db.bulk_transaction():
        db.delete_usb_file_correlations(case_id=case_id)
        db.insert_usb_file_correlations(correlation_rows)
    return len(correlation_rows)


def usb_file_correlation_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 500,
    persist: bool = True,
    grouped: bool = False,
    contains: str | None = None,
    serial: str | None = None,
    volume_serial_number: str | None = None,
    volume_name: str | None = None,
    source_artifact_type: str | None = None,
    include_drive_roots: bool = True,
) -> dict[str, Any]:
    db.get_case(case_id)
    if persist:
        rebuild_usb_file_correlations(db, case_id)
    filters = ["case_id = ?"]
    params: list[Any] = [case_id]
    if contains:
        filters.append(
            """
            LOWER(
              COALESCE(file_name, '') || ' ' ||
              COALESCE(file_location, '') || ' ' ||
              COALESCE(source_artifact_name, '') || ' ' ||
              COALESCE(source_artifact_path, '') || ' ' ||
              COALESCE(usb_volume_name, '') || ' ' ||
              COALESCE(artifact_volume_name, '') || ' ' ||
              COALESCE(usb_serial, '') || ' ' ||
              COALESCE(usb_volume_serial_number, '') || ' ' ||
              COALESCE(artifact_volume_serial_number, '')
            ) LIKE LOWER(?)
            """
        )
        params.append(f"%{contains}%")
    if serial:
        filters.append("UPPER(usb_serial) = UPPER(?)")
        params.append(serial)
    if volume_serial_number:
        filters.append(
            "(UPPER(REPLACE(usb_volume_serial_number, '-', '')) = UPPER(REPLACE(?, '-', '')) "
            "OR UPPER(REPLACE(artifact_volume_serial_number, '-', '')) = UPPER(REPLACE(?, '-', '')))"
        )
        params.extend([volume_serial_number, volume_serial_number])
    if volume_name:
        filters.append("(LOWER(usb_volume_name) = LOWER(?) OR LOWER(artifact_volume_name) = LOWER(?))")
        params.extend([volume_name, volume_name])
    if source_artifact_type:
        filters.append("LOWER(source_artifact_type) = LOWER(?)")
        params.append(source_artifact_type)
    if not include_drive_roots:
        filters.append(
            """
            NOT (
              LENGTH(TRIM(COALESCE(file_location, file_name, ''))) <= 3
              AND SUBSTR(TRIM(COALESCE(file_location, file_name, '')), 2, 1) = ':'
            )
            """
        )
    params.append(limit)
    rows = _query_report_rows(
        db,
        case_id,
        "usb_file_correlations",
        f"""
        SELECT *
        FROM usb_file_correlations
        WHERE {' AND '.join(filters)}
        ORDER BY
          COALESCE(NULLIF(usb_volume_serial_number, ''), artifact_volume_serial_number),
          source_artifact_type,
          file_location,
          file_name,
          source_artifact_path
        LIMIT ?
        """,
        params,
    )
    _annotate_usb_file_rows_access_precision(db, case_id, rows)
    files = _dedupe_usb_file_items(rows)
    counts_by_device: dict[tuple[str, str | None, str | None, str | None], dict[str, Any]] = {}
    for row in rows:
        row["matched_volume_serial_number"] = row.get("usb_volume_serial_number") or row.get("artifact_volume_serial_number")
        row["matched_volume_name"] = row.get("usb_volume_name") or row.get("artifact_volume_name")
        key = (
            row["usb_serial"],
            row["usb_volume_serial_number"],
            row["usb_volume_name"],
            row["usb_drive_letter"],
        )
        item = counts_by_device.setdefault(
            key,
            {
                "usb_serial": row["usb_serial"],
                "usb_volume_serial_number": row["usb_volume_serial_number"],
                "usb_volume_name": row["usb_volume_name"],
                "usb_drive_letter": row["usb_drive_letter"],
                "usb_product": row["usb_product"],
                "file_artifact_matches": 0,
                "lnk_matches": 0,
                "jumplist_matches": 0,
                "shellbag_matches": 0,
                "exact_vsn_matches": 0,
                "suffix_vsn_matches": 0,
            },
        )
        item["file_artifact_matches"] += 1
        if row["source_artifact_type"] == "lnk":
            item["lnk_matches"] += 1
        elif row["source_artifact_type"] == "jumplist":
            item["jumplist_matches"] += 1
        elif row["source_artifact_type"] == "shellbag":
            item["shellbag_matches"] += 1
        if row["volume_serial_match"] == "exact":
            item["exact_vsn_matches"] += 1
        elif row["volume_serial_match"] == "suffix":
            item["suffix_vsn_matches"] += 1
        elif row["volume_serial_match"] == "volume_name":
            item["volume_name_matches"] = item.get("volume_name_matches", 0) + 1
    shellbag_rows = db.conn.execute(
        "SELECT COUNT(*) AS count FROM shellbag_entries WHERE case_id = ?",
        (case_id,),
    ).fetchone()["count"]
    return {
        "case_id": case_id,
        "correlation_key": "normalized volume serial number; volume label fallback when device-side volume serial is missing",
        "notes": [
            "LNK and Jump List rows are matched to USB storage devices by volume serial number.",
            "When USB device evidence lacks a volume serial number, LNK and Jump List rows can fall back to a non-generic matching volume label.",
            "Rows include artifact_volume_serial_number and matched_volume_serial_number so file-activity-derived serials remain visible when device-side USB volume serials are blank.",
            "Shellbag rows participate when volume serial data is available in shellbag_entries.",
            "Suffix matching is used when USB evidence has a wider NTFS-style serial and shortcut evidence has the lower 32-bit serial.",
        ],
        "filters": {
            "contains": contains or "",
            "serial": serial or "",
            "volume_serial_number": volume_serial_number or "",
            "volume_name": volume_name or "",
            "source_artifact_type": source_artifact_type or "",
            "include_drive_roots": include_drive_roots,
        },
        "shellbag_rows_available": shellbag_rows,
        "devices": list(counts_by_device.values()),
        "files": files,
        "items": rows,
        "total_files": len(files),
        "total_returned": len(files) if grouped else len(rows),
    }


def _annotate_usb_file_rows_access_precision(db: Database, case_id: str, rows: list[dict[str, Any]]) -> None:
    if not rows:
        return
    devices = _query_report_rows(
        db,
        case_id,
        "usb_storage_devices",
        """
        SELECT serial, volume_serial_number, volume_name, file_system, vbr_file_system
        FROM usb_storage_devices
        WHERE case_id = ?
        """,
        (case_id,),
    )
    devices.extend(
        _query_report_rows(
            db,
            case_id,
            "usb_devices",
            """
            SELECT serial, volume_serial_number, volume_name, file_system, vbr_file_system
            FROM usb_devices
            WHERE case_id = ?
              AND (
                COALESCE(file_system, '') <> ''
                OR COALESCE(vbr_file_system, '') <> ''
              )
            """,
            (case_id,),
        )
    )
    by_serial: dict[str, dict[str, Any]] = {}
    by_vsn: dict[str, dict[str, Any]] = {}
    by_volume_name: dict[str, dict[str, Any]] = {}
    for device in devices:
        serial_key = _external_storage_serial_key(device.get("serial")).upper()
        vsn_key = _norm_vsn(device.get("volume_serial_number"))
        volume_name_key = _normalize_usb_volume_name(device.get("volume_name"))
        for mapping, key in ((by_serial, serial_key), (by_vsn, vsn_key), (by_volume_name, volume_name_key)):
            if key and (key not in mapping or _usb_device_has_more_filesystem_metadata(device, mapping[key])):
                mapping[key] = device
    for row in rows:
        device = (
            by_serial.get(_external_storage_serial_key(row.get("usb_serial")).upper())
            or by_vsn.get(_norm_vsn(row.get("usb_volume_serial_number") or row.get("artifact_volume_serial_number")))
            or by_volume_name.get(_normalize_usb_volume_name(row.get("usb_volume_name") or row.get("artifact_volume_name")))
        )
        if device:
            row["usb_file_system"] = row.get("usb_file_system") or device.get("file_system") or ""
            row["usb_vbr_file_system"] = row.get("usb_vbr_file_system") or device.get("vbr_file_system") or ""
        _normalize_usb_file_access_precision(row)


def _usb_device_has_more_filesystem_metadata(candidate: dict[str, Any], current: dict[str, Any]) -> bool:
    return bool(
        (candidate.get("file_system") and not current.get("file_system"))
        or (candidate.get("vbr_file_system") and not current.get("vbr_file_system"))
    )


def _usb_file_correlation_rows(db: Database, case_id: str, *, limit: int | None) -> list[dict[str, Any]]:
    if db.analytics_mode != "sqlite":
        return _usb_file_correlation_rows_duckdb(db, case_id, limit=limit)
    limit_clause = "" if limit is None else "LIMIT ?"
    params: list[Any] = [case_id, case_id, case_id, case_id, case_id]
    if limit is not None:
        params.append(limit)
    return [
        dict(row)
        for row in db.conn.execute(
            f"""
            WITH usb AS (
              SELECT *,
                     UPPER(REPLACE(volume_serial_number, '-', '')) AS usb_vsn_norm,
                     UPPER(TRIM(COALESCE(volume_name, ''))) AS usb_volume_name_norm,
                     UPPER(REPLACE(REPLACE(volume_guid, CHAR(123), ''), CHAR(125), '')) AS usb_guid_norm,
                     UPPER(drive_letter) AS usb_drive_norm
              FROM usb_storage_devices
              WHERE case_id = ?
            ),
            usb_sessions AS (
              SELECT
                start_event.case_id,
                start_event.image_id,
                start_event.serial,
                UPPER(REPLACE(start_event.volume_serial_number, '-', '')) AS session_vsn_norm,
                start_event.event_time_utc AS session_start,
                COALESCE(
                  (
                    SELECT MIN(end_event.event_time_utc)
                    FROM usb_connection_events end_event
                    WHERE end_event.case_id = start_event.case_id
                      AND end_event.image_id = start_event.image_id
                      AND end_event.serial = start_event.serial
                      AND end_event.event_type = 'removal'
                      AND datetime(REPLACE(SUBSTR(end_event.event_time_utc, 1, 19), 'T', ' ')) >=
                          datetime(REPLACE(SUBSTR(start_event.event_time_utc, 1, 19), 'T', ' '))
                  ),
                  start_event.event_time_utc
                ) AS session_end
              FROM usb_connection_events start_event
              WHERE start_event.case_id = ?
                AND start_event.event_type IN ('arrival', 'first_connected', 'partition_seen')
            ),
            artifacts AS (
              SELECT
                id AS source_artifact_id,
                case_id,
                computer_id,
                image_id,
                artifact_type AS source_artifact_type,
                artifact_name AS source_artifact_name,
                artifact_path AS source_artifact_path,
                NULL AS user_profile,
                jumplist_item_number,
                file_name,
                file_location,
                target_created,
                target_modified,
                target_accessed,
                device_type,
                volume_serial_number AS artifact_volume_serial_number,
                volume_name AS artifact_volume_name,
                NULL AS artifact_volume_guid,
                NULL AS artifact_drive_letter,
                UPPER(REPLACE(volume_serial_number, '-', '')) AS artifact_vsn_norm,
                UPPER(TRIM(COALESCE(volume_name, ''))) AS artifact_volume_name_norm,
                NULL AS artifact_guid_norm,
                NULL AS artifact_drive_norm,
                UPPER(REPLACE(COALESCE(file_location, file_name, ''), '\\\\', '\\')) AS artifact_path_norm,
                NULL AS interaction_start_norm,
                NULL AS interaction_end_norm
              FROM shortcut_items
              WHERE case_id = ?
                AND volume_serial_number IS NOT NULL
                AND TRIM(volume_serial_number) != ''
              UNION ALL
              SELECT
                id AS source_artifact_id,
                case_id,
                computer_id,
                image_id,
                'shellbag' AS source_artifact_type,
                value_name AS source_artifact_name,
                source_file AS source_artifact_path,
                user_profile,
                NULL AS jumplist_item_number,
                NULL AS file_name,
                absolute_path AS file_location,
                created_on AS target_created,
                modified_on AS target_modified,
                COALESCE(NULLIF(last_interacted, ''), NULLIF(first_interacted, ''), accessed_on) AS target_accessed,
                shell_type AS device_type,
                volume_serial_number AS artifact_volume_serial_number,
                volume_name AS artifact_volume_name,
                volume_guid AS artifact_volume_guid,
                drive_letter AS artifact_drive_letter,
                UPPER(REPLACE(volume_serial_number, '-', '')) AS artifact_vsn_norm,
                UPPER(TRIM(COALESCE(volume_name, ''))) AS artifact_volume_name_norm,
                UPPER(REPLACE(REPLACE(volume_guid, CHAR(123), ''), CHAR(125), '')) AS artifact_guid_norm,
                UPPER(drive_letter) AS artifact_drive_norm,
                UPPER(
                  REPLACE(
                    REPLACE(
                      REPLACE(COALESCE(absolute_path, ''), 'Desktop\\This PC\\', ''),
                      'Desktop\\',
                      ''
                    ),
                    '\\\\',
                    '\\'
                  )
                ) AS artifact_path_norm,
                datetime(
                  REPLACE(
                    SUBSTR(
                      COALESCE(NULLIF(first_interacted, ''), NULLIF(last_interacted, '')),
                      1,
                      19
                    ),
                    'T',
                    ' '
                  )
                ) AS interaction_start_norm,
                datetime(
                  REPLACE(
                    SUBSTR(
                      COALESCE(NULLIF(last_interacted, ''), NULLIF(first_interacted, '')),
                      1,
                      19
                    ),
                    'T',
                    ' '
                  )
                ) AS interaction_end_norm
              FROM shellbag_entries
              WHERE case_id = ?
                AND (
                  (volume_serial_number IS NOT NULL AND TRIM(volume_serial_number) != '')
                  OR (volume_guid IS NOT NULL AND TRIM(volume_guid) != '')
                  OR (drive_letter IS NOT NULL AND TRIM(drive_letter) != '')
                )
            ),
            anchor_paths AS (
              SELECT
                case_id,
                UPPER(REPLACE(volume_serial_number, '-', '')) AS anchor_vsn_norm,
                UPPER(REPLACE(COALESCE(file_location, file_name, ''), '\\\\', '\\')) AS anchor_path_norm
              FROM shortcut_items
              WHERE case_id = ?
                AND volume_serial_number IS NOT NULL
                AND TRIM(volume_serial_number) != ''
                AND COALESCE(file_location, file_name, '') IS NOT NULL
                AND LENGTH(TRIM(COALESCE(file_location, file_name, ''))) > 3
            ),
            anchor_scores AS (
              SELECT
                artifacts.source_artifact_id,
                usb.usb_vsn_norm,
                COUNT(DISTINCT anchor_paths.anchor_path_norm) AS anchor_count
              FROM artifacts
              JOIN usb
                ON artifacts.source_artifact_type = 'shellbag'
                AND artifacts.artifact_drive_norm IS NOT NULL
                AND artifacts.artifact_drive_norm != ''
                AND artifacts.artifact_drive_norm = usb.usb_drive_norm
              JOIN anchor_paths
                ON anchor_paths.case_id = artifacts.case_id
                AND anchor_paths.anchor_vsn_norm = usb.usb_vsn_norm
                AND anchor_paths.anchor_path_norm != ''
                AND artifacts.artifact_path_norm != ''
                AND LENGTH(RTRIM(anchor_paths.anchor_path_norm, '\\')) > 2
                AND (
                  anchor_paths.anchor_path_norm = artifacts.artifact_path_norm
                  OR anchor_paths.anchor_path_norm LIKE artifacts.artifact_path_norm || '\\%'
                  OR artifacts.artifact_path_norm LIKE anchor_paths.anchor_path_norm || '\\%'
                )
              GROUP BY artifacts.source_artifact_id, usb.usb_vsn_norm
            ),
            anchor_summary AS (
              SELECT
                source_artifact_id,
                COUNT(*) AS anchored_device_count,
                MAX(anchor_count) AS max_anchor_count
              FROM anchor_scores
              GROUP BY source_artifact_id
            ),
            scored AS (
              SELECT
                usb.*,
                artifacts.*,
                COALESCE(anchor_scores.anchor_count, 0) AS anchor_count,
                COALESCE(anchor_summary.anchored_device_count, 0) AS anchored_device_count,
                CASE
                  WHEN artifacts.source_artifact_type = 'shellbag'
                    AND artifacts.interaction_start_norm IS NOT NULL
                    AND EXISTS (
                      SELECT 1
                      FROM usb_sessions
                      WHERE usb_sessions.case_id = usb.case_id
                        AND usb_sessions.image_id = usb.image_id
                        AND usb_sessions.serial = usb.serial
                        AND (
                          usb.usb_vsn_norm IS NULL
                          OR usb.usb_vsn_norm = ''
                          OR usb_sessions.session_vsn_norm IS NULL
                          OR usb_sessions.session_vsn_norm = ''
                          OR usb_sessions.session_vsn_norm = usb.usb_vsn_norm
                        )
                        AND artifacts.interaction_start_norm <=
                            datetime(REPLACE(SUBSTR(usb_sessions.session_end, 1, 19), 'T', ' '))
                        AND artifacts.interaction_end_norm >=
                            datetime(REPLACE(SUBSTR(usb_sessions.session_start, 1, 19), 'T', ' '))
                    )
                  THEN 1
                  WHEN artifacts.source_artifact_type = 'shellbag'
                    AND artifacts.interaction_start_norm IS NOT NULL
                    AND NOT EXISTS (
                      SELECT 1
                      FROM usb_sessions
                      WHERE usb_sessions.case_id = usb.case_id
                        AND usb_sessions.image_id = usb.image_id
                        AND usb_sessions.serial = usb.serial
                        AND (
                          usb.usb_vsn_norm IS NULL
                          OR usb.usb_vsn_norm = ''
                          OR usb_sessions.session_vsn_norm IS NULL
                          OR usb_sessions.session_vsn_norm = ''
                          OR usb_sessions.session_vsn_norm = usb.usb_vsn_norm
                        )
                    )
                    AND datetime(REPLACE(SUBSTR(usb.first_install_date_utc, 1, 19), 'T', ' ')) IS NOT NULL
                    AND datetime(REPLACE(SUBSTR(COALESCE(usb.last_removal_utc, usb.last_arrival_utc, usb.first_install_date_utc), 1, 19), 'T', ' ')) IS NOT NULL
                    AND artifacts.interaction_start_norm <= datetime(REPLACE(SUBSTR(COALESCE(usb.last_removal_utc, usb.last_arrival_utc, usb.first_install_date_utc), 1, 19), 'T', ' '))
                    AND artifacts.interaction_end_norm >= datetime(REPLACE(SUBSTR(usb.first_install_date_utc, 1, 19), 'T', ' '))
                  THEN 1
                  ELSE 0
                END AS interaction_overlaps_usb
              FROM usb
              JOIN artifacts
                ON (artifacts.artifact_vsn_norm IS NOT NULL AND artifacts.artifact_vsn_norm = usb.usb_vsn_norm)
                OR (
                  artifacts.artifact_vsn_norm IS NOT NULL
                  AND LENGTH(usb.usb_vsn_norm) > 8
                  AND artifacts.artifact_vsn_norm = SUBSTR(usb.usb_vsn_norm, -8)
                )
                OR (
                  artifacts.artifact_guid_norm IS NOT NULL
                  AND artifacts.artifact_guid_norm != ''
                  AND usb.usb_guid_norm LIKE '%' || artifacts.artifact_guid_norm || '%'
                )
                OR (
                  artifacts.source_artifact_type != 'shellbag'
                  AND (usb.usb_vsn_norm IS NULL OR usb.usb_vsn_norm = '')
                  AND artifacts.artifact_volume_name_norm IS NOT NULL
                  AND artifacts.artifact_volume_name_norm NOT IN ('', 'LOCAL DISK', 'NEW VOLUME', 'USB DRIVE', 'REMOVABLE DISK')
                  AND artifacts.artifact_volume_name_norm = usb.usb_volume_name_norm
                )
                OR (
                  artifacts.source_artifact_type = 'shellbag'
                  AND artifacts.artifact_drive_norm IS NOT NULL
                  AND artifacts.artifact_drive_norm != ''
                  AND artifacts.artifact_drive_norm = usb.usb_drive_norm
                )
              LEFT JOIN anchor_scores
                ON anchor_scores.source_artifact_id = artifacts.source_artifact_id
                AND anchor_scores.usb_vsn_norm = usb.usb_vsn_norm
              LEFT JOIN anchor_summary
                ON anchor_summary.source_artifact_id = artifacts.source_artifact_id
            )
            SELECT
              scored.case_id,
              scored.computer_id,
              scored.image_id,
              scored.serial AS usb_serial,
              scored.volume_serial_number AS usb_volume_serial_number,
              scored.volume_name AS usb_volume_name,
              scored.drive_letter AS usb_drive_letter,
              scored.vendor_id AS usb_vendor_id,
              scored.product_id AS usb_product_id,
              scored.vendor AS usb_vendor,
              scored.product AS usb_product,
              scored.friendly_name AS usb_friendly_name,
              scored.file_system AS usb_file_system,
              scored.vbr_file_system AS usb_vbr_file_system,
              scored.first_install_date_utc AS usb_first_install_date_utc,
              scored.last_arrival_utc AS usb_last_arrival_utc,
              scored.last_removal_utc AS usb_last_removal_utc,
              scored.source_artifact_type,
              scored.source_artifact_id,
              scored.source_artifact_name,
              scored.source_artifact_path,
              COALESCE(scored.user_profile, '') AS user_profile,
              scored.jumplist_item_number,
              scored.file_name,
              scored.file_location,
              scored.target_created,
              scored.target_modified,
              scored.target_accessed,
              scored.device_type,
              scored.artifact_volume_serial_number,
              scored.artifact_volume_name,
              scored.artifact_volume_guid,
              scored.artifact_drive_letter,
              CASE
                WHEN scored.artifact_vsn_norm = scored.usb_vsn_norm THEN 'exact'
                WHEN scored.artifact_vsn_norm IS NOT NULL
                  AND LENGTH(scored.usb_vsn_norm) > 8
                  AND scored.artifact_vsn_norm = SUBSTR(scored.usb_vsn_norm, -8) THEN 'suffix'
                WHEN scored.artifact_guid_norm IS NOT NULL
                  AND scored.usb_guid_norm LIKE '%' || scored.artifact_guid_norm || '%' THEN 'volume_guid'
                WHEN scored.source_artifact_type != 'shellbag'
                  AND (scored.usb_vsn_norm IS NULL OR scored.usb_vsn_norm = '')
                  AND scored.artifact_volume_name_norm IS NOT NULL
                  AND scored.artifact_volume_name_norm NOT IN ('', 'LOCAL DISK', 'NEW VOLUME', 'USB DRIVE', 'REMOVABLE DISK')
                  AND scored.artifact_volume_name_norm = scored.usb_volume_name_norm THEN 'volume_name'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.anchor_count >= 2
                  AND scored.anchored_device_count = 1
                  AND scored.interaction_overlaps_usb = 1 THEN 'folder_tree_time'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.anchor_count >= 2
                  AND scored.anchored_device_count = 1 THEN 'folder_tree'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.anchor_count > 0
                  AND scored.interaction_overlaps_usb = 1 THEN 'path_time_anchor'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.anchor_count > 0 THEN 'path_anchor'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.interaction_overlaps_usb = 1 THEN 'time_overlap'
                ELSE 'drive_letter'
              END AS volume_serial_match,
              CASE
                WHEN scored.artifact_vsn_norm = scored.usb_vsn_norm THEN 'high'
                WHEN scored.artifact_vsn_norm IS NOT NULL
                  AND LENGTH(scored.usb_vsn_norm) > 8
                  AND scored.artifact_vsn_norm = SUBSTR(scored.usb_vsn_norm, -8) THEN 'medium'
                WHEN scored.artifact_guid_norm IS NOT NULL
                  AND scored.usb_guid_norm LIKE '%' || scored.artifact_guid_norm || '%' THEN 'high'
                WHEN scored.source_artifact_type != 'shellbag'
                  AND (scored.usb_vsn_norm IS NULL OR scored.usb_vsn_norm = '')
                  AND scored.artifact_volume_name_norm IS NOT NULL
                  AND scored.artifact_volume_name_norm NOT IN ('', 'LOCAL DISK', 'NEW VOLUME', 'USB DRIVE', 'REMOVABLE DISK')
                  AND scored.artifact_volume_name_norm = scored.usb_volume_name_norm THEN 'medium'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.anchor_count >= 2
                  AND scored.anchored_device_count = 1 THEN 'high'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.anchor_count > 0
                  AND scored.interaction_overlaps_usb = 1 THEN 'high'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.anchor_count > 0 THEN 'medium'
                WHEN scored.source_artifact_type = 'shellbag'
                  AND scored.interaction_overlaps_usb = 1 THEN 'medium'
                ELSE 'low'
              END AS confidence
            FROM scored
            ORDER BY
              scored.volume_serial_number,
              scored.source_artifact_type,
              scored.file_location,
              scored.file_name,
              scored.source_artifact_path
            {limit_clause}
            """,
            params,
        ).fetchall()
    ]


def _usb_file_correlation_rows_duckdb(db: Database, case_id: str, *, limit: int | None) -> list[dict[str, Any]]:
    usb_rows = _query_report_rows(
        db,
        case_id,
        "usb_storage_devices",
        "SELECT * FROM usb_storage_devices WHERE case_id = ?",
        (case_id,),
    )
    if not usb_rows:
        usb_rows = _external_storage_devices(db, case_id, limit=10000)
        _merge_external_storage_partition_events(db, case_id, usb_rows)
    shortcut_rows = _query_report_rows(
        db,
        case_id,
        "shortcut_items",
        """
        SELECT *
        FROM shortcut_items
        WHERE case_id = ?
          AND volume_serial_number IS NOT NULL
          AND TRIM(volume_serial_number) != ''
        """,
        (case_id,),
    )
    shellbag_rows = _query_report_rows(
        db,
        case_id,
        "shellbag_entries",
        """
        SELECT *
        FROM shellbag_entries
        WHERE case_id = ?
          AND (
            (volume_serial_number IS NOT NULL AND TRIM(volume_serial_number) != '')
            OR (volume_guid IS NOT NULL AND TRIM(volume_guid) != '')
            OR (drive_letter IS NOT NULL AND TRIM(drive_letter) != '')
          )
        """,
        (case_id,),
    )
    connection_rows = _query_report_rows(
        db,
        case_id,
        "usb_connection_events",
        "SELECT * FROM usb_connection_events WHERE case_id = ? ORDER BY event_time_utc",
        (case_id,),
    )
    anchor_paths: dict[str, list[str]] = {}
    for shortcut in shortcut_rows:
        vsn = _normalize_usb_serial(shortcut.get("volume_serial_number"))
        path = _normalize_usb_artifact_path(shortcut.get("file_location") or shortcut.get("file_name"))
        if vsn and path:
            anchor_paths.setdefault(vsn, []).append(path)
    results: list[dict[str, Any]] = []
    for artifact in shortcut_rows:
        artifact_vsn = _normalize_usb_serial(artifact.get("volume_serial_number"))
        if not artifact_vsn:
            continue
        for usb in usb_rows:
            usb_vsn = _normalize_usb_serial(usb.get("volume_serial_number"))
            usb_volume_name = _normalize_usb_volume_name(usb.get("volume_name"))
            artifact_volume_name = _normalize_usb_volume_name(artifact.get("volume_name"))
            if not usb_vsn and not _usb_volume_name_matchable(usb_volume_name, artifact_volume_name):
                continue
            match = (
                "exact"
                if usb_vsn and artifact_vsn == usb_vsn
                else "suffix"
                if usb_vsn and (usb_vsn.endswith(artifact_vsn) or artifact_vsn.endswith(usb_vsn))
                else "volume_name"
                if not usb_vsn and _usb_volume_name_matchable(usb_volume_name, artifact_volume_name)
                else ""
            )
            if not match:
                continue
            results.append(
                {
                    "case_id": case_id,
                    "computer_id": artifact.get("computer_id"),
                    "image_id": artifact.get("image_id"),
                    "usb_serial": usb.get("serial"),
                    "usb_volume_serial_number": usb.get("volume_serial_number"),
                    "usb_volume_name": usb.get("volume_name"),
                    "usb_drive_letter": usb.get("drive_letter"),
                    "usb_vendor_id": usb.get("vendor_id"),
                    "usb_product_id": usb.get("product_id"),
                    "usb_vendor": usb.get("vendor"),
                    "usb_product": usb.get("product"),
                    "usb_friendly_name": usb.get("friendly_name"),
                    "usb_file_system": usb.get("file_system"),
                    "usb_vbr_file_system": usb.get("vbr_file_system"),
                    "usb_first_install_date_utc": usb.get("first_install_date_utc"),
                    "usb_last_arrival_utc": usb.get("last_arrival_utc"),
                    "usb_last_removal_utc": usb.get("last_removal_utc"),
                    "source_artifact_type": artifact.get("artifact_type"),
                    "source_artifact_id": artifact.get("id"),
                    "source_artifact_name": artifact.get("artifact_name"),
                    "source_artifact_path": artifact.get("artifact_path"),
                    "user_profile": _user_profile_from_artifact_path(artifact.get("artifact_path")),
                    "jumplist_item_number": artifact.get("jumplist_item_number"),
                    "file_name": artifact.get("file_name"),
                    "file_location": artifact.get("file_location"),
                    "target_created": artifact.get("target_created"),
                    "target_modified": artifact.get("target_modified"),
                    "target_accessed": artifact.get("target_accessed"),
                    "device_type": artifact.get("device_type"),
                    "artifact_volume_serial_number": artifact.get("volume_serial_number"),
                    "artifact_volume_name": artifact.get("volume_name"),
                    "artifact_volume_guid": None,
                    "artifact_drive_letter": None,
                    "volume_serial_match": match,
                    "confidence": "high" if match == "exact" else "medium",
                }
            )
            if limit is not None and len(results) >= limit:
                return results
    for artifact in shellbag_rows:
        artifact_vsn = _normalize_usb_serial(artifact.get("volume_serial_number"))
        artifact_guid = _normalize_usb_guid(artifact.get("volume_guid"))
        artifact_drive = _normalize_usb_drive(artifact.get("drive_letter"))
        artifact_path = _normalize_usb_artifact_path(artifact.get("absolute_path"))
        for usb in usb_rows:
            usb_vsn = _normalize_usb_serial(usb.get("volume_serial_number"))
            usb_guid = _normalize_usb_guid(usb.get("volume_guid"))
            usb_drive = _normalize_usb_drive(usb.get("drive_letter"))
            match = ""
            confidence = "low"
            if artifact_vsn and usb_vsn and artifact_vsn == usb_vsn:
                match = "exact"
                confidence = "high"
            elif artifact_guid and usb_guid and artifact_guid in usb_guid:
                match = "volume_guid"
                confidence = "high"
            elif artifact_drive and usb_drive and artifact_drive == usb_drive:
                anchor_count = _usb_anchor_count(anchor_paths.get(usb_vsn or "", []), artifact_path)
                overlaps = _usb_shellbag_overlaps_device(artifact, usb, connection_rows)
                if anchor_count >= 2 and overlaps:
                    match = "folder_tree_time"
                    confidence = "high"
                elif anchor_count >= 2:
                    match = "folder_tree"
                    confidence = "high"
                elif anchor_count > 0 and overlaps:
                    match = "path_time_anchor"
                    confidence = "high"
                elif anchor_count > 0:
                    match = "path_anchor"
                    confidence = "medium"
                elif overlaps:
                    match = "time_overlap"
                    confidence = "medium"
                else:
                    match = "drive_letter"
                    confidence = "low"
            if not match:
                continue
            results.append(
                {
                    "case_id": case_id,
                    "computer_id": artifact.get("computer_id"),
                    "image_id": artifact.get("image_id"),
                    "usb_serial": usb.get("serial"),
                    "usb_volume_serial_number": usb.get("volume_serial_number"),
                    "usb_volume_name": usb.get("volume_name"),
                    "usb_drive_letter": usb.get("drive_letter"),
                    "usb_vendor_id": usb.get("vendor_id"),
                    "usb_product_id": usb.get("product_id"),
                    "usb_vendor": usb.get("vendor"),
                    "usb_product": usb.get("product"),
                    "usb_friendly_name": usb.get("friendly_name"),
                    "usb_file_system": usb.get("file_system"),
                    "usb_vbr_file_system": usb.get("vbr_file_system"),
                    "usb_first_install_date_utc": usb.get("first_install_date_utc"),
                    "usb_last_arrival_utc": usb.get("last_arrival_utc"),
                    "usb_last_removal_utc": usb.get("last_removal_utc"),
                    "source_artifact_type": "shellbag",
                    "source_artifact_id": artifact.get("id"),
                    "source_artifact_name": artifact.get("value_name"),
                    "source_artifact_path": artifact.get("source_file"),
                    "user_profile": artifact.get("user_profile") or _user_profile_from_artifact_path(artifact.get("source_file")),
                    "jumplist_item_number": None,
                    "file_name": None,
                    "file_location": artifact.get("absolute_path"),
                    "target_created": artifact.get("created_on"),
                    "target_modified": artifact.get("modified_on"),
                    "target_accessed": artifact.get("last_interacted") or artifact.get("first_interacted") or artifact.get("accessed_on"),
                    "device_type": artifact.get("shell_type"),
                    "artifact_volume_serial_number": artifact.get("volume_serial_number"),
                    "artifact_volume_name": artifact.get("volume_name"),
                    "artifact_volume_guid": artifact.get("volume_guid"),
                    "artifact_drive_letter": artifact.get("drive_letter"),
                    "volume_serial_match": match,
                    "confidence": confidence,
                }
            )
            if limit is not None and len(results) >= limit:
                return results
    return results


def _normalize_usb_serial(value: Any) -> str:
    return re.sub(r"[^0-9A-F]", "", str(value or "").upper())


def _normalize_usb_guid(value: Any) -> str:
    return re.sub(r"[^0-9A-F]", "", str(value or "").upper())


def _normalize_usb_drive(value: Any) -> str:
    text = str(value or "").upper().strip()
    if not text:
        return ""
    return text if text.endswith(":") else f"{text[:1]}:"


def _normalize_usb_volume_name(value: Any) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip().upper())


def _usb_volume_name_matchable(left: str, right: str) -> bool:
    if not left or not right or left != right:
        return False
    return left not in {"LOCAL DISK", "NEW VOLUME", "USB DRIVE", "REMOVABLE DISK"}


def _normalize_usb_artifact_path(value: Any) -> str:
    text = str(value or "").upper().replace("/", "\\")
    text = text.replace("DESKTOP\\THIS PC\\", "").replace("DESKTOP\\", "")
    while "\\\\" in text:
        text = text.replace("\\\\", "\\")
    return text.rstrip("\\")


def _usb_anchor_count(anchors: list[str], artifact_path: str) -> int:
    if not artifact_path:
        return 0
    count = 0
    for anchor in set(anchors):
        anchor = anchor.rstrip("\\")
        if anchor == artifact_path or anchor.startswith(f"{artifact_path}\\") or artifact_path.startswith(f"{anchor}\\"):
            count += 1
    return count


def _usb_shellbag_overlaps_device(
    artifact: dict[str, Any],
    usb: dict[str, Any],
    connection_rows: list[dict[str, Any]],
) -> bool:
    start = _parse_report_timestamp(artifact.get("first_interacted") or artifact.get("last_interacted"))
    end = _parse_report_timestamp(artifact.get("last_interacted") or artifact.get("first_interacted"))
    if not start or not end:
        return False
    serial = str(usb.get("serial") or "")
    usb_vsn = _normalize_usb_serial(usb.get("volume_serial_number"))
    arrivals = [
        row
        for row in connection_rows
        if str(row.get("serial") or "") == serial
        and str(row.get("event_type") or "") in {"arrival", "first_connected", "partition_seen"}
        and (not usb_vsn or not _normalize_usb_serial(row.get("volume_serial_number")) or _normalize_usb_serial(row.get("volume_serial_number")) == usb_vsn)
    ]
    if arrivals:
        for arrival in arrivals:
            session_start = _parse_report_timestamp(arrival.get("event_time_utc"))
            if not session_start:
                continue
            removals = [
                _parse_report_timestamp(row.get("event_time_utc"))
                for row in connection_rows
                if str(row.get("serial") or "") == serial
                and str(row.get("event_type") or "") == "removal"
                and _parse_report_timestamp(row.get("event_time_utc"))
                and _parse_report_timestamp(row.get("event_time_utc")) >= session_start
            ]
            session_end = min(removals) if removals else session_start
            if start <= session_end and end >= session_start:
                return True
        return False
    device_start = _parse_report_timestamp(usb.get("first_install_date_utc"))
    device_end = _parse_report_timestamp(usb.get("last_removal_utc") or usb.get("last_arrival_utc") or usb.get("first_install_date_utc"))
    return bool(device_start and device_end and start <= device_end and end >= device_start)


def _usb_file_temporal_context(row: dict[str, Any], connection_rows: list[dict[str, Any]]) -> dict[str, Any]:
    target_times = [
        timestamp
        for timestamp in (
            _parse_report_timestamp(row.get("target_created")),
            _parse_report_timestamp(row.get("target_modified")),
            None if row.get("target_accessed_precision") == "date" else _parse_report_timestamp(row.get("target_accessed")),
        )
        if timestamp is not None
    ]
    if not target_times:
        return _usb_temporal_result("no_file_timestamps")
    sessions = _usb_connection_sessions_for_row(row, connection_rows)
    if not sessions:
        fallback = _usb_fallback_session_for_row(row)
        if fallback:
            sessions = [fallback]
        else:
            return _usb_temporal_result("no_connection_window_available")
    all_sessions = _usb_all_connection_sessions(connection_rows)
    active_counts = [_usb_active_session_count_at(all_sessions, timestamp) for timestamp in target_times]
    if any(count > 1 for count in active_counts):
        return _usb_temporal_result(
            "ambiguous_multiple_devices_connected",
            sessions=sessions,
            target_times=target_times,
            basis="multiple external-storage sessions overlap at one or more file timestamps",
        )
    if any(_timestamp_in_session(timestamp, session) for timestamp in target_times for session in sessions):
        return _usb_temporal_result("within_known_connection", sessions=sessions, target_times=target_times)
    if sessions and all(session["start"] == session["end"] for session in sessions):
        return _usb_temporal_result("connection_observed_no_removal_window", sessions=sessions, target_times=target_times)
    first_start = min(session["start"] for session in sessions)
    last_end = max(session["end"] for session in sessions)
    if max(target_times) < first_start:
        status = "before_first_known_connection"
    elif min(target_times) > last_end:
        status = "after_last_known_connection"
    else:
        status = "outside_known_connection"
    return _usb_temporal_result(status, sessions=sessions, target_times=target_times)


def _normalize_usb_file_access_precision(row: dict[str, Any]) -> None:
    accessed = str(row.get("target_accessed") or "").strip()
    row["target_accessed_original"] = row.get("target_accessed_original") or ""
    row["target_accessed_precision"] = row.get("target_accessed_precision") or ("timestamp" if accessed else "")
    row["target_accessed_note"] = row.get("target_accessed_note") or ""
    if not accessed or not _usb_file_row_is_fat_family(row):
        return
    access_date = _usb_access_date(accessed)
    if not access_date:
        return
    row["target_accessed_original"] = row.get("target_accessed_original") or accessed
    row["target_accessed"] = access_date
    row["target_accessed_precision"] = "date"
    row["target_accessed_note"] = (
        "FAT stores last access as a date only; source tool supplied a synthetic time component, so Perceptor reports the access value as date-only."
    )


def _usb_file_row_is_fat_family(row: dict[str, Any]) -> bool:
    values = [
        str(row.get(field) or "").strip().upper()
        for field in ("usb_file_system", "usb_vbr_file_system")
        if str(row.get(field) or "").strip()
    ]
    return any(value in {"FAT", "FAT12", "FAT16", "FAT32"} for value in values)


def _usb_access_date(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    match = re.match(r"^(\d{4}-\d{2}-\d{2})", text)
    return match.group(1) if match else ""


def _usb_temporal_result(
    status: str,
    *,
    sessions: list[dict[str, Any]] | None = None,
    target_times: list[datetime] | None = None,
    basis: str | None = None,
) -> dict[str, Any]:
    sessions = sessions or []
    target_times = target_times or []
    starts = [session["start"] for session in sessions if session.get("start")]
    ends = [session["end"] for session in sessions if session.get("end")]
    nearest_before = None
    nearest_after = None
    if target_times:
        first_target = min(target_times)
        candidates_before = [start for start in starts if start <= first_target]
        candidates_after = [end for end in ends if end >= first_target]
        nearest_before = max(candidates_before) if candidates_before else None
        nearest_after = min(candidates_after) if candidates_after else None
    return {
        "temporal_status": status,
        "temporal_basis": basis or _usb_temporal_basis(status),
        "first_known_connection_utc": _format_report_timestamp(min(starts)) if starts else None,
        "last_known_connection_utc": _format_report_timestamp(max(ends)) if ends else None,
        "nearest_connection_before_utc": _format_report_timestamp(nearest_before) if nearest_before else None,
        "nearest_removal_after_utc": _format_report_timestamp(nearest_after) if nearest_after else None,
    }


def _usb_temporal_basis(status: str) -> str:
    return {
        "within_known_connection": "one or more file timestamps fall inside a known connection window",
        "outside_known_connection": "file timestamps fall between known connection windows",
        "before_first_known_connection": "file timestamps predate the first known connection window",
        "after_last_known_connection": "file timestamps postdate the last known connection window",
        "ambiguous_multiple_devices_connected": "multiple external-storage sessions overlap at one or more file timestamps",
        "connection_observed_no_removal_window": "connection observations exist, but no removal/window end time was available",
        "no_connection_window_available": "no usable connection window was available for this device or volume",
        "no_file_timestamps": "the source artifact did not provide usable file timestamps",
    }.get(status, "")


def _usb_connection_sessions_for_row(row: dict[str, Any], connection_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    serial = str(row.get("usb_serial") or "")
    vsn = _normalize_usb_serial(row.get("usb_volume_serial_number"))
    matched = [
        item
        for item in connection_rows
        if (not serial or str(item.get("serial") or "") == serial)
        and (not vsn or not _normalize_usb_serial(item.get("volume_serial_number")) or _normalize_usb_serial(item.get("volume_serial_number")) == vsn)
    ]
    return _usb_sessions_from_connection_rows(matched)


def _usb_event_log_connection_observations(db: Database, case_id: str) -> list[dict[str, Any]]:
    rows = _query_report_rows(
        db,
        case_id,
        "evtx_events",
        """
        SELECT *
        FROM evtx_events
        WHERE case_id = ?
          AND LOWER(COALESCE(provider, '')) LIKE '%driverframeworks-usermode%'
          AND COALESCE(event_id, '') IN ('10000', '20001')
          AND (
            LOWER(COALESCE(payload_data1, '')) LIKE '%usbstor%'
            OR LOWER(COALESCE(payload_data2, '')) LIKE '%usbstor%'
            OR LOWER(COALESCE(payload_data3, '')) LIKE '%usbstor%'
            OR LOWER(COALESCE(map_description, '')) LIKE '%usb%'
          )
        ORDER BY time_created
        """,
        (case_id,),
    )
    output = []
    for row in rows:
        text = html.unescape(
            " ".join(
                str(row.get(field) or "")
                for field in (
                    "payload_data1",
                    "payload_data2",
                    "payload_data3",
                    "payload_data4",
                    "payload_data5",
                    "payload_data6",
                    "map_description",
                )
            )
        )
        serial = _usb_storage_serial_from_text(text)
        if not serial:
            continue
        output.append(
            {
                "case_id": case_id,
                "computer_id": row.get("computer_id"),
                "image_id": row.get("image_id"),
                "serial": serial,
                "volume_serial_number": "",
                "drive_letter": "",
                "event_time_utc": row.get("time_created"),
                "event_type": "arrival",
                "event_source": "driverframeworks_usermode",
                "event_id": row.get("event_id"),
                "record_number": row.get("record_number"),
                "source_path": row.get("source_file"),
            }
        )
    return output


def _usb_storage_serial_from_text(text: str) -> str:
    match = re.search(r"USBSTOR[#\\][^#\\]+[#\\]([^#\\{]+)", text, re.IGNORECASE)
    if not match:
        return ""
    return match.group(1).replace("&0", "").strip()


def _usb_all_connection_sessions(connection_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    return _usb_sessions_from_connection_rows(connection_rows)


def _usb_sessions_from_connection_rows(connection_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    arrivals = [
        row
        for row in connection_rows
        if str(row.get("event_type") or "") in {"arrival", "first_connected", "partition_seen"}
        and _parse_report_timestamp(row.get("event_time_utc"))
    ]
    removals = [
        row
        for row in connection_rows
        if str(row.get("event_type") or "") == "removal"
        and _parse_report_timestamp(row.get("event_time_utc"))
    ]
    sessions = []
    for arrival in arrivals:
        start = _parse_report_timestamp(arrival.get("event_time_utc"))
        if not start:
            continue
        serial = str(arrival.get("serial") or "")
        vsn = _normalize_usb_serial(arrival.get("volume_serial_number"))
        end_candidates = [
            _parse_report_timestamp(removal.get("event_time_utc"))
            for removal in removals
            if str(removal.get("serial") or "") == serial
            and (not vsn or not _normalize_usb_serial(removal.get("volume_serial_number")) or _normalize_usb_serial(removal.get("volume_serial_number")) == vsn)
            and _parse_report_timestamp(removal.get("event_time_utc"))
            and _parse_report_timestamp(removal.get("event_time_utc")) >= start
        ]
        end = min(end_candidates) if end_candidates else start
        sessions.append({"start": start, "end": end, "serial": serial, "volume_serial_number": vsn})
    return sessions


def _usb_fallback_session_for_row(row: dict[str, Any]) -> dict[str, Any] | None:
    start = _parse_report_timestamp(row.get("usb_first_install_date_utc"))
    end = _parse_report_timestamp(row.get("usb_last_removal_utc") or row.get("usb_last_arrival_utc") or row.get("usb_first_install_date_utc"))
    if not start or not end:
        return None
    if end < start:
        end = start
    return {"start": start, "end": end, "serial": str(row.get("usb_serial") or ""), "volume_serial_number": _normalize_usb_serial(row.get("usb_volume_serial_number"))}


def _usb_active_session_count_at(sessions: list[dict[str, Any]], timestamp: datetime) -> int:
    return sum(1 for session in sessions if _timestamp_in_session(timestamp, session))


def _timestamp_in_session(timestamp: datetime, session: dict[str, Any]) -> bool:
    return bool(session.get("start") and session.get("end") and session["start"] <= timestamp <= session["end"])


def _format_report_timestamp(value: datetime | None) -> str | None:
    if value is None:
        return None
    if value.tzinfo is not None:
        value = value.astimezone(timezone.utc).replace(tzinfo=None)
    return value.isoformat(timespec="seconds") + "Z"


def _dedupe_usb_file_items(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    grouped: dict[tuple[str, str, str], dict[str, Any]] = {}
    for row in rows:
        key = (
            row.get("usb_serial") or "",
            row.get("usb_volume_serial_number") or "",
            row.get("file_location") or row.get("file_name") or "",
        )
        item = grouped.setdefault(
            key,
            {
                "usb_serial": row.get("usb_serial"),
                "usb_volume_serial_number": row.get("usb_volume_serial_number"),
                "usb_volume_name": row.get("usb_volume_name"),
                "usb_drive_letter": row.get("usb_drive_letter"),
                "usb_product": row.get("usb_product"),
                "matched_volume_serial_number": row.get("matched_volume_serial_number") or row.get("usb_volume_serial_number") or row.get("artifact_volume_serial_number"),
                "matched_volume_name": row.get("matched_volume_name") or row.get("usb_volume_name") or row.get("artifact_volume_name"),
                "file_name": row.get("file_name"),
                "file_location": row.get("file_location"),
                "artifact_count": 0,
                "computer_ids": set(),
                "image_ids": set(),
                "source_artifact_types": set(),
                "user_profiles": set(),
                "first_target_time": None,
                "last_target_time": None,
                "temporal_statuses": set(),
                "temporal_bases": set(),
                "first_known_connection_utc": None,
                "last_known_connection_utc": None,
                "nearest_connection_before_utc": None,
                "nearest_removal_after_utc": None,
                "best_confidence": "low",
                "match_types": set(),
            },
        )
        item["artifact_count"] += 1
        if row.get("computer_id"):
            item["computer_ids"].add(str(row["computer_id"]))
        if row.get("image_id"):
            item["image_ids"].add(str(row["image_id"]))
        if row.get("source_artifact_type"):
            item["source_artifact_types"].add(row["source_artifact_type"])
        if row.get("user_profile"):
            item["user_profiles"].add(row["user_profile"])
        if row.get("confidence") == "high":
            item["best_confidence"] = "high"
        elif row.get("confidence") == "medium" and item["best_confidence"] == "low":
            item["best_confidence"] = "medium"
        if row.get("volume_serial_match"):
            item["match_types"].add(row["volume_serial_match"])
        if row.get("temporal_status"):
            item["temporal_statuses"].add(row["temporal_status"])
        if row.get("temporal_basis"):
            item["temporal_bases"].add(row["temporal_basis"])
        for field, reducer in (
            ("first_known_connection_utc", min),
            ("nearest_connection_before_utc", max),
            ("nearest_removal_after_utc", min),
            ("last_known_connection_utc", max),
        ):
            value = row.get(field)
            if not value:
                continue
            current = item.get(field)
            item[field] = value if current is None else reducer(current, value)
        for field in ("target_created", "target_modified", "target_accessed"):
            value = row.get(field)
            if not value:
                continue
            if item["first_target_time"] is None or value < item["first_target_time"]:
                item["first_target_time"] = value
            if item["last_target_time"] is None or value > item["last_target_time"]:
                item["last_target_time"] = value
    result = []
    for item in grouped.values():
        converted = dict(item)
        converted["computer_id"] = ", ".join(sorted(item["computer_ids"]))
        converted["image_id"] = ", ".join(sorted(item["image_ids"]))
        converted["source_artifact_types"] = ", ".join(sorted(item["source_artifact_types"]))
        converted["user_profiles"] = ", ".join(sorted(item["user_profiles"]))
        converted["match_types"] = ", ".join(sorted(item["match_types"]))
        converted["temporal_statuses"] = ", ".join(sorted(item["temporal_statuses"]))
        converted["temporal_bases"] = " | ".join(sorted(item["temporal_bases"]))
        result.append(converted)
    return sorted(
        result,
        key=lambda item: (
            item.get("usb_volume_serial_number") or "",
            item.get("file_location") or item.get("file_name") or "",
        ),
    )


def _find_usb_storage_device(
    db: Database,
    case_id: str,
    *,
    serial: str | None,
    volume_serial_number: str | None,
    volume_guid: str | None,
) -> dict[str, Any]:
    criteria = []
    params: list[Any] = [case_id]
    if serial:
        criteria.append("UPPER(serial) = UPPER(?)")
        params.append(serial)
    if volume_serial_number:
        criteria.append("UPPER(REPLACE(volume_serial_number, '-', '')) = UPPER(REPLACE(?, '-', ''))")
        params.append(volume_serial_number)
    if volume_guid:
        criteria.append(
            "UPPER(REPLACE(REPLACE(COALESCE(volume_guid, ''), CHAR(123), ''), CHAR(125), '')) "
            "LIKE '%' || UPPER(REPLACE(REPLACE(?, CHAR(123), ''), CHAR(125), '')) || '%'"
        )
        params.append(volume_guid)
    if not criteria:
        raise ValueError("Provide one of serial, volume_serial_number, or volume_guid")
    rows = _query_report_rows(
        db,
        case_id,
        "usb_storage_devices",
        f"""
        SELECT *
        FROM usb_storage_devices
        WHERE usb_storage_devices.case_id = ?
          AND ({' OR '.join(criteria)})
        ORDER BY evidence_row_count DESC, COALESCE(last_removal_utc, last_arrival_utc, first_install_date_utc) DESC
        LIMIT 1
        """,
        params,
    )
    if not rows:
        raise ValueError("No USB storage device matched the provided identifier")
    item = dict(rows[0])
    computer = db.conn.execute("SELECT label FROM computers WHERE id = ?", (item.get("computer_id"),)).fetchone()
    image = db.conn.execute("SELECT path FROM images WHERE id = ?", (item.get("image_id"),)).fetchone()
    item["computer_label"] = computer["label"] if computer else None
    item["image_path"] = image["path"] if image else None
    item["first_connection_utc"] = item.get("first_install_date_utc")
    return item


def _usb_verbose_raw_rows(db: Database, case_id: str, device: dict[str, Any]) -> list[dict[str, Any]]:
    serial = device.get("serial")
    vsn = _norm_vsn(device.get("volume_serial_number"))
    guids = _split_multi_value(device.get("volume_guid"))
    clauses = []
    params: list[Any] = [case_id]
    if serial:
        clauses.append("UPPER(COALESCE(serial, alternate_scsi_serial, instance_id, '')) LIKE '%' || UPPER(?) || '%'")
        params.append(serial)
    if vsn:
        clauses.append("UPPER(REPLACE(COALESCE(volume_serial_number, ''), '-', '')) = ?")
        params.append(vsn)
    for guid in guids:
        clauses.append("UPPER(COALESCE(volume_guid, key_path, property_value, '')) LIKE '%' || UPPER(?) || '%'")
        params.append(guid.strip("{}"))
    if not clauses:
        return []
    return _query_report_rows(
        db,
        case_id,
        "usb_devices",
        f"""
        SELECT *
        FROM usb_devices
        WHERE case_id = ?
          AND ({' OR '.join(clauses)})
        ORDER BY COALESCE(key_last_write_utc, property_name, artifact), artifact, row_number
        """,
        params,
    )


def _usb_verbose_file_rows(
    db: Database,
    case_id: str,
    device: dict[str, Any],
    *,
    limit: int,
) -> list[dict[str, Any]]:
    clauses = []
    params: list[Any] = [case_id]
    serial = _external_storage_serial_key(device.get("serial"), device=device)
    if serial:
        clauses.append("UPPER(usb_serial) = UPPER(?)")
        params.append(serial)
    vsn = _norm_vsn(device.get("volume_serial_number"))
    if vsn:
        clauses.append("UPPER(REPLACE(usb_volume_serial_number, '-', '')) = ?")
        params.append(vsn)
    if not clauses:
        return []
    params.append(limit)
    return _query_report_rows(
        db,
        case_id,
        "usb_file_correlations",
        f"""
        SELECT *
        FROM usb_file_correlations
        WHERE case_id = ?
          AND ({' OR '.join(clauses)})
        ORDER BY
          CASE confidence WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END,
          COALESCE(target_modified, target_created, target_accessed, ''),
          COALESCE(file_location, file_name, '')
        LIMIT ?
        """,
        params,
    )


def _usb_verbose_description_attributes(device: dict[str, Any], raw_rows: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "serial": device.get("serial"),
        "vid": device.get("vendor_id"),
        "pid": device.get("product_id"),
        "vendor": device.get("vendor"),
        "product": device.get("product"),
        "revision": device.get("revision"),
        "friendly_name": device.get("friendly_name"),
        "parent_id_prefix": device.get("parent_id_prefix"),
        "device_service": device.get("device_service"),
        "alternate_scsi_serial": device.get("alternate_scsi_serial"),
        "sources": _usb_verbose_sources(raw_rows),
    }


def _usb_verbose_connection_times(device: dict[str, Any], raw_rows: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "first_connected_utc": device.get("first_install_date_utc"),
        "last_arrival_utc": device.get("last_arrival_utc"),
        "last_removal_utc": device.get("last_removal_utc"),
        "first_volume_serial_event_utc": device.get("first_volume_serial_event_utc"),
        "last_partition_event_utc": device.get("last_partition_event_utc"),
        "raw_events": [
            _usb_verbose_raw_summary(row)
            for row in raw_rows
            if row.get("key_last_write_utc") or row.get("property_name") in {"0064", "0065", "0066", "0067"}
        ],
    }


def _usb_verbose_volume_attributes(device: dict[str, Any], raw_rows: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "drive_letter": device.get("drive_letter"),
        "volume_guid": device.get("volume_guid"),
        "volume_serial_number": device.get("volume_serial_number"),
        "candidate_volume_serial_numbers": device.get("candidate_volume_serial_numbers"),
        "candidate_volume_serial_sources": device.get("candidate_volume_serial_sources"),
        "candidate_volume_serial_note": device.get("candidate_volume_serial_note"),
        "volume_name": device.get("volume_name"),
        "capacity_bytes": device.get("capacity_bytes"),
        "user_profiles": device.get("user_profiles"),
        "raw_volume_rows": [
            _usb_verbose_raw_summary(row)
            for row in raw_rows
            if row.get("drive_letter") or row.get("volume_guid") or row.get("volume_serial_number") or row.get("volume_name")
        ],
    }


def _usb_verbose_mbr_vbr_details(raw_rows: list[dict[str, Any]]) -> dict[str, Any]:
    partition_rows = [row for row in raw_rows if row.get("artifact") == "partition_diagnostic"]
    return {
        "available": bool(partition_rows),
        "partition_diagnostic_rows": [_usb_verbose_raw_summary(row) for row in partition_rows],
    }


def _usb_verbose_other_details(raw_rows: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "device_classes": [
            _usb_verbose_raw_summary(row)
            for row in raw_rows
            if row.get("artifact") in {"usb_device_history", "usb_volume_history"}
            and "DeviceClasses" in (row.get("key_path") or "")
        ],
        "mounted_devices": [
            _usb_verbose_raw_summary(row)
            for row in raw_rows
            if row.get("artifact") == "mounted_devices"
        ],
    }


def _usb_verbose_counts(raw_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    counts: dict[tuple[str, str], int] = {}
    for row in raw_rows:
        key = (row.get("artifact") or "", row.get("device_type") or "")
        counts[key] = counts.get(key, 0) + 1
    return [
        {"artifact": artifact, "device_type": device_type, "row_count": count}
        for (artifact, device_type), count in sorted(counts.items(), key=lambda item: (-item[1], item[0]))
    ]


def _usb_verbose_sources(raw_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    sources: dict[tuple[str, str], int] = {}
    for row in raw_rows:
        key = (row.get("artifact") or "", row.get("source_path") or "")
        sources[key] = sources.get(key, 0) + 1
    return [
        {"artifact": artifact, "source_path": source_path, "row_count": count}
        for (artifact, source_path), count in sorted(sources.items(), key=lambda item: (-item[1], item[0]))
    ]


def _usb_verbose_raw_summary(row: dict[str, Any]) -> dict[str, Any]:
    return {
        "artifact": row.get("artifact"),
        "device_type": row.get("device_type"),
        "source_path": row.get("source_path"),
        "row_number": row.get("row_number"),
        "key_path": row.get("key_path"),
        "key_last_write_utc": row.get("key_last_write_utc"),
        "property_name": row.get("property_name"),
        "property_value": row.get("property_value"),
        "drive_letter": row.get("drive_letter"),
        "volume_guid": row.get("volume_guid"),
        "volume_serial_number": row.get("volume_serial_number"),
        "volume_name": row.get("volume_name"),
        "capacity_bytes": row.get("capacity_bytes"),
    }


def _norm_vsn(value: str | None) -> str | None:
    if not value:
        return None
    normalized = value.replace("-", "").upper()
    return normalized or None


def _split_multi_value(value: str | None) -> list[str]:
    if not value:
        return []
    return [part.strip() for part in value.split(",") if part.strip()]


def usb_timeline_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 500,
    rebuild_correlations: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    if rebuild_correlations:
        rebuild_usb_file_correlations(db, case_id)
    events = []
    connection_count_rows = _query_report_rows(
        db,
        case_id,
        "usb_connection_events",
        "SELECT COUNT(*) AS count FROM usb_connection_events WHERE case_id = ?",
        (case_id,),
    )
    connection_event_count = int((connection_count_rows[0] if connection_count_rows else {}).get("count") or 0)
    if connection_event_count:
        connection_rows = _query_report_rows(
            db,
            case_id,
            "usb_connection_events",
            """
            SELECT *
            FROM usb_connection_events
            WHERE usb_connection_events.case_id = ?
            """,
            (case_id,),
        )
        storage_rows = _query_report_rows(
            db,
            case_id,
            "usb_storage_devices",
            "SELECT id, product, volume_name FROM usb_storage_devices WHERE case_id = ?",
            (case_id,),
        )
        storage_by_id = {row["id"]: row for row in storage_rows}
        for row in connection_rows:
            base = dict(row)
            storage = storage_by_id.get(base.get("usb_device_id"), {})
            events.append(
                {
                    "timestamp": base["event_time_utc"],
                    "event_type": f"usb_{base['event_type']}",
                    "computer_id": base.get("computer_id"),
                    "image_id": base.get("image_id"),
                    "usb_serial": base["serial"],
                    "usb_volume_serial_number": base["volume_serial_number"],
                    "usb_volume_name": storage.get("volume_name"),
                    "usb_drive_letter": base["drive_letter"],
                    "usb_product": storage.get("product"),
                    "user_profile": None,
                    "source_artifact_type": base["event_source"] or "usb",
                    "file_location": None,
                    "description": f"usb_{base['event_type']}: {base['serial']}",
                    "confidence": "high",
                }
            )
    else:
        for row in _query_report_rows(
            db,
            case_id,
            "usb_storage_devices",
            """
            SELECT computer_id, image_id, serial, volume_serial_number, volume_name, drive_letter, product,
                   first_install_date_utc, last_arrival_utc, last_removal_utc,
                   first_volume_serial_event_utc, last_partition_event_utc
            FROM usb_storage_devices
            WHERE case_id = ?
            """,
            (case_id,),
        ):
            base = dict(row)
            for event_type, field in (
                ("usb_first_connected", "first_install_date_utc"),
                ("usb_last_arrival", "last_arrival_utc"),
                ("usb_last_removal", "last_removal_utc"),
                ("usb_first_partition_event", "first_volume_serial_event_utc"),
                ("usb_last_partition_event", "last_partition_event_utc"),
            ):
                timestamp = base.get(field)
                if timestamp:
                    events.append(
                        {
                            "timestamp": timestamp,
                            "event_type": event_type,
                            "computer_id": base.get("computer_id"),
                            "image_id": base.get("image_id"),
                            "usb_serial": base["serial"],
                            "usb_volume_serial_number": base["volume_serial_number"],
                            "usb_volume_name": base["volume_name"],
                            "usb_drive_letter": base["drive_letter"],
                            "usb_product": base["product"],
                            "user_profile": None,
                            "source_artifact_type": "usb",
                            "file_location": None,
                            "description": f"{event_type}: {base['serial']}",
                            "confidence": "high",
                        }
                    )
    for row in _query_report_rows(
        db,
        case_id,
        "usb_file_correlations",
        """
        SELECT *
        FROM usb_file_correlations
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        item = dict(row)
        for event_type, field in (
            ("usb_file_target_created", "target_created"),
            ("usb_file_target_modified", "target_modified"),
            ("usb_file_target_accessed", "target_accessed"),
        ):
            timestamp = item.get(field)
            if timestamp and not _is_placeholder_timestamp(timestamp):
                events.append(
                    {
                        "timestamp": timestamp,
                        "event_type": event_type,
                        "computer_id": item.get("computer_id"),
                        "image_id": item.get("image_id"),
                        "usb_serial": item["usb_serial"],
                        "usb_volume_serial_number": item["usb_volume_serial_number"],
                        "usb_volume_name": item["usb_volume_name"],
                        "usb_drive_letter": item["usb_drive_letter"],
                        "usb_product": item["usb_product"],
                        "user_profile": item.get("user_profile"),
                        "source_artifact_type": item["source_artifact_type"],
                        "file_location": item["file_location"],
                        "description": item["file_location"] or item["file_name"],
                        "confidence": item["confidence"],
                    }
                )
    events = _dedupe_timeline_events(events)
    events.sort(key=lambda item: (item["timestamp"], item["event_type"], item.get("description") or ""))
    return {"case_id": case_id, "events": events[:limit], "total_returned": min(len(events), limit), "total_events": len(events)}


def external_storage_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 500,
    rebuild_correlations: bool = True,
    include_file_activity: bool = True,
) -> dict[str, Any]:
    db.get_case(case_id)
    if rebuild_correlations:
        rebuild_usb_file_correlations(db, case_id)
    devices = _external_storage_devices(db, case_id, limit=limit)
    media_instances = _external_storage_media_instances(db, case_id, limit=max(limit * 5, 500))
    _annotate_external_storage_row_attribution(db, case_id, media_instances)
    _annotate_external_storage_device_media_instances(devices, media_instances)
    _merge_external_storage_partition_events(db, case_id, devices)
    file_activity = []
    if include_file_activity:
        file_activity = _dedupe_usb_file_items(
            _query_report_rows(
                db,
                case_id,
                "usb_file_correlations",
                """
                SELECT *
                FROM usb_file_correlations
                WHERE case_id = ?
                ORDER BY
                  CASE confidence WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END,
                  COALESCE(target_modified, target_created, target_accessed, ''),
                  COALESCE(file_location, file_name, '')
                LIMIT ?
                """,
                (case_id, max(limit * 5, 500)),
            )
        )[:limit]
    _annotate_external_storage_row_attribution(db, case_id, file_activity)
    _annotate_external_storage_file_activity(devices, file_activity)
    unattributed_volume_activity = _external_storage_unattributed_removable_activity(
        db,
        case_id,
        devices=devices,
        attributed_file_activity=file_activity,
        limit=limit,
    )
    _annotate_external_storage_row_attribution(db, case_id, unattributed_volume_activity)
    timeline = _external_storage_filtered_timeline(
        usb_timeline_report(db, case_id, limit=max(limit * 5, 500), rebuild_correlations=False)["events"],
        devices,
        limit=limit,
    )
    timeline = _dedupe_timeline_events([*timeline, *_external_storage_partition_event_timeline(db, case_id, devices)])
    setupapi_observations = _external_storage_setupapi_rows(db, case_id, devices=devices, limit=limit)
    timeline = _dedupe_timeline_events([*timeline, *_setupapi_storage_timeline(setupapi_observations)])
    _annotate_external_storage_row_attribution(db, case_id, timeline)
    _annotate_external_storage_row_attribution(db, case_id, setupapi_observations)
    timeline.sort(key=lambda item: (item.get("timestamp") or "", item.get("event_type") or "", item.get("description") or ""))
    timeline = timeline[:limit]
    event_logs = _external_storage_event_log_rows(db, case_id, devices=devices, limit=limit)
    _annotate_external_storage_row_attribution(db, case_id, event_logs)
    registry_counts = _external_storage_registry_counts(db, case_id)
    _annotate_external_storage_corroboration(
        devices,
        file_activity=file_activity,
        timeline=timeline,
        event_logs=event_logs,
        setupapi_observations=setupapi_observations,
    )
    source_counts: dict[str, int] = {}
    temporal_counts: dict[str, int] = {}
    for row in file_activity:
        for source in str(row.get("source_artifact_types") or "").split(","):
            source = source.strip()
            if source:
                source_counts[source] = source_counts.get(source, 0) + 1
        for status in str(row.get("temporal_statuses") or "").split(","):
            status = status.strip()
            if status:
                temporal_counts[status] = temporal_counts.get(status, 0) + 1
    return {
        "case_id": case_id,
        "summary": {
            "device_count": len(devices),
            "media_instance_count": len(media_instances),
            "adapter_reuse_count": len(
                {
                    str(row.get("adapter_serial") or "")
                    for row in media_instances
                    if row.get("reuse_warning") and row.get("adapter_serial")
                }
            ),
            "timeline_event_count": len(timeline),
            "file_activity_count": len(file_activity),
            "unattributed_removable_volume_count": len(unattributed_volume_activity),
            "unattributed_removable_file_activity_count": sum(
                int(row.get("file_activity_count") or 0) for row in unattributed_volume_activity
            ),
            "event_log_observation_count": len(event_logs),
            "setupapi_observation_count": len(setupapi_observations),
            "registry_evidence_counts": registry_counts,
            "identity_tier_counts": _external_storage_identity_tier_counts(devices),
            "file_activity_source_counts": [
                {"source_artifact_type": key, "count": value}
                for key, value in sorted(source_counts.items(), key=lambda item: (-item[1], item[0]))
            ],
            "file_activity_temporal_counts": [
                {"temporal_status": key, "count": value}
                for key, value in sorted(temporal_counts.items(), key=lambda item: (-item[1], item[0]))
            ],
            "dedupe_note": (
                "File and folder activity is summarized per device. "
                "Connection events are deduped by timestamp, event type, serial, volume serial, source, and path."
            ),
        },
        "devices": devices,
        "media_instances": media_instances,
        "timeline": timeline,
        "file_activity": file_activity,
        "unattributed_removable_volume_activity": unattributed_volume_activity,
        "event_log_observations": event_logs,
        "setupapi_observations": setupapi_observations,
        "registry_evidence_counts": registry_counts,
        "total_returned": {
            "devices": len(devices),
            "media_instances": len(media_instances),
            "timeline": len(timeline),
            "file_activity": len(file_activity),
            "unattributed_removable_volume_activity": len(unattributed_volume_activity),
            "event_log_observations": len(event_logs),
            "setupapi_observations": len(setupapi_observations),
        },
    }


