def opened_from_removable_media_markdown(report: dict[str, Any]) -> str:
    lines = ["# Opened From Removable Media Report", "", f"Case: `{report.get('case_id')}`", ""]
    summary = report.get("summary") or {}
    lines.extend(
        [
            "## Summary",
            "",
            f"- Removable-path user references: `{summary.get('opened_from_removable_count', 0)}`",
            f"- Attributed references: `{summary.get('attributed_count', 0)}`",
            f"- Candidate references: `{summary.get('candidate_count', 0)}`",
            f"- Unattributed references: `{summary.get('unattributed_count', 0)}`",
            f"- Excluded cloud-drive references: `{summary.get('excluded_cloud_drive_path_count', 0)}`",
            f"- Groups: `{summary.get('group_count', 0)}`",
            "",
        ]
    )
    groups = report.get("groups") or []
    if groups:
        lines.extend(["## Groups", ""])
        for group in groups[:25]:
            lines.append(
                "- "
                f"computer `{group.get('computer_label') or group.get('computer_id') or ''}` "
                f"drive `{group.get('drive_letter') or ''}` "
                f"top folder `{group.get('top_folder') or ''}` "
                f"status `{group.get('attribution_status') or ''}` "
                f"items `{group.get('item_count') or 0}` "
                f"first/last `{group.get('first_timestamp') or ''}` / `{group.get('last_timestamp') or ''}`"
            )
        lines.append("")
    lines.extend(["## Items", ""])
    for item in report.get("items") or []:
        lines.append(
            "- "
            f"`{item.get('timestamp') or ''}` "
            f"`{item.get('source') or ''}` "
            f"computer `{item.get('computer_label') or item.get('computer_id') or ''}` "
            f"user `{item.get('user_profile') or ''}` "
            f"status `{item.get('attribution_status') or ''}` "
            f"confidence `{item.get('confidence') or ''}` "
            f"path `{item.get('display_path') or item.get('path') or ''}`"
        )
        for match in (item.get("matched_devices") or [])[:3]:
            lines.append(
                f"  - `{match.get('device_identity') or ''}` status `{match.get('attribution_status') or ''}` basis `{match.get('match_basis') or ''}` tier `{match.get('identity_confidence_tier') or ''}`"
            )
    if not report.get("items"):
        lines.append("No removable-media user references matched the filters.")
    return "\n".join(lines).rstrip() + "\n"


def opened_from_cloud_storage_report(
    db: Database,
    case_id: str,
    *,
    user: str | None = None,
    provider: str | None = None,
    contains: str | None = None,
    limit: int = 250,
) -> dict[str, Any]:
    intent = user_intent_artifacts_report(db, case_id, user=user, contains=contains, limit=max(limit * 4, 500))
    mount_intent = intent if contains is None else user_intent_artifacts_report(db, case_id, user=user, limit=5000)
    mounts = _cloud_mounted_drive_roots(mount_intent.get("events") or [])
    provider_filter = provider.casefold() if provider else ""
    if provider_filter:
        mounts = [mount for mount in mounts if provider_filter in str(mount.get("provider") or "").casefold()]
    rows: list[dict[str, Any]] = []
    for event in intent.get("events") or []:
        path = str(event.get("path") or "")
        match = _cloud_storage_reference_match(path, event, mounts)
        if not match:
            continue
        if provider_filter and provider_filter not in str(match.get("provider") or "").casefold():
            continue
        rows.append(
            {
                **{key: event.get(key) for key in ("timestamp", "source", "activity", "computer_id", "computer_label", "image_id", "user_profile", "path", "source_id")},
                "display_path": _display_drive_path(path),
                "drive_letter": _path_drive_letter(path),
                "top_folder": _drive_path_top_folder(path),
                "provider": match.get("provider"),
                "cloud_root": match.get("cloud_root"),
                "storage_mode": match.get("storage_mode"),
                "mount_confidence": match.get("confidence"),
                "mount_basis": match.get("basis"),
                "details": event.get("details"),
            }
        )
    rows.sort(key=lambda row: str(row.get("timestamp") or ""), reverse=True)
    rows = rows[:limit]
    provider_counts: dict[str, int] = {}
    confidence_counts: dict[str, int] = {}
    storage_mode_counts: dict[str, int] = {}
    for row in rows:
        provider_name = str(row.get("provider") or "unknown")
        confidence = str(row.get("mount_confidence") or "unknown")
        storage_mode = str(row.get("storage_mode") or "unknown")
        provider_counts[provider_name] = provider_counts.get(provider_name, 0) + 1
        confidence_counts[confidence] = confidence_counts.get(confidence, 0) + 1
        storage_mode_counts[storage_mode] = storage_mode_counts.get(storage_mode, 0) + 1
    return {
        "case_id": case_id,
        "filters": {"user": user, "provider": provider, "contains": contains},
        "summary": {
            "opened_from_cloud_storage_count": len(rows),
            "cloud_mount_count": len(mounts),
            "provider_counts": [{"provider": key, "count": value} for key, value in sorted(provider_counts.items())],
            "confidence_counts": [{"confidence": key, "count": value} for key, value in sorted(confidence_counts.items())],
            "storage_mode_counts": [{"storage_mode": key, "count": value} for key, value in sorted(storage_mode_counts.items())],
        },
        "cloud_mounts": mounts[:25],
        "items": rows,
        "total_returned": len(rows),
    }


