def _looks_like_removable_path(path: str) -> bool:
    drive = _path_drive_letter(path)
    return bool(drive and drive[0].upper() != "C")


def _cloud_mounted_drive_roots(events: list[dict[str, Any]]) -> list[dict[str, Any]]:
    roots: dict[tuple[Any, ...], dict[str, Any]] = {}
    for event in events:
        path = event.get("path")
        drive = _path_drive_letter(path)
        if not drive or drive.upper() == "C:":
            continue
        provider = _cloud_mounted_drive_provider(path)
        if not provider:
            continue
        root = _cloud_mounted_drive_root(path, provider)
        if not root:
            continue
        key = (event.get("computer_id"), event.get("user_profile"), provider, drive.upper(), root.casefold())
        item = roots.setdefault(
            key,
            {
                "computer_id": event.get("computer_id"),
                "computer_label": event.get("computer_label"),
                "user_profile": event.get("user_profile"),
                "provider": provider,
                "drive_letter": drive.upper(),
                "cloud_root": root,
                "top_folder": _drive_path_top_folder(path),
                "evidence_count": 0,
                "first_timestamp": event.get("timestamp"),
                "last_timestamp": event.get("timestamp"),
                "sources": set(),
                "examples": [],
                "confidence": "low",
                "evidence_basis": "inferred_path_artifact",
                "basis": "",
            },
        )
        item["evidence_count"] += 1
        timestamp = str(event.get("timestamp") or "")
        if timestamp:
            if not item.get("first_timestamp") or timestamp < str(item.get("first_timestamp")):
                item["first_timestamp"] = timestamp
            if not item.get("last_timestamp") or timestamp > str(item.get("last_timestamp")):
                item["last_timestamp"] = timestamp
        if event.get("source"):
            item["sources"].add(str(event.get("source")))
        if len(item["examples"]) < 5:
            item["examples"].append(_display_drive_path(path))
    output = []
    for item in roots.values():
        row = dict(item)
        row["sources"] = ", ".join(sorted(row["sources"]))
        source_count = len([source for source in row["sources"].split(", ") if source])
        evidence_count = int(row.get("evidence_count") or 0)
        row["confidence"] = "high" if evidence_count >= 3 and source_count >= 2 else "medium" if evidence_count >= 2 else "low"
        row["basis"] = f"observed_cloud_root:{row['provider']}:{row['cloud_root']}; evidence_count:{evidence_count}; sources:{row['sources']}"
        output.append(row)
    output.sort(key=lambda row: (row.get("confidence") == "high", row.get("evidence_count") or 0, row.get("last_timestamp") or ""), reverse=True)
    return output


def _cloud_mounted_drive_match(path: Any, event: dict[str, Any], mounts: list[dict[str, Any]]) -> dict[str, Any] | None:
    display = _display_drive_path(path)
    drive = _path_drive_letter(display)
    if not drive:
        return None
    folded = display.casefold()
    for mount in mounts:
        if drive.upper() != str(mount.get("drive_letter") or "").upper():
            continue
        if event.get("computer_id") and mount.get("computer_id") and event.get("computer_id") != mount.get("computer_id"):
            continue
        root = str(mount.get("cloud_root") or "")
        if root and (folded == root.casefold() or folded.startswith(root.casefold().rstrip("\\") + "\\")):
            result = dict(mount)
            result["storage_mode"] = "virtual_drive"
            return result
    return None


def _cloud_storage_reference_match(path: Any, event: dict[str, Any], mounts: list[dict[str, Any]]) -> dict[str, Any] | None:
    mount = _cloud_mounted_drive_match(path, event, mounts)
    if mount:
        return mount
    display = _display_drive_path(path)
    provider = _cloud_mounted_drive_provider(display)
    if not provider:
        return None
    root = _cloud_local_storage_root(display, provider)
    return {
        "provider": provider,
        "drive_letter": _path_drive_letter(display),
        "cloud_root": root,
        "storage_mode": _cloud_storage_mode(display, provider),
        "confidence": "low",
        "basis": f"path_cloud_indicator:{provider}:{root or display}",
        "evidence_basis": "path_indicator",
    }


def _cloud_storage_mode(path: Any, provider: str) -> str:
    text = str(path or "").casefold()
    drive = _path_drive_letter(path)
    if "drivefs" in text or "\\appdata\\local\\google\\drive" in text or "/appdata/local/google/drive" in text:
        return "cache_or_config_path"
    if drive and drive.upper() != "C:" and _cloud_mounted_drive_root(path, provider):
        return "virtual_drive_candidate"
    if drive and drive.upper() == "C:":
        return "local_sync_folder"
    return "cloud_path_indicator"


def _cloud_local_storage_root(path: Any, provider: str) -> str:
    display = _display_drive_path(path)
    drive = _path_drive_letter(display)
    if not drive:
        return ""
    parts = re.split(r"[\\/]+", display)
    lowered = [part.casefold() for part in parts]
    provider_lower = provider.casefold()
    if provider_lower == "onedrive":
        for index, part in enumerate(lowered):
            if part.startswith("onedrive"):
                return "\\".join(parts[: index + 1])
    if provider_lower == "google drive":
        for marker in ("google drive", "drivefs"):
            if marker in lowered:
                return "\\".join(parts[: lowered.index(marker) + 1])
    if provider_lower == "dropbox" and "dropbox" in lowered:
        return "\\".join(parts[: lowered.index("dropbox") + 1])
    if provider_lower == "icloud drive":
        for index, part in enumerate(lowered):
            if part in {"icloud drive", "icloud"}:
                return "\\".join(parts[: index + 1])
    return _cloud_mounted_drive_root(display, provider)


def _cloud_virtual_top_folder(provider: str, top: str) -> bool:
    top_lower = top.casefold()
    provider_lower = provider.casefold()
    if provider_lower == "google drive":
        return top_lower in {"my drive", "shared drives", "computers"}
    if provider_lower == "onedrive":
        return top_lower.startswith("onedrive")
    if provider_lower == "dropbox":
        return top_lower == "dropbox"
    if provider_lower == "icloud drive":
        return top_lower in {"icloud drive", "icloud"}
    return False


def _cloud_mounted_drive_fallback(path: Any) -> dict[str, Any] | None:
    display = _display_drive_path(path)
    provider = _cloud_mounted_drive_provider(display)
    if not provider:
        return None
    root = _cloud_mounted_drive_root(display, provider)
    if not root:
        return None
    return {
        "provider": provider,
        "drive_letter": drive.upper(),
        "cloud_root": root,
        "storage_mode": "virtual_drive_candidate",
        "confidence": "low",
        "basis": f"path_cloud_root_indicator:{provider}:{root}",
        "evidence_basis": "path_indicator",
    }


def _cloud_mounted_drive_provider(path: Any) -> str:
    top = _drive_path_top_folder(path).casefold()
    text = str(path or "").casefold()
    if top in {"my drive", "shared drives"} or any(token in text for token in ("google drive", "drivefs", "drive file stream")):
        return "Google Drive"
    if top == "onedrive" or "onedrive" in text:
        return "OneDrive"
    if top == "dropbox" or "dropbox" in text:
        return "Dropbox"
    if top in {"icloud drive", "icloud"} or "icloud drive" in text:
        return "iCloud Drive"
    return ""


def _cloud_mounted_drive_root(path: Any, provider: str) -> str:
    display = _display_drive_path(path)
    drive = _path_drive_letter(display)
    top = _drive_path_top_folder(display)
    if not drive or not top:
        return ""
    provider_lower = provider.casefold()
    if _cloud_virtual_top_folder(provider, top):
        return f"{drive}\\{top}"
    if any(token in display.casefold() for token in ("google drive", "drivefs", "drive file stream")):
        return f"{drive}\\{top}"
    return ""


def _removable_path_device_match(
    path: str,
    event: dict[str, Any],
    device: dict[str, Any],
    connection_rows: list[dict[str, Any]],
) -> dict[str, Any] | None:
    drive = _normalize_external_storage_drive_letters(_path_drive_letter(path))
    device_drives = _normalize_external_storage_drive_letters(device.get("observed_drive_letters") or device.get("drive_letter"))
    bases = []
    if drive and device_drives and drive in _split_external_storage_values(device_drives):
        bases.append("drive_letter")
    if event.get("computer_id") and device.get("computer_id") and event.get("computer_id") == device.get("computer_id"):
        bases.append("same_computer")
    temporal_status = _removable_device_temporal_status(event.get("timestamp"), device, connection_rows)
    if temporal_status == "within_known_connection":
        bases.append("time_overlap")
    if not bases:
        return None
    attribution_status = "attributed" if any(basis in bases for basis in ("drive_letter", "time_overlap")) else "candidate"
    return {
        "serial": device.get("serial"),
        "device_identity": device.get("device_identity") or _external_storage_device_label(device),
        "volume_serial_number": device.get("observed_volume_serial_numbers") or device.get("volume_serial_number"),
        "volume_guid": device.get("observed_volume_guids") or device.get("volume_guid"),
        "drive_letter": device.get("observed_drive_letters") or device.get("drive_letter"),
        "match_basis": ", ".join(_ordered_unique(bases)),
        "attribution_status": attribution_status,
        "temporal_status": temporal_status,
        "identity_confidence_tier": device.get("identity_confidence_tier"),
    }


def _opened_removable_confidence(matches: list[dict[str, Any]], path: str) -> str:
    if any("time_overlap" in str(match.get("match_basis") or "") and "drive_letter" in str(match.get("match_basis") or "") for match in matches):
        return "high"
    if any(str(match.get("attribution_status") or "") == "attributed" for match in matches):
        return "medium"
    if matches:
        return "low"
    if _looks_like_removable_path(path):
        return "review"
    return "low"


def _opened_removable_basis(matches: list[dict[str, Any]], path: str) -> str:
    if matches:
        return "; ".join(
            f"{match.get('attribution_status') or 'unknown'}:{match.get('match_basis') or ''}"
            for match in matches
        )
    drive = _path_drive_letter(path)
    return f"removable_style_drive_path:{drive}" if drive else ""


def _opened_removable_attribution_status(matches: list[dict[str, Any]]) -> str:
    if any(match.get("attribution_status") == "attributed" for match in matches):
        return "attributed"
    if matches:
        return "candidate"
    return "unattributed"


def _path_drive_letter(path: Any) -> str:
    match = re.search(r"(?<![A-Za-z])([A-Za-z]):[\\/]", str(path or ""))
    return f"{match.group(1).upper()}:" if match else ""


def _display_drive_path(path: Any) -> str:
    text = str(path or "")
    match = re.search(r"(?<![A-Za-z])([A-Za-z]):[\\/]+(.+)$", text)
    if not match:
        return text
    rest = re.sub(r"[\\/]+", r"\\", match.group(2)).strip("\\")
    return f"{match.group(1).upper()}:\\{rest}" if rest else f"{match.group(1).upper()}:\\"


def _drive_path_top_folder(path: Any) -> str:
    display = _display_drive_path(path)
    match = re.match(r"^[A-Za-z]:\\([^\\]+)", display)
    return match.group(1) if match else ""


def _opened_removable_groups(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    groups: dict[tuple[Any, ...], dict[str, Any]] = {}
    for row in rows:
        key = (
            row.get("computer_id"),
            row.get("drive_letter"),
            row.get("top_folder"),
            row.get("attribution_status"),
        )
        group = groups.setdefault(
            key,
            {
                "computer_id": row.get("computer_id"),
                "computer_label": row.get("computer_label"),
                "drive_letter": row.get("drive_letter"),
                "top_folder": row.get("top_folder"),
                "attribution_status": row.get("attribution_status"),
                "item_count": 0,
                "first_timestamp": row.get("timestamp"),
                "last_timestamp": row.get("timestamp"),
                "sources": set(),
                "confidence_values": set(),
                "examples": [],
            },
        )
        group["item_count"] += 1
        timestamp = str(row.get("timestamp") or "")
        if timestamp:
            if not group.get("first_timestamp") or timestamp < str(group.get("first_timestamp")):
                group["first_timestamp"] = timestamp
            if not group.get("last_timestamp") or timestamp > str(group.get("last_timestamp")):
                group["last_timestamp"] = timestamp
        if row.get("source"):
            group["sources"].add(str(row.get("source")))
        if row.get("confidence"):
            group["confidence_values"].add(str(row.get("confidence")))
        if len(group["examples"]) < 5:
            group["examples"].append(row.get("display_path") or row.get("path"))
    output = []
    for group in groups.values():
        item = dict(group)
        item["sources"] = ", ".join(sorted(item["sources"]))
        item["confidence_values"] = ", ".join(sorted(item["confidence_values"]))
        output.append(item)
    output.sort(key=lambda row: (row.get("last_timestamp") or "", row.get("item_count") or 0), reverse=True)
    return output


def _removable_device_temporal_status(timestamp: Any, device: dict[str, Any], connection_rows: list[dict[str, Any]]) -> str:
    event_time = _parse_report_timestamp(str(timestamp)) if timestamp else None
    if not event_time:
        return "no_event_timestamp"
    sessions = _removable_device_sessions(device, connection_rows)
    if not sessions:
        fallback = _removable_device_fallback_session(device)
        if fallback:
            sessions = [fallback]
        else:
            return "no_connection_window_available"
    if any(_timestamp_in_session(event_time, session) for session in sessions):
        return "within_known_connection"
    first_start = min(session["start"] for session in sessions if session.get("start"))
    last_end = max(session["end"] for session in sessions if session.get("end"))
    if event_time < first_start:
        return "before_first_known_connection"
    if event_time > last_end:
        return "after_last_known_connection"
    return "outside_known_connection"


def _removable_device_sessions(device: dict[str, Any], connection_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    serial = str(device.get("serial") or "")
    vsns = {
        _normalize_usb_serial(value)
        for value in _split_external_storage_values(device.get("observed_volume_serial_numbers") or device.get("volume_serial_number"))
        if _normalize_usb_serial(value)
    }
    drives = set(_split_external_storage_values(device.get("observed_drive_letters") or device.get("drive_letter")))
    computer_id = str(device.get("computer_id") or "")
    matched = []
    for row in connection_rows:
        if computer_id and str(row.get("computer_id") or "") and str(row.get("computer_id") or "") != computer_id:
            continue
        row_serial = str(row.get("serial") or "")
        row_vsn = _normalize_usb_serial(row.get("volume_serial_number"))
        row_drive = _normalize_external_storage_drive_letters(row.get("drive_letter"))
        if serial and row_serial and row_serial == serial:
            matched.append(row)
        elif vsns and row_vsn and row_vsn in vsns:
            matched.append(row)
        elif drives and row_drive and row_drive in drives:
            matched.append(row)
    return _usb_sessions_from_connection_rows(matched)


def _removable_device_fallback_session(device: dict[str, Any]) -> dict[str, Any] | None:
    start = _parse_report_timestamp(device.get("first_install_date_utc") or device.get("last_arrival_utc") or device.get("last_partition_event_utc"))
    end = _parse_report_timestamp(device.get("last_removal_utc") or device.get("last_arrival_utc") or device.get("last_partition_event_utc") or device.get("first_install_date_utc"))
    if not start or not end:
        return None
    if end < start:
        end = start
    return {"start": start, "end": end, "serial": str(device.get("serial") or ""), "volume_serial_number": _normalize_usb_serial(device.get("volume_serial_number"))}


def activity_summary_report(db: Database, case_id: str, *, user: str | None = None, limit: int = 25) -> dict[str, Any]:
    db.get_case(case_id)
    user_like = f"%{user}%" if user else None
    user_path_like = f"%/Users/{user}/%" if user else None
    return {
        "case_id": case_id,
        "user": user,
        "counts": {
            "accounts": _count(db, "sam_accounts", case_id, user_filter=("username", user_like)),
            "prefetch": _count(db, "prefetch_items", case_id),
            "shortcuts": _count(
                db,
                "shortcut_items",
                case_id,
                user_filter=("artifact_path", user_like),
            ),
            "copied_file_indicators": _count_timeline(db, case_id, "copied_file_indicator"),
            "recycle_items": _count(
                db,
                "recycle_items",
                case_id,
                user_filter=("original_path", user_like),
            ),
            "browser_history": _count(
                db,
                "firefox_history",
                case_id,
                user_filter=("profile_path", user_like),
            ),
            "evtx_logons": _count_evtx_logons(db, case_id, user_like),
            "registry_artifacts": _count(
                db,
                "registry_artifacts",
                case_id,
                user_filter=("user_profile", user_like),
            ),
            "registry_activity": _count_registry_activity(db, case_id, user_like),
            "amcache": _count(db, "amcache_entries", case_id),
            "shimcache": _count(db, "shimcache_entries", case_id),
            "shellbags": _count(
                db,
                "shellbag_entries",
                case_id,
                user_filter=("user_profile", user_like),
            ),
            "usb_devices": _count(db, "usb_devices", case_id),
        },
        "recent_execution": _recent_prefetch(db, case_id, limit=limit),
        "recent_file_activity": _recent_shortcuts(db, case_id, user_path_like or user_like, limit=limit),
        "recent_browser_history": _recent_browser(db, case_id, user_like, limit=limit),
        "recent_logons": _recent_logons(db, case_id, user_like, limit=limit),
        "recycle_items": _recent_recycle(db, case_id, user_like, limit=limit),
    }


def users_report(db: Database, case_id: str) -> dict[str, Any]:
    accounts = accounts_report(db, case_id)["accounts"]
    users = [
        account for account in accounts
        if account.get("account_category") == "local" or _safe_int(account.get("rid"), 0) >= 1000
    ]
    return {"case_id": case_id, "users": users, "total_users": len(users)}


def files_report(db: Database, case_id: str, *, user: str | None = None, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    rows: list[dict[str, Any]] = []
    mft_params: list[Any] = [case_id]
    mft_user_filter = ""
    if user:
        mft_user_filter = "AND (mft_entries.parent_path LIKE ? OR mft_entries.file_name LIKE ?)"
        mft_params.extend([f"%Users/{user}/%", f"%{user}%"])
    mft_params.append(limit)
    rows.extend(
        _query_report_rows(
            db,
            case_id,
            "mft_entries",
            f"""
            SELECT *, 'mft_entries' AS source_table
            FROM mft_entries
            WHERE mft_entries.case_id = ? {mft_user_filter}
            ORDER BY mft_entries.parent_path, mft_entries.file_name
            LIMIT ?
            """,
            mft_params,
        )
    )
    fs_params: list[Any] = [case_id]
    fs_user_filter = ""
    if user:
        fs_user_filter = "AND (filesystem_entries.parent_path LIKE ? OR filesystem_entries.file_name LIKE ?)"
        fs_params.extend([f"%Users/{user}/%", f"%{user}%"])
    fs_params.append(limit)
    rows.extend(
        _query_report_rows(
            db,
            case_id,
            "filesystem_entries",
            f"""
            SELECT *, 'filesystem_entries' AS source_table
            FROM filesystem_entries
            WHERE filesystem_entries.case_id = ? {fs_user_filter}
            ORDER BY filesystem_entries.parent_path, filesystem_entries.file_name
            LIMIT ?
            """,
            fs_params,
        )
    )
    rows = sorted(rows, key=lambda row: (str(row.get("parent_path") or ""), str(row.get("file_name") or "")))[:limit]
    _fill_computer_image_fields(db, case_id, rows)
    files = []
    for row in rows:
        item = dict(row)
        item["correlations"] = _correlations_for_mft_entry(db, row["id"]) if item.get("source_table") == "mft_entries" else []
        files.append(item)
    return {"case_id": case_id, "files": files, "total_returned": len(files)}


def file_names_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 100,
    contains: str | None = None,
    include_mft: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    groups: dict[str, dict[str, Any]] = {}
    rows: list[dict[str, Any]] = []

    def include_name(name: str | None) -> bool:
        if not name:
            return False
        if contains and contains.lower() not in name.lower():
            return False
        return True

    def add_signal(
        *,
        source: str,
        source_table: str,
        source_id: str,
        file_name: str | None,
        path: str | None = None,
        timestamp: str | None = None,
        user_profile: str | None = None,
        application: str | None = None,
        detail: dict[str, Any] | None = None,
    ) -> None:
        name = _coalesce_file_name(file_name, path)
        if not include_name(name):
            return
        key = name.lower()
        group = groups.setdefault(
            key,
            {
                "file_name": name,
                "evidence_count": 0,
                "sources": set(),
                "source_tables": set(),
                "paths": set(),
                "users": set(),
                "applications": set(),
                "first_seen_utc": None,
                "last_seen_utc": None,
            },
        )
        group["evidence_count"] += 1
        group["sources"].add(source)
        group["source_tables"].add(source_table)
        if path:
            group["paths"].add(path)
            normalized_path = _normalize_artifact_path(path)
            if normalized_path:
                group.setdefault("normalized_paths", set()).add(normalized_path)
        if user_profile:
            group["users"].add(user_profile)
        if application:
            group["applications"].add(application)
        _merge_time_bounds(group, timestamp)
        evidence_tags = _file_evidence_tags(source=source, source_table=source_table, path=path, detail=detail)
        rows.append(
            {
                "file_name": name,
                "source": source,
                "source_table": source_table,
                "source_id": source_id,
                "path": path,
                "normalized_path": _normalize_artifact_path(path),
                "timestamp": timestamp,
                "user_profile": user_profile,
                "application": application,
                "evidence_tags": evidence_tags,
                "details": detail or {},
            }
        )

    for row in _query_report_rows(
        db,
        case_id,
        "shortcut_items",
        """
        SELECT id, artifact_type, artifact_name, artifact_path, file_name,
               file_location, target_created, target_modified, target_accessed
        FROM shortcut_items
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        add_signal(
            source=row["artifact_type"] or "shortcut",
            source_table="shortcut_items",
            source_id=row["id"],
            file_name=row["file_name"],
            path=row["file_location"] or row["artifact_path"],
            timestamp=row["target_accessed"] or row["target_modified"] or row["target_created"],
            user_profile=_user_from_path(row["artifact_path"] or row["file_location"]),
            detail={"artifact_name": row["artifact_name"], "artifact_path": row["artifact_path"]},
        )

    for row in _query_report_rows(
        db,
        case_id,
        "copied_file_indicators",
        """
        SELECT id, source_artifact_type, source_artifact_name, file_name,
               file_location, created_timestamp_utc, modified_timestamp_utc
        FROM copied_file_indicators
        WHERE case_id = ?
          AND source_artifact_type NOT IN ('mft_si', 'mft_fn')
        """,
        (case_id,),
    ):
        add_signal(
            source=f"copied:{row['source_artifact_type']}",
            source_table="copied_file_indicators",
            source_id=row["id"],
            file_name=row["file_name"],
            path=row["file_location"],
            timestamp=row["created_timestamp_utc"],
            user_profile=_user_from_path(row["file_location"]),
            detail={
                "source_artifact_name": row["source_artifact_name"],
                "modified_timestamp_utc": row["modified_timestamp_utc"],
            },
        )

    for row in _query_report_rows(
        db,
        case_id,
        "windows_activities",
        """
        SELECT id, user_profile, app_display_name, activity_type, file_name,
               display_text, content_uri, activation_uri, fallback_uri,
               start_time_utc, end_time_utc
        FROM windows_activities
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        path = row["content_uri"] or row["activation_uri"] or row["fallback_uri"]
        add_signal(
            source="windows_activities",
            source_table="windows_activities",
            source_id=row["id"],
            file_name=row["file_name"] or row["display_text"],
            path=path,
            timestamp=row["start_time_utc"] or row["end_time_utc"],
            user_profile=row["user_profile"],
            application=row["app_display_name"],
            detail={"activity_type": row["activity_type"], "display_text": row["display_text"]},
        )

    for row in _query_report_rows(
        db,
        case_id,
        "browser_downloads",
        """
        SELECT id, browser, profile_path, target_path, tab_url, site_url,
               start_time_utc, end_time_utc
        FROM browser_downloads
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        add_signal(
            source=f"browser_download:{row['browser'] or 'browser'}",
            source_table="browser_downloads",
            source_id=row["id"],
            file_name=None,
            path=row["target_path"],
            timestamp=row["end_time_utc"] or row["start_time_utc"],
            user_profile=_user_from_path(row["profile_path"] or row["target_path"]),
            application=row["browser"],
            detail={"tab_url": row["tab_url"], "site_url": row["site_url"]},
        )

    for row in _query_report_rows(
        db,
        case_id,
        "webcache_file_accesses",
        """
        SELECT id, user_name, application, file_name, normalized_path, url,
               accessed_utc, modified_utc, created_utc
        FROM webcache_file_accesses
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        add_signal(
            source="webcache_file",
            source_table="webcache_file_accesses",
            source_id=row["id"],
            file_name=row["file_name"],
            path=row["normalized_path"] or row["url"],
            timestamp=row["accessed_utc"] or row["modified_utc"] or row["created_utc"],
            user_profile=row["user_name"] or _user_from_path(row["normalized_path"]),
            application=row["application"],
            detail={"url": row["url"]},
        )

    for row in _query_report_rows(
        db,
        case_id,
        "windows_search_files",
        """
        SELECT id, item_path, item_url, file_name, gather_time, date_created,
               date_modified, date_accessed, owner
        FROM windows_search_files
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        add_signal(
            source="windows_search_file",
            source_table="windows_search_files",
            source_id=row["id"],
            file_name=row["file_name"],
            path=row["item_path"] or row["item_url"],
            timestamp=row["date_accessed"] or row["date_modified"] or row["gather_time"] or row["date_created"],
            user_profile=row["owner"] or _user_from_path(row["item_path"]),
        )

    for row in _query_report_rows(
        db,
        case_id,
        "thumbcache_search_correlations",
        """
        SELECT id, cache_id, thumbcache_user, thumbcache_name, search_file_name,
               search_item_path, search_date_created, search_date_modified,
               search_date_accessed, search_date_imported, correlation_basis,
               confidence
        FROM thumbcache_search_correlations
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        add_signal(
            source="thumbcache_search",
            source_table="thumbcache_search_correlations",
            source_id=row["id"],
            file_name=row["search_file_name"],
            path=row["search_item_path"],
            timestamp=(
                row["search_date_accessed"]
                or row["search_date_modified"]
                or row["search_date_created"]
                or row["search_date_imported"]
            ),
            user_profile=row["thumbcache_user"] or _user_from_path(row["search_item_path"]),
            detail={
                "cache_id": row["cache_id"],
                "thumbcache_name": row["thumbcache_name"],
                "correlation_basis": row["correlation_basis"],
                "confidence": row["confidence"],
            },
        )

    for row in _query_report_rows(
        db,
        case_id,
        "windows_search_indexed_content",
        """
        SELECT id, item_path, item_name, item_type, content_field,
               content_length, timestamp, gather_time
        FROM windows_search_indexed_content
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        add_signal(
            source="windows_search_content",
            source_table="windows_search_indexed_content",
            source_id=row["id"],
            file_name=row["item_name"],
            path=row["item_path"],
            timestamp=row["timestamp"] or row["gather_time"],
            user_profile=_user_from_path(row["item_path"]),
            detail={"item_type": row["item_type"], "content_field": row["content_field"], "content_length": row["content_length"]},
        )

    for row in _query_report_rows(
        db,
        case_id,
        "file_internal_metadata",
        """
        SELECT id, original_path, file_name, extension, property_name,
               property_value, mft_created, mft_modified, mft_accessed
        FROM file_internal_metadata
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        add_signal(
            source="file_metadata",
            source_table="file_internal_metadata",
            source_id=row["id"],
            file_name=row["file_name"],
            path=row["original_path"],
            timestamp=row["mft_accessed"] or row["mft_modified"] or row["mft_created"],
            user_profile=_user_from_path(row["original_path"]),
            detail={"property_name": row["property_name"], "extension": row["extension"]},
        )

    for row in _query_report_rows(
        db,
        case_id,
        "usn_journal_entries",
        """
        SELECT id, file_name, full_path, reason, update_timestamp
        FROM usn_journal_entries
        WHERE case_id = ?
        """,
        (case_id,),
    ):
        add_signal(
            source="usn_journal",
            source_table="usn_journal_entries",
            source_id=row["id"],
            file_name=row["file_name"],
            path=row["full_path"],
            timestamp=row["update_timestamp"],
            user_profile=_user_from_path(row["full_path"]),
            detail={"reason": row["reason"]},
        )

    if include_mft:
        for row in _query_report_rows(
            db,
            case_id,
            "mft_entries",
            """
            SELECT id, file_name, parent_path, created_si, modified_si,
                   accessed_si, in_use, is_directory
            FROM mft_entries
            WHERE case_id = ?
            """,
            (case_id,),
        ):
            path = _join_path(row["parent_path"], row["file_name"])
            add_signal(
                source="mft",
                source_table="mft_entries",
                source_id=row["id"],
                file_name=row["file_name"],
                path=path,
                timestamp=row["accessed_si"] or row["modified_si"] or row["created_si"],
                user_profile=_user_from_path(path),
                detail={"in_use": row["in_use"], "is_directory": row["is_directory"]},
            )

    file_names = []
    for group in groups.values():
        item = dict(group)
        item["sources"] = sorted(item["sources"])
        item["source_tables"] = sorted(item["source_tables"])
        item["paths"] = sorted(item["paths"])[:10]
        item["normalized_paths"] = sorted(item.get("normalized_paths", set()))[:10]
        item["users"] = sorted(item["users"])
        item["applications"] = sorted(item["applications"])
        item["source_count"] = len(item["sources"])
        item["path_count"] = len(group["paths"])
        item["evidence_tags"] = _group_evidence_tags(item)
        file_names.append(item)
    file_names.sort(key=lambda item: (-item["source_count"], -item["evidence_count"], item["file_name"].lower()))
    visible_names = {item["file_name"].lower() for item in file_names[:limit]}
    evidence_rows = [
        row for row in rows
        if row["file_name"].lower() in visible_names
    ]
    evidence_rows.sort(key=lambda row: (row["file_name"].lower(), row.get("timestamp") or "", row["source"]))
    return {
        "case_id": case_id,
        "filters": {"contains": contains, "include_mft": include_mft},
        "file_names": file_names[:limit],
        "evidence": evidence_rows[: limit * 10],
        "total_file_names": len(file_names),
        "total_evidence_rows": len(rows),
        "total_returned": min(len(file_names), limit),
    }


def file_name_drilldown_report(
    db: Database,
    case_id: str,
    *,
    name: str,
    include_mft: bool = True,
    limit: int = 500,
) -> dict[str, Any]:
    report = file_names_report(db, case_id, contains=name, include_mft=include_mft, limit=max(limit, 1000))
    exact = name.lower()
    evidence = [
        row for row in report["evidence"]
        if row["file_name"].lower() == exact or exact in row["file_name"].lower()
    ][:limit]
    evidence_by_source: dict[str, list[dict[str, Any]]] = {}
    for row in evidence:
        evidence_by_source.setdefault(row["source_table"], []).append(row)
    matching_names = [
        row for row in report["file_names"]
        if row["file_name"].lower() == exact or exact in row["file_name"].lower()
    ]
    return {
        "case_id": case_id,
        "name": name,
        "include_mft": include_mft,
        "matching_file_names": matching_names,
        "evidence_by_source": evidence_by_source,
        "evidence": evidence,
        "total_matching_file_names": len(matching_names),
        "total_evidence_rows": len(evidence),
    }


def file_history_report(
    db: Database,
    case_id: str,
    *,
    name: str | None = None,
    path: str | None = None,
    mft_entry: str | None = None,
    include_artifacts: bool = True,
    include_vsc: bool = False,
    limit: int = 500,
) -> dict[str, Any]:
    db.get_case(case_id)
    if not any((name, path, mft_entry)):
        raise ValueError("file_history_report requires name, path, or mft_entry")

    derived_name = name or _basename_from_path(path)
    duplicate_condition = (
        _artifact_duplicate_condition("filesystem_review")
        if db.analytics_mode == "sqlite"
        else "1=1"
    )
    filters = ["filesystem_review.case_id = ?", duplicate_condition]
    params: list[Any] = [case_id]
    if mft_entry:
        filters.append("filesystem_review.mft_entry_number = ?")
        params.append(mft_entry)
    if path:
        filters.append("filesystem_review.file_path LIKE ?")
        params.append(f"%{path}%")
    elif name:
        filters.append("(filesystem_review.file_name LIKE ? OR filesystem_review.file_path LIKE ?)")
        params.extend([f"%{name}%", f"%{name}%"])
    where = " AND ".join(filters)
    fs_rows = _query_report_rows(
        db,
        case_id,
        "filesystem_review",
        f"""
        SELECT filesystem_review.*
        FROM filesystem_review
        WHERE {where}
        ORDER BY COALESCE(filesystem_review.event_time, '') ASC,
                 filesystem_review.source_table,
                 filesystem_review.source_row_number
        LIMIT ?
        """,
        [*params, limit],
    )
    _fill_computer_image_fields(db, case_id, fs_rows)
    source_counts_by_id = _source_counts(db, "filesystem_review")
    for row in fs_rows:
        row["source_count"] = source_counts_by_id.get(str(row.get("id")), 0)
    if not fs_rows:
        fs_rows = _duckdb_file_history_rows(
            db,
            case_id,
            name=name,
            path=path,
            mft_entry=mft_entry,
            limit=limit,
        )

    events: list[dict[str, Any]] = []
    for row in fs_rows:
        item = dict(row)
        details = _json_details(item.pop("details_json", None))
        events.append(
            {
                "timestamp": item["event_time"],
                "source": _history_source_label(item["source_table"]),
                "source_table": item["source_table"],
                "source_id": item["source_id"],
                "event_type": item["event_type"],
                "status": item["status"],
                "operation": item["operation"],
                "reason": item["reason"],
                "file_name": item["file_name"],
                "path": item["file_path"],
                "display_path": _display_evidence_path(item["file_path"]),
                "normalized_path": _normalize_artifact_path(item["file_path"]),
                "parent_path": item["parent_path"],
                "mft_entry_number": item["mft_entry_number"],
                "mft_sequence_number": item["mft_sequence_number"],
                "computer_label": item["computer_label"],
                "details": details,
            }
        )

    artifact_events: list[dict[str, Any]] = (
        _direct_file_history_artifact_events(
            db,
            case_id,
            name=derived_name,
            path=path,
            limit=limit,
        )
        if include_artifacts
        else []
    )
    events.extend(artifact_events)
    if include_artifacts and derived_name:
        seen_artifact_events: set[tuple[str, str, str, str, str]] = set()
        drilldown = file_name_drilldown_report(
            db,
            case_id,
            name=derived_name,
            include_mft=False,
            limit=limit,
        )
        for row in drilldown["evidence"]:
            if row.get("source_table") in {
                "mft_entries",
                "usn_journal_entries",
                "filesystem_review",
                "shortcut_items",
            }:
                continue
            row_path = row.get("path") or ""
            if path and path.lower() not in row_path.lower():
                continue
            reason = ",".join(row.get("evidence_tags") or [])
            artifact_key = (
                str(row.get("timestamp") or ""),
                str(row.get("source_table") or ""),
                str(row.get("file_name") or "").casefold(),
                _normalize_path_for_like(row_path).casefold(),
                reason,
            )
            if artifact_key in seen_artifact_events:
                continue
            seen_artifact_events.add(artifact_key)
            generic_event = {
                "timestamp": row.get("timestamp"),
                "source": row.get("source"),
                "source_table": row.get("source_table"),
                "source_id": row.get("source_id"),
                "event_type": "artifact_reference",
                "status": None,
                "operation": None,
                "reason": reason,
                "file_name": row.get("file_name"),
                "path": row_path,
                "display_path": _display_evidence_path(row_path),
                "normalized_path": _normalize_artifact_path(row_path),
                "parent_path": None,
                "mft_entry_number": None,
                "mft_sequence_number": None,
                "computer_label": None,
                "details": row.get("details") or {},
            }
            artifact_events.append(generic_event)
            events.append(generic_event)

    events.sort(
        key=lambda item: (
            _timestamp_sort_key(item.get("timestamp")),
            item.get("source") or "",
            item.get("path") or "",
        )
    )
    if len(events) > limit:
        events = events[:limit]

    vsc_events = (
        _vsc_file_history_events(
            db,
            case_id,
            name=derived_name,
            path=path,
            mft_entry=mft_entry,
            limit=limit,
        )
        if include_vsc
        else []
    )

    source_counts: dict[str, int] = {}
    event_type_counts: dict[str, int] = {}
    for event in events:
        source_counts[event["source"]] = source_counts.get(event["source"], 0) + 1
        event_type_counts[event["event_type"]] = event_type_counts.get(event["event_type"], 0) + 1
    vsc_source_counts: dict[str, int] = {}
    vsc_event_type_counts: dict[str, int] = {}
    for event in vsc_events:
        vsc_source_counts[event["source"]] = vsc_source_counts.get(event["source"], 0) + 1
        vsc_event_type_counts[event["event_type"]] = vsc_event_type_counts.get(event["event_type"], 0) + 1

    return {
        "case_id": case_id,
        "filters": {
            "name": name,
            "path": path,
            "mft_entry": mft_entry,
            "include_artifacts": include_artifacts,
            "include_vsc": include_vsc,
        },
        "summary": {
            "source_counts": source_counts,
            "event_type_counts": event_type_counts,
            "vsc_source_counts": vsc_source_counts,
            "vsc_event_type_counts": vsc_event_type_counts,
            "filesystem_event_count": len(fs_rows),
            "artifact_event_count": len(artifact_events),
            "vsc_event_count": len(vsc_events),
        },
        "events": events,
        "vsc_events": vsc_events,
        "total_returned": len(events),
        "total_vsc_returned": len(vsc_events),
    }


def _vsc_file_history_events(
    db: Database,
    case_id: str,
    *,
    name: str | None,
    path: str | None,
    mft_entry: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    case_root = db.get_case(case_id).root
    main_db_path = case_root / "analytics" / "events.duckdb"
    sidecar_path = db.get_case(case_id).root / "vsc-work" / "parsed" / "vsc.duckdb"
    if not main_db_path.exists() and not sidecar_path.exists():
        return []
    events: list[dict[str, Any]] = []
    terms = _file_history_vsc_like_terms(path or name)
    if main_db_path.exists():
        main_conn = db.analytics._connect(case_id) if db.analytics is not None else duckdb.connect(str(main_db_path), read_only=True)
        try:
            events.extend(_vsc_mft_file_history_events(main_conn, case_id, terms=terms, mft_entry=mft_entry, limit=limit))
            events.extend(_vsc_usn_file_history_events(main_conn, case_id, terms=terms, mft_entry=mft_entry, limit=limit))
        finally:
            if db.analytics is None:
                main_conn.close()
    if sidecar_path.exists():
        conn = duckdb.connect(str(sidecar_path), read_only=True)
        try:
            events.extend(_vsc_recycle_file_history_events(conn, case_id, terms=terms, limit=limit))
            events.extend(_vsc_shortcut_file_history_events(conn, case_id, terms=terms, limit=limit))
            events.extend(_vsc_registry_file_history_events(conn, case_id, terms=terms, limit=limit))
        finally:
            conn.close()
    events.sort(
        key=lambda item: (
            _timestamp_sort_key(item.get("timestamp")),
            item.get("snapshot_id") or "",
            item.get("source") or "",
            item.get("path") or "",
        )
    )
    return events[:limit]


def _file_history_vsc_like_terms(target: str | None) -> list[str]:
    if not target:
        return []
    text = str(target).strip()
    basename = _basename_from_path(text) or text
    candidates = {
        text,
        text.replace("\\", "/"),
        text.replace("/", "\\"),
        basename,
    }
    return [candidate.casefold() for candidate in candidates if candidate]


def _vsc_table_exists(conn: duckdb.DuckDBPyConnection, table: str) -> bool:
    if not _safe_identifier(table):
        return False
    return _duckdb_table_exists(conn, table)


def _vsc_match_clause(columns: list[str], terms: list[str]) -> tuple[str, list[Any]]:
    if not terms:
        return "1=1", []
    clauses: list[str] = []
    params: list[Any] = []
    for column in columns:
        if not _safe_identifier(column):
            continue
        for term in terms:
            clauses.append(f"lower(COALESCE({column}, '')) LIKE ?")
            params.append(f"%{term}%")
    return "(" + " OR ".join(clauses) + ")", params


def _vsc_event(
    row: dict[str, Any],
    *,
    source: str,
    source_table: str,
    event_type: str,
    timestamp: Any,
    file_name: Any,
    path: Any,
    operation: Any = None,
    reason: Any = None,
    details: dict[str, Any] | None = None,
) -> dict[str, Any]:
    event_details = {
        "snapshot_id": row.get("snapshot_id"),
        "snapshot_created_utc": row.get("snapshot_created_utc"),
        "snapshot_index": row.get("snapshot_index"),
        "source_table": source_table,
    }
    if details:
        event_details.update(details)
    return {
        "timestamp": timestamp,
        "source": source,
        "source_table": source_table,
        "source_id": row.get("id"),
        "source_scope": "vsc",
        "event_type": event_type,
        "status": None,
        "operation": operation,
        "reason": reason,
        "file_name": file_name,
        "path": path,
        "display_path": _display_evidence_path(path),
        "normalized_path": _normalize_artifact_path(path),
        "parent_path": row.get("parent_path"),
        "mft_entry_number": row.get("entry_number") or row.get("file_reference_number"),
        "mft_sequence_number": row.get("sequence_number") or row.get("file_reference_sequence_number"),
        "computer_label": None,
        "snapshot_id": row.get("snapshot_id"),
        "snapshot_created_utc": row.get("snapshot_created_utc"),
        "details": event_details,
    }


def _vsc_mft_file_history_events(
    conn: duckdb.DuckDBPyConnection,
    case_id: str,
    *,
    terms: list[str],
    mft_entry: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    if not _vsc_table_exists(conn, "vsc_mft_deltas"):
        return []
    filters = ["case_id = ?"]
    params: list[Any] = [case_id]
    if mft_entry:
        filters.append("entry_number = ?")
        params.append(mft_entry)
    match_clause, match_params = _vsc_match_clause(["normalized_path", "file_name", "path_key"], terms)
    filters.append(match_clause)
    params.extend(match_params)
    result = conn.execute(
        f"""
        SELECT snapshot_id, snapshot_index, snapshot_created_utc, id, entry_number, sequence_number,
               NULL AS parent_path, file_name, file_size, in_use, is_directory, normalized_path,
               created_si, modified_si, record_changed_si, accessed_si
        FROM vsc_mft_deltas
        WHERE {" AND ".join(filters)}
        ORDER BY snapshot_index, normalized_path
        LIMIT ?
        """,
        [*params, limit],
    )
    rows = [dict(zip([col[0] for col in result.description or []], row, strict=False)) for row in result.fetchall()]
    events: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for row in rows:
        for field, event_type, reason in (
            ("created_si", "vsc_mft_created", "VSC MFT created timestamp"),
            ("modified_si", "vsc_mft_modified", "VSC MFT modified timestamp"),
            ("record_changed_si", "vsc_mft_record_changed", "VSC MFT record changed timestamp"),
            ("accessed_si", "vsc_mft_accessed", "VSC MFT accessed timestamp"),
        ):
            timestamp = row.get(field)
            if not timestamp:
                continue
            key = (str(row.get("snapshot_id") or ""), str(row.get("normalized_path") or ""), event_type, str(timestamp))
            if key in seen:
                continue
            seen.add(key)
            events.append(
                _vsc_event(
                    row,
                    source="VSC MFT",
                    source_table="vsc_mft_deltas",
                    event_type=event_type,
                    timestamp=timestamp,
                    file_name=row.get("file_name"),
                    path=row.get("normalized_path"),
                    operation=field,
                    reason=reason,
                    details={"file_size": row.get("file_size"), "in_use": row.get("in_use"), "is_directory": row.get("is_directory")},
                )
            )
    return events


def _vsc_usn_file_history_events(
    conn: duckdb.DuckDBPyConnection,
    case_id: str,
    *,
    terms: list[str],
    mft_entry: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    if not _vsc_table_exists(conn, "vsc_usn_deltas"):
        return []
    filters = ["case_id = ?"]
    params: list[Any] = [case_id]
    if mft_entry:
        filters.append("file_reference_number = ?")
        params.append(mft_entry)
    match_clause, match_params = _vsc_match_clause(["normalized_path", "file_name", "path_key"], terms)
    filters.append(match_clause)
    params.extend(match_params)
    result = conn.execute(
        f"""
        SELECT snapshot_id, snapshot_index, snapshot_created_utc, id, NULL AS source_file,
               update_sequence_number, update_timestamp, file_name, file_reference_number,
               file_reference_sequence_number, reason, normalized_path, NULL AS full_path
        FROM vsc_usn_deltas
        WHERE {" AND ".join(filters)}
        ORDER BY update_timestamp, snapshot_index, update_sequence_number
        LIMIT ?
        """,
        [*params, limit],
    )
    names = [col[0] for col in result.description or []]
    events: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for row_values in result.fetchall():
        row = dict(zip(names, row_values, strict=False))
        key = (
            str(row.get("snapshot_id") or ""),
            str(row.get("update_sequence_number") or ""),
            str(row.get("normalized_path") or row.get("full_path") or ""),
            str(row.get("reason") or ""),
        )
        if key in seen:
            continue
        seen.add(key)
        events.append(
            _vsc_event(
                row,
                source="VSC USN",
                source_table="vsc_usn_deltas",
                event_type="vsc_usn_record",
                timestamp=row.get("update_timestamp"),
                file_name=row.get("file_name"),
                path=row.get("normalized_path") or row.get("full_path"),
                operation=row.get("reason"),
                reason=row.get("reason"),
                details={"update_sequence_number": row.get("update_sequence_number"), "source_file": row.get("source_file")},
            )
        )
    return events


def _vsc_recycle_file_history_events(
    conn: duckdb.DuckDBPyConnection,
    case_id: str,
    *,
    terms: list[str],
    limit: int,
) -> list[dict[str, Any]]:
    if not terms or not _vsc_table_exists(conn, "vsc_recycle_items"):
        return []
    match_clause, params = _vsc_match_clause(["original_path", "display_name", "source_vsc_path", "recycled_path"], terms)
    result = conn.execute(
        f"""
        SELECT snapshot_id, snapshot_index, snapshot_created_utc, record_type, source_vsc_path,
               display_name, original_path, deletion_time_utc, file_size, recycle_format
        FROM vsc_recycle_items
        WHERE case_id = ? AND {match_clause}
        ORDER BY deletion_time_utc, snapshot_index, original_path
        LIMIT ?
        """,
        [case_id, *params, limit],
    )
    names = [col[0] for col in result.description or []]
    events: list[dict[str, Any]] = []
    for row_values in result.fetchall():
        row = dict(zip(names, row_values, strict=False))
        events.append(
            _vsc_event(
                row,
                source="VSC Recycle Bin",
                source_table="vsc_recycle_items",
                event_type="vsc_recycle_deleted",
                timestamp=row.get("deletion_time_utc"),
                file_name=row.get("display_name") or _basename_from_path(row.get("original_path")),
                path=row.get("original_path") or row.get("source_vsc_path"),
                operation="deleted_to_recycle_bin",
                reason=row.get("record_type"),
                details={"file_size": row.get("file_size"), "recycle_format": row.get("recycle_format")},
            )
        )
    return events


def _vsc_shortcut_file_history_events(
    conn: duckdb.DuckDBPyConnection,
    case_id: str,
    *,
    terms: list[str],
    limit: int,
) -> list[dict[str, Any]]:
    if not terms or not _vsc_table_exists(conn, "vsc_shortcut_items"):
        return []
    match_clause, params = _vsc_match_clause(["file_name", "file_location", "artifact_name", "artifact_path", "source_vsc_path"], terms)
    result = conn.execute(
        f"""
        SELECT snapshot_id, snapshot_index, snapshot_created_utc, artifact_type, artifact_name,
               artifact_path, source_vsc_path, file_name, file_location, target_created,
               target_modified, target_accessed, lnk_created, lnk_modified, lnk_accessed,
               command_line_arguments, working_directory
        FROM vsc_shortcut_items
        WHERE case_id = ? AND {match_clause}
        ORDER BY snapshot_index, artifact_type, artifact_path
        LIMIT ?
        """,
        [case_id, *params, limit],
    )
    names = [col[0] for col in result.description or []]
    events: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for row_values in result.fetchall():
        row = dict(zip(names, row_values, strict=False))
        for field, event_type, reason in (
            ("target_created", "vsc_shortcut_target_created", "VSC shortcut target created timestamp"),
            ("target_modified", "vsc_shortcut_target_modified", "VSC shortcut target modified timestamp"),
            ("target_accessed", "vsc_shortcut_target_accessed", "VSC shortcut target accessed timestamp"),
            ("lnk_created", "vsc_shortcut_created", "VSC shortcut file created timestamp"),
            ("lnk_modified", "vsc_shortcut_modified", "VSC shortcut file modified timestamp"),
            ("lnk_accessed", "vsc_shortcut_accessed", "VSC shortcut file accessed timestamp"),
        ):
            timestamp = row.get(field)
            if not timestamp:
                continue
            key = (str(row.get("snapshot_id") or ""), str(row.get("artifact_path") or ""), event_type, str(timestamp))
            if key in seen:
                continue
            seen.add(key)
            events.append(
                _vsc_event(
                    row,
                    source=f"VSC {row.get('artifact_type') or 'shortcut'}",
                    source_table="vsc_shortcut_items",
                    event_type=event_type,
                    timestamp=timestamp,
                    file_name=row.get("file_name") or row.get("artifact_name"),
                    path=row.get("file_location") or row.get("artifact_path"),
                    operation=field,
                    reason=reason,
                    details={
                        "artifact_name": row.get("artifact_name"),
                        "artifact_path": row.get("artifact_path"),
                        "source_vsc_path": row.get("source_vsc_path"),
                        "command_line_arguments": row.get("command_line_arguments"),
                        "working_directory": row.get("working_directory"),
                    },
                )
            )
    return events


def _vsc_registry_file_history_events(
    conn: duckdb.DuckDBPyConnection,
    case_id: str,
    *,
    terms: list[str],
    limit: int,
) -> list[dict[str, Any]]:
    if not terms or not _vsc_table_exists(conn, "vsc_registry_artifacts"):
        return []
    match_clause, params = _vsc_match_clause(["display_name", "normalized_path", "value_data", "key_path"], terms)
    result = conn.execute(
        f"""
        SELECT snapshot_id, snapshot_index, snapshot_created_utc, source_path, hive_type,
               user_profile, user_sid, artifact, category, key_path, key_last_write_utc,
               event_time_utc, value_name, value_type, value_data, display_name,
               normalized_path, application_identity, resolved_application
        FROM vsc_registry_artifacts
        WHERE case_id = ?
          AND artifact IN ('recentdocs', 'office_recent_docs', 'common_dialog', 'wordwheel_query')
          AND {match_clause}
        ORDER BY COALESCE(event_time_utc, key_last_write_utc, ''), snapshot_index, artifact
        LIMIT ?
        """,
        [case_id, *params, limit],
    )
    names = [col[0] for col in result.description or []]
    events: list[dict[str, Any]] = []
    for row_values in result.fetchall():
        row = dict(zip(names, row_values, strict=False))
        path = row.get("normalized_path") or row.get("value_data") or row.get("display_name")
        events.append(
            _vsc_event(
                row,
                source="VSC registry",
                source_table="vsc_registry_artifacts",
                event_type=f"vsc_registry_{row.get('artifact') or 'file_reference'}",
                timestamp=row.get("event_time_utc") or row.get("key_last_write_utc"),
                file_name=row.get("display_name") or _basename_from_path(path),
                path=path,
                operation=row.get("artifact"),
                reason=row.get("category"),
                details={
                    "artifact": row.get("artifact"),
                    "key_path": row.get("key_path"),
                    "value_name": row.get("value_name"),
                    "user_profile": row.get("user_profile"),
                    "source_path": row.get("source_path"),
                    "resolved_application": row.get("resolved_application") or row.get("application_identity"),
                },
            )
        )
    return events


def _direct_file_history_artifact_events(
    db: Database,
    case_id: str,
    *,
    name: str | None,
    path: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    events: list[dict[str, Any]] = []
    events.extend(_shortcut_file_history_events(db, case_id, name=name, path=path, limit=limit))
    events.extend(_prefetch_file_history_events(db, case_id, name=name, path=path, limit=limit))
    events.extend(_office_backstage_file_history_events(db, case_id, name=name, path=path, limit=limit))
    events.extend(_cloud_file_history_events(db, case_id, name=name, path=path, limit=limit))
    events.extend(_email_attachment_file_history_events(db, case_id, name=name, path=path, limit=limit))
    events.extend(_webcache_file_history_events(db, case_id, name=name, path=path, limit=limit))
    return events


def _shortcut_file_history_events(
    db: Database,
    case_id: str,
    *,
    name: str | None,
    path: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    filters = ["case_id = ?"]
    params: list[Any] = [case_id]
    target = path or name
    if target:
        filters.append(
            "(file_name LIKE ? OR file_location LIKE ? OR artifact_name LIKE ? OR artifact_path LIKE ?)"
        )
        params.extend([f"%{target}%", f"%{target}%", f"%{target}%", f"%{target}%"])
    rows = _query_report_rows(
        db,
        case_id,
        "shortcut_items",
        f"""
        SELECT id, artifact_type, artifact_name, artifact_path, file_name, file_location,
               target_created, target_modified, target_accessed,
               lnk_created, lnk_modified, lnk_accessed
        FROM shortcut_items
        WHERE {" AND ".join(filters)}
        ORDER BY artifact_type, artifact_path, row_number
        LIMIT ?
        """,
        [*params, limit],
    )
    events: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str, str]] = set()
    for row in rows:
        for field, event_type, reason in (
            ("target_created", "target_created", "shortcut target created timestamp"),
            ("target_modified", "target_modified", "shortcut target modified timestamp"),
            ("target_accessed", "target_accessed", "shortcut target accessed timestamp"),
            ("lnk_created", "shortcut_created", "shortcut file created timestamp"),
            ("lnk_modified", "shortcut_modified", "shortcut file modified timestamp"),
            ("lnk_accessed", "shortcut_accessed", "shortcut file accessed timestamp"),
        ):
            timestamp = row.get(field)
            if not timestamp:
                continue
            key = (
                str(row.get("artifact_type") or "shortcut"),
                str(row.get("artifact_name") or ""),
                str(row.get("file_name") or ""),
                str(row.get("file_location") or ""),
                event_type,
            )
            if key in seen:
                continue
            seen.add(key)
            events.append(
                {
                    "timestamp": timestamp,
                    "source": row.get("artifact_type") or "shortcut",
                    "source_table": "shortcut_items",
                    "source_id": row.get("id"),
                    "event_type": event_type,
                    "status": None,
                    "operation": field,
                    "reason": reason,
                    "file_name": row.get("file_name"),
                    "path": row.get("file_location") or row.get("artifact_path"),
                    "display_path": _display_evidence_path(row.get("file_location") or row.get("artifact_path")),
                    "normalized_path": _normalize_artifact_path(row.get("file_location") or row.get("artifact_path")),
                    "parent_path": None,
                    "mft_entry_number": None,
                    "mft_sequence_number": None,
                    "computer_label": None,
                    "details": {
                        "artifact_name": row.get("artifact_name"),
                        "artifact_path": row.get("artifact_path"),
                        "source_table": "shortcut_items",
                    },
                }
            )
    return events


def _prefetch_file_history_events(
    db: Database,
    case_id: str,
    *,
    name: str | None,
    path: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    target = path or name
    if not target:
        return []
    target_name = _basename_from_path(target) or target
    target_terms = {
        str(target).replace("/", "\\").casefold(),
        str(target).replace("\\", "/").casefold(),
        str(target_name).casefold(),
    }
    like_terms = [term for term in target_terms if term]
    if not like_terms:
        return []
    columns = _report_table_columns(db, case_id, "prefetch_items")
    if "referenced_strings" not in columns:
        return []
    last_run_times_expr = "last_run_times_utc" if "last_run_times_utc" in columns else "NULL AS last_run_times_utc"
    filters = ["case_id = ?", "referenced_strings IS NOT NULL", "(" + " OR ".join("lower(referenced_strings) LIKE ?" for _ in like_terms) + ")"]
    params: list[Any] = [case_id, *(f"%{term}%" for term in like_terms)]
    rows = _query_report_rows(
        db,
        case_id,
        "prefetch_items",
        f"""
        SELECT id, computer_id, image_id, tool_name, source_csv, row_number,
               prefetch_name, executable_name, artifact_path, original_path,
               prefetch_hash, run_count, last_run_time_utc, {last_run_times_expr},
               referenced_strings
        FROM prefetch_items
        WHERE {" AND ".join(filters)}
        ORDER BY COALESCE(last_run_time_utc, '') ASC, executable_name, prefetch_name
        LIMIT ?
        """,
        [*params, limit],
    )
    events: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    for row in rows:
        references = [
            str(value)
            for value in _coerce_list(row.get("referenced_strings"))
            if any(term in str(value).casefold() for term in target_terms)
        ]
        if not references:
            references = [str(row.get("referenced_strings") or "")]
        timestamps = _coerce_list(row.get("last_run_times_utc"))
        if not timestamps and row.get("last_run_time_utc"):
            timestamps = [row.get("last_run_time_utc")]
        if not timestamps:
            timestamps = [None]
        for reference in references:
            for timestamp in timestamps:
                key = (str(row.get("id") or ""), str(timestamp or ""), reference)
                if key in seen:
                    continue
                seen.add(key)
                events.append(
                    {
                        "timestamp": timestamp,
                        "source": "Prefetch",
                        "source_table": "prefetch_items",
                        "source_id": row.get("id"),
                        "event_type": "prefetch_file_reference",
                        "status": None,
                        "operation": "prefetch_referenced_string",
                        "reason": "file path/name appears in Prefetch referenced strings; indicates file use context during executable runs, not direct file execution",
                        "file_name": target_name,
                        "path": reference,
                        "display_path": _display_evidence_path(reference),
                        "normalized_path": _normalize_artifact_path(reference),
                        "parent_path": None,
                        "mft_entry_number": None,
                        "mft_sequence_number": None,
                        "computer_label": None,
                        "details": {
                            "executable_name": row.get("executable_name"),
                            "prefetch_name": row.get("prefetch_name"),
                            "prefetch_hash": row.get("prefetch_hash"),
                            "run_count": row.get("run_count"),
                            "prefetch_artifact_path": row.get("artifact_path") or row.get("original_path"),
                            "source_file": row.get("source_csv"),
                            "row_number": row.get("row_number"),
                        },
                    }
                )
    return events


def _office_backstage_file_history_events(
    db: Database,
    case_id: str,
    *,
    name: str | None,
    path: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    if not _duckdb_table_available(db, case_id, "office_backstage_items"):
        return []
    target = path or name
    filters = ["case_id = ?"]
    params: list[Any] = [case_id]
    if target:
        filters.append("(name LIKE ? OR value LIKE ? OR path LIKE ? OR source_path LIKE ? OR url LIKE ?)")
        params.extend([f"%{target}%", f"%{target}%", f"%{target}%", f"%{target}%", f"%{target}%"])
    rows = _query_report_rows(
        db,
        case_id,
        "office_backstage_items",
        f"""
        SELECT id, artifact_type, source_path, user_profile, application, name, value, path, url,
               timestamp_utc, details_json
        FROM office_backstage_items
        WHERE {" AND ".join(filters)}
        ORDER BY COALESCE(timestamp_utc, '') ASC, row_number
        LIMIT ?
        """,
        [*params, limit],
    )
    events: list[dict[str, Any]] = []
    for row in rows:
        details = _json_details(row.get("details_json"))
        details.update(
            {
                "artifact_name": row.get("name"),
                "source_artifact_name": row.get("artifact_type"),
                "source_path": row.get("source_path"),
                "application": row.get("application"),
                "user_profile": row.get("user_profile"),
            }
        )
        events.append(
            {
                "timestamp": row.get("timestamp_utc"),
                "source": "office_backstage",
                "source_table": "office_backstage_items",
                "source_id": row.get("id"),
                "event_type": row.get("artifact_type") or "office_backstage_reference",
                "status": None,
                "operation": row.get("artifact_type"),
                "reason": "office backstage recent-file reference",
                        "file_name": _coalesce_file_name(row.get("name"), row.get("path") or row.get("value")),
                        "path": row.get("path") or row.get("value") or row.get("url"),
                        "display_path": _display_evidence_path(row.get("path") or row.get("value") or row.get("url")),
                        "normalized_path": _normalize_artifact_path(row.get("path") or row.get("value") or row.get("url")),
                        "parent_path": None,
                "mft_entry_number": None,
                "mft_sequence_number": None,
                "computer_label": None,
                "details": details,
            }
        )
    return events


def _cloud_file_history_events(
    db: Database,
    case_id: str,
    *,
    name: str | None,
    path: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    target = path or name
    if not target:
        return []
    events: list[dict[str, Any]] = []
    for table, sql, source_name in (
        (
            "cloud_sync_artifacts",
            """
            SELECT id, provider AS source, file_name, COALESCE(local_path, cloud_path, server_path) AS path,
                   event_time_utc AS timestamp, COALESCE(sync_status, event_type, artifact_type) AS reason
            FROM cloud_sync_artifacts
            WHERE case_id = ? AND (file_name LIKE ? OR local_path LIKE ? OR cloud_path LIKE ? OR server_path LIKE ?)
            ORDER BY COALESCE(event_time_utc, '') ASC
            LIMIT ?
            """,
            "cloud_sync",
        ),
        (
            "onedrive_items",
            """
            SELECT id, account AS source, name AS file_name, path,
                   COALESCE(last_change_utc, disk_last_access_utc, disk_creation_utc, delete_time_utc) AS timestamp,
                   COALESCE(status, record_type, artifact_type) AS reason
            FROM onedrive_items
            WHERE case_id = ? AND (name LIKE ? OR path LIKE ? OR resource_id LIKE ? OR parent_resource_id LIKE ?)
            ORDER BY COALESCE(last_change_utc, disk_last_access_utc, disk_creation_utc, delete_time_utc, '') ASC
            LIMIT ?
            """,
            "onedrive",
        ),
        (
            "google_drive_cache_map",
            """
            SELECT id, account_id AS source, file_name,
                   COALESCE(virtual_path, windows_cache_path, cache_path) AS path,
                   NULL AS timestamp, mapping_method AS reason
            FROM google_drive_cache_map
            WHERE case_id = ? AND (file_name LIKE ? OR virtual_path LIKE ? OR windows_cache_path LIKE ? OR cache_path LIKE ?)
            LIMIT ?
            """,
            "google_drive",
        ),
    ):
        if not _duckdb_table_available(db, case_id, table):
            continue
        rows = _query_report_rows(
            db,
            case_id,
            table,
            sql,
            (case_id, f"%{target}%", f"%{target}%", f"%{target}%", f"%{target}%", limit),
        )
        for row in rows:
            events.append(
                {
                    "timestamp": row.get("timestamp"),
                    "source": row.get("source") or source_name,
                    "source_table": table,
                    "source_id": row.get("id"),
                    "event_type": "cloud_sync_reference",
                    "status": None,
                    "operation": None,
                    "reason": row.get("reason"),
                    "file_name": row.get("file_name"),
                    "path": row.get("path"),
                    "display_path": _display_evidence_path(row.get("path")),
                    "normalized_path": _normalize_artifact_path(row.get("path")),
                    "parent_path": None,
                    "mft_entry_number": None,
                    "mft_sequence_number": None,
                    "computer_label": None,
                    "details": {},
                }
            )
    return events


def _email_attachment_file_history_events(
    db: Database,
    case_id: str,
    *,
    name: str | None,
    path: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    target = path or name
    if not target:
        return []
