def file_history_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    filters = report.get("filters") if isinstance(report.get("filters"), dict) else {}
    events = report.get("events") if isinstance(report.get("events"), list) else []
    vsc_events = report.get("vsc_events") if isinstance(report.get("vsc_events"), list) else []
    lines = [
        "# File History Report",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Scope",
        "",
        f"- Name: `{filters.get('name') or ''}`",
        f"- Path: `{filters.get('path') or ''}`",
        f"- MFT entry: `{filters.get('mft_entry') or ''}`",
        f"- Artifact references included: `{filters.get('include_artifacts')}`",
        f"- VSC history included: `{filters.get('include_vsc')}`",
        "",
        "## Summary",
        "",
        f"- Filesystem events: `{summary.get('filesystem_event_count', 0)}`",
        f"- Artifact references: `{summary.get('artifact_event_count', 0)}`",
        f"- VSC history events: `{summary.get('vsc_event_count', 0)}`",
        f"- Total returned: `{report.get('total_returned', 0)}`",
        "",
    ]
    source_counts = summary.get("source_counts") if isinstance(summary.get("source_counts"), dict) else {}
    if source_counts:
        lines.extend(["### Sources", ""])
        for source, count in sorted(source_counts.items()):
            lines.append(f"- `{source}`: `{count}`")
        lines.append("")
    event_type_counts = summary.get("event_type_counts") if isinstance(summary.get("event_type_counts"), dict) else {}
    if event_type_counts:
        lines.extend(["### Event Types", ""])
        for event_type, count in sorted(event_type_counts.items()):
            lines.append(f"- `{event_type}`: `{count}`")
        lines.append("")
    vsc_source_counts = summary.get("vsc_source_counts") if isinstance(summary.get("vsc_source_counts"), dict) else {}
    if vsc_source_counts:
        lines.extend(["### VSC Sources", ""])
        for source, count in sorted(vsc_source_counts.items()):
            lines.append(f"- `{source}`: `{count}`")
        lines.append("")
    vsc_event_type_counts = summary.get("vsc_event_type_counts") if isinstance(summary.get("vsc_event_type_counts"), dict) else {}
    if vsc_event_type_counts:
        lines.extend(["### VSC Event Types", ""])
        for event_type, count in sorted(vsc_event_type_counts.items()):
            lines.append(f"- `{event_type}`: `{count}`")
        lines.append("")
    lines.extend(["## Timeline", ""])
    if not events:
        lines.append("- No matching file history events were found.")
    for event in events:
        if not isinstance(event, dict):
            continue
        lines.append(
            f"- `{event.get('timestamp') or ''}` `{event.get('source') or ''}` `{event.get('event_type') or ''}` "
            f"`{event.get('file_name') or ''}` path `{event.get('display_path') or _display_evidence_path(event.get('path'))}`"
        )
        details = event.get("details") if isinstance(event.get("details"), dict) else {}
        detail_bits = [
            f"{key}={value}"
            for key, value in {
                "status": event.get("status"),
                "operation": event.get("operation"),
                "reason": event.get("reason"),
                "mft_entry": event.get("mft_entry_number"),
                "computer": event.get("computer_label"),
                "artifact": details.get("artifact_name") or details.get("source_artifact_name"),
                "source_table": event.get("source_table"),
                "registry_key": details.get("key_path"),
                "email_subject": details.get("subject"),
                "webcache_table": details.get("source_webcache_table"),
            }.items()
            if value not in (None, "")
        ]
        if detail_bits:
            lines.append(f"  - " + "; ".join(detail_bits))
    if filters.get("include_vsc"):
        lines.extend(["", "## VSC Timeline", ""])
        if not vsc_events:
            lines.append("- No matching VSC file-history events were found.")
        for event in vsc_events:
            if not isinstance(event, dict):
                continue
            lines.append(
                f"- `{event.get('timestamp') or ''}` `{event.get('source') or ''}` `{event.get('event_type') or ''}` "
                f"`{event.get('file_name') or ''}` path `{event.get('display_path') or _display_evidence_path(event.get('path'))}`"
            )
            details = event.get("details") if isinstance(event.get("details"), dict) else {}
            detail_bits = [
                f"{key}={value}"
                for key, value in {
                    "snapshot": event.get("snapshot_id"),
                    "snapshot_created": event.get("snapshot_created_utc"),
                    "operation": event.get("operation"),
                    "reason": event.get("reason"),
                    "mft_entry": event.get("mft_entry_number"),
                    "artifact": details.get("artifact_name") or details.get("artifact"),
                    "source_table": event.get("source_table"),
                    "registry_key": details.get("key_path"),
                    "source_vsc_path": details.get("source_vsc_path"),
                }.items()
                if value not in (None, "")
            ]
            if detail_bits:
                lines.append(f"  - " + "; ".join(detail_bits))
    return "\n".join(lines).rstrip() + "\n"


def file_history_overview_markdown(report: dict[str, Any]) -> str:
    file_names = report.get("file_names") if isinstance(report.get("file_names"), list) else []
    evidence = report.get("evidence") if isinstance(report.get("evidence"), list) else []
    lines = [
        "# File History Overview",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Matching file names: `{report.get('total_file_names', 0)}`",
        f"- Evidence rows scanned: `{report.get('total_evidence_rows', 0)}`",
        f"- File names returned: `{report.get('total_returned', 0)}`",
        "",
        "## Top File Names",
        "",
    ]
    if not file_names:
        lines.append("- No file-history evidence was found.")
    for item in file_names:
        if not isinstance(item, dict):
            continue
        sources = ", ".join(f"`{source}`" for source in item.get("sources") or [])
        users = ", ".join(f"`{user}`" for user in item.get("users") or [])
        lines.append(
            f"- `{item.get('file_name') or ''}`: evidence `{item.get('evidence_count') or 0}`, "
            f"sources {sources or '`<none>`'}, users {users or '`<none>`'}"
        )
        for path in (item.get("paths") or [])[:3]:
            lines.append(f"  - path `{path}`")
    lines.extend(["", "## Evidence Sample", ""])
    if not evidence:
        lines.append("- No evidence rows available.")
    for row in evidence[:50]:
        if not isinstance(row, dict):
            continue
        tags = ",".join(row.get("evidence_tags") or [])
        lines.append(
            f"- `{row.get('timestamp') or ''}` `{row.get('source') or ''}` "
            f"`{row.get('file_name') or ''}` path `{row.get('path') or ''}` tags `{tags}`"
        )
    return "\n".join(lines).rstrip() + "\n"


def _duckdb_file_history_rows(
    db: Database,
    case_id: str,
    *,
    name: str | None,
    path: str | None,
    mft_entry: str | None,
    limit: int,
) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    computer_labels = _computer_labels(db, case_id)
    image_paths = _image_paths(db, case_id)

    mft_where = ["case_id = ?"]
    mft_params: list[Any] = [case_id]
    if mft_entry:
        mft_where.append("entry_number = ?")
        mft_params.append(mft_entry)
    if name:
        mft_where.append("(file_name LIKE ? OR parent_path LIKE ?)")
        mft_params.extend([f"%{name}%", f"%{name}%"])
    if path:
        mft_where.append("(file_name LIKE ? OR parent_path LIKE ?)")
        mft_params.extend([f"%{path}%", f"%{path}%"])
    mft_params.append(limit)
    if _duckdb_table_available(db, case_id, "mft_entries"):
        for row in _query_report_rows(
            db,
            case_id,
            "mft_entries",
            f"""
            SELECT id, computer_id, image_id, entry_number, sequence_number,
                   parent_path, file_name, in_use, is_directory,
                   created_si, modified_si, accessed_si
            FROM mft_entries
            WHERE {' AND '.join(mft_where)}
            ORDER BY COALESCE(accessed_si, modified_si, created_si, created_at)
            LIMIT ?
            """,
            mft_params,
        ):
            file_path = _join_path(row.get("parent_path"), row.get("file_name"))
            rows.append(
                {
                    "event_time": row.get("accessed_si") or row.get("modified_si") or row.get("created_si"),
                    "source_table": "mft_entries",
                    "source_id": row.get("id"),
                    "event_type": "mft_record",
                    "status": "in_use" if str(row.get("in_use")).lower() in {"true", "1", "yes"} else "not_in_use",
                    "operation": None,
                    "reason": None,
                    "file_name": row.get("file_name"),
                    "file_path": file_path,
                    "parent_path": row.get("parent_path"),
                    "mft_entry_number": row.get("entry_number"),
                    "mft_sequence_number": row.get("sequence_number"),
                    "computer_label": computer_labels.get(str(row.get("computer_id"))),
                    "image_path": image_paths.get(str(row.get("image_id"))),
                    "details_json": json.dumps({"is_directory": row.get("is_directory")}),
                }
            )

    usn_where = ["case_id = ?"]
    usn_params: list[Any] = [case_id]
    if mft_entry:
        usn_where.append("file_reference_number = ?")
        usn_params.append(mft_entry)
    if name:
        usn_where.append("(file_name LIKE ? OR full_path LIKE ?)")
        usn_params.extend([f"%{name}%", f"%{name}%"])
    if path:
        usn_where.append("(file_name LIKE ? OR full_path LIKE ?)")
        usn_params.extend([f"%{path}%", f"%{path}%"])
    usn_params.append(limit)
    if _duckdb_table_available(db, case_id, "usn_journal_entries"):
        for row in _query_report_rows(
            db,
            case_id,
            "usn_journal_entries",
            f"""
            SELECT id, computer_id, image_id, file_name, full_path, reason,
                   update_timestamp, file_reference_number, file_reference_sequence_number
            FROM usn_journal_entries
            WHERE {' AND '.join(usn_where)}
            ORDER BY update_timestamp
            LIMIT ?
            """,
            usn_params,
        ):
            rows.append(
                {
                    "event_time": row.get("update_timestamp"),
                    "source_table": "usn_journal_entries",
                    "source_id": row.get("id"),
                    "event_type": "usn_record",
                    "status": None,
                    "operation": None,
                    "reason": row.get("reason"),
                    "file_name": row.get("file_name"),
                    "file_path": row.get("full_path"),
                    "parent_path": None,
                    "mft_entry_number": row.get("file_reference_number"),
                    "mft_sequence_number": row.get("file_reference_sequence_number"),
                    "computer_label": computer_labels.get(str(row.get("computer_id"))),
                    "image_path": image_paths.get(str(row.get("image_id"))),
                    "details_json": "{}",
                }
            )
    rows.sort(key=lambda item: (_timestamp_sort_key(item.get("event_time")), item.get("source_table") or ""))
    return rows[:limit]


def correlations_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    rows = db.conn.execute(
        """
        SELECT file_correlations.*, computers.label AS computer_label, images.path AS image_path
        FROM file_correlations
        LEFT JOIN computers ON file_correlations.computer_id = computers.id
        LEFT JOIN images ON file_correlations.image_id = images.id
        WHERE file_correlations.case_id = ?
        ORDER BY file_correlations.confidence DESC, file_correlations.match_type, file_correlations.mft_path
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()
    return {
        "case_id": case_id,
        "correlations": [dict(row) for row in rows],
        "total_returned": len(rows),
    }


def copied_files_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    rows = db.conn.execute(
        """
        SELECT timeline_events.*, computers.label AS computer_label, images.path AS image_path
        FROM timeline_events
        LEFT JOIN computers ON timeline_events.computer_id = computers.id
        LEFT JOIN images ON timeline_events.image_id = images.id
        WHERE timeline_events.case_id = ? AND timeline_events.event_type = 'copied_file_indicator'
        ORDER BY timeline_events.timestamp_utc
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()
    copied = []
    for row in rows:
        item = dict(row)
        item["details"] = json.loads(item.pop("details_json"))
        copied.append(item)
    return {"case_id": case_id, "copied_files": copied, "total_returned": len(copied)}


def copied_file_indicators_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 100,
    source_artifact_type: str | None = None,
    user_only: bool = False,
    exclude_system: bool = True,
    include_mft_only: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    filters = ["copied_file_indicators.case_id = ?"]
    params: list[Any] = [case_id]
    if source_artifact_type:
        filters.append("copied_file_indicators.source_artifact_type = ?")
        params.append(source_artifact_type)
    elif not include_mft_only:
        filters.append("copied_file_indicators.source_artifact_type NOT IN ('mft_si', 'mft_fn')")
    if user_only:
        filters.append(
            """
            (
              copied_file_indicators.file_location LIKE '.\\Users\\%'
              OR copied_file_indicators.file_location LIKE 'Users/%'
              OR copied_file_indicators.file_location LIKE 'C:\\Users\\%'
            )
            """
        )
    if exclude_system:
        filters.append(
            """
            copied_file_indicators.file_location NOT LIKE '.\\Windows\\%'
            AND copied_file_indicators.file_location NOT LIKE '.\\Windows/%'
            AND copied_file_indicators.file_location NOT LIKE '.\\Program Files%'
            AND copied_file_indicators.file_location NOT LIKE '.\\ProgramData%'
            AND copied_file_indicators.file_location NOT LIKE 'C:\\Windows\\%'
            AND copied_file_indicators.file_location NOT LIKE 'C:\\Windows/%'
            AND copied_file_indicators.file_location NOT LIKE 'C:\\Program Files%'
            AND copied_file_indicators.file_location NOT LIKE '%/Windows/%'
            AND copied_file_indicators.file_location NOT LIKE '%/Program Files%'
            AND copied_file_indicators.file_location NOT LIKE '%/ProgramData/%'
            """
        )
    params.append(limit)
    rows = _query_report_rows(
        db,
        case_id,
        "copied_file_indicators",
        f"""
        SELECT copied_file_indicators.*
        FROM copied_file_indicators
        WHERE {' AND '.join(filters)}
        ORDER BY copied_file_indicators.created_timestamp_utc, copied_file_indicators.source_table
        LIMIT ?
        """,
        params,
    )
    items = []
    for row in rows:
        item = dict(row)
        item["details"] = json.loads(item.pop("details_json") or "{}")
        items.append(item)
    return {
        "case_id": case_id,
        "filters": {
            "source_artifact_type": source_artifact_type,
            "user_only": user_only,
            "exclude_system": exclude_system,
            "include_mft_only": include_mft_only,
        },
        "copied_file_indicators": items,
        "total_returned": len(items),
    }


def copied_file_groups_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 100,
    include_system: bool = False,
    include_mft_only: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    filters, params = _copied_indicator_filter_sql(
        case_id=case_id,
        exclude_system=not include_system,
        include_mft_only=include_mft_only,
    )
    params.append(limit)
    rows = _query_report_rows(
        db,
        case_id,
        "copied_file_indicators",
        f"""
        SELECT
          COALESCE(file_location, file_name, '') AS file_location,
          ANY_VALUE(file_name) AS file_name,
          created_timestamp_utc,
          modified_timestamp_utc,
          COUNT(*) AS indicator_count,
          COUNT(DISTINCT source_artifact_type) AS source_type_count,
          GROUP_CONCAT(DISTINCT source_artifact_type) AS source_artifact_types,
          GROUP_CONCAT(DISTINCT source_tool) AS source_tools,
          MIN(created_at) AS first_recorded_at,
          MAX(created_at) AS last_recorded_at
        FROM copied_file_indicators
        WHERE {' AND '.join(filters)}
        GROUP BY COALESCE(file_location, file_name, ''), created_timestamp_utc, modified_timestamp_utc
        ORDER BY indicator_count DESC, source_type_count DESC, created_timestamp_utc
        LIMIT ?
        """,
        params,
    )
    groups = [dict(row) for row in rows]
    for group in groups:
        group["source_artifact_types"] = _split_csv(group.get("source_artifact_types"))
        group["source_tools"] = _split_csv(group.get("source_tools"))
    total_group_rows = _query_report_rows(
        db,
        case_id,
        "copied_file_indicators",
        f"""
        SELECT COUNT(*) AS count
        FROM (
          SELECT 1
          FROM copied_file_indicators
          WHERE {' AND '.join(filters)}
          GROUP BY COALESCE(file_location, file_name, ''), created_timestamp_utc, modified_timestamp_utc
        )
        """,
        params[:-1],
    )
    total_groups = int(total_group_rows[0]["count"]) if total_group_rows else 0
    return {
        "case_id": case_id,
        "filters": {
            "include_system": include_system,
            "include_mft_only": include_mft_only,
        },
        "groups": groups,
        "total_groups": total_groups,
        "total_returned": len(groups),
    }


def copied_usb_files_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 250,
    grouped: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    rebuild_usb_file_correlations(db, case_id)
    if db.analytics_mode != "sqlite":
        return _copied_usb_files_report_duckdb(db, case_id, limit=limit, grouped=grouped)
    rows = [
        dict(row)
        for row in db.conn.execute(
            """
            SELECT
              copied_file_indicators.id AS copied_indicator_id,
              copied_file_indicators.source_tool,
              copied_file_indicators.source_table,
              copied_file_indicators.source_artifact_type,
              copied_file_indicators.source_artifact_name,
              copied_file_indicators.file_name,
              copied_file_indicators.file_location,
              copied_file_indicators.created_timestamp_utc,
              copied_file_indicators.modified_timestamp_utc,
              copied_file_indicators.details_json,
              usb_file_correlations.usb_serial,
              usb_file_correlations.usb_volume_serial_number,
              usb_file_correlations.usb_volume_name,
              usb_file_correlations.usb_drive_letter,
              usb_file_correlations.usb_vendor_id,
              usb_file_correlations.usb_product_id,
              usb_file_correlations.usb_vendor,
              usb_file_correlations.usb_product,
              usb_file_correlations.usb_friendly_name,
              usb_file_correlations.usb_first_install_date_utc,
              usb_file_correlations.usb_last_arrival_utc,
              usb_file_correlations.usb_last_removal_utc,
              usb_file_correlations.user_profile,
              usb_file_correlations.jumplist_item_number,
              usb_file_correlations.artifact_volume_serial_number,
              usb_file_correlations.artifact_volume_name,
              usb_file_correlations.artifact_volume_guid,
              usb_file_correlations.artifact_drive_letter,
              usb_file_correlations.volume_serial_match AS association_basis,
              computers.label AS computer_label,
              images.path AS image_path
            FROM copied_file_indicators
            JOIN usb_file_correlations
              ON usb_file_correlations.case_id = copied_file_indicators.case_id
             AND usb_file_correlations.image_id = copied_file_indicators.image_id
             AND usb_file_correlations.source_artifact_id = copied_file_indicators.source_row_id
            LEFT JOIN computers ON copied_file_indicators.computer_id = computers.id
            LEFT JOIN images ON copied_file_indicators.image_id = images.id
            WHERE copied_file_indicators.case_id = ?
              AND copied_file_indicators.source_artifact_type NOT IN ('mft_si', 'mft_fn')
            ORDER BY
              usb_file_correlations.usb_volume_serial_number,
              copied_file_indicators.created_timestamp_utc,
              copied_file_indicators.file_location
            LIMIT ?
            """,
            (case_id, limit),
        ).fetchall()
    ]
    for row in rows:
        row["details"] = json.loads(row.pop("details_json") or "{}")
        row["association_wording"] = _usb_association_wording(row["source_artifact_type"], row["association_basis"])
    groups = _group_copied_usb_rows(rows) if grouped else []
    device_counts: dict[tuple[str | None, str | None, str | None], dict[str, Any]] = {}
    for row in rows:
        key = (row["usb_serial"], row["usb_volume_serial_number"], row["usb_volume_name"])
        item = device_counts.setdefault(
            key,
            {
                "usb_serial": row["usb_serial"],
                "usb_volume_serial_number": row["usb_volume_serial_number"],
                "usb_volume_name": row["usb_volume_name"],
                "usb_drive_letter": row["usb_drive_letter"],
                "usb_product": row["usb_product"],
                "copied_file_indicators": 0,
            },
        )
        item["copied_file_indicators"] += 1
    return {
        "case_id": case_id,
        "notes": [
            "Rows are copied-file timestamp indicators that also correlate to USB storage evidence.",
            "LNK and Jump List rows are associated by volume serial where available.",
            "Shellbag folder rows are worded as consistent with a USB device when based on folder tree and/or connection-time overlap.",
        ],
        "devices": list(device_counts.values()),
        "items": rows,
        "groups": groups,
        "total_returned": len(groups) if grouped else len(rows),
    }


def _copied_usb_files_report_duckdb(db: Database, case_id: str, *, limit: int, grouped: bool) -> dict[str, Any]:
    correlations = _query_report_rows(
        db,
        case_id,
        "usb_file_correlations",
        """
        SELECT *
        FROM usb_file_correlations
        WHERE case_id = ?
        ORDER BY usb_volume_serial_number, target_created, file_location
        LIMIT ?
        """,
        (case_id, limit),
    )
    indicators = {
        row.get("source_row_id"): row
        for row in _query_report_rows(
            db,
            case_id,
            "copied_file_indicators",
            "SELECT * FROM copied_file_indicators WHERE case_id = ?",
            (case_id,),
        )
    }
    rows = []
    for corr in correlations:
        indicator = indicators.get(corr.get("source_artifact_id"), {})
        row = {
            **corr,
            "copied_indicator_id": indicator.get("id"),
            "source_tool": indicator.get("source_tool"),
            "source_table": indicator.get("source_table"),
            "source_artifact_type": corr.get("source_artifact_type") or indicator.get("source_artifact_type"),
            "source_artifact_name": corr.get("source_artifact_name") or indicator.get("source_artifact_name"),
            "file_name": corr.get("file_name") or indicator.get("file_name"),
            "file_location": corr.get("file_location") or indicator.get("file_location"),
            "created_timestamp_utc": indicator.get("created_timestamp_utc") or corr.get("target_created"),
            "modified_timestamp_utc": indicator.get("modified_timestamp_utc") or corr.get("target_modified"),
            "details": _json_details(indicator.get("details_json")),
            "association_basis": corr.get("volume_serial_match"),
            "computer_label": None,
            "image_path": None,
        }
        row["association_wording"] = _usb_association_wording(row["source_artifact_type"], row["association_basis"])
        rows.append(row)
    groups = _group_copied_usb_rows(rows) if grouped else []
    device_counts: dict[tuple[str | None, str | None, str | None], dict[str, Any]] = {}
    for row in rows:
        key = (row["usb_serial"], row["usb_volume_serial_number"], row["usb_volume_name"])
        item = device_counts.setdefault(
            key,
            {
                "usb_serial": row["usb_serial"],
                "usb_volume_serial_number": row["usb_volume_serial_number"],
                "usb_volume_name": row["usb_volume_name"],
                "usb_drive_letter": row["usb_drive_letter"],
                "usb_product": row["usb_product"],
                "copied_file_indicators": 0,
            },
        )
        item["copied_file_indicators"] += 1
    return {
        "case_id": case_id,
        "notes": [
            "Rows are copied-file timestamp indicators that also correlate to USB storage evidence.",
            "LNK and Jump List rows are associated by volume serial where available.",
            "Shellbag folder rows are worded as consistent with a USB device when based on folder tree and/or connection-time overlap.",
        ],
        "devices": list(device_counts.values()),
        "items": rows,
        "groups": groups,
        "total_returned": len(groups) if grouped else len(rows),
    }


def tool_run_summary_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    db.get_case(case_id)
    rows = db.conn.execute(
        """
        SELECT jobs.*, computers.label AS computer_label, images.path AS image_path,
               COUNT(DISTINCT tool_outputs.id) AS output_count,
               COALESCE(SUM(tool_outputs.row_count), 0) AS imported_row_count,
               COUNT(DISTINCT CASE WHEN activity_log.level = 'warning' THEN activity_log.id END) AS warning_count,
               COUNT(DISTINCT CASE WHEN activity_log.level = 'error' THEN activity_log.id END) AS error_count
        FROM jobs
        LEFT JOIN computers ON jobs.computer_id = computers.id
        LEFT JOIN images ON jobs.image_id = images.id
        LEFT JOIN tool_outputs ON tool_outputs.job_id = jobs.id
        LEFT JOIN activity_log ON activity_log.job_id = jobs.id
        WHERE jobs.case_id = ?
        GROUP BY jobs.id
        ORDER BY jobs.start_time DESC
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()
    runs = []
    for row in rows:
        item = dict(row)
        item["command"] = json.loads(item.pop("command_json") or "[]")
        item["source_scope"] = _job_source_scope(item)
        item["status"] = _job_status(item)
        if item["status"] == "source_not_present":
            item["source_not_present"] = True
            item["error_count"] = 0
        item["warnings"] = _job_activity(db, item["id"], level="warning")
        item["errors"] = _job_activity(db, item["id"], level="error")
        runs.append(item)
    status_counts = _job_status_counts(db, case_id)
    tool_count_rows = [
        dict(row)
        for row in db.conn.execute(
            """
            SELECT tool_name, source_scope, command_json, output_folder, stdout_path, stderr_path, exit_code, dry_run
            FROM jobs
            WHERE case_id = ?
            ORDER BY tool_name
            """,
            (case_id,),
        ).fetchall()
    ]
    tool_counts_by_name: dict[str, dict[str, Any]] = {}
    tool_counts_by_scope: dict[tuple[str, str], dict[str, Any]] = {}
    for row in tool_count_rows:
        command = json.loads(row.get("command_json") or "[]")
        scope = _job_source_scope({**row, "command": command})
        name_key = row["tool_name"]
        scope_key = (row["tool_name"], scope)
        for bucket in (
            tool_counts_by_name.setdefault(
                name_key,
                {
                    "tool_name": row["tool_name"],
                    "run_count": 0,
                    "succeeded": 0,
                    "failed": 0,
                    "dry_runs": 0,
                    "source_scopes": set(),
                },
            ),
            tool_counts_by_scope.setdefault(
                scope_key,
                {
                    "tool_name": row["tool_name"],
                    "source_scope": scope,
                    "run_count": 0,
                    "succeeded": 0,
                    "failed": 0,
                    "dry_runs": 0,
                },
            ),
        ):
            bucket["run_count"] += 1
            bucket["succeeded"] += 1 if row.get("exit_code") == 0 else 0
            bucket["failed"] += 1 if row.get("exit_code") is not None and row.get("exit_code") != 0 else 0
            bucket["dry_runs"] += 1 if row.get("dry_run") else 0
            if "source_scopes" in bucket:
                bucket["source_scopes"].add(scope)
    tool_counts = []
    for item in tool_counts_by_name.values():
        item["source_scopes"] = ", ".join(sorted(item["source_scopes"]))
        tool_counts.append(item)
    tool_counts.sort(key=lambda item: item["tool_name"])
    tool_scope_counts = sorted(
        tool_counts_by_scope.values(),
        key=lambda item: (item["tool_name"], item["source_scope"]),
    )
    return {
        "case_id": case_id,
        "status_counts": status_counts,
        "tools": tool_counts,
        "tool_scopes": tool_scope_counts,
        "runs": runs,
        "total_returned": len(runs),
    }


def process_timing_report(db: Database, case_id: str, *, limit: int = 500) -> dict[str, Any]:
    db.get_case(case_id)
    rows = [
        dict(row)
        for row in db.conn.execute(
            """
            SELECT process_timings.*, computers.label AS computer_label, images.path AS image_path
            FROM process_timings
            LEFT JOIN computers ON computers.id = process_timings.computer_id
            LEFT JOIN images ON images.id = process_timings.image_id
            WHERE process_timings.case_id = ?
            ORDER BY process_timings.start_time DESC
            LIMIT ?
            """,
            (case_id, limit),
        ).fetchall()
    ]
    for row in rows:
        row["details"] = json.loads(row.pop("details_json") or "{}")
        row["duration_seconds"] = round((row.get("duration_ms") or 0) / 1000, 3)
        row["source_scope"] = _process_timing_source_scope(row)
    summary = [
        dict(row)
        for row in db.conn.execute(
            """
            SELECT scope, phase, status, COUNT(*) AS count,
                   SUM(COALESCE(duration_ms, 0)) AS total_duration_ms,
                   AVG(COALESCE(duration_ms, 0)) AS avg_duration_ms,
                   MIN(start_time) AS first_start,
                   MAX(end_time) AS last_end
            FROM process_timings
            WHERE case_id = ?
            GROUP BY scope, phase, status
            ORDER BY scope, phase, status
            """,
            (case_id,),
        ).fetchall()
    ]
    for row in summary:
        row["total_duration_seconds"] = round((row.get("total_duration_ms") or 0) / 1000, 3)
        row["avg_duration_seconds"] = round((row.get("avg_duration_ms") or 0) / 1000, 3)
    worker_requests = [
        {
            "name": row.get("name"),
            "requested_workers": (row.get("details") or {}).get("requested_workers"),
            "effective_workers": (row.get("details") or {}).get("effective_workers"),
            "parallel_note": (row.get("details") or {}).get("parallel_note"),
        }
        for row in rows
        if (row.get("details") or {}).get("requested_workers")
    ]
    return {
        "case_id": case_id,
        "summary": summary,
        "worker_requests": worker_requests,
        "timings": rows,
        "total_returned": len(rows),
    }


def _disk_usage_row(path: Path, *, label: str, min_free_gb: float) -> dict[str, Any]:
    path = path.expanduser()
    probe = path if path.exists() else path.parent
    while not probe.exists() and probe.parent != probe:
        probe = probe.parent
    try:
        usage = shutil.disk_usage(probe)
    except OSError as exc:
        return {"label": label, "path": str(path), "status": "error", "message": str(exc)}
    free_gb = round(usage.free / (1024**3), 2)
    total_gb = round(usage.total / (1024**3), 2)
    used_pct = round((usage.used / usage.total) * 100, 1) if usage.total else 0
    return {
        "label": label,
        "path": str(path),
        "probe_path": str(probe),
        "status": "ok" if free_gb >= min_free_gb else "low_space",
        "free_gb": free_gb,
        "total_gb": total_gb,
        "used_pct": used_pct,
        "min_free_gb": min_free_gb,
    }


def _report_mount_path_state(path: Path) -> tuple[str, str]:
    try:
        if not path.exists():
            return "missing", "Path does not exist."
        if path.is_dir():
            next(path.iterdir(), None)
        return "accessible", ""
    except OSError as exc:
        return "stale", str(exc)


def workspace_health_report(db: Database, case_id: str | None = None, *, min_free_gb: float = 10.0) -> dict[str, Any]:
    case = db.get_case(case_id) if case_id else None
    db_path = Path(db.path)
    workspace_root = db_path.parent
    temp_root = Path(
        os.environ.get("PERCEPTOR_TMPDIR")
        or os.environ.get("DUCKDB_TMPDIR")
        or os.environ.get("TMPDIR")
        or "/tmp"
    )
    paths = [
        _disk_usage_row(workspace_root, label="workspace", min_free_gb=min_free_gb),
        _disk_usage_row(db_path, label="sqlite_database", min_free_gb=min_free_gb),
        _disk_usage_row(temp_root, label="temporary_directory", min_free_gb=min_free_gb),
    ]
    if case:
        paths.extend(
            [
                _disk_usage_row(case.root, label="case_root", min_free_gb=min_free_gb),
                _disk_usage_row(case.root / "analytics", label="case_analytics", min_free_gb=min_free_gb),
                _disk_usage_row(case.root / "outputs", label="case_outputs", min_free_gb=min_free_gb),
            ]
        )
    mount_rows: list[dict[str, Any]] = []
    if case_id:
        for row in db.conn.execute(
            """
            SELECT id, image_id, volume_mount_path, ewf_mount_path, raw_path, created_at
            FROM mounts
            WHERE case_id = ?
            ORDER BY created_at DESC
            """,
            (case_id,),
        ).fetchall():
            item = dict(row)
            for field in ("volume_mount_path", "ewf_mount_path"):
                value = item.get(field)
                if not value:
                    continue
                status, message = _report_mount_path_state(Path(value))
                mount_rows.append({**item, "mount_field": field, "mount_path": value, "status": status, "message": message})
    warnings = [
        f"{row.get('label')} has {row.get('free_gb')} GB free below requested {row.get('min_free_gb')} GB"
        for row in paths
        if row.get("status") == "low_space"
    ]
    warnings.extend(f"Mount path {row.get('mount_path')} is {row.get('status')}: {row.get('message')}" for row in mount_rows if row.get("status") != "accessible")
    return {
        "case_id": case_id,
        "summary": {
            "passed": not warnings,
            "path_count": len(paths),
            "mount_count": len(mount_rows),
            "warning_count": len(warnings),
        },
        "environment": {
            "tmpdir": os.environ.get("TMPDIR") or "",
            "duckdb_tmpdir": os.environ.get("DUCKDB_TMPDIR") or "",
            "perceptor_tmpdir": os.environ.get("PERCEPTOR_TMPDIR") or "",
        },
        "paths": paths,
        "mounts": mount_rows,
        "warnings": warnings,
    }


def workspace_health_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") or {}
    lines = ["# Workspace Health Report", "", f"Case: `{report.get('case_id') or ''}`", ""]
    lines.extend(
        [
            "## Summary",
            "",
            f"- Passed: `{summary.get('passed')}`",
            f"- Warnings: `{summary.get('warning_count', 0)}`",
            "",
            "## Paths",
            "",
        ]
    )
    for row in report.get("paths") or []:
        lines.append(f"- `{row.get('status')}` `{row.get('label')}` `{row.get('path')}` free `{row.get('free_gb')}` GB of `{row.get('total_gb')}` GB")
    if report.get("warnings"):
        lines.extend(["", "## Warnings", ""])
        lines.extend(f"- {warning}" for warning in report.get("warnings") or [])
    return "\n".join(lines).rstrip() + "\n"


def processing_disk_estimate_report(
    db: Database,
    case_id: str,
    *,
    image_id: str | None = None,
    profile: str | None = None,
    min_free_gb: float = 10.0,
) -> dict[str, Any]:
    db.get_case(case_id)
    where = ["case_id = ?"]
    params: list[Any] = [case_id]
    if image_id:
        where.append("id = ?")
        params.append(image_id)
    image_rows = [
        dict(row)
        for row in db.conn.execute(
            f"SELECT id, computer_id, path, created_at FROM images WHERE {' AND '.join(where)} ORDER BY created_at",
            params,
        ).fetchall()
    ]
    profile_text = (profile or "").casefold()
    multiplier = 0.75
    if "deep" in profile_text or "recovery" in profile_text:
        multiplier = 1.25
    elif "full" in profile_text:
        multiplier = 1.0
    elif "basic" in profile_text:
        multiplier = 0.5
    estimates: list[dict[str, Any]] = []
    total_image_bytes = 0
    missing_sizes = 0
    for image in image_rows:
        path = Path(str(image.get("path") or ""))
        size_bytes: int | None
        try:
            size_bytes = path.stat().st_size
        except OSError:
            size_bytes = None
            missing_sizes += 1
        if size_bytes:
            total_image_bytes += size_bytes
        estimated_output_bytes = int((size_bytes or 0) * multiplier)
        estimates.append(
            {
                "image_id": image.get("id"),
                "computer_id": image.get("computer_id"),
                "path": str(path),
                "size_gb": round((size_bytes or 0) / (1024**3), 2) if size_bytes is not None else None,
                "estimated_processing_gb": round(estimated_output_bytes / (1024**3), 2),
                "profile": profile or "",
                "multiplier": multiplier,
                "status": "size_unavailable" if size_bytes is None else "estimated",
            }
        )
    estimated_processing_bytes = int(total_image_bytes * multiplier)
    reserve_bytes = int(min_free_gb * 1024**3)
    required_bytes = estimated_processing_bytes + reserve_bytes
    health = workspace_health_report(db, case_id, min_free_gb=min_free_gb)
    free_values = [
        float(row.get("free_gb") or 0)
        for row in health.get("paths") or []
        if row.get("label") in {"workspace", "case_root", "case_analytics", "case_outputs", "temporary_directory"}
    ]
    min_free_observed_gb = min(free_values) if free_values else 0.0
    estimated_processing_gb = round(estimated_processing_bytes / (1024**3), 2)
    required_gb = round(required_bytes / (1024**3), 2)
    status = "ok"
    warnings: list[str] = []
    if not image_rows:
        status = "warning"
        warnings.append("No registered images matched the estimate request.")
    if missing_sizes:
        status = "warning"
        warnings.append(f"{missing_sizes} image path(s) could not be stat()ed; estimates exclude unavailable sizes.")
    if min_free_observed_gb and min_free_observed_gb < required_gb:
        status = "low_space"
        warnings.append(
            f"Observed free space floor {round(min_free_observed_gb, 2)} GB is below estimated processing need plus reserve {required_gb} GB."
        )
    return {
        "case_id": case_id,
        "image_id": image_id or "",
        "profile": profile or "",
        "summary": {
            "status": status,
            "image_count": len(image_rows),
            "total_image_gb": round(total_image_bytes / (1024**3), 2),
            "estimated_processing_gb": estimated_processing_gb,
            "reserve_gb": min_free_gb,
            "required_free_gb": required_gb,
            "free_space_floor_gb": round(min_free_observed_gb, 2),
            "warning_count": len(warnings),
        },
        "notes": [
            "Estimate is conservative and intended for preflight warning, not exact output prediction.",
            "UTC/report data is not changed by this estimate.",
            "Deep recovery and carving profiles can exceed this estimate on fragmented or artifact-heavy images.",
        ],
        "warnings": warnings,
        "images": estimates,
        "workspace_health": health,
    }


def unmapped_imports_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    db.get_case(case_id)
    rows = []
    for row in db.conn.execute(
        """
        SELECT activity_log.*, computers.label AS computer_label
        FROM activity_log
        LEFT JOIN computers ON computers.id = activity_log.computer_id
        WHERE activity_log.case_id = ?
          AND activity_log.event = 'report_bundle.csv_unsupported'
        ORDER BY activity_log.created_at DESC
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall():
        item = dict(row)
        details = json.loads(item.pop("details_json") or "{}")
        rows.append({**item, **details})
    return {
        "case_id": case_id,
        "summary": {
            "unmapped_count": len(rows),
            "computer_counts": _count_by_key(rows, "computer_label"),
        },
        "unmapped": rows,
        "total_returned": len(rows),
    }


def processing_progress_report(db: Database, case_id: str, *, limit: int = 50) -> dict[str, Any]:
    db.get_case(case_id)
    summary = case_summary_report(db, case_id)
    timings = process_timing_report(db, case_id, limit=limit)
    jobs = db.case_status(case_id).get("jobs") or []
    job_counts: dict[str, int] = {}
    for job in jobs:
        status = "running" if job.get("exit_code") is None and not job.get("end_time") else ("completed" if job.get("exit_code") == 0 else "failed")
        job_counts[status] = job_counts.get(status, 0) + 1
    active_timings = [row for row in timings.get("timings") or [] if row.get("status") in {"running", "started"}]
    failed_timings = [row for row in timings.get("timings") or [] if row.get("status") == "failed"]
    return {
        "case_id": case_id,
        "summary": {
            "computers": (summary.get("counts") or {}).get("computers", 0),
            "images": (summary.get("counts") or {}).get("images", 0),
            "tool_outputs": (summary.get("counts") or {}).get("outputs", 0),
            "parsed_row_count": sum(int(row.get("count") or 0) for row in summary.get("parsed_row_counts") or []),
            "job_counts": job_counts,
            "active_timing_count": len(active_timings),
            "failed_timing_count": len(failed_timings),
        },
        "recent_timings": (timings.get("timings") or [])[:limit],
        "active_timings": active_timings[:limit],
        "failed_timings": failed_timings[:limit],
        "recent_jobs": jobs[:limit],
    }


def case_dashboard_report(db: Database, case_id: str, *, limit: int = 25) -> dict[str, Any]:
    db.get_case(case_id)
    summary = case_summary_report(db, case_id)
    progress = processing_progress_report(db, case_id, limit=limit)
    unmapped = unmapped_imports_report(db, case_id, limit=limit)
    gaps = evidence_gaps_report(db, case_id, limit=limit)
    suspicious = suspicious_executions_report(db, case_id, limit=limit)
    latest_reports = [
        {**dict(row), "details": json.loads(row["details_json"] or "{}")}
        for row in db.conn.execute(
            """
            SELECT created_at, event, message, details_json
            FROM activity_log
            WHERE case_id = ?
              AND event IN ('report_bundle.import_completed', 'report_bundle.csv_unsupported')
            ORDER BY created_at DESC
            LIMIT ?
            """,
            (case_id, limit),
        ).fetchall()
    ]
    warnings = db.activity_for_case(case_id, level="warning", limit=limit)
    errors = db.activity_for_case(case_id, level="error", limit=limit)
    top_findings = []
    for row in suspicious.get("findings") or suspicious.get("items") or []:
        if isinstance(row, dict):
            top_findings.append(row)
    return {
        "case_id": case_id,
        "summary": {
            **(summary.get("counts") or {}),
            "parsed_row_count": (progress.get("summary") or {}).get("parsed_row_count", 0),
            "active_timing_count": (progress.get("summary") or {}).get("active_timing_count", 0),
            "failed_timing_count": (progress.get("summary") or {}).get("failed_timing_count", 0),
            "unmapped_import_count": (unmapped.get("summary") or {}).get("unmapped_count", 0),
            "evidence_gap_count": (gaps.get("summary") or {}).get("gap_count", 0),
            "suspicious_finding_count": (suspicious.get("summary") or {}).get("finding_count", 0),
            "warning_count": len(warnings),
            "error_count": len(errors),
        },
        "computers": summary.get("computers") or [],
        "images": summary.get("images") or [],
        "parsed_row_counts": summary.get("parsed_row_counts") or [],
        "active_timings": progress.get("active_timings") or [],
        "failed_timings": progress.get("failed_timings") or [],
        "unmapped_imports": unmapped.get("unmapped") or [],
        "evidence_gaps": gaps.get("gaps") or [],
        "top_findings": top_findings[:limit],
        "latest_report_activity": latest_reports,
        "warnings": [dict(row) for row in warnings],
        "errors": [dict(row) for row in errors],
    }


def resume_plan_report(db: Database, case_id: str, *, limit: int = 50) -> dict[str, Any]:
    progress = processing_progress_report(db, case_id, limit=limit)
    health = workspace_health_report(db, case_id)
    decisions = processing_decision_report(db, case_id, limit=limit)
    failed = progress.get("failed_timings") or []
    commands = [
        f"perceptor --root <workspace> report workspace-health --case {case_id}",
        f"perceptor --root <workspace> case rebuild-postprocess {case_id}",
        f"perceptor --root <workspace> report processing-decisions --case {case_id}",
        f"perceptor --root <workspace> report regression-smoke --case {case_id}",
    ]
    if failed:
        commands.insert(1, f"perceptor --root <workspace> report process-timings --case {case_id} --format table")
    return {
        "case_id": case_id,
        "summary": {
            "workspace_passed": (health.get("summary") or {}).get("passed"),
            "failed_timing_count": len(failed),
            "decision_count": (decisions.get("summary") or {}).get("decision_count", 0),
        },
        "recommended_commands": commands,
        "workspace_warnings": health.get("warnings") or [],
        "failed_timings": failed[:limit],
        "decisions": (decisions.get("decisions") or [])[:limit],
    }


def process_timing_markdown(report: dict[str, Any]) -> str:
    lines = [f"# Process Timing Report", "", f"Case: `{report['case_id']}`", ""]
    lines.append("## Summary")
    lines.append("")
    lines.append("| Scope | Phase | Status | Count | Total seconds | Average seconds | First start | Last end |")
    lines.append("|---|---|---|---:|---:|---:|---|---|")
    for row in report.get("summary", []):
        lines.append(
            "| {scope} | {phase} | {status} | {count} | {total:.3f} | {avg:.3f} | {first} | {last} |".format(
                scope=row.get("scope") or "",
                phase=row.get("phase") or "",
                status=row.get("status") or "",
                count=row.get("count") or 0,
                total=row.get("total_duration_seconds") or 0,
                avg=row.get("avg_duration_seconds") or 0,
                first=row.get("first_start") or "",
                last=row.get("last_end") or "",
            )
        )
    worker_requests = report.get("worker_requests") or []
    if worker_requests:
        lines.extend(["", "## Worker Requests", ""])
        for row in worker_requests[:25]:
            lines.append(
                f"- `{row.get('name') or ''}` requested `{row.get('requested_workers')}` "
                f"effective `{row.get('effective_workers')}` {row.get('parallel_note') or ''}"
            )
    lines.extend(["", "## Timings", ""])
    lines.append("| Start | End | Seconds | Source | Scope | Phase | Name | Status | Tool | Artifact |")
    lines.append("|---|---|---:|---|---|---|---|---|---|---|")
    for row in reversed(report.get("timings", [])):
        lines.append(
            "| {start} | {end} | {seconds:.3f} | {source} | {scope} | {phase} | {name} | {status} | {tool} | {artifact} |".format(
                start=row.get("start_time") or "",
                end=row.get("end_time") or "",
                seconds=row.get("duration_seconds") or 0,
                source=row.get("source_scope") or "",
                scope=row.get("scope") or "",
                phase=row.get("phase") or "",
                name=str(row.get("name") or "").replace("|", "\\|"),
                status=row.get("status") or "",
                tool=str(row.get("tool_name") or "").replace("|", "\\|"),
                artifact=str(row.get("artifact_name") or "").replace("|", "\\|"),
            )
        )
    return "\n".join(lines).rstrip() + "\n"


def recovery_coverage_report(db: Database, case_id: str, *, limit: int = 500) -> dict[str, Any]:
    db.get_case(case_id)
    rows = [
        dict(row)
        for row in db.conn.execute(
            """
            SELECT process_timings.*, computers.label AS computer_label, images.path AS image_path
            FROM process_timings
            LEFT JOIN computers ON computers.id = process_timings.computer_id
            LEFT JOIN images ON images.id = process_timings.image_id
            WHERE process_timings.case_id = ?
              AND process_timings.scope = 'artifact'
              AND process_timings.phase = 'extract'
            ORDER BY process_timings.start_time DESC
            LIMIT ?
            """,
            (case_id, limit),
        ).fetchall()
    ]
    coverage = []
    for row in rows:
        details = json.loads(row.pop("details_json") or "{}")
        recovery = details.get("recovery") or {}
        method = details.get("method") or ""
        recovered = method == "tsk" and (recovery.get("deleted_files") or recovery.get("orphaned_files"))
        if not recovered and not recovery:
            continue
        item = {
            "case_id": row.get("case_id"),
            "computer_id": row.get("computer_id"),
            "computer_label": row.get("computer_label"),
            "image_id": row.get("image_id"),
            "image_path": row.get("image_path"),
            "profile": details.get("profile"),
            "artifact_name": row.get("artifact_name") or row.get("name"),
            "tool_name": row.get("tool_name"),
            "method": method,
            "status": row.get("status"),
            "duration_seconds": round((row.get("duration_ms") or 0) / 1000, 3),
            "matched_count": details.get("count"),
            "extracted_count": details.get("extracted_count"),
            "failed_count": details.get("failed_count"),
            "recovery_limited": bool(details.get("recovery_limited")),
            "limit_reason": details.get("limit_reason"),
            "limit_max_files": details.get("limit_max_files"),
            "limit_max_bytes": details.get("limit_max_bytes"),
            "limit_max_seconds": details.get("limit_max_seconds"),
            "file_count": details.get("file_count"),
            "byte_count": details.get("byte_count"),
            "deleted_files": bool(recovery.get("deleted_files")),
            "orphaned_files": bool(recovery.get("orphaned_files")),
            "recovery_scope": _recovery_scope_label(recovery),
            "cost": recovery.get("cost"),
            "noise": recovery.get("noise"),
            "path": details.get("path"),
            "source": details.get("source"),
            "destination": details.get("destination"),
            "start_time": row.get("start_time"),
            "end_time": row.get("end_time"),
        }
        coverage.append(item)
    forced = [item for item in coverage if item["method"] == "tsk" and (item["deleted_files"] or item["orphaned_files"])]
    summary = {
        "artifact_extracts_returned": len(coverage),
        "tsk_recovery_artifacts": len(forced),
        "total_duration_seconds": round(sum(item.get("duration_seconds") or 0 for item in coverage), 3),
        "tsk_recovery_duration_seconds": round(sum(item.get("duration_seconds") or 0 for item in forced), 3),
        "matched_count": sum(int(item.get("matched_count") or 0) for item in forced),
        "extracted_count": sum(int(item.get("extracted_count") or 0) for item in forced),
        "failed_count": sum(int(item.get("failed_count") or 0) for item in forced),
        "limited_count": sum(1 for item in forced if item.get("recovery_limited")),
        "status_counts": _count_by_key(forced, "status"),
        "limit_reason_counts": _count_by_key(
            [item for item in forced if item.get("limit_reason")],
            "limit_reason",
        ),
        "recovery_scope_counts": _count_by_key(forced, "recovery_scope"),
        "added_over_live": [
            {
                "artifact_name": item.get("artifact_name"),
                "tool_name": item.get("tool_name"),
                "scope": item.get("recovery_scope"),
                "extracted_count": item.get("extracted_count"),
                "status": item.get("status"),
                "limit_reason": item.get("limit_reason"),
            }
            for item in forced[:20]
        ],
    }
    by_artifact = {}
    for item in forced:
        name = item.get("artifact_name") or ""
        current = by_artifact.setdefault(
            name,
            {
                "artifact_name": name,
                "tool_name": item.get("tool_name"),
                "runs": 0,
                "duration_seconds": 0.0,
                "matched_count": 0,
                "extracted_count": 0,
                "failed_count": 0,
                "limited_count": 0,
                "limit_reasons": {},
                "recovery_scopes": {},
                "cost": item.get("cost"),
                "noise": item.get("noise"),
            },
        )
        current["runs"] += 1
        current["duration_seconds"] = round(current["duration_seconds"] + (item.get("duration_seconds") or 0), 3)
        current["matched_count"] += int(item.get("matched_count") or 0)
        current["extracted_count"] += int(item.get("extracted_count") or 0)
        current["failed_count"] += int(item.get("failed_count") or 0)
        if item.get("recovery_limited"):
            current["limited_count"] += 1
            reason = str(item.get("limit_reason") or "unspecified")
            current["limit_reasons"][reason] = int(current["limit_reasons"].get(reason, 0)) + 1
        scope = str(item.get("recovery_scope") or "unspecified")
        current["recovery_scopes"][scope] = int(current["recovery_scopes"].get(scope, 0)) + 1
    return {
        "case_id": case_id,
        "summary": summary,
        "by_artifact": sorted(by_artifact.values(), key=lambda item: item["duration_seconds"], reverse=True),
        "artifacts": coverage,
        "total_returned": len(coverage),
    }


def carve_coverage_report(db: Database, case_id: str, *, limit: int = 500) -> dict[str, Any]:
    db.get_case(case_id)
    rows = _query_report_rows(
        db,
        case_id,
        "staged_carves",
        """
        SELECT staged_carves.*, source_csv AS manifest_path
        FROM staged_carves
        WHERE staged_carves.case_id = ?
        ORDER BY staged_carves.created_at DESC, staged_carves.row_number ASC
        LIMIT ?
        """,
        (case_id, limit),
    )
    scan_ranges = _query_report_rows(
        db,
        case_id,
        "carve_scan_ranges",
        """
        SELECT *
        FROM carve_scan_ranges
        WHERE case_id = ?
        ORDER BY created_at DESC, row_number ASC
        LIMIT ?
        """,
        (case_id, limit),
    )
    scanned_bytes = sum(int(row.get("scanned_bytes") or 0) for row in scan_ranges)
    source_sizes = {
        str(row.get("source_path") or ""): int(row.get("source_size") or 0)
        for row in scan_ranges
        if row.get("source_path")
    }
    source_coverage = _carve_source_coverage(scan_ranges)
    total_source_bytes = sum(source_sizes.values())
    summary = {
        "carve_count": len(rows),
        "scan_range_count": len(scan_ranges),
        "scanned_bytes": scanned_bytes,
        "unique_source_count": len(source_sizes),
        "total_source_bytes": total_source_bytes,
        "scan_coverage_percent": round((scanned_bytes / total_source_bytes) * 100, 3) if total_source_bytes else 0,
        "profile_counts": _count_by_key(rows, "profile"),
        "type_counts": _count_by_key(rows, "carve_type"),
        "range_type_counts": _count_by_key(scan_ranges, "carve_type"),
        "source_coverage": source_coverage,
        "next_scan_recommendations": [
            item for item in source_coverage
            if int(item.get("remaining_bytes") or 0) > 0
        ][:20],
        "format_counts": _count_by_key(rows, "detected_format"),
        "parser_status_counts": _count_by_key(rows, "parser_status"),
        "import_status_counts": _count_by_key(rows, "import_status"),
        "total_staged_bytes": sum(int(row.get("staged_size") or 0) for row in rows),
        "parsed_sqlite_count": sum(1 for row in rows if row.get("detected_format") == "sqlite" and row.get("parser_status") in {"parsed", "schema_only"}),
    }
    return {
        "case_id": case_id,
        "summary": summary,
        "carves": rows,
        "scan_ranges": scan_ranges,
        "notes": [
            "Carve coverage tracks staged outputs from explicit carve workflows.",
            "A parsed or schema-only SQLite carve can still be partial; corroborate rows with source offsets and independent artifacts.",
            "Encrypted or unsupported fragments are retained as staged evidence but are not parsed without a matching decoder.",
        ],
        "total_returned": len(rows),
    }


def _carve_source_coverage(scan_ranges: list[dict[str, Any]]) -> list[dict[str, Any]]:
    groups: dict[tuple[str, str], dict[str, Any]] = {}
    for row in scan_ranges:
        key = (str(row.get("source_path") or ""), str(row.get("carve_type") or ""))
        current = groups.setdefault(
            key,
            {
                "source_path": key[0],
                "carve_type": key[1],
                "source_size": int(row.get("source_size") or 0),
                "range_count": 0,
                "scanned_bytes": 0,
                "hits_found": 0,
                "max_range_end": 0,
            },
        )
        current["source_size"] = max(int(current.get("source_size") or 0), int(row.get("source_size") or 0))
        current["range_count"] += 1
        current["scanned_bytes"] += int(row.get("scanned_bytes") or 0)
        current["hits_found"] += int(row.get("hits_found") or 0)
        current["max_range_end"] = max(int(current.get("max_range_end") or 0), int(row.get("range_end") or 0))
    output = []
    for item in groups.values():
        source_size = int(item.get("source_size") or 0)
        scanned = int(item.get("scanned_bytes") or 0)
        max_end = int(item.get("max_range_end") or 0)
        remaining = max(0, source_size - max_end) if source_size else 0
        output.append(
            {
                **item,
                "remaining_bytes": remaining,
                "next_start_offset": max_end if remaining else "",
                "coverage_percent": round((scanned / source_size) * 100, 3) if source_size else 0,
            }
        )
    output.sort(key=lambda item: (str(item.get("source_path") or ""), str(item.get("carve_type") or "")))
    return output


def carve_coverage_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Carve Coverage Report",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Carves: `{summary.get('carve_count', 0)}`",
        f"- Scan ranges: `{summary.get('scan_range_count', 0)}`",
        f"- Scanned bytes: `{summary.get('scanned_bytes', 0)}` of `{summary.get('total_source_bytes', 0)}` (`{summary.get('scan_coverage_percent', 0)}%`)",
        f"- Parsed SQLite carves: `{summary.get('parsed_sqlite_count', 0)}`",
        f"- Total staged bytes: `{summary.get('total_staged_bytes', 0)}`",
        f"- Parser statuses: `{summary.get('parser_status_counts', {})}`",
        "",
        "## Carves",
        "",
    ]
    rows = report.get("carves") if isinstance(report.get("carves"), list) else []
    if not rows:
        lines.append("- No staged carve outputs were found.")
    for row in rows:
        lines.append(
            f"- `{row.get('profile') or ''}` `{row.get('carve_type') or ''}` "
            f"format `{row.get('detected_format') or ''}` status `{row.get('parser_status') or ''}` "
            f"offset `{row.get('source_offset') or ''}` path `{row.get('staged_path') or ''}`"
        )
        if row.get("parser_error"):
            lines.append(f"  - parser error: {row.get('parser_error')}")
    lines.extend(["", "## Scan Ranges", ""])
    scan_ranges = report.get("scan_ranges") if isinstance(report.get("scan_ranges"), list) else []
    if not scan_ranges:
        lines.append("- No carve scan ranges were recorded.")
    for row in scan_ranges[:25]:
        lines.append(
            f"- `{row.get('carve_type') or ''}` `{row.get('source_path') or ''}` "
            f"bytes `{row.get('range_start') or 0}`-`{row.get('range_end') or 0}` "
            f"scanned `{row.get('scanned_bytes') or 0}` hits `{row.get('hits_found') or 0}`"
        )
    lines.extend(["", "## Source Coverage", ""])
    coverage = summary.get("source_coverage") if isinstance(summary.get("source_coverage"), list) else []
    if not coverage:
        lines.append("- No source coverage records were available.")
    for item in coverage:
        next_offset = item.get("next_start_offset")
        next_text = f", next offset `{next_offset}`" if next_offset not in ("", None) else ""
        lines.append(
            f"- `{item.get('carve_type') or ''}` `{item.get('source_path') or ''}` "
            f"scanned `{item.get('scanned_bytes') or 0}` of `{item.get('source_size') or 0}` "
            f"(`{item.get('coverage_percent') or 0}%`), hits `{item.get('hits_found') or 0}`{next_text}"
        )
    lines.extend(["", "## Notes", ""])
    for note in report.get("notes") or []:
        lines.append(f"- {note}")
    return "\n".join(lines).rstrip() + "\n"


def sqlite_inventory_report(db: Database, case_id: str, *, limit: int = 100, sample_rows: int = 0) -> dict[str, Any]:
    db.get_case(case_id)
    carves = _query_report_rows(
        db,
        case_id,
        "staged_carves",
        """
        SELECT *
        FROM staged_carves
        WHERE case_id = ?
          AND detected_format = 'sqlite'
        ORDER BY created_at DESC, row_number ASC
        LIMIT ?
        """,
        (case_id, limit),
    )
    inventories = [_sqlite_inventory_for_carve(row, sample_rows=sample_rows) for row in carves]
    return {
        "case_id": case_id,
        "summary": {
            "sqlite_carves": len(inventories),
            "readable": sum(1 for item in inventories if item.get("status") == "parsed"),
            "schema_only": sum(1 for item in inventories if item.get("status") == "schema_only"),
            "failed": sum(1 for item in inventories if item.get("status") == "failed"),
            "table_count": sum(len(item.get("tables") or []) for item in inventories),
        },
        "inventories": inventories,
        "total_returned": len(inventories),
    }


def sqlite_inventory_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# SQLite Carve Inventory",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- SQLite carves: `{summary.get('sqlite_carves', 0)}`",
        f"- Readable: `{summary.get('readable', 0)}`",
        f"- Schema-only: `{summary.get('schema_only', 0)}`",
        f"- Failed: `{summary.get('failed', 0)}`",
        f"- Tables: `{summary.get('table_count', 0)}`",
        "",
        "## Databases",
        "",
    ]
    inventories = report.get("inventories") if isinstance(report.get("inventories"), list) else []
    if not inventories:
        lines.append("- No staged SQLite carve databases were found.")
    for inventory in inventories:
        lines.append(
            f"- `{inventory.get('status') or ''}` `{inventory.get('staged_path') or ''}` "
            f"tables `{len(inventory.get('tables') or [])}`"
        )
        if inventory.get("error"):
            lines.append(f"  - error: {inventory.get('error')}")
        for table in inventory.get("tables") or []:
            columns = ", ".join(column.get("name") or "" for column in table.get("columns") or [])
            lines.append(f"  - table `{table.get('name')}` rows `{table.get('row_count')}` columns `{columns}`")
    return "\n".join(lines).rstrip() + "\n"


def _sqlite_inventory_for_carve(row: dict[str, Any], *, sample_rows: int) -> dict[str, Any]:
    path = Path(str(row.get("staged_path") or ""))
    inventory = {
        "id": row.get("id"),
        "profile": row.get("profile"),
        "staged_path": str(path),
        "source_path": row.get("source_path"),
        "source_offset": row.get("source_offset"),
        "staged_sha256": row.get("staged_sha256"),
        "status": "failed",
        "error": "",
        "tables": [],
    }
    if not path.exists():
        inventory["error"] = "staged path is missing"
        return inventory
    try:
        conn = sqlite3.connect(f"file:{path}?mode=ro", uri=True)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA query_only=ON")
        tables = [
            row["name"]
            for row in conn.execute("SELECT name FROM sqlite_master WHERE type = 'table' ORDER BY name").fetchall()
        ]
        table_infos = []
        for table in tables:
            columns = [
                {"name": col["name"], "type": col["type"], "notnull": col["notnull"], "pk": col["pk"]}
                for col in conn.execute(f"PRAGMA table_info({_quote_identifier(table)})").fetchall()
            ]
            try:
                row_count = int(conn.execute(f"SELECT COUNT(*) FROM {_quote_identifier(table)}").fetchone()[0])
            except sqlite3.Error:
                row_count = None
            samples = []
            if sample_rows > 0:
                try:
                    cursor = conn.execute(f'SELECT * FROM "{table}" LIMIT ?', (sample_rows,))
                    names = [description[0] for description in cursor.description or []]
                    samples = [dict(zip(names, values, strict=False)) for values in cursor.fetchall()]
                except sqlite3.Error:
                    samples = []
            table_infos.append({"name": table, "columns": columns, "row_count": row_count, "sample_rows": samples})
        conn.close()
        inventory["tables"] = table_infos
        inventory["status"] = "parsed" if any((table.get("row_count") or 0) > 0 for table in table_infos) else "schema_only"
    except Exception as exc:
        inventory["error"] = str(exc)
    return inventory


def _recovery_scope_label(recovery: dict[str, Any]) -> str:
    deleted = bool(recovery.get("deleted_files"))
    orphaned = bool(recovery.get("orphaned_files"))
    if deleted and orphaned:
        return "deleted_and_orphaned"
    if deleted:
        return "deleted"
    if orphaned:
        return "orphaned"
    return "live_only"


def case_review_report(db: Database, case_id: str, *, limit: int = 25) -> dict[str, Any]:
    db.get_case(case_id)
    completeness = artifact_completeness_report(db, case_id, limit=limit)
    gaps = evidence_gaps_report(db, case_id, limit=limit)
    memory = memory_artifacts_report(db, case_id, limit=limit)
    copied = copied_file_indicators_report(db, case_id, limit=limit)
    copied_groups = copied_file_groups_report(db, case_id, limit=limit)
    copied_usb = copied_usb_files_report(db, case_id, limit=limit, grouped=True)
    usb = usb_report(db, case_id, limit=limit)
    issues = issues_report(db, case_id, limit=limit)
    evtx = evtx_recovery_report(db, case_id, limit=limit)
    recovery = recovery_coverage_report(db, case_id, limit=max(limit, 100))
    credentials = memory_credentials_report(db, case_id, limit=limit)
    crash = crash_dump_analysis_report(db, case_id, limit=limit)
    tool_runs = tool_run_summary_report(db, case_id, limit=limit)
    activity = activity_summary_report(db, case_id, limit=limit)
    return {
        "case_id": case_id,
        "summary": {
            "copied_file_indicators": _count_default_copied_indicators(db, case_id),
            "copied_file_groups": copied_groups["total_groups"],
            "copied_usb_file_groups": len(copied_usb["groups"]),
            "usb_storage_devices": _count(db, "usb_storage_devices", case_id),
            "warnings": len([item for item in issues["issues"] if item["level"] == "warning"]),
            "errors": len([item for item in issues["issues"] if item["level"] == "error"]),
            "evtx_recovery_status_counts": evtx["status_counts"],
            "job_status_counts": tool_runs["status_counts"],
            "tools_with_errors": completeness["summary"]["tools_with_errors"],
            "tools_with_warnings": completeness["summary"]["tools_with_warnings"],
            "tools_without_output": completeness["summary"]["tools_without_output"],
            "evidence_gap_count": gaps["summary"]["gap_count"],
            "memory_artifact_count": memory["summary"]["artifact_count"],
            "recovery_tsk_artifacts": recovery["summary"]["tsk_recovery_artifacts"],
            "recovery_limited_count": recovery["summary"]["limited_count"],
            "memory_credential_leads": credentials["summary"]["credential_hit_count"],
            "crash_dump_count": crash["summary"]["dump_count"],
        },
        "evidence_gaps_summary": gaps["summary"],
        "top_evidence_gaps": gaps["gaps"][:limit],
        "memory_artifacts_summary": memory["summary"],
        "recovery_coverage_summary": recovery["summary"],
        "recovery_coverage_by_artifact": recovery["by_artifact"][:limit],
        "memory_credentials_summary": credentials["summary"],
        "crash_dump_analysis_summary": crash["summary"],
        "memory_artifacts": memory["artifacts"][:limit],
        "evidence_strength_guide": evidence_strength_guide(),
        "artifact_completeness_summary": completeness["summary"],
        "artifact_completeness_by_tool": completeness["tools"][:limit],
        "copied_files": copied["copied_file_indicators"],
        "copied_file_groups": copied_groups["groups"],
        "copied_usb_files": copied_usb["groups"] or copied_usb["items"],
        "usb_devices": usb.get("usb_storage_devices", usb.get("devices", [])),
        "tool_runs": tool_runs["tools"],
        "issues": issues["issues"],
        "evtx_recovery": evtx["evtx_recovery"],
        "activity_counts": activity["counts"],
    }


def evidence_strength_guide() -> list[dict[str, str]]:
    return [
        {
            "strength": "strong",
            "meaning": "Direct timestamped source or multiple independent sources agree.",
            "report_use": "Can support a conclusion when provenance and parsing status are sound.",
        },
        {
            "strength": "moderate",
            "meaning": "Single parsed artifact or inferred correlation with clear source details.",
            "report_use": "Use as support with corroboration where available.",
        },
        {
            "strength": "lead",
            "meaning": "String hit, cache remnant, inventory artifact, or weak temporal/path correlation.",
            "report_use": "Treat as an investigative lead, not standalone proof.",
        },
        {
            "strength": "limitation",
            "meaning": "Unsupported, encrypted, missing, partial, failed, or skipped evidence source.",
            "report_use": "Disclose explicitly when absence could affect an opinion.",
        },
    ]


def _evidence_strength_for_category(category: Any) -> str:
    text = str(category or "").casefold()
    if any(token in text for token in ("prefetch", "execution", "evtx", "bam", "srum")):
        return "strong"
    if any(token in text for token in ("correlation", "browser", "cloud", "email", "remote")):
        return "moderate"
    if any(token in text for token in ("memory", "string", "credential", "crash")):
        return "lead"
    if any(token in text for token in ("gap", "failed", "missing", "skipped", "encrypted")):
        return "limitation"
    return "moderate"


def combined_artifact_family_report(
    db: Database,
    case_id: str,
    *,
    family: str = "all",
    limit: int = 100,
    memory_disk_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    db.get_case(case_id)
    memory_disk = memory_disk_report or memory_disk_correlations_report(db, case_id, limit=max(limit * 10, 500))
    families = ["browser", "cloud", "email", "remote_access", "windows_search", "file"]
    if family != "all":
        families = [family]
    disk_refs = _memory_disk_reference_rows(db, case_id, max_rows=5000)
    family_rows: list[dict[str, Any]] = []
    for name in families:
        correlations = [
            row for row in memory_disk.get("correlations") or []
            if str(row.get("disk_artifact_family") or "") == name
        ][:limit]
        family_rows.append(
            {
                "family": name,
                "disk_reference_count": sum(1 for row in disk_refs if row.get("artifact_family") == name),
                "memory_correlation_count": len(correlations),
                "evidence_strength": _evidence_strength_for_category(name if correlations else "lead"),
                "caveat": _combined_family_caveat(name),
                "memory_corroboration": correlations,
            }
        )
    return {
        "case_id": case_id,
        "filters": {"family": family, "limit": limit},
        "summary": {
            "family_count": len(family_rows),
            "memory_correlation_count": sum(int(row.get("memory_correlation_count") or 0) for row in family_rows),
        },
        "families": family_rows,
        "evidence_strength_guide": evidence_strength_guide(),
    }


def combined_artifact_family_markdown(report: dict[str, Any]) -> str:
    lines = ["# Combined Artifact Family Report", "", f"Case: `{report.get('case_id') or ''}`", "", "## Families", ""]
    for row in report.get("families") or []:
        lines.append(
            f"- `{row.get('family')}` strength `{row.get('evidence_strength')}` "
            f"disk refs `{row.get('disk_reference_count')}` memory correlations `{row.get('memory_correlation_count')}`"
        )
        if row.get("caveat"):
            lines.append(f"  - caveat: {row.get('caveat')}")
        for corr in row.get("memory_corroboration") or []:
            lines.append(
                f"  - `{corr.get('match_type')}` `{corr.get('match_value')}` "
                f"memory `{corr.get('source_artifact_type')}` disk `{corr.get('disk_table')}`"
            )
    return "\n".join(lines).rstrip() + "\n"


def _combined_family_caveat(family: str) -> str:
    caveats = {
        "browser": "Browser memory strings can reflect cached paths, URLs, or labels; corroborate with browser databases and timestamps.",
        "cloud": "Cloud memory strings can identify services or URLs but do not prove sync, upload, or download without disk/server context.",
        "email": "Email memory strings can reflect cached addresses or filenames; corroborate with mailbox/message artifacts.",
        "remote_access": "Remote-access memory strings are leads unless paired with session, event log, or application artifacts.",
        "windows_search": "Windows Search memory strings do not decrypt encrypted indexes by themselves; live collection may be required for keys/plaintext.",
        "file": "File/path memory strings show a path existed in memory or support files, not necessarily file open or copy activity.",
    }
    return caveats.get(family, "Memory correlations are leads and require source-specific corroboration.")


def artifact_processing_status_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    db.get_case(case_id)
    rows: list[dict[str, Any]] = []
    for artifact in memory_artifacts_report(db, case_id, limit=limit).get("artifacts") or []:
        rows.append(
            {
                "artifact_family": "memory",
                "artifact_type": artifact.get("artifact_type"),
                "path": artifact.get("path"),
                "status": artifact.get("processed_status") or "not_processed",
                "source": artifact.get("source"),
                "notes": artifact.get("notes"),
            }
        )
    for output in _query_report_rows(
        db,
        case_id,
        "tool_outputs",
        """
        SELECT tool_name, output_type, path, row_count, created_at
        FROM tool_outputs
        WHERE case_id = ?
        ORDER BY created_at DESC
        LIMIT ?
        """,
        (case_id, limit),
    ):
        rows.append(
            {
                "artifact_family": _tool_output_family(output.get("tool_name")),
                "artifact_type": output.get("tool_name"),
                "path": output.get("path"),
                "status": "processed" if int(output.get("row_count") or 0) >= 0 else "unknown",
                "row_count": output.get("row_count"),
                "source": "tool_outputs",
                "notes": output.get("output_type"),
            }
        )
    for timing in _query_report_rows(
        db,
        case_id,
        "process_timings",
        """
        SELECT scope, phase, name, status, tool_name, artifact_name, duration_ms, details_json, start_time, end_time
        FROM process_timings
        WHERE case_id = ?
          AND scope IN ('profile', 'artifact', 'tool', 'postprocess')
        ORDER BY COALESCE(start_time, '') DESC
        LIMIT ?
        """,
        (case_id, limit),
    ):
        details = _json_details(timing.get("details_json"))
        rows.append(
            {
                "artifact_family": "processing",
                "artifact_type": timing.get("scope"),
                "path": details.get("path") or details.get("output_path") or "",
                "status": timing.get("status"),
                "source": "process_timings",
                "tool_name": timing.get("tool_name"),
                "artifact_name": timing.get("artifact_name"),
                "task_name": timing.get("name"),
                "phase": timing.get("phase"),
                "duration_seconds": round(float(timing.get("duration_ms") or 0) / 1000, 3),
                "row_count": details.get("row_count") or details.get("count"),
                "notes": details.get("parallel_note") or details.get("error") or "",
            }
        )
    return {
        "case_id": case_id,
        "summary": {
            "item_count": len(rows),
            "status_counts": _count_by_key(rows, "status"),
            "family_counts": _count_by_key(rows, "artifact_family"),
        },
        "items": rows[:limit],
        "total_returned": min(len(rows), limit),
    }


def processing_decision_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    timings = process_timing_report(db, case_id, limit=max(limit * 5, 500))
    recovery = recovery_coverage_report(db, case_id, limit=max(limit * 5, 500))
    memory = memory_artifacts_report(db, case_id, limit=max(limit * 5, 500))
    credentials = memory_credentials_report(db, case_id, limit=limit)
    crash = crash_dump_analysis_report(db, case_id, limit=limit)
    issues = issues_report(db, case_id, limit=limit)
    decisions: list[dict[str, Any]] = []
    for row in timings.get("timings") or []:
        status = str(row.get("status") or "")
        details = row.get("details") if isinstance(row.get("details"), dict) else {}
        if row.get("scope") == "profile":
            decisions.append(
                {
                    "severity": "info" if status == "completed" else "high",
                    "decision_type": "profile",
                    "status": status,
                    "item": row.get("name"),
                    "summary": f"Profile {row.get('name')} {status}.",
                    "followup": "Review failed or running profile state before relying on downstream reports." if status != "completed" else "",
                    "details": {"duration_seconds": row.get("duration_seconds"), **details},
                }
            )
        elif status in {"failed", "source_not_present", "partial_limited"}:
            decisions.append(
                {
                    "severity": "high" if status == "failed" else "medium",
                    "decision_type": "processing_status",
                    "status": status,
                    "item": row.get("artifact_name") or row.get("tool_name") or row.get("name"),
                    "summary": _processing_decision_summary(row, details),
                    "followup": _processing_decision_followup(status, details),
                    "details": {"duration_seconds": row.get("duration_seconds"), **details},
                }
            )
    for item in recovery.get("artifacts") or []:
        if item.get("recovery_limited"):
            decisions.append(
                {
                    "severity": "medium",
                    "decision_type": "recovery_limit",
                    "status": item.get("status"),
                    "item": item.get("artifact_name"),
                    "summary": f"Recovery for {item.get('artifact_name')} stopped at {item.get('limit_reason')}.",
                    "followup": "Run a narrower deep profile or raise the guardrail only if this artifact is material.",
                    "details": item,
                }
            )
    unprocessed_memory = [
        row for row in memory.get("artifacts") or []
        if row.get("processed_status") != "processed"
    ]
    for row in unprocessed_memory[:limit]:
        decisions.append(
            {
                "severity": "medium" if row.get("artifact_type") in {"pagefile", "hiberfil", "swapfile"} else "low",
                "decision_type": "memory_followup",
                "status": row.get("processed_status"),
                "item": row.get("path"),
                "summary": f"{row.get('artifact_type')} is available but not processed.",
                "followup": "Run memory profile or crash-dumps processing when memory leads are in scope.",
                "details": row,
            }
        )
    if (credentials.get("summary") or {}).get("likely_usable_count") or (credentials.get("summary") or {}).get("possible_secret_count"):
        decisions.append(
            {
                "severity": "high",
                "decision_type": "credential_review",
                "status": "needs_review",
                "item": "memory_credentials",
                "summary": "Memory credential-like strings require examiner review.",
                "followup": "Run report memory-credentials with controlled reveal only if validation is authorized.",
                "details": credentials.get("summary"),
            }
        )
    if (crash.get("summary") or {}).get("dump_count"):
        decisions.append(
            {
                "severity": "low",
                "decision_type": "crash_dump_review",
                "status": "available",
                "item": "crash_dumps",
                "summary": "Crash or process dumps are available for memory-style review.",
                "followup": "Review crash-dump-analysis and correlate dump strings with WER/process context.",
                "details": crash.get("summary"),
            }
        )
    for issue in issues.get("issues") or []:
        if issue.get("level") in {"warning", "error"}:
            decisions.append(
                {
                    "severity": "high" if issue.get("level") == "error" else "medium",
                    "decision_type": "issue",
                    "status": issue.get("level"),
                    "item": issue.get("event"),
                    "summary": issue.get("message"),
                    "followup": "Review activity log details and rerun or document as a limitation.",
                    "details": issue,
                }
            )
    decisions = _dedupe_processing_decisions(decisions)
    decisions.sort(key=lambda row: (_severity_rank(row.get("severity")), str(row.get("decision_type") or ""), str(row.get("item") or "")))
    return {
        "case_id": case_id,
        "summary": {
            "decision_count": len(decisions),
            "severity_counts": _count_by_key(decisions, "severity"),
            "decision_type_counts": _count_by_key(decisions, "decision_type"),
            "recovery_limited_count": (recovery.get("summary") or {}).get("limited_count", 0),
            "unprocessed_memory_artifacts": len(unprocessed_memory),
            "credential_lead_count": (credentials.get("summary") or {}).get("credential_hit_count", 0),
            "crash_dump_count": (crash.get("summary") or {}).get("dump_count", 0),
        },
        "decisions": decisions[:limit],
        "inputs": {
            "recovery_coverage": recovery.get("summary"),
            "memory_artifacts": memory.get("summary"),
            "memory_credentials": credentials.get("summary"),
            "crash_dump_analysis": crash.get("summary"),
        },
        "total_returned": min(len(decisions), limit),
    }


def processing_decision_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Processing Decision Report",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Decisions: `{summary.get('decision_count', 0)}`",
        f"- Recovery limited artifacts: `{summary.get('recovery_limited_count', 0)}`",
        f"- Unprocessed memory artifacts: `{summary.get('unprocessed_memory_artifacts', 0)}`",
        f"- Credential leads: `{summary.get('credential_lead_count', 0)}`",
        f"- Crash dumps: `{summary.get('crash_dump_count', 0)}`",
        "",
        "## Decisions",
        "",
    ]
    rows = report.get("decisions") if isinstance(report.get("decisions"), list) else []
    if not rows:
        lines.append("- No processing decisions or follow-ups were identified.")
    for row in rows:
        lines.append(
            f"- `{row.get('severity')}` `{row.get('decision_type')}` `{row.get('status')}` "
            f"{row.get('item') or ''}: {row.get('summary') or ''}"
        )
        if row.get("followup"):
            lines.append(f"  - follow-up: {row.get('followup')}")
    return "\n".join(lines).rstrip() + "\n"


def processing_readiness_report(db: Database, case_id: str, *, limit: int = 100, profile: str | None = None) -> dict[str, Any]:
    case = db.get_case(case_id)
    timings = process_timing_report(db, case_id, limit=max(limit * 5, 500))
    memory = memory_artifacts_report(db, case_id, limit=max(limit * 5, 500))
    recovery = recovery_coverage_report(db, case_id, limit=max(limit * 5, 500))
    carve = carve_coverage_report(db, case_id, limit=max(limit * 5, 500))
    decisions = processing_decision_report(db, case_id, limit=max(limit, 100))
    items: list[dict[str, Any]] = []

    mount_rows = [
        dict(row)
        for row in db.conn.execute(
            """
            SELECT image_id, partition_id, volume_mount_path, raw_path, offset_bytes, created_at
            FROM mounts
            WHERE case_id = ?
            ORDER BY created_at DESC
            """,
            (case_id,),
        ).fetchall()
    ]
    active_mounts = [
        row for row in mount_rows
        if row.get("volume_mount_path") and _path_accessible(Path(str(row["volume_mount_path"])))
    ]
    profile_rows = [row for row in timings.get("timings") or [] if row.get("scope") == "profile"]
    artifact_rows = [row for row in timings.get("timings") or [] if row.get("scope") == "artifact"]
    tool_rows = [row for row in timings.get("timings") or [] if row.get("scope") == "tool"]
    postprocess_rows = [row for row in timings.get("timings") or [] if row.get("scope") == "postprocess"]
    worker_rows = timings.get("worker_requests") or []
    memory_summary = memory.get("summary") or {}
    memory_support_summary = memory_support_files_report(db, case_id, limit=max(limit, 100)).get("summary") or {}
    recovery_summary = recovery.get("summary") or {}
    carve_summary = carve.get("summary") or {}
    decision_summary = decisions.get("summary") or {}

    required_keys = _readiness_required_keys(profile)

    def add(key: str, title: str, complete: bool, details: dict[str, Any], next_step: str) -> None:
        required = required_keys is None or key in required_keys
        items.append(
            {
                "key": key,
                "title": title,
                "status": "complete" if complete else "needs_action",
                "required": required,
                "details": details,
                "next_step": "" if complete else next_step,
            }
        )

    add("case_exists", "Case is registered", True, {"case_root": str(case.root)}, "")
    add("mount_recorded", "At least one image mount is recorded", bool(mount_rows), {"mount_count": len(mount_rows)}, "Run image mount before broad profile processing.")
    add("mounted_volume_accessible", "Mounted-volume-first processing can access a filesystem", bool(active_mounts), {"active_mount_count": len(active_mounts)}, "Remount the target volume; mounted extraction avoids broad TSK fallback.")
    add("profile_run_recorded", "A processing profile has run", bool(profile_rows), {"profile_count": len(profile_rows)}, "Run an appropriate Windows profile.")
    add("parallel_workers_used", "Parallel workers have been exercised", any((row.get("requested_workers") or 1) > 1 for row in worker_rows), {"worker_requests": worker_rows[:10]}, "Run a profile or memory scan with --workers > 1.")
    add("artifact_extraction_timed", "Artifact extraction timings are present", bool(artifact_rows), {"artifact_timing_count": len(artifact_rows)}, "Run a profile with artifact extraction.")
    add("tool_parse_timed", "Tool parse timings are present", bool(tool_rows), {"tool_timing_count": len(tool_rows)}, "Run parser tools through a profile.")
    add("postprocess_timed", "Postprocess rebuild timings are present", bool(postprocess_rows), {"postprocess_count": len(postprocess_rows)}, "Run a profile that triggers postprocess rebuilds.")
    add("memory_inventory", "Memory-support artifacts are inventoried", bool(memory_summary.get("artifact_count")), memory_summary, "Run report memory-artifacts after mounting or parsing MFT.")
    add("pagefile_inventory", "Pagefile is represented when present", bool(memory_summary.get("pagefile_present")), memory_summary, "Confirm pagefile.sys exists or document absence.")
    add("swapfile_inventory", "Swapfile is represented when present", bool(memory_summary.get("swapfile_present")), memory_summary, "Confirm swapfile.sys exists or document absence.")
    add(
        "hiberfil_inventory",
        "Hiberfil status is assessed when present",
        not memory_summary.get("hiberfil_present")
        or any(row.get("hiberfil_status") for row in memory.get("artifacts") or [] if row.get("artifact_type") == "hiberfil")
        or bool(memory_support_summary.get("hiberfil_count")),
        {"memory": memory_summary, "memory_support": memory_support_summary},
        "Run memory-artifacts or memory-support-files against hiberfil.sys.",
    )
    add("crash_dump_inventory", "Crash/process dumps are inventoried", bool(memory_summary.get("crash_dump_present") or memory_summary.get("process_dump_present")), memory_summary, "Run memory crash-dumps when dumps exist or document absence.")
    add(
        "memory_processed",
        "Memory artifacts have been processed",
        bool(memory_summary.get("processed_count") or memory_support_summary.get("processed_count")),
        {"memory": memory_summary, "memory_support": memory_support_summary},
        "Run memory profile or memory crash-dumps.",
    )
    add("memory_support_report", "Memory support-file processing is summarized", bool(memory_support_summary.get("support_file_count")), memory_support_summary, "Run report memory-support-files after memory inventory.")
    add("memory_timeline", "Memory string hits can feed the timeline", _report_table_count(db, case_id, "memory_string_hits") == 0 or _report_table_count(db, case_id, "timeline_events") > 0, {"memory_string_hits": _report_table_count(db, case_id, "memory_string_hits"), "timeline_events": _report_table_count(db, case_id, "timeline_events")}, "Re-run memory processing or timeline rebuild.")
    add("carve_coverage", "Carve scan ranges or staged carves are tracked", bool(carve_summary.get("scan_range_count") or carve_summary.get("carve_count")), carve_summary, "Run explicit carve sqlite/ese commands for in-scope sources.")
    add("carve_empty_ranges", "Zero-hit carve ranges are recorded", bool(carve_summary.get("scan_range_count")), carve_summary, "Use chunked carve scanning so empty coverage is documented.")
    add("sqlite_inventory", "SQLite staged carve inventory is available when carves exist", not carve_summary.get("parsed_sqlite_count") or bool(sqlite_inventory_report(db, case_id, limit=1).get("summary", {}).get("sqlite_carves")), {"parsed_sqlite_count": carve_summary.get("parsed_sqlite_count")}, "Run report sqlite-inventory.")
    add(
        "recovery_coverage",
        "Recovery coverage is reportable",
        bool(recovery_summary.get("artifact_extracts_returned")),
        recovery_summary,
        "Run a balanced or deep recovery profile when deleted/orphaned artifact recovery is in scope.",
    )
    add("deep_recovery_separated", "Deep recovery is represented separately from windows-full", True, {"profiles": ["windows-basic-evtx-deep-recovery", "windows-browser-deep-recovery", "windows-full-deep-recovery"]}, "")
    add("windows_old_scoped", "Windows.old is tracked as a separate source scope", any(row.get("source_scope") == "Windows.old" for row in timings.get("timings") or []), {"windows_old_timings": sum(1 for row in timings.get("timings") or [] if row.get("source_scope") == "Windows.old")}, "Run windows-old or a profile that includes Windows.old when present.")
    add("combined_reports", "Combined disk/memory reports are available", True, {"reports": ["combined-artifacts", "memory-disk-correlations", "windows-search-combined"]}, "")
    add("ual_external_option", "UAL external parser option is checked", True, {"ual_timeliner": shutil.which("ual-timeliner") or os.environ.get("UAL_TIMELINER_BIN") or "not installed; internal parser fallback remains available"}, "")
    add("processing_decisions", "Processing decisions report has evaluated follow-ups", True, decision_summary, "")
    add("duckdb_write_serialized", "Same-case DuckDB writes are serialized", True, {"lock_file": "events.duckdb.write.lock"}, "")
    backlog_path = Path(__file__).resolve().parents[1] / "docs" / "OUTSTANDING_ITEMS.md"
    add("outstanding_backlog_documented", "Outstanding engineering backlog is documented", backlog_path.exists(), {"path": str(backlog_path)}, "Create or update docs/OUTSTANDING_ITEMS.md.")

    return {
        "case_id": case_id,
        "profile": profile or "",
        "summary": {
            "item_count": len(items),
            "complete_count": sum(1 for row in items if row["status"] == "complete"),
            "needs_action_count": sum(1 for row in items if row["status"] != "complete"),
            "required_needs_action_count": sum(1 for row in items if row.get("required", True) and row["status"] != "complete"),
        },
        "items": items[:limit],
        "total_returned": min(len(items), limit),
    }


def processing_readiness_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") or {}
    lines = [
        "# Processing Readiness Report",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Items: `{summary.get('item_count', 0)}`",
        f"- Complete: `{summary.get('complete_count', 0)}`",
        f"- Needs action: `{summary.get('needs_action_count', 0)}`",
        f"- Required needs action: `{summary.get('required_needs_action_count', summary.get('needs_action_count', 0))}`",
        "",
        "## Items",
        "",
    ]
    for row in report.get("items") or []:
        required = "required" if row.get("required", True) else "optional"
        lines.append(f"- `{row.get('status')}` `{required}` `{row.get('key')}` {row.get('title')}")
        if row.get("next_step"):
            lines.append(f"  - next: {row.get('next_step')}")
    return "\n".join(lines).rstrip() + "\n"


def deep_recovery_status_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    readiness = processing_readiness_report(db, case_id, limit=limit, profile="windows-full-deep-recovery")
    recovery = recovery_coverage_report(db, case_id, limit=max(limit, 250))
    carve = carve_coverage_report(db, case_id, limit=max(limit, 250))
    sqlite_inventory = sqlite_inventory_report(db, case_id, limit=limit)
    failed_required = [
        row for row in readiness.get("items") or []
        if row.get("required", True) and row.get("status") != "complete"
    ]
    recovery_summary = recovery.get("summary") if isinstance(recovery.get("summary"), dict) else {}
    carve_summary = carve.get("summary") if isinstance(carve.get("summary"), dict) else {}
    sqlite_summary = sqlite_inventory.get("summary") if isinstance(sqlite_inventory.get("summary"), dict) else {}
    return {
        "case_id": case_id,
        "profile": "windows-full-deep-recovery",
        "passed": not failed_required,
        "summary": {
            "required_needs_action_count": len(failed_required),
            "recovery_artifact_extracts_returned": recovery_summary.get("artifact_extracts_returned", 0),
            "tsk_recovery_artifacts": recovery_summary.get("tsk_recovery_artifacts", 0),
            "carve_scan_range_count": carve_summary.get("scan_range_count", 0),
            "carve_count": carve_summary.get("carve_count", 0),
            "parsed_sqlite_count": carve_summary.get("parsed_sqlite_count", 0),
            "sqlite_carves": sqlite_summary.get("sqlite_carves", 0),
            "readable_sqlite_carves": sqlite_summary.get("readable", 0),
        },
        "required_gaps": failed_required,
        "recovery_by_artifact": recovery.get("by_artifact") or [],
        "carve_source_coverage": carve_summary.get("source_coverage") if isinstance(carve_summary.get("source_coverage"), list) else [],
        "next_steps": [
            {
                "key": row.get("key"),
                "title": row.get("title"),
                "next_step": row.get("next_step"),
            }
            for row in failed_required
            if row.get("next_step")
        ],
        "notes": [
            "Deep recovery is an opt-in profile family separate from windows-full because it can be slower and noisier.",
            "Deleted/orphaned artifact recovery is tracked from TSK-backed extraction timings.",
            "Carve coverage is complete only for explicitly scanned ranges; unscanned bytes remain outside the report scope.",
        ],
        "readiness": readiness,
        "total_returned": len(failed_required),
    }


def deep_recovery_status_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Deep Recovery Status",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        f"Profile: `{report.get('profile') or ''}`",
        "",
        "## Summary",
        "",
        f"- Passed: `{bool(report.get('passed'))}`",
        f"- Required gaps: `{summary.get('required_needs_action_count', 0)}`",
        f"- TSK recovery artifacts: `{summary.get('tsk_recovery_artifacts', 0)}`",
        f"- Recovery artifact extracts returned: `{summary.get('recovery_artifact_extracts_returned', 0)}`",
        f"- Carve scan ranges: `{summary.get('carve_scan_range_count', 0)}`",
        f"- Staged carves: `{summary.get('carve_count', 0)}`",
        f"- Parsed SQLite carves: `{summary.get('parsed_sqlite_count', 0)}`",
        "",
        "## Required Gaps",
        "",
    ]
    gaps = report.get("required_gaps") if isinstance(report.get("required_gaps"), list) else []
    if not gaps:
        lines.append("- No required deep-recovery readiness gaps were found.")
    for row in gaps:
        lines.append(f"- `{row.get('key') or ''}` {row.get('title') or ''}: {row.get('next_step') or 'Review readiness details.'}")
    lines.extend(["", "## Recovery By Artifact", ""])
    artifacts = report.get("recovery_by_artifact") if isinstance(report.get("recovery_by_artifact"), list) else []
    if not artifacts:
        lines.append("- No TSK deleted/orphaned recovery artifact runs were found.")
    for row in artifacts[:25]:
        lines.append(
            f"- `{row.get('artifact_name') or ''}` runs `{row.get('runs') or 0}` "
            f"extracted `{row.get('extracted_count') or 0}` failed `{row.get('failed_count') or 0}` "
            f"duration `{row.get('duration_seconds') or 0}`s"
        )
    lines.extend(["", "## Carve Source Coverage", ""])
    coverage = report.get("carve_source_coverage") if isinstance(report.get("carve_source_coverage"), list) else []
    if not coverage:
        lines.append("- No carve source coverage rows were found.")
    for row in coverage[:25]:
        lines.append(
            f"- `{row.get('carve_type') or ''}` `{row.get('source_path') or ''}` "
            f"coverage `{row.get('coverage_percent') or 0}%` hits `{row.get('hits_found') or 0}`"
        )
    lines.extend(["", "## Notes", ""])
    for note in report.get("notes") or []:
        lines.append(f"- {note}")
    return "\n".join(lines).rstrip() + "\n"


def _readiness_required_keys(profile: str | None) -> set[str] | None:
    if not profile:
        return None
    normalized = profile.casefold()
    base = {
        "case_exists",
        "mount_recorded",
        "profile_run_recorded",
        "artifact_extraction_timed",
        "tool_parse_timed",
        "postprocess_timed",
        "combined_reports",
        "processing_decisions",
        "duckdb_write_serialized",
        "ual_external_option",
        "outstanding_backlog_documented",
    }
    memory = {
        "memory_inventory",
        "pagefile_inventory",
        "swapfile_inventory",
        "hiberfil_inventory",
        "memory_processed",
        "memory_support_report",
        "memory_timeline",
    }
    recovery = {
        "carve_coverage",
        "carve_empty_ranges",
        "sqlite_inventory",
        "recovery_coverage",
        "deep_recovery_separated",
    }
    if normalized in {"memory", "memory-profile"} or normalized.endswith("-memory"):
        return {"case_exists", *memory, "duckdb_write_serialized"}
    if "deep-recovery" in normalized or normalized.endswith("-deep"):
        return base | memory | recovery | {"parallel_workers_used"}
    if normalized.startswith("windows-full"):
        return base | memory | {"parallel_workers_used"}
    if normalized.startswith("windows-browser"):
        return base | {"carve_coverage", "sqlite_inventory"}
    if "windows-old" in normalized:
        return base | {"windows_old_scoped"}
    return base


def _processing_decision_summary(row: dict[str, Any], details: dict[str, Any]) -> str:
    status = row.get("status")
    name = row.get("artifact_name") or row.get("tool_name") or row.get("name")
    if status == "partial_limited":
        return f"{name} stopped at recovery limit {details.get('limit_reason') or 'unspecified'}."
    if status == "source_not_present":
        return f"{name} source was not present."
    return f"{name} {status}: {details.get('error') or 'review process timing details'}."


def _processing_decision_followup(status: str, details: dict[str, Any]) -> str:
    if status == "partial_limited":
        return "Accept as partial, narrow the artifact scope, or raise the limit with analyst approval."
    if status == "source_not_present":
        return "Document absence when expected; otherwise no action required."
    if status == "failed":
        return "Review stderr/details and rerun after fixing the parser or source issue."
    return ""


def _dedupe_processing_decisions(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, str, str]] = set()
    output: list[dict[str, Any]] = []
    for row in rows:
        key = (str(row.get("decision_type") or ""), str(row.get("status") or ""), str(row.get("item") or ""))
        if key in seen:
            continue
        seen.add(key)
        output.append(row)
    return output


def _tool_output_family(tool_name: Any) -> str:
    text = str(tool_name or "").casefold()
    if "memory" in text or "crash" in text:
        return "memory"
    if "browser" in text or "webcache" in text:
        return "browser"
    if "cloud" in text or "onedrive" in text or "drive" in text:
        return "cloud"
    if "mail" in text or "email" in text:
        return "email"
    if "rdp" in text or "vpn" in text or "remote" in text:
        return "remote_access"
    if "search" in text:
        return "windows_search"
    return "general"


def memory_artifacts_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    mounted = _mounted_memory_artifacts(db, case_id)
    mft = _mft_memory_artifacts(db, case_id, limit=limit)
    rows = _dedupe_memory_artifacts([*mounted, *mft])
    processed_sources = _processed_memory_sources(db, case_id)
    for row in rows:
        source_keys = {
            str(row.get("actual_path") or ""),
            str(row.get("path") or ""),
        }
        normalized_keys = {_normalize_memory_source_key(value) for value in source_keys if value}
        if normalized_keys.intersection(processed_sources):
            row["processed_status"] = "processed"
            row["notes"] = "Memory strings have been scanned for this artifact."
    rows.sort(key=lambda row: (row.get("artifact_type") or "", row.get("path") or ""))
    total_bytes = sum(int(row.get("size_bytes") or 0) for row in rows)
    return {
        "case_id": case_id,
        "summary": {
            "artifact_count": len(rows),
            "total_bytes": total_bytes,
            "hiberfil_present": any(row.get("artifact_type") == "hiberfil" for row in rows),
            "pagefile_present": any(row.get("artifact_type") == "pagefile" for row in rows),
            "swapfile_present": any(row.get("artifact_type") == "swapfile" for row in rows),
            "crash_dump_present": any(row.get("artifact_type") == "crash_dump" for row in rows),
            "process_dump_present": any(row.get("artifact_type") == "process_dump" for row in rows),
            "processed_count": sum(1 for row in rows if row.get("processed_status") == "processed"),
        },
        "artifacts": rows[:limit],
        "notes": [
            "This report inventories on-disk memory-adjacent artifacts. It does not parse memory contents.",
            "Use memory profile or crash-dumps processing to scan hiberfil, pagefile, swapfile, crash dumps, and full memory dumps.",
            "Hiberfil assessment is best-effort. Unsupported or compressed hiberfil data is reported as a caveat rather than failing the report.",
        ],
        "total_returned": min(len(rows), limit),
    }


def memory_artifacts_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") or {}
    lines = [
        "# Memory Artifact Inventory",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Artifacts: `{summary.get('artifact_count', 0)}`",
        f"- Total bytes: `{summary.get('total_bytes', 0)}`",
        f"- Hibernation file present: `{summary.get('hiberfil_present', False)}`",
        f"- Pagefile present: `{summary.get('pagefile_present', False)}`",
        f"- Swapfile present: `{summary.get('swapfile_present', False)}`",
        f"- Crash dump present: `{summary.get('crash_dump_present', False)}`",
        f"- Process dump present: `{summary.get('process_dump_present', False)}`",
        f"- Processed artifacts: `{summary.get('processed_count', 0)}`",
        "",
        "## Artifacts",
        "",
    ]
    rows = report.get("artifacts") or []
    if not rows:
        lines.append("- No on-disk memory artifacts were found.")
    for row in rows:
        lines.append(
            f"- `{row.get('artifact_type') or ''}` `{row.get('path') or ''}` "
            f"size `{row.get('size_bytes') or ''}` source `{row.get('source') or ''}` "
            f"status `{row.get('processed_status') or ''}`"
        )
        if row.get("hiberfil_status"):
            lines.append(f"  - hiberfil status: `{row.get('hiberfil_status')}` {row.get('hiberfil_note') or ''}")
    lines.extend(["", "## Notes", ""])
    for note in report.get("notes") or []:
        lines.append(f"- {note}")
    return "\n".join(lines).rstrip() + "\n"


def memory_support_files_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    artifacts = memory_artifacts_report(db, case_id, limit=max(limit, 5000)).get("artifacts") or []
    hits = _query_report_rows(
        db,
        case_id,
        "memory_string_hits",
        """
        SELECT source_artifact_type, source_path, scanned_path, decompressed_path,
               hit_category, COUNT(*) AS hit_count
        FROM memory_string_hits
        WHERE case_id = ?
        GROUP BY source_artifact_type, source_path, scanned_path, decompressed_path, hit_category
        """,
        (case_id,),
    )
    scan_activity = _memory_scan_activity_rows(db, case_id)
    scan_by_source: dict[str, dict[str, Any]] = {}
    scan_by_artifact_type: dict[str, dict[str, Any]] = {}
    for row in scan_activity:
        for key in ("source_path", "original_source_path", "scanned_path"):
            normalized = _normalize_memory_source_key(row.get(key))
            if normalized:
                scan_by_source[normalized] = row
        artifact_type = str(row.get("source_artifact_type") or row.get("artifact_type") or "")
        if artifact_type:
            scan_by_artifact_type.setdefault(artifact_type, row)
    hit_by_source: dict[str, dict[str, Any]] = {}
    for row in hits:
        keys = {
            _normalize_memory_source_key(row.get("source_path")),
            _normalize_memory_source_key(row.get("scanned_path")),
            _normalize_memory_source_key(row.get("decompressed_path")),
        }
        for key in keys:
            if not key:
                continue
            bucket = hit_by_source.setdefault(key, {"hit_count": 0, "categories": {}, "source_artifact_type": row.get("source_artifact_type")})
            count = int(row.get("hit_count") or 0)
            bucket["hit_count"] += count
            categories = bucket.setdefault("categories", {})
            categories[str(row.get("hit_category") or "unknown")] = int(categories.get(str(row.get("hit_category") or "unknown"), 0)) + count
    items: list[dict[str, Any]] = []
    seen: set[str] = set()
    for artifact in artifacts:
        keys = [
            _normalize_memory_source_key(artifact.get("actual_path")),
            _normalize_memory_source_key(artifact.get("path")),
        ]
        key = next((candidate for candidate in keys if candidate in hit_by_source or candidate in scan_by_source), keys[0] or keys[1] or "")
        if key in seen:
            continue
        seen.add(key)
        scan = scan_by_source.get(key) or scan_by_artifact_type.get(str(artifact.get("artifact_type") or "")) or {}
        if scan:
            for scan_key in ("source_path", "original_source_path", "scanned_path", "decompressed_path"):
                normalized_scan_key = _normalize_memory_source_key(scan.get(scan_key))
                if normalized_scan_key:
                    seen.add(normalized_scan_key)
        hit = hit_by_source.get(key, {})
        if not hit and scan:
            for scan_key in ("source_path", "original_source_path", "scanned_path", "decompressed_path"):
                hit = hit_by_source.get(_normalize_memory_source_key(scan.get(scan_key)), {})
                if hit:
                    break
        hit_count = int(hit.get("hit_count") or 0)
        processed = artifact.get("processed_status") == "processed" or bool(scan) or hit_count > 0
        items.append(
            {
                "artifact_type": artifact.get("artifact_type"),
                "path": artifact.get("path"),
                "actual_path": artifact.get("actual_path"),
                "source": artifact.get("source"),
                "size_bytes": artifact.get("size_bytes"),
                "entry_number": artifact.get("entry_number"),
                "sequence_number": artifact.get("sequence_number"),
                "processed_status": "processed" if processed else "not_processed",
                "scan_status": scan.get("status") or ("scanned" if hit_count else ""),
                "hit_count": hit_count,
                "categories": hit.get("categories") or {},
                "scanner": scan.get("scanner") or "",
                "decompress_status": scan.get("decompress_status") or "",
                "decompress_error": scan.get("decompress_error") or "",
                "decompress_command": scan.get("decompress_command") or "",
                "decompress_attempt_count": scan.get("decompress_attempt_count") or "",
                "extract_status": scan.get("extract_status") or "",
                "extract_command": scan.get("extract_command") or "",
                "source_size_bytes": scan.get("source_size_bytes") or "",
                "scanned_size_bytes": scan.get("scanned_size_bytes") or "",
                "hiberfil_status": scan.get("hiberfil_status") or artifact.get("hiberfil_status") or "",
                "hiberfil_note": scan.get("hiberfil_note") or artifact.get("hiberfil_note") or "",
                "scanned_path": scan.get("scanned_path") or "",
                "output": scan.get("output") or "",
                "imported_rows": scan.get("imported_rows"),
                "notes": artifact.get("notes"),
            }
        )
    for key, hit in hit_by_source.items():
        if key in seen:
            continue
        seen.add(key)
        scan = scan_by_source.get(key, {})
        items.append(
            {
                "artifact_type": hit.get("source_artifact_type") or scan.get("source_artifact_type") or "",
                "path": scan.get("source_path") or key,
                "actual_path": scan.get("source_path") or key,
                "source": "memory_string_hits",
                "processed_status": "processed",
                "scan_status": scan.get("status") or "scanned",
                "hit_count": int(hit.get("hit_count") or 0),
                "categories": hit.get("categories") or {},
                "scanner": scan.get("scanner") or "",
                "decompress_status": scan.get("decompress_status") or "",
                "decompress_error": scan.get("decompress_error") or "",
                "decompress_command": scan.get("decompress_command") or "",
                "decompress_attempt_count": scan.get("decompress_attempt_count") or "",
                "extract_status": scan.get("extract_status") or "",
                "extract_command": scan.get("extract_command") or "",
                "source_size_bytes": scan.get("source_size_bytes") or "",
                "scanned_size_bytes": scan.get("scanned_size_bytes") or "",
                "hiberfil_status": scan.get("hiberfil_status") or "",
                "hiberfil_note": scan.get("hiberfil_note") or "",
                "scanned_path": scan.get("scanned_path") or "",
                "output": scan.get("output") or "",
                "imported_rows": scan.get("imported_rows"),
                "notes": "Processed memory source not present in current artifact inventory.",
            }
        )
    for key, scan in scan_by_source.items():
        if key in seen or key in hit_by_source:
            continue
        seen.add(key)
        items.append(
            {
                "artifact_type": scan.get("source_artifact_type") or scan.get("artifact_type") or "",
                "path": scan.get("original_source_path") or scan.get("source_path") or key,
                "actual_path": scan.get("source_path") or key,
                "source": "activity_log",
                "processed_status": "processed",
                "scan_status": scan.get("status") or "scanned",
                "hit_count": int(scan.get("imported_rows") or 0),
                "categories": {},
                "scanner": scan.get("scanner") or "",
                "decompress_status": scan.get("decompress_status") or "",
                "decompress_error": scan.get("decompress_error") or "",
                "decompress_command": scan.get("decompress_command") or "",
                "decompress_attempt_count": scan.get("decompress_attempt_count") or "",
                "extract_status": scan.get("extract_status") or "",
                "extract_command": scan.get("extract_command") or "",
                "source_size_bytes": scan.get("source_size_bytes") or "",
                "scanned_size_bytes": scan.get("scanned_size_bytes") or "",
                "hiberfil_status": scan.get("hiberfil_status") or "",
                "hiberfil_note": scan.get("hiberfil_note") or "",
                "scanned_path": scan.get("scanned_path") or "",
                "output": scan.get("output") or "",
                "imported_rows": scan.get("imported_rows"),
                "notes": "Processed memory source recorded in activity log with no imported string hits.",
            }
        )
    items.sort(key=lambda row: (str(row.get("artifact_type") or ""), str(row.get("path") or "")))
    return {
        "case_id": case_id,
        "summary": {
            "support_file_count": len(items),
            "processed_count": sum(1 for row in items if row.get("processed_status") == "processed"),
            "not_processed_count": sum(1 for row in items if row.get("processed_status") != "processed"),
            "hit_count": sum(int(row.get("hit_count") or 0) for row in items),
            "hiberfil_count": sum(1 for row in items if row.get("artifact_type") == "hiberfil"),
            "decompress_caveat_count": sum(1 for row in items if row.get("decompress_status") and row.get("decompress_status") != "decompressed" and row.get("decompress_status") != "not_applicable"),
            "sources": _count_by_key(items, "artifact_type"),
        },
        "support_files": items[:limit],
        "total_returned": min(len(items), limit),
        "caveats": [
            "A processed memory support file means targeted string scanning completed or produced logged scan metadata.",
            "Zero imported rows is a useful negative result when the scan status and source file are recorded.",
            "Hiberfil decompression failures are reported as caveats; raw-file string scans may still produce leads but are not equivalent to full decompression.",
        ],
    }


def memory_support_files_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Memory Support File Processing",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Support files: `{summary.get('support_file_count', 0)}`",
        f"- Processed: `{summary.get('processed_count', 0)}`",
        f"- Not processed: `{summary.get('not_processed_count', 0)}`",
        f"- Memory string hits: `{summary.get('hit_count', 0)}`",
        f"- Hiberfil files: `{summary.get('hiberfil_count', 0)}`",
        f"- Decompression caveats: `{summary.get('decompress_caveat_count', 0)}`",
        "",
        "## Files",
        "",
    ]
    rows = report.get("support_files") if isinstance(report.get("support_files"), list) else []
    if not rows:
        lines.append("- No memory support files were inventoried.")
    for row in rows:
        category_text = ", ".join(f"{key}:{value}" for key, value in sorted((row.get("categories") or {}).items()))
        lines.append(
            f"- `{row.get('artifact_type') or ''}` `{row.get('processed_status') or ''}` "
            f"hits `{row.get('hit_count') or 0}` path `{row.get('path') or ''}`"
        )
        details = []
        if row.get("scan_status"):
            details.append(f"scan `{row.get('scan_status')}`")
        if row.get("scanner"):
            details.append(f"scanner `{row.get('scanner')}`")
        if row.get("decompress_status"):
            details.append(f"decompress `{row.get('decompress_status')}`")
        if row.get("extract_status"):
            details.append(f"extract `{row.get('extract_status')}`")
        if category_text:
            details.append(f"categories `{category_text}`")
        if details:
            lines.append(f"  - {'; '.join(details)}")
        if row.get("source_size_bytes") or row.get("scanned_size_bytes"):
            lines.append(
                f"  - sizes: source `{row.get('source_size_bytes') or ''}` scanned `{row.get('scanned_size_bytes') or ''}`"
            )
        if row.get("hiberfil_status"):
            lines.append(f"  - hiberfil `{row.get('hiberfil_status')}` {row.get('hiberfil_note') or ''}")
        if row.get("decompress_command"):
            lines.append(f"  - decompression command: `{row.get('decompress_command')}`")
        if row.get("extract_command"):
            lines.append(f"  - extraction command: `{row.get('extract_command')}`")
        if row.get("decompress_error"):
            lines.append(f"  - decompression caveat: `{str(row.get('decompress_error'))[:180]}`")
    lines.extend(["", "## Caveats", ""])
    for caveat in report.get("caveats") or []:
        lines.append(f"- {caveat}")
    return "\n".join(lines).rstrip() + "\n"


def structured_memory_report(
    db: Database,
    case_id: str,
    *,
    category: str | None = None,
    process: str | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    db.get_case(case_id)
    filters = ["case_id = ?"]
    params: list[Any] = [case_id]
    if category:
        filters.append("category = ?")
        params.append(category)
    if process:
        filters.append("(process_name LIKE ? OR command_line LIKE ? OR pid = ?)")
        params.extend([f"%{process}%", f"%{process}%", process])
    where = " AND ".join(filters)
    rows = _query_report_rows(
        db,
        case_id,
        "structured_memory_records",
        f"""
        SELECT *
        FROM structured_memory_records
        WHERE {where}
        ORDER BY analysis_engine, plugin, row_number
        LIMIT ?
        """,
        (*params, limit),
    )
    counts = _query_report_rows(
        db,
        case_id,
        "structured_memory_records",
        f"""
        SELECT analysis_engine, plugin, category, COUNT(*) AS count
        FROM structured_memory_records
        WHERE {where}
        GROUP BY analysis_engine, plugin, category
        ORDER BY analysis_engine, plugin, category
        """,
        tuple(params),
    )
    attempts = _structured_memory_activity_rows(db, case_id)
    return {
        "case_id": case_id,
        "summary": {
            "result_count": len(rows),
            "limit": limit,
            "limited": len(rows) >= limit,
            "total_record_count": sum(int(row.get("count") or 0) for row in counts),
            "attempt_count": len(attempts),
            "category_counts": _count_by_key(rows, "category"),
            "engine_counts": _count_by_key(rows, "analysis_engine"),
            "suspicious_count": sum(1 for row in rows if str(row.get("suspicious") or "").lower() == "true"),
            "architecture_limitations": _structured_memory_limitations(attempts),
            "filters": {"category": category or "", "process": process or ""},
        },
        "counts": counts,
        "attempts": attempts,
        "records": rows,
        "caveats": [
            "Structured memory rows are parsed summaries of Volatility or MemProcFS output; preserve raw output files for detailed validation.",
            "Not every plugin has event timestamps. Process, network, file-object, and handle rows are primarily state-at-capture evidence.",
            "Report output may be limited. Increase --limit or query a category/process-specific view for the full record set.",
        ],
    }


def structured_memory_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Structured Memory Analysis",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Records shown: `{summary.get('result_count', 0)}`",
        f"- Total matching records: `{summary.get('total_record_count', 0)}`",
        f"- Run attempts: `{summary.get('attempt_count', 0)}`",
        f"- Limited: `{summary.get('limited', False)}`",
        f"- Suspicious rows shown: `{summary.get('suspicious_count', 0)}`",
        "",
        "## Plugin Counts",
        "",
    ]
    limitations = summary.get("architecture_limitations") if isinstance(summary.get("architecture_limitations"), list) else []
    if limitations:
        lines.extend(["## Limitations", ""])
        for limitation in limitations:
            lines.append(f"- {limitation}")
        lines.append("")
    for row in report.get("counts") or []:
        lines.append(
            f"- `{row.get('analysis_engine') or ''}` `{row.get('plugin') or ''}` "
            f"`{row.get('category') or ''}` count `{row.get('count') or 0}`"
        )
    lines.extend(["", "## Run Attempts", ""])
    attempts = report.get("attempts") if isinstance(report.get("attempts"), list) else []
    if not attempts:
        lines.append("- No structured memory run attempts were recorded.")
    for attempt in attempts[:25]:
        lines.append(
            f"- `{attempt.get('created_at') or ''}` source `{attempt.get('source_artifact_type') or ''}` "
            f"imported `{attempt.get('imported_rows') or 0}` output `{attempt.get('output') or ''}`"
        )
        for run in attempt.get("runs") or []:
            if not isinstance(run, dict):
                continue
            lines.append(
                f"  - `{run.get('engine') or ''}` `{run.get('plugin') or ''}` "
                f"status `{run.get('status') or ''}` records `{run.get('record_count') or 0}`"
            )
            if run.get("detected_os") or run.get("detected_architecture"):
                lines.append(f"    - detected: `{run.get('detected_os') or run.get('detected_architecture')}`")
            if run.get("limitation"):
                lines.append(f"    - limitation: {run.get('limitation')}")
    lines.extend(["", "## Records", ""])
    records = report.get("records") if isinstance(report.get("records"), list) else []
    if not records:
        lines.append("- No structured memory records matched.")
    for row in records[:50]:
        lines.append(
            f"- `{row.get('analysis_engine') or ''}` `{row.get('category') or ''}` "
            f"pid `{row.get('pid') or ''}` process `{row.get('process_name') or ''}` "
            f"{row.get('summary') or row.get('path') or row.get('object_name') or ''}"
        )
    lines.extend(["", "## Caveats", ""])
    for caveat in report.get("caveats") or []:
        lines.append(f"- {caveat}")
    return "\n".join(lines).rstrip() + "\n"


def _structured_memory_activity_rows(db: Database, case_id: str) -> list[dict[str, Any]]:
    rows = db.conn.execute(
        """
        SELECT created_at, level, event, message, details_json
        FROM activity_log
        WHERE case_id = ?
          AND event = 'memory.structured_analyzed'
        ORDER BY created_at DESC
        LIMIT 50
        """,
        (case_id,),
    ).fetchall()
    output: list[dict[str, Any]] = []
    for row in rows:
        details = _json_details(row["details_json"])
        output.append(
            {
                "created_at": row["created_at"],
                "level": row["level"],
                "event": row["event"],
                "message": row["message"],
                "source_path": details.get("source_path"),
                "source_artifact_type": details.get("source_artifact_type"),
                "output": details.get("output"),
                "imported_rows": details.get("imported_rows"),
                "runs": details.get("runs") if isinstance(details.get("runs"), list) else [],
            }
        )
    return output


def _structured_memory_limitations(attempts: list[dict[str, Any]]) -> list[str]:
    values: list[str] = []
    seen: set[str] = set()
    for attempt in attempts:
        for run in attempt.get("runs") or []:
            if not isinstance(run, dict):
                continue
            value = str(run.get("limitation") or "").strip()
            if value and value not in seen:
                seen.add(value)
                values.append(value)
    return values


def memory_analysis_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    artifacts = memory_artifacts_report(db, case_id, limit=max(limit, 1000))
    support_files = memory_support_files_report(db, case_id, limit=max(limit, 1000))
    structured_memory = structured_memory_report(db, case_id, limit=max(limit, 1000))
    string_hits = memory_string_hits_report(db, case_id, limit=limit)
    search_status = _windows_search_parser_status(db, case_id)
    workflow = _memory_processing_workflow(case_id, (artifacts.get("artifacts") or []) + (support_files.get("support_files") or []))
    useful_hits = _memory_useful_hits(string_hits.get("hits") or [], limit=limit)
    search_assessment = _memory_windows_search_assessment(search_status, string_hits)
    findings = _memory_analysis_findings(artifacts, string_hits, search_assessment)
    hiberfil_structured = _hiberfil_structured_analysis_status(support_files.get("support_files") or artifacts.get("artifacts") or [])
    return {
        "case_id": case_id,
        "summary": {
            "memory_artifact_count": (artifacts.get("summary") or {}).get("artifact_count", 0),
            "hiberfil_present": (artifacts.get("summary") or {}).get("hiberfil_present", False),
            "hiberfil_structured_status": hiberfil_structured.get("status"),
            "pagefile_present": (artifacts.get("summary") or {}).get("pagefile_present", False),
            "swapfile_present": (artifacts.get("summary") or {}).get("swapfile_present", False),
            "crash_dump_present": (artifacts.get("summary") or {}).get("crash_dump_present", False),
            "memory_string_hit_count": (string_hits.get("summary") or {}).get("hit_count", 0),
            "structured_memory_record_count": (structured_memory.get("summary") or {}).get("total_record_count", 0),
            "structured_memory_attempt_count": (structured_memory.get("summary") or {}).get("attempt_count", 0),
            "useful_memory_hit_count": len(useful_hits),
            "windows_search_status": search_status.get("summary_status"),
            "windows_search_memory_result": search_assessment.get("result"),
            "workflow_step_count": len(workflow),
            "finding_count": len(findings),
        },
        "tool_availability": _memory_tool_availability(),
        "workflow": workflow,
        "hiberfil_structured_analysis": hiberfil_structured,
        "artifacts": (artifacts.get("artifacts") or [])[:limit],
        "memory_support_summary": support_files.get("summary") or {},
        "structured_memory_summary": structured_memory.get("summary") or {},
        "structured_memory_counts": structured_memory.get("counts") or [],
        "memory_string_summary": string_hits.get("summary") or {},
        "useful_hits": useful_hits,
        "windows_search_assessment": search_assessment,
        "findings": findings,
        "caveats": [
            "Memory strings and recovered pages are investigative leads unless corroborated by stronger artifacts.",
            "Crash dumps can contain process-local memory. Treat crash-dump strings as memory leads and correlate with WER/process context before reporting conclusions.",
            "For encrypted Windows 11 Search SQLite databases, offline hiberfil/pagefile/swapfile scans may not recover the live AES-GCM material.",
            "The DPAPI/LSA workflow is a validation path, not a conclusion; report it only after extracted keys successfully decrypt the target database.",
            "To maximize Windows Search plaintext/key recovery, collect RAM while the relevant user session and SearchIndexer.exe are still live.",
        ],
    }


def _hiberfil_structured_analysis_status(rows: list[dict[str, Any]]) -> dict[str, Any]:
    hiberfils = [row for row in rows if str(row.get("artifact_type") or "").casefold() == "hiberfil"]
    if not hiberfils:
        return {
            "status": "not_present",
            "ready_for_structured_memory_analysis": False,
            "summary": "No hiberfil.sys artifact was inventoried for this case.",
            "caveat": "",
        }
    decompressed = [row for row in hiberfils if str(row.get("decompress_status") or "").casefold() == "decompressed" or row.get("decompressed_path")]
    scanned = [row for row in hiberfils if row.get("processed_status") == "processed" or row.get("scan_status")]
    failed = [row for row in hiberfils if row.get("decompress_status") and str(row.get("decompress_status")).casefold() not in {"decompressed", "not_applicable"}]
    if decompressed:
        return {
            "status": "decompressed_ready",
            "ready_for_structured_memory_analysis": True,
            "summary": "At least one hiberfil source has decompressed output recorded and can be treated as the best available structured-memory candidate.",
            "decompressed_paths": [row.get("decompressed_path") or row.get("scanned_path") for row in decompressed if row.get("decompressed_path") or row.get("scanned_path")],
            "caveat": "Run Volatility/MemProcFS validation where supported; decompressed hiberfil output is not always equivalent to a full live-memory capture.",
        }
    if scanned:
        return {
            "status": "scanned_without_structured_decompression",
            "ready_for_structured_memory_analysis": False,
            "summary": "Hiberfil was scanned for strings or leads, but no decompressed structured-memory output is recorded.",
            "caveat": "String scanning can produce leads but should not be reported as full hiberfil memory analysis.",
        }
    if failed:
        return {
            "status": "decompression_failed",
            "ready_for_structured_memory_analysis": False,
            "summary": "Hiberfil decompression was attempted but did not produce structured-memory output.",
            "errors": [str(row.get("decompress_error") or "")[:500] for row in failed if row.get("decompress_error")],
            "caveat": "This is an expected recoverable condition; reports should record the caveat and continue with other artifacts.",
        }
    return {
        "status": "present_not_processed",
        "ready_for_structured_memory_analysis": False,
        "summary": "Hiberfil is present but no hiberfil processing result is recorded.",
        "caveat": "Run the memory profile if hibernation-time process/network/context analysis is in scope.",
    }


def memory_analysis_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Memory Processing and Analysis",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Memory artifacts: `{summary.get('memory_artifact_count', 0)}`",
        f"- Hiberfil/pagefile/swapfile/crash present: `{summary.get('hiberfil_present', False)}` / `{summary.get('pagefile_present', False)}` / `{summary.get('swapfile_present', False)}` / `{summary.get('crash_dump_present', False)}`",
        f"- Hiberfil structured status: `{summary.get('hiberfil_structured_status') or ''}`",
        f"- Memory string hits: `{summary.get('memory_string_hit_count', 0)}`",
        f"- Structured memory records: `{summary.get('structured_memory_record_count', 0)}`",
        f"- Structured memory attempts: `{summary.get('structured_memory_attempt_count', 0)}`",
        f"- Useful memory hits: `{summary.get('useful_memory_hit_count', 0)}`",
        f"- Windows Search status: `{summary.get('windows_search_status') or ''}`",
        f"- Windows Search memory result: `{summary.get('windows_search_memory_result') or ''}`",
        "",
        "## Tool Availability",
        "",
    ]
    for row in report.get("tool_availability") or []:
        lines.append(f"- `{row.get('tool')}`: `{row.get('status')}` {row.get('path') or ''}")
    lines.extend(["", "## Workflow", ""])
    for step in report.get("workflow") or []:
        lines.append(f"- `{step.get('step')}` {step.get('purpose')}")
        command = step.get("command")
        if command:
            lines.append(f"  - command: `{command}`")
        if step.get("output"):
            lines.append(f"  - output: {step.get('output')}")
    structured = report.get("hiberfil_structured_analysis") if isinstance(report.get("hiberfil_structured_analysis"), dict) else {}
    lines.extend(["", "## Hiberfil Structured Analysis", ""])
    lines.append(f"- Status: `{structured.get('status') or ''}`")
    lines.append(f"- Ready: `{structured.get('ready_for_structured_memory_analysis', False)}`")
    if structured.get("summary"):
        lines.append(f"- Summary: {structured.get('summary')}")
    if structured.get("caveat"):
        lines.append(f"- Caveat: {structured.get('caveat')}")
    lines.extend(["", "## Structured Tool Output", ""])
    structured_summary = report.get("structured_memory_summary") if isinstance(report.get("structured_memory_summary"), dict) else {}
    lines.append(f"- Total records: `{structured_summary.get('total_record_count', 0)}`")
    lines.append(f"- Limited: `{structured_summary.get('limited', False)}`")
    for row in report.get("structured_memory_counts") or []:
        lines.append(
            f"- `{row.get('analysis_engine') or ''}` `{row.get('plugin') or ''}` "
            f"`{row.get('category') or ''}` count `{row.get('count') or 0}`"
        )
    lines.extend(["", "## Findings", ""])
    findings = report.get("findings") if isinstance(report.get("findings"), list) else []
    if not findings:
        lines.append("- No memory-analysis findings were produced.")
    for finding in findings:
        lines.append(
            f"- `{finding.get('severity') or ''}` `{finding.get('category') or ''}` "
            f"{finding.get('title') or ''}: {finding.get('summary') or ''}"
        )
    lines.extend(["", "## Useful String Hits", ""])
    hits = report.get("useful_hits") if isinstance(report.get("useful_hits"), list) else []
    if not hits:
        lines.append("- No targeted memory string hits were imported.")
    for hit in hits[:25]:
        lines.append(
            f"- `{hit.get('hit_category') or ''}` `{hit.get('matched_term') or ''}` "
            f"source `{hit.get('source_artifact_type') or ''}` offset `{hit.get('offset') or ''}` "
            f"{hit.get('context_hint') or ''}"
        )
    lines.extend(["", "## Windows Search Assessment", ""])
    assessment = report.get("windows_search_assessment") if isinstance(report.get("windows_search_assessment"), dict) else {}
    lines.append(f"- Result: `{assessment.get('result') or ''}`")
    lines.append(f"- Recommendation: {assessment.get('recommendation') or ''}")
    if assessment.get("note"):
        lines.append(f"- Note: {assessment.get('note')}")
    lines.extend(["", "## Caveats", ""])
    for caveat in report.get("caveats") or []:
        lines.append(f"- {caveat}")
    return "\n".join(lines).rstrip() + "\n"


