def _crash_dump_metadata(
    artifacts: list[dict[str, Any]],
    wer_rows: list[dict[str, Any]],
    string_rows: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    string_counts: dict[str, int] = {}
    for row in string_rows:
        path = str(row.get("source_path") or "")
        if path:
            string_counts[path.casefold()] = string_counts.get(path.casefold(), 0) + int(row.get("count") or 0)
    output: list[dict[str, Any]] = []
    for artifact in artifacts:
        path = str(artifact.get("actual_path") or artifact.get("path") or "")
        name = _basename(path) or ""
        access_status = "accessible" if artifact.get("actual_path") and Path(str(artifact.get("actual_path"))).exists() else "metadata_only"
        wer_match = next(
            (
                row for row in wer_rows
                if name and name.casefold() in " ".join(str(row.get(field) or "") for field in ("source_file", "report_folder", "ui_path")).casefold()
            ),
            None,
        )
        output.append(
            {
                "dump_path": artifact.get("path"),
                "dump_name": name,
                "dump_type": artifact.get("artifact_type"),
                "size_bytes": artifact.get("size_bytes"),
                "access_status": access_status,
                "string_hit_groups": string_counts.get(path.casefold(), 0) or string_counts.get(str(artifact.get("path") or "").casefold(), 0),
                "likely_application": (wer_match or {}).get("app_name") or (wer_match or {}).get("original_filename"),
                "exception_code": (wer_match or {}).get("exception_code"),
                "event_time_utc": (wer_match or {}).get("event_time_utc"),
            }
        )
    return output


_MEMORY_CREDENTIAL_ASSIGNMENT_RE = re.compile(
    r"(?i)\b(?P<name>password|passwd|pwd|token|bearer|refresh_token|credential|secret|apikey|api_key)"
    r"[\w .:/\\-]{0,32}(?:=|:)\s*[\"']?(?P<secret>[A-Za-z0-9._~+/=-]{4,})"
)
_MEMORY_BEARER_RE = re.compile(r"(?i)\bbearer\s+(?P<secret>[A-Za-z0-9._~+/=-]{12,})")
_MEMORY_EMAIL_RE = re.compile(r"(?i)\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b")
_MEMORY_URL_RE = re.compile(r"(?i)\bhttps?://[^\s\"'<>]+")
_MEMORY_WINDOWS_PATH_RE = re.compile(r"(?i)(?:[A-Z]:\\|\\\\|\\Users\\|/Users/)[^\s\"'<>|]{4,}")


def _assess_memory_credential_hit(value: Any, matched_term: Any) -> dict[str, str]:
    text = str(value or "")
    lowered = text.lower()
    if not text.strip():
        return {
            "credential_status": "label_or_false_positive",
            "credential_validation_status": "not_usable",
            "credential_reason": "Empty memory string.",
        }
    false_positive_terms = (
        "publickeytoken",
        "cancellationtoken",
        "securitytokenreference",
        "tokenbinding",
        "passwordchar",
        "passwordbox",
        "credential provider",
        "credentialprovider",
        "credential manager",
        "decrypted password isransom:",
        "ransom:win32",
    )
    if any(term in lowered for term in false_positive_terms):
        return {
            "credential_status": "label_or_false_positive",
            "credential_validation_status": "not_usable",
            "credential_reason": "Known token/password label or API type, not a secret value.",
        }
    assignment = _MEMORY_CREDENTIAL_ASSIGNMENT_RE.search(text) or _MEMORY_BEARER_RE.search(text)
    if assignment:
        secret = assignment.group("secret")
        if _memory_secret_is_placeholder(secret):
            return {
                "credential_status": "label_or_false_positive",
                "credential_validation_status": "not_usable",
                "credential_reason": "Credential assignment value is a common placeholder or field name.",
            }
        term = str(matched_term or "").lower()
        if term in {"password", "passwd", "pwd="} and len(secret) < 8:
            return {
                "credential_status": "possible_secret",
                "credential_validation_status": "candidate_unverified",
                "credential_reason": "Password-like assignment has a short value and needs manual validation.",
            }
        if len(secret) >= 12 or term in {"refresh_token", "bearer "}:
            return {
                "credential_status": "likely_usable_secret",
                "credential_validation_status": "candidate_unverified",
                "credential_reason": "Credential keyword is paired with an assigned value or bearer token.",
            }
        return {
            "credential_status": "possible_secret",
            "credential_validation_status": "candidate_unverified",
            "credential_reason": "Credential keyword has an assigned value but the value is short.",
        }
    if re.search(r"(?i)\b(token|password|passwd|credential)\b", text):
        return {
            "credential_status": "possible_secret",
            "credential_validation_status": "candidate_unverified",
            "credential_reason": "Credential keyword present without a clear extractable value.",
        }
    return {
        "credential_status": "label_or_false_positive",
        "credential_validation_status": "not_usable",
        "credential_reason": "No clear credential assignment pattern was found.",
    }


def _redact_memory_credential(value: Any) -> str:
    text = str(value or "")
    if not text:
        return ""
    redacted = _MEMORY_CREDENTIAL_ASSIGNMENT_RE.sub(lambda match: f"{match.group('name')}=<redacted:{_short_hash(match.group('secret'))}>", text)
    redacted = _MEMORY_BEARER_RE.sub(lambda match: f"Bearer <redacted:{_short_hash(match.group('secret'))}>", redacted)
    if redacted != text:
        return redacted[:240]
    return f"<redacted-context:{_short_hash(text)}>"


def _memory_credential_score(row: dict[str, Any]) -> dict[str, Any]:
    status = str(row.get("credential_status") or "")
    text = str(row.get("string_value") or "")
    matched = str(row.get("matched_term") or "").casefold()
    score = 0
    reasons: list[str] = []
    if status == "likely_usable_secret":
        score += 70
        reasons.append("assignment_or_bearer_pattern")
    elif status == "possible_secret":
        score += 35
        reasons.append("credential_keyword_present")
    if matched in {"bearer ", "refresh_token", "token"}:
        score += 15
        reasons.append("token_term")
    assignment = _MEMORY_CREDENTIAL_ASSIGNMENT_RE.search(text) or _MEMORY_BEARER_RE.search(text)
    if assignment:
        secret = assignment.group("secret")
        if len(secret) >= 24:
            score += 10
            reasons.append("long_secret_value")
        if re.search(r"[A-Za-z]", secret) and re.search(r"\d", secret):
            score += 5
            reasons.append("mixed_alpha_numeric")
    if _MEMORY_URL_RE.search(text) or _MEMORY_EMAIL_RE.search(text):
        score += 5
        reasons.append("service_context_present")
    if status == "label_or_false_positive":
        score = 0
    score = max(0, min(score, 100))
    if score >= 75:
        triage = "high_value_candidate"
    elif score >= 35:
        triage = "review_candidate"
    else:
        triage = "low_value_or_noise"
    return {
        "credential_score": score,
        "credential_triage": triage,
        "credential_score_reasons": ",".join(reasons),
    }


def _memory_secret_is_placeholder(value: Any) -> bool:
    text = str(value or "").strip().strip("\"'").casefold()
    if not text:
        return True
    placeholders = {
        "password",
        "passwd",
        "pwd",
        "token",
        "bearer",
        "credential",
        "secret",
        "changeme",
        "example",
        "sample",
        "null",
        "none",
        "undefined",
        "the",
        "true",
        "false",
    }
    return text in placeholders or bool(re.fullmatch(r"(x+|\*+|#+|0+|1+|a+|test|dummy)", text))


def _short_hash(value: Any) -> str:
    return hashlib.sha256(str(value or "").encode("utf-8", errors="replace")).hexdigest()[:12]


def _dedupe_memory_credentials(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, str, str, str]] = set()
    output: list[dict[str, Any]] = []
    for row in rows:
        key = (
            str(row.get("credential_status") or ""),
            str(row.get("matched_term") or "").casefold(),
            str(row.get("string_sha256") or _short_hash(row.get("string_value"))),
            str(row.get("source_artifact_type") or ""),
        )
        if key in seen:
            continue
        seen.add(key)
        output.append(row)
    status_order = {"likely_usable_secret": 0, "possible_secret": 1, "label_or_false_positive": 2}
    output.sort(key=lambda row: (status_order.get(str(row.get("credential_status") or ""), 9), str(row.get("source_artifact_type") or ""), str(row.get("offset") or "")))
    return output


def _memory_credential_groups(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    grouped: dict[tuple[str, str, str], dict[str, Any]] = {}
    for row in rows:
        key = (
            str(row.get("credential_triage") or ""),
            str(row.get("credential_status") or ""),
            str(row.get("matched_term") or ""),
        )
        group = grouped.setdefault(
            key,
            {
                "credential_triage": key[0],
                "credential_status": key[1],
                "matched_term": key[2],
                "count": 0,
                "sources": set(),
                "max_score": 0,
            },
        )
        group["count"] += 1
        if row.get("source_artifact_type"):
            group["sources"].add(str(row.get("source_artifact_type")))
        group["max_score"] = max(int(group.get("max_score") or 0), int(row.get("credential_score") or 0))
    output = []
    for group in grouped.values():
        item = dict(group)
        item["sources"] = ",".join(sorted(item["sources"]))
        output.append(item)
    output.sort(key=lambda row: (-int(row.get("max_score") or 0), -int(row.get("count") or 0), str(row.get("matched_term") or "")))
    return output


def _memory_extracted_indicators(value: Any) -> dict[str, list[str]]:
    text = str(value or "")
    paths = [_normalize_memory_path(match.group(0)) for match in _MEMORY_WINDOWS_PATH_RE.finditer(text)]
    urls = [_normalize_memory_url(match.group(0)) for match in _MEMORY_URL_RE.finditer(text)]
    emails = [match.group(0).casefold() for match in _MEMORY_EMAIL_RE.finditer(text)]
    domains = [_domain_from_url(url) for url in urls]
    domains.extend(email.rsplit("@", 1)[-1] for email in emails if "@" in email)
    return {
        "paths": _unique_nonempty(paths),
        "urls": _unique_nonempty(urls),
        "emails": _unique_nonempty(emails),
        "domains": _unique_nonempty(domains),
    }


def _memory_disk_reference_rows(db: Database, case_id: str, *, max_rows: int) -> list[dict[str, Any]]:
    specs = [
        ("mft_entries", "file", "id", "file_name", "coalesce(parent_path, '') || '/' || coalesce(file_name, '')", "NULL", "NULL"),
        ("filesystem_entries", "file", "id", "file_name", "file_path", "NULL", "NULL"),
        ("usn_journal_entries", "file", "id", "file_name", "full_path", "NULL", "NULL"),
        ("windows_search_files", "windows_search", "id", "file_name", "item_path", "item_url", "NULL"),
        ("windows_search_gather_logs", "windows_search", "id", "source_name", "item_path", "item_url", "NULL"),
        ("windows_search_email_indicators", "email", "id", "context_title", "context_path", "NULL", "email"),
        ("browser_history", "browser", "id", "title", "source_path", "url", "NULL"),
        ("browser_downloads", "browser", "id", "browser", "target_path", "coalesce(tab_url, site_url, referrer)", "NULL"),
        ("browser_artifacts", "browser", "id", "name", "coalesce(local_path, source_path)", "url", "NULL"),
        ("webcache_file_accesses", "browser", "id", "file_name", "normalized_path", "url", "NULL"),
        ("cloud_sync_artifacts", "cloud", "id", "coalesce(file_name, source_name)", "coalesce(local_path, cloud_path, server_path, source_path)", "url", "NULL"),
        ("onedrive_items", "cloud", "id", "name", "path", "NULL", "account"),
        ("mailbox_messages", "email", "id", "subject", "coalesce(message_path, source_path)", "NULL", "sender"),
        ("mailbox_attachments", "email", "id", "attachment_name", "coalesce(message_path, source_path)", "NULL", "sender"),
        ("shortcut_items", "remote_access", "id", "coalesce(artifact_name, file_name, app_id_description)", "coalesce(artifact_path, command_line_arguments, working_directory, network_path)", "network_path", "NULL"),
        ("rdp_cache_items", "remote_access", "id", "file_name", "coalesce(source_cache_path, fragment_path, contact_sheet_path)", "NULL", "NULL"),
        ("rdp_visual_observations", "remote_access", "id", "coalesce(observed_application, observation_type)", "coalesce(observed_path, source_cache_path, contact_sheet_path)", "NULL", "NULL"),
        ("evtx_events", "remote_access", "id", "coalesce(remote_host, provider, map_description)", "executable_info", "remote_host", "NULL"),
        ("srum_records", "remote_access", "id", "coalesce(app_name, vpn_profile_name, vpn_server)", "coalesce(app_path, vpn_phonebook_path)", "vpn_server", "NULL"),
    ]
    refs: list[dict[str, Any]] = []
    per_table_limit = max(50, max_rows // max(len(specs), 1))
    for table, family, row_id, label, path_expr, url_expr, email_expr in specs:
        if not _table_exists(db, table) and not _duckdb_table_available(db, case_id, table):
            continue
        columns = _report_table_columns(db, case_id, table)
        if not columns:
            continue
        safe_exprs = {
            "source_row_id": _safe_report_expr(row_id, columns),
            "label": _safe_report_expr(label, columns),
            "path": _safe_report_expr(path_expr, columns),
            "url": _safe_report_expr(url_expr, columns),
            "email": _safe_report_expr(email_expr, columns),
        }
        rows = _query_report_rows(
            db,
            case_id,
            table,
            f"""
            SELECT {safe_exprs['source_row_id']} AS source_row_id,
                   {safe_exprs['label']} AS label,
                   {safe_exprs['path']} AS path,
                   {safe_exprs['url']} AS url,
                   {safe_exprs['email']} AS email
            FROM {_quote_identifier(table)}
            WHERE case_id = ?
            LIMIT ?
            """,
            (case_id, per_table_limit),
        )
        for row in rows:
            refs.append(
                {
                    "source_table": table,
                    "artifact_family": family,
                    "source_row_id": row.get("source_row_id"),
                    "label": row.get("label"),
                    "path": row.get("path"),
                    "url": row.get("url"),
                    "email": row.get("email"),
                    "normalized_path": _normalize_memory_path(row.get("path")),
                    "normalized_url": _normalize_memory_url(row.get("url")),
                    "normalized_email": str(row.get("email") or "").casefold(),
                    "domain": _domain_from_url(row.get("url")) or _domain_from_email(row.get("email")),
                }
            )
    return refs[:max_rows]


def _safe_report_expr(expr: str, columns: set[str]) -> str:
    if expr == "NULL":
        return "NULL"
    for column in re.findall(r"\b[A-Za-z_][A-Za-z0-9_]*\b", expr):
        if column.lower() in {"coalesce", "concat", "null"}:
            continue
        if column not in columns:
            return "NULL"
    return expr


def _memory_disk_match(indicators: dict[str, list[str]], ref: dict[str, Any]) -> dict[str, str] | None:
    ref_path = str(ref.get("normalized_path") or "")
    for path in indicators.get("paths") or []:
        if path and ref_path and (path == ref_path or path.endswith("/" + _basename(ref_path) if _basename(ref_path) else "\x00") or ref_path.endswith("/" + _basename(path) if _basename(path) else "\x00")):
            return {"match_type": "path", "match_value": path, "confidence": "high" if path == ref_path else "medium"}
    ref_url = str(ref.get("normalized_url") or "")
    for url in indicators.get("urls") or []:
        if url and ref_url and (url == ref_url or url.rstrip("/") == ref_url.rstrip("/")):
            return {"match_type": "url", "match_value": url, "confidence": "high"}
    ref_email = str(ref.get("normalized_email") or "")
    for email in indicators.get("emails") or []:
        if email and ref_email and email == ref_email:
            return {"match_type": "email", "match_value": email, "confidence": "high"}
    ref_domain = str(ref.get("domain") or "")
    for domain in indicators.get("domains") or []:
        if domain and ref_domain and domain == ref_domain:
            return {"match_type": "domain", "match_value": domain, "confidence": "medium"}
    return None


def _normalize_memory_path(value: Any) -> str:
    text = str(value or "").strip().strip(".,;:)]}'\"")
    if not text:
        return ""
    text = unquote(text).replace("\\", "/")
    text = re.sub(r"^[A-Za-z]:", "", text)
    text = re.sub(r"^/+", "/", text)
    return text.casefold()


def _normalize_memory_url(value: Any) -> str:
    text = str(value or "").strip().strip(".,;:)]}'\"")
    if not text:
        return ""
    return unquote(text).casefold()


def _domain_from_url(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    try:
        parsed = urlparse(text if "://" in text else f"https://{text}")
    except ValueError:
        return ""
    return (parsed.hostname or "").casefold()


def _domain_from_email(value: Any) -> str:
    text = str(value or "")
    return text.rsplit("@", 1)[-1].casefold() if "@" in text else ""


def _unique_nonempty(values: list[str]) -> list[str]:
    seen: set[str] = set()
    output: list[str] = []
    for value in values:
        if not value or value in seen:
            continue
        seen.add(value)
        output.append(value)
    return output


def _dedupe_memory_disk_correlations(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, str, str, str, str]] = set()
    output: list[dict[str, Any]] = []
    for row in rows:
        key = (
            str(row.get("disk_artifact_family") or ""),
            str(row.get("disk_table") or ""),
            str(row.get("match_type") or ""),
            str(row.get("match_value") or ""),
            str(row.get("disk_path") or row.get("disk_url") or row.get("disk_email") or row.get("disk_label") or ""),
        )
        if key in seen:
            continue
        seen.add(key)
        output.append(row)
    confidence_order = {"high": 0, "medium": 1, "low": 2}
    output.sort(key=lambda row: (confidence_order.get(str(row.get("confidence") or ""), 9), str(row.get("disk_artifact_family") or ""), str(row.get("match_type") or "")))
    return output


def _memory_tool_availability() -> list[dict[str, str]]:
    tools = [
        ("memprocfs", ("memprocfs", "MemProcFS")),
        ("volatility3", ("vol", "vol.py", "volatility3")),
        ("pypykatz", ("pypykatz",)),
        ("mimikatz", ("mimikatz", "mimikatz.exe")),
        ("bstrings", ("bstrings",)),
        ("strings", ("strings",)),
        ("hibr2bin", ("hibr2bin", "Hibr2Bin", "HIBR2BIN")),
    ]
    rows = []
    for label, candidates in tools:
        path = None
        if label == "memprocfs" and os.environ.get("MEMPROCFS_BIN"):
            candidate = Path(os.environ["MEMPROCFS_BIN"]).expanduser()
            if candidate.exists():
                path = str(candidate)
        if label == "volatility3" and os.environ.get("VOLATILITY3_BIN"):
            candidate = Path(os.environ["VOLATILITY3_BIN"]).expanduser()
            if candidate.exists():
                path = str(candidate)
        path = path or next((shutil.which(candidate) for candidate in candidates if shutil.which(candidate)), None)
        if label == "memprocfs" and not path:
            for candidate in _tool_root_candidates("MemProcFS/memprocfs", "memprocfs/memprocfs"):
                if Path(candidate).exists():
                    path = candidate
                    break
        if label == "bstrings" and not path:
            for candidate in _tool_root_candidates(
                "bstrings/bstrings.dll",
                "eztools/bstrings/bstrings.dll",
                "eztools/net9/bstrings.dll",
            ):
                if Path(candidate).exists():
                    path = candidate
                    break
        if label == "hibr2bin" and not path:
            for candidate in _tool_root_candidates(
                "Hibr2Bin-linux/hibr2bin-linux",
                "Hibr2Bin-build/Hibr2Bin.exe",
                "Hibr2Bin/Hibr2Bin.exe",
            ):
                if Path(candidate).exists():
                    path = candidate
                    break
        rows.append({"tool": label, "status": "available" if path else "missing", "path": path or ""})
    return rows


def _tool_root_candidates(*relative_paths: str) -> list[str]:
    roots: list[Path] = []
    if os.environ.get("PERCEPTOR_TOOLS_ROOT"):
        roots.append(Path(os.environ["PERCEPTOR_TOOLS_ROOT"]).expanduser())
    if os.environ.get("FORENSIC_ORCHESTRATOR_TOOLS_ROOT"):
        roots.append(Path(os.environ["FORENSIC_ORCHESTRATOR_TOOLS_ROOT"]).expanduser())
    roots.extend([Path("/opt/perceptor-tools"), Path.home() / "tools"])
    output: list[str] = []
    seen: set[str] = set()
    for root in roots:
        for relative_path in relative_paths:
            candidate = str(root / relative_path)
            if candidate in seen:
                continue
            seen.add(candidate)
            output.append(candidate)
    return output


def _memory_processing_workflow(case_id: str, artifacts: list[dict[str, Any]]) -> list[dict[str, str]]:
    artifact_paths = [
        {
            "artifact_type": str(row.get("artifact_type") or "").lower(),
            "path": str(row.get("actual_path") or row.get("path") or ""),
            "decompressed_path": str(row.get("decompressed_path") or row.get("scanned_path") or ""),
        }
        for row in artifacts
        if row.get("actual_path") or row.get("path")
    ]

    def candidates_for(kind: str) -> list[str]:
        values: list[str] = []
        for row in artifact_paths:
            if row["artifact_type"] != kind:
                continue
            if row.get("decompressed_path"):
                values.append(row["decompressed_path"])
            if row.get("path"):
                values.append(row["path"])
        return values

    ordered_candidates = (
        candidates_for("full_memory_dump")
        + candidates_for("hiberfil")
        + candidates_for("crash_dump")
        + [row["path"] for row in artifact_paths if not row["path"].lower().endswith(("pagefile.sys", "swapfile.sys"))]
    )
    primary = next((path for path in ordered_candidates if path and Path(path).exists()), next((path for path in ordered_candidates if path), "MEMORY_OR_HIBERFIL_PATH"))
    workflow = [
        {
            "step": "inventory",
            "purpose": "Inventory RAM, hiberfil, pagefile, and swapfile candidates before content analysis.",
            "command": f"forensic-orchestrator report memory-artifacts --case {case_id} --format table",
            "output": "Memory-adjacent artifact list with source paths and sizes.",
        },
        {
            "step": "targeted_strings",
            "purpose": "Run targeted bstrings/strings collection over each memory artifact and import hits.",
            "command": f"forensic-orchestrator memory strings --case {case_id} --path {primary}",
            "output": "Rows in memory_string_hits for credentials, paths, cloud, browser, Search, and email leads.",
        },
        {
            "step": "memprocfs_mount",
            "purpose": "Mount a full RAM image or decompressed hibernation image for process, VAD, handle, module, and file-object review.",
            "command": f"memprocfs -device {primary} -mount /tmp/memprocfs-{case_id} -forensic 1",
            "output": "MemProcFS process trees, modules, VADs, handles, files, registry, and forensic CSV views.",
        },
        {
            "step": "volatility_inventory",
            "purpose": "Build a process/module/network inventory and identify target processes such as SearchIndexer.exe.",
            "command": f"vol -f {primary} windows.pslist.PsList",
            "output": "Process list used to pick focused follow-up plugins and VAD dumps.",
        },
        {
            "step": "searchindexer_vads",
            "purpose": "Dump SearchIndexer.exe VADs when Windows Search encrypted SQLite recovery is in scope.",
            "command": f"vol -f {primary} windows.vaddump.VadDump --pid SEARCHINDEXER_PID --dump-dir CASE_OUTPUT/searchindexer-vads",
            "output": "Process-specific memory regions for targeted plaintext/key-material scanning.",
        },
        {
            "step": "dpapi_lsa_validation",
            "purpose": "When the memory image is live and registry hives are available, test whether system DPAPI/LSA material can unwrap Search-related database keys.",
            "command": f"vol -f {primary} windows.registry.hivelist.HiveList && pypykatz registry --sam SAM --security SECURITY --system SYSTEM",
            "output": "Extracted LSA/DPAPI material for a controlled decrypt attempt; treat as unproven until it opens the target Windows.db.",
        },
        {
            "step": "report",
            "purpose": "Summarize processed memory artifacts, useful string hits, limitations, and follow-up actions.",
            "command": f"forensic-orchestrator report memory-analysis --case {case_id} --format md",
            "output": "Investigator-facing memory processing and analysis report.",
        },
    ]
    if not artifact_paths:
        workflow.insert(
            1,
            {
                "step": "collect_live_memory",
                "purpose": "Acquire RAM before relying on hiberfil/pagefile/swapfile-only workflows.",
                "command": "Acquire a full memory image from the live host while the relevant user session is logged in.",
                "output": "Full RAM image suitable for MemProcFS and Volatility analysis.",
            },
        )
    return workflow


def _memory_useful_hits(hits: list[dict[str, Any]], *, limit: int) -> list[dict[str, Any]]:
    priority = {
        "credentials": 0,
        "search": 1,
        "browser": 2,
        "cloud": 3,
        "remote_access": 4,
        "email": 5,
        "paths": 6,
    }
    rows = [dict(hit) for hit in hits if isinstance(hit, dict)]
    rows.sort(
        key=lambda row: (
            priority.get(str(row.get("hit_category") or ""), 99),
            str(row.get("source_artifact_type") or ""),
            str(row.get("matched_term") or ""),
            str(row.get("source_path") or ""),
        )
    )
    return rows[:limit]


def _memory_windows_search_assessment(search_status: dict[str, Any], string_hits: dict[str, Any]) -> dict[str, Any]:
    status = str(search_status.get("summary_status") or "")
    hit_categories = (string_hits.get("summary") or {}).get("categories") or []
    search_hit_count = sum(int(row.get("count") or 0) for row in hit_categories if row.get("value") == "search")
    if status == "partial_unsupported_encrypted_sqlite":
        if search_hit_count:
            result = "encrypted_sqlite_memory_leads_only"
            note = f"{search_hit_count} Windows Search string hits were imported, but string hits do not decrypt the encrypted SQLite database."
        else:
            result = "encrypted_sqlite_no_memory_key"
            note = "No imported memory string hits currently indicate usable Windows Search plaintext or AES-GCM key material."
        recommendation = (
            "Treat offline memory-support-file recovery as tested but not sufficient for this case unless a usable key/plaintext is later found. "
            "For future acquisitions, collect RAM while the user is logged in and SearchIndexer.exe is live. "
            "If live memory and registry hives are available, separately validate the DPAPI/LSA key-unwrapping path before claiming Search database decryption."
        )
    elif status == "parsed":
        result = "search_index_parsed"
        note = "The Windows Search parser produced normalized rows; memory work is optional corroboration."
        recommendation = "Use memory analysis only for corroboration or recovery of artifacts absent from the parsed Search rows."
    else:
        result = "memory_followup_optional"
        note = search_status.get("summary_note") or ""
        recommendation = "Run memory strings and process-specific memory review when Search or user-session artifacts are material to the investigation."
    return {
        "result": result,
        "search_string_hit_count": search_hit_count,
        "windows_search_status": status,
        "note": note,
        "recommendation": recommendation,
    }


def _memory_analysis_findings(
    artifacts: dict[str, Any],
    string_hits: dict[str, Any],
    search_assessment: dict[str, Any],
) -> list[dict[str, Any]]:
    findings: list[dict[str, Any]] = []
    artifact_count = int((artifacts.get("summary") or {}).get("artifact_count") or 0)
    if artifact_count:
        findings.append(
            {
                "severity": "info",
                "category": "memory_artifacts",
                "title": "Memory-adjacent artifacts available",
                "summary": f"{artifact_count} hiberfil/pagefile/swapfile or memory artifacts are available for processing.",
            }
        )
    hit_count = int((string_hits.get("summary") or {}).get("hit_count") or 0)
    if hit_count:
        findings.append(
            {
                "severity": "lead",
                "category": "memory_strings",
                "title": "Targeted memory string hits imported",
                "summary": f"{hit_count} memory string hits are available for review and corroboration.",
            }
        )
    if search_assessment.get("result") in {"encrypted_sqlite_no_memory_key", "encrypted_sqlite_memory_leads_only"}:
        findings.append(
            {
                "severity": "limitation",
                "category": "windows_search",
                "title": "Encrypted Windows 11 Search database remains offline-limited",
                "summary": search_assessment.get("note") or "",
            }
        )
    return findings


def evidence_gaps_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    gaps: list[dict[str, Any]] = []
    completeness = artifact_completeness_report(db, case_id, limit=limit)
    search_status = _windows_search_parser_status(db, case_id)
    memory = memory_artifacts_report(db, case_id, limit=limit)
    search_has_signal = bool(
        search_status.get("inventories")
        or search_status.get("tool_outputs")
        or any((search_status.get("table_counts") or {}).values())
    )
    if search_has_signal and search_status["summary_status"] != "parsed":
        severity = "warning" if search_status["summary_status"].startswith("partial_") else "info"
        gaps.append(
            {
                "severity": severity,
                "category": "windows_search",
                "title": "Windows Search full index coverage is limited",
                "summary": search_status["summary_note"],
                "details": search_status,
                "recommendation": "Use gather logs, MFT/USN, file-history artifacts, and content parsers as fallback. If a memory image is available, consider looking for SearchIndexer plaintext/key material.",
            }
        )
    if memory["summary"]["artifact_count"]:
        gaps.append(
            {
                "severity": "info",
                "category": "memory_artifacts",
                "title": "On-disk memory artifacts are present but not parsed",
                "summary": f"{memory['summary']['artifact_count']} memory-adjacent artifacts are available for later analysis.",
                "details": memory["summary"],
                "recommendation": "Process hibernation/page/swap files with the memory workflow when available.",
            }
        )
    for job in completeness.get("failed_jobs", []):
        gaps.append(
            {
                "severity": "error",
                "category": "failed_job",
                "title": f"{job.get('tool_name')} failed",
                "summary": f"Exit code {job.get('exit_code')}",
                "details": job,
                "recommendation": "Review stderr and rerun or classify as unsupported/input-specific.",
            }
        )
    for caveat in completeness.get("extraction_caveats", []):
        gaps.append(
            {
                "severity": "warning",
                "category": "extraction_caveat",
                "title": f"Extraction caveat: {caveat.get('target') or caveat.get('tool_name')}",
                "summary": caveat.get("error") or caveat.get("caveat_type") or "",
                "details": caveat,
                "recommendation": "Confirm whether the caveat affects relevant evidence before relying on absence.",
            }
        )
    for skipped in completeness.get("skipped", []):
        gaps.append(
            {
                "severity": "warning",
                "category": "skipped_artifact",
                "title": skipped.get("message") or skipped.get("event"),
                "summary": f"{skipped.get('count', 0)} matching activity records",
                "details": skipped,
                "recommendation": "Review whether this was expected for the OS/application mix.",
            }
        )
    for row in completeness.get("evtx_recovery", []):
        if row.get("status") in {"partial", "salvaged_partial"}:
            gaps.append(
                {
                    "severity": "warning",
                    "category": "evtx_recovery",
                    "title": f"Event log recovery was {row.get('status')}",
                    "summary": row.get("source_path") or row.get("log_name") or "",
                    "details": row,
                    "recommendation": "Use recovered events with caveats and corroborate with adjacent logs/artifacts.",
                }
            )
    gaps.extend(_opensearch_gap_rows(db, case_id))
    gaps = _dedupe_gap_rows(gaps)
    gaps.sort(key=lambda row: (_gap_severity_rank(row.get("severity")), row.get("category") or "", row.get("title") or ""))
    severity_counts = _count_by_key(gaps, "severity")
    category_counts = _count_by_key(gaps, "category")
    return {
        "case_id": case_id,
        "summary": {
            "gap_count": len(gaps),
            "severity_counts": severity_counts,
            "category_counts": category_counts,
            "windows_search_status": search_status["summary_status"],
            "memory_artifacts": memory["summary"]["artifact_count"],
        },
        "gaps": gaps[:limit],
        "windows_search_status": search_status,
        "memory_artifacts": memory,
        "total_returned": min(len(gaps), limit),
    }


def evidence_gaps_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") or {}
    lines = [
        "# Evidence Gaps and Limitations",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Gaps: `{summary.get('gap_count', 0)}`",
        f"- Windows Search status: `{summary.get('windows_search_status') or ''}`",
        f"- Memory artifacts: `{summary.get('memory_artifacts', 0)}`",
        "",
        "## Findings",
        "",
    ]
    gaps = report.get("gaps") or []
    if not gaps:
        lines.append("- No evidence gaps or limitations were identified.")
    for gap in gaps:
        lines.append(
            f"- `{gap.get('severity') or ''}` `{gap.get('category') or ''}` "
            f"{gap.get('title') or ''}: {gap.get('summary') or ''}"
        )
        if gap.get("recommendation"):
            lines.append(f"  Recommendation: {gap.get('recommendation')}")
    return "\n".join(lines).rstrip() + "\n"


def file_dossier_report(
    db: Database,
    case_id: str,
    *,
    path: str | None = None,
    name: str | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    db.get_case(case_id)
    if not path and not name:
        raise ValueError("Provide path or name for file dossier")
    basename = name or _coalesce_file_name(None, path)
    if not basename:
        raise ValueError("Could not derive a file name from dossier query")

    rows: list[dict[str, Any]] = []
    windows_search_record_ids: set[str] = set()
    windows_search_work_ids: set[str] = set()

    def add_row(
        *,
        category: str,
        source_table: str,
        source_id: str,
        file_name: str | None,
        row_path: str | None,
        timestamp: str | None,
        summary: str,
        details: dict[str, Any] | None = None,
        row_confidence: str | None = None,
    ) -> None:
        if not _dossier_include_row(row_path, path):
            return
        path_matched = _dossier_path_matches(row_path, path)
        rows.append(
            {
                "category": category,
                "source_table": source_table,
                "source_id": source_id,
                "source_type": _dossier_source_type(source_table, category),
                "confidence": _dossier_confidence(source_table, path_matched=path_matched, row_confidence=row_confidence),
                "timestamp": timestamp,
                "file_name": file_name or basename,
                "path": row_path,
                "normalized_path": _normalize_artifact_path(row_path),
                "summary": summary,
                "details": details or {},
            }
        )

    mft_rows = _query_report_rows(
        db,
        case_id,
        "mft_entries",
        """
        SELECT id, file_name, parent_path, created_si, modified_si, accessed_si,
               record_changed_si, in_use, is_directory, entry_number, sequence_number
        FROM mft_entries
        WHERE case_id = ? AND file_name = ?
        ORDER BY row_number
        LIMIT ?
        """,
        (case_id, basename, limit),
    )
    for row in mft_rows:
        row_path = _join_path(row["parent_path"], row["file_name"])
        for event_type, timestamp in (
            ("MFT created", row["created_si"]),
            ("MFT modified", row["modified_si"]),
            ("MFT accessed", row["accessed_si"]),
            ("MFT record changed", row["record_changed_si"]),
        ):
            if timestamp:
                add_row(
                    category="filesystem",
                    source_table="mft_entries",
                    source_id=row["id"],
                    file_name=row["file_name"],
                    row_path=row_path,
                    timestamp=timestamp,
                    summary=event_type,
                    details={
                        "entry_number": row["entry_number"],
                        "sequence_number": row["sequence_number"],
                        "in_use": row["in_use"],
                        "is_directory": row["is_directory"],
                    },
                )

    filesystem_entry_rows = _query_report_rows(
        db,
        case_id,
        "filesystem_entries",
        """
        SELECT *
        FROM filesystem_entries
        WHERE case_id = ? AND file_name = ?
        ORDER BY COALESCE(modified_utc, created_utc, accessed_utc, metadata_changed_utc, created_at, ''),
                 file_path,
                 row_number
        LIMIT ?
        """,
        (case_id, basename, limit),
    )
    for row in filesystem_entry_rows:
        add_row(
            category="filesystem",
            source_table="filesystem_entries",
            source_id=row["id"],
            file_name=row["file_name"],
            row_path=row["file_path"],
            timestamp=row["modified_utc"] or row["created_utc"] or row["accessed_utc"] or row["metadata_changed_utc"],
            summary=f"Generated filesystem listing: {row['scan_status'] or 'listed'}",
            details={
                "computer_id": row["computer_id"],
                "image_id": row["image_id"],
                "partition_id": row["partition_id"],
                "filesystem_type": row["filesystem_type"],
                "source_root": row["source_root"],
                "parent_path": row["parent_path"],
                "extension": row["extension"],
                "file_size": row["file_size"],
                "is_directory": row["is_directory"],
                "created_utc": row["created_utc"],
                "modified_utc": row["modified_utc"],
                "accessed_utc": row["accessed_utc"],
                "metadata_changed_utc": row["metadata_changed_utc"],
                "mode": row["mode"],
                "uid": row["uid"],
                "gid": row["gid"],
                "scan_status": row["scan_status"],
                "error": row["error"],
                "tool_name": row["tool_name"],
            },
        )

    fs_rows = _query_report_rows(
        db,
        case_id,
        "filesystem_review",
        """
        SELECT *
        FROM filesystem_review
        WHERE case_id = ? AND file_name = ?
        ORDER BY COALESCE(event_time, ''), source_table, source_row_number
        LIMIT ?
        """,
        (case_id, basename, limit),
    )
    for row in fs_rows:
        add_row(
            category=_dossier_category(row["source_table"]),
            source_table=row["source_table"],
            source_id=row["source_id"],
            file_name=row["file_name"],
            row_path=row["file_path"],
            timestamp=row["event_time"],
            summary=row["event_type"],
            details={
                "status": row["status"],
                "reason": row["reason"],
                "operation": row["operation"],
                "mft_entry_number": row["mft_entry_number"],
                "mft_sequence_number": row["mft_sequence_number"],
                **_json_details(row["details_json"]),
            },
        )

    shortcut_rows = _query_report_rows(
        db,
        case_id,
        "shortcut_items",
        """
        SELECT id, artifact_type, artifact_name, artifact_path, file_name, file_location,
               target_created, target_modified, target_accessed, device_type,
               volume_serial_number, volume_name, jumplist_item_number
        FROM shortcut_items
        WHERE case_id = ? AND file_name = ?
        ORDER BY COALESCE(target_accessed, target_modified, target_created, '')
        LIMIT ?
        """,
        (case_id, basename, limit),
    )
    for row in shortcut_rows:
        add_row(
            category="shortcuts",
            source_table="shortcut_items",
            source_id=row["id"],
            file_name=row["file_name"],
            row_path=row["file_location"],
            timestamp=row["target_accessed"] or row["target_modified"] or row["target_created"],
            summary=f"{row['artifact_type'] or 'shortcut'} reference",
            details={
                "artifact_name": row["artifact_name"],
                "artifact_path": row["artifact_path"],
                "item_number": row["jumplist_item_number"],
                "target_created": row["target_created"],
                "target_modified": row["target_modified"],
                "target_accessed": row["target_accessed"],
                "target_device_type": row["device_type"],
                "volume_serial_number": row["volume_serial_number"],
                "volume_name": row["volume_name"],
            },
        )

    copied_rows = _query_report_rows(
        db,
        case_id,
        "copied_file_indicators",
        """
        SELECT *
        FROM copied_file_indicators
        WHERE case_id = ? AND file_name = ?
        ORDER BY created_timestamp_utc, source_artifact_type
        LIMIT ?
        """,
        (case_id, basename, limit),
    )
    for row in copied_rows:
        add_row(
            category="copied_indicators",
            source_table="copied_file_indicators",
            source_id=row["id"],
            file_name=row["file_name"],
            row_path=row["file_location"],
            timestamp=row["created_timestamp_utc"],
            summary=row["indicator"],
            row_confidence=row["confidence"],
            details={
                "source_artifact_type": row["source_artifact_type"],
                "source_artifact_name": row["source_artifact_name"],
                "created_timestamp_utc": row["created_timestamp_utc"],
                "modified_timestamp_utc": row["modified_timestamp_utc"],
                "reason": row["reason"],
            },
        )

    search_file_rows = _query_report_rows(
        db,
        case_id,
        "windows_search_files",
        """
        SELECT *
        FROM windows_search_files
        WHERE case_id = ? AND file_name = ?
        ORDER BY COALESCE(date_accessed, date_modified, gather_time, date_created, '')
        LIMIT ?
        """,
        (case_id, basename, limit),
    )
    for row in search_file_rows:
        if row["id"]:
            windows_search_record_ids.add(row["id"])
        if row["work_id"]:
            windows_search_work_ids.add(row["work_id"])
        add_row(
            category="windows_search",
            source_table="windows_search_files",
            source_id=row["id"],
            file_name=row["file_name"],
            row_path=row["item_path"] or row["item_url"],
            timestamp=row["date_accessed"] or row["date_modified"] or row["gather_time"] or row["date_created"],
            summary="Windows Search file record",
            details={
                "work_id": row["work_id"],
                "item_type": row["item_type"],
                "file_extension": row["file_extension"],
                "date_created": row["date_created"],
                "date_modified": row["date_modified"],
                "date_accessed": row["date_accessed"],
                "date_imported": row["date_imported"],
                "size": row["size"],
                "owner": row["owner"],
            },
        )

    if windows_search_record_ids or windows_search_work_ids:
        property_filters: list[str] = []
        params: list[Any] = [case_id]
        if windows_search_record_ids:
            placeholders = ",".join("?" for _ in windows_search_record_ids)
            property_filters.append(f"source_record_id IN ({placeholders})")
            params.extend(sorted(windows_search_record_ids))
        if windows_search_work_ids:
            placeholders = ",".join("?" for _ in windows_search_work_ids)
            property_filters.append(f"work_id IN ({placeholders})")
            params.extend(sorted(windows_search_work_ids))
        params.append(limit * 5)
        property_rows = _query_report_rows(
            db,
            case_id,
            "windows_search_properties",
            f"""
            SELECT *
            FROM windows_search_properties
            WHERE case_id = ? AND ({' OR '.join(property_filters)})
            ORDER BY property_name, timestamp
            LIMIT ?
            """,
            params,
        )
        for row in property_rows:
            translated = _translate_windows_search_property(row["property_name"], row["property_value"])
            add_row(
                category="windows_search",
                source_table="windows_search_properties",
                source_id=row["id"],
                file_name=basename,
                row_path=row["item_path"],
                timestamp=row["timestamp"],
                summary=f"Windows Search property: {row['normalized_name'] or row['property_name']}",
                details={
                    "property_name": row["property_name"],
                    "normalized_name": row["normalized_name"],
                    "property_value": row["property_value"],
                    "translated": translated,
                    "work_id": row["work_id"],
                },
            )

    thumb_rows = db.conn.execute(
        """
        SELECT *
        FROM thumbcache_search_correlations
        WHERE case_id = ? AND search_file_name = ?
        ORDER BY COALESCE(search_date_accessed, search_date_modified, search_date_created, search_date_imported, '')
        LIMIT ?
        """,
        (case_id, basename, limit),
    ).fetchall()
    for row in thumb_rows:
        add_row(
            category="thumbcache",
            source_table="thumbcache_search_correlations",
            source_id=row["id"],
            file_name=row["search_file_name"],
            row_path=row["search_item_path"],
            timestamp=row["search_date_accessed"] or row["search_date_modified"] or row["search_date_created"] or row["search_date_imported"],
            summary="Thumbcache to Windows Search path correlation",
            row_confidence=row["confidence"],
            details={
                "cache_id": row["cache_id"],
                "thumbcache_name": row["thumbcache_name"],
                "correlation_basis": row["correlation_basis"],
                "confidence": row["confidence"],
            },
        )

    metadata_rows = _query_report_rows(
        db,
        case_id,
        "file_internal_metadata",
        """
        SELECT *
        FROM file_internal_metadata
        WHERE case_id = ? AND file_name = ?
        ORDER BY metadata_group, property_name
        LIMIT ?
        """,
        (case_id, basename, max(limit, 250)),
    )
    for row in metadata_rows:
        add_row(
            category="internal_metadata",
            source_table="file_internal_metadata",
            source_id=row["id"],
            file_name=row["file_name"],
            row_path=row["original_path"] or row["source_file"],
            timestamp=row["mft_modified"] or row["mft_created"] or row["mft_accessed"],
            summary=f"{row['metadata_group'] or row['parser'] or 'metadata'}: {row['property_name']}",
            details={
                "property_name": row["property_name"],
                "property_value": row["property_value"],
                "raw_property_name": row["raw_property_name"],
                "parser": row["parser"],
                "metadata_group": row["metadata_group"],
                "file_size": row["file_size"],
                "extraction_method": row["extraction_method"],
            },
        )

    cloud_rows = db.conn.execute(
        """
        SELECT *
        FROM cloud_sync_artifacts
        WHERE case_id = ? AND file_name = ?
        ORDER BY COALESCE(event_time_utc, '')
        LIMIT ?
        """,
        (case_id, basename, limit),
    ).fetchall()
    for row in cloud_rows:
        add_row(
            category="cloud_sync",
            source_table="cloud_sync_artifacts",
            source_id=row["id"],
            file_name=row["file_name"],
            row_path=row["local_path"] or row["cloud_path"] or row["server_path"],
            timestamp=row["event_time_utc"],
            summary=f"{row['provider'] or 'cloud'} {row['artifact_type'] or 'artifact'}",
            details={
                "provider": row["provider"],
                "artifact_type": row["artifact_type"],
                "sync_status": row["sync_status"],
                "event_type": row["event_type"],
                "direction": row["direction"],
                "file_id": row["file_id"],
                "parent_id": row["parent_id"],
                "stable_id": row["stable_id"],
                "is_deleted": row["is_deleted"],
                "mime_type": row["mime_type"],
                "file_size": row["file_size"],
            },
        )

    google_cache_rows = _query_report_rows(
        db,
        case_id,
        "google_drive_cache_map",
        """
        SELECT *
        FROM google_drive_cache_map
        WHERE case_id = ? AND file_name = ?
        ORDER BY virtual_path, cache_path
        LIMIT ?
        """,
        (case_id, basename, limit),
    )
    for row in google_cache_rows:
        add_row(
            category="cloud_sync",
            source_table="google_drive_cache_map",
            source_id=row["id"],
            file_name=row["file_name"],
            row_path=row["virtual_path"],
            timestamp=None,
            summary="Google Drive virtual path to cache mapping",
            details={
                "account_id": row["account_id"],
                "stable_id": row["stable_id"],
                "file_id": row["file_id"],
                "cache_id": row["cache_id"],
                "cache_path": row["cache_path"],
                "windows_cache_path": row["windows_cache_path"],
                "cache_file_size": row["cache_file_size"],
                "mapping_method": row["mapping_method"],
                "evidence_basis": row["evidence_basis"],
            },
        )

    onedrive_rows = _query_report_rows(
        db,
        case_id,
        "onedrive_items",
        """
        SELECT *
        FROM onedrive_items
        WHERE case_id = ? AND name = ?
        ORDER BY COALESCE(last_change_utc, disk_last_access_utc, disk_creation_utc, delete_time_utc, '')
        LIMIT ?
        """,
        (case_id, basename, limit),
    )
    for row in onedrive_rows:
        add_row(
            category="cloud_sync",
            source_table="onedrive_items",
            source_id=row["id"],
            file_name=row["name"],
            row_path=row["path"],
            timestamp=row["last_change_utc"] or row["disk_last_access_utc"] or row["disk_creation_utc"] or row["delete_time_utc"],
            summary=f"OneDrive {row['record_type'] or row['artifact_type'] or 'item'}",
            details={
                "account": row["account"],
                "artifact_type": row["artifact_type"],
                "record_type": row["record_type"],
                "resource_id": row["resource_id"],
                "parent_resource_id": row["parent_resource_id"],
                "status": row["status"],
                "volume_id": row["volume_id"],
                "size": row["size"],
                "local_hash_digest": row["local_hash_digest"],
                "local_hash_algorithm": row["local_hash_algorithm"],
                "shared_item": row["shared_item"],
                "is_deleted": row["is_deleted"],
                "delete_time_utc": row["delete_time_utc"],
            },
        )

    deduped_rows = _dedupe_dossier_rows(rows)
    sections = _dossier_sections(deduped_rows)
    metadata_summary = _dossier_metadata_summary(sections["internal_metadata"])
    filesystem_metadata_summary = _dossier_filesystem_metadata_summary(sections["filesystem"])
    source_counts: dict[str, int] = {}
    source_type_counts: dict[str, int] = {}
    for row in deduped_rows:
        source_counts[row["source_table"]] = source_counts.get(row["source_table"], 0) + row.get("source_count", 1)
        source_type_counts[row["source_type"]] = source_type_counts.get(row["source_type"], 0) + row.get("source_count", 1)

    evidence = deduped_rows[:limit]
    copied = {
        "case_id": case_id,
        "path_query": path or basename,
        "copied_file_indicators": sections["copied_indicators"],
        "shortcuts": sections["shortcuts"],
        "shellbags": [],
        "mft_entries": [row for row in sections["filesystem"] if row["source_table"] == "mft_entries"],
        "usb_matches": [],
        "counts": {
            "copied_file_indicators": len(sections["copied_indicators"]),
            "shortcuts": len(sections["shortcuts"]),
            "shellbags": 0,
            "mft_entries": len([row for row in sections["filesystem"] if row["source_table"] == "mft_entries"]),
            "usb_matches": 0,
        },
    }
    return {
        "case_id": case_id,
        "filters": {"path": path, "name": name},
        "summary": {
            "queried_file_name": basename,
            "evidence_rows": len(deduped_rows),
            "raw_evidence_rows": len(rows),
            "deduplicated_rows_removed": max(0, len(rows) - len(deduped_rows)),
            "timeline_events": len(sections["filesystem"]),
            "copied_indicators": len(sections["copied_indicators"]),
            "windows_search_hits": len(sections["windows_search"]),
            "filesystem_listing_hits": len([row for row in sections["filesystem"] if row["source_table"] == "filesystem_entries"]),
            "internal_metadata_hits": len(sections["internal_metadata"]),
            "mailbox_attachment_hits": 0,
            "web_references": 0,
            "source_counts": [{"source": key, "count": value} for key, value in sorted(source_counts.items())],
            "source_type_counts": [{"source_type": key, "count": value} for key, value in sorted(source_type_counts.items())],
            "internal_metadata_property_counts": metadata_summary["property_counts"],
        },
        "identity": {
            "file_name": basename,
            "requested_path": path,
            "normalized_requested_path": _normalize_artifact_path(path),
        },
        "sections": sections,
        "filesystem_metadata": filesystem_metadata_summary,
        "internal_metadata": metadata_summary,
        "interpretation": _dossier_interpretation(sections),
        "history": sections["filesystem"],
        "evidence": evidence,
        "copied": copied,
        "windows_search_hits": sections["windows_search"],
        "mailbox_attachments": [],
        "web_references": [],
    }


def file_intelligence_report(
    db: Database,
    case_id: str,
    *,
    path: str | None = None,
    name: str | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    dossier = file_dossier_report(db, case_id, path=path, name=name, limit=limit)
    evidence_rows = list(dossier["evidence"])
    source_counts: dict[str, int] = {}
    timestamped_rows = 0
    for row in evidence_rows:
        source = str(row.get("source_table") or row.get("source") or "unknown")
        source_counts[source] = source_counts.get(source, 0) + 1
        if row.get("timestamp"):
            timestamped_rows += 1
    sections = {
        "filesystem_history": len(dossier["history"]),
        "artifact_evidence": len(evidence_rows),
        "copied_indicators": dossier["summary"].get("copied_indicators", 0),
        "windows_search_hits": len(dossier["windows_search_hits"]),
        "mailbox_attachment_hits": len(dossier["mailbox_attachments"]),
        "web_references": len(dossier["web_references"]),
    }
    return {
        "case_id": case_id,
        "filters": dossier["filters"],
        "summary": {
            **dossier["summary"],
            "sections": sections,
            "source_counts": [{"source": key, "count": value} for key, value in sorted(source_counts.items())],
            "timestamped_evidence_rows": timestamped_rows,
        },
        "identity": dossier.get("identity"),
        "filesystem_metadata": dossier.get("filesystem_metadata"),
        "internal_metadata": dossier.get("internal_metadata"),
        "sections": dossier.get("sections"),
        "interpretation": dossier.get("interpretation"),
        "timeline": dossier["history"],
        "evidence": evidence_rows,
        "copied": dossier["copied"],
        "windows_search_hits": dossier["windows_search_hits"],
        "mailbox_attachments": dossier["mailbox_attachments"],
        "web_references": dossier["web_references"],
    }


def user_activity_report(
    db: Database,
    case_id: str,
    *,
    user: str,
    limit: int = 100,
) -> dict[str, Any]:
    db.get_case(case_id)
    summary = activity_summary_report(db, case_id, user=user, limit=min(limit, 50))
    communications = communications_report(db, case_id, user=user, limit=min(limit, 50))
    usb_rows = _query_report_rows(
        db,
        case_id,
        "usb_file_correlations",
        """
        SELECT *
        FROM usb_file_correlations
        WHERE case_id = ?
          AND (user_profile LIKE ? OR file_location LIKE ? OR source_artifact_path LIKE ?)
        ORDER BY
          CASE confidence WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END,
          COALESCE(target_modified, target_created, target_accessed, ''),
          COALESCE(file_location, file_name, '')
        LIMIT ?
        """,
        (case_id, f"%{user}%", f"%{user}%", f"%{user}%", min(limit, 50)),
    )
    return {
        "case_id": case_id,
        "user": user,
        "counts": {
            **summary["counts"],
            "communications": communications["total_returned"],
            "copied_usb_file_hits": len(usb_rows),
        },
        "recent_execution": summary["recent_execution"],
        "recent_file_activity": summary["recent_file_activity"],
        "recent_browser_history": summary["recent_browser_history"],
        "recent_logons": summary["recent_logons"],
        "communications": communications["communications"],
        "browser_activity": {
            "recent_browser_history": summary["recent_browser_history"],
        },
        "copied_usb_files": usb_rows,
    }


