def malware_hiding_places_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 100,
    long_value_threshold: int = 300,
) -> dict[str, Any]:
    db.get_case(case_id)
    execution = execution_report(db, case_id, limit=max(limit, 250))
    autostart_references = _malware_autostart_references(db, case_id)
    unusual_rows = _malware_unusual_execution_rows(execution, autostart_references=autostart_references)
    registry_rows, registry_suppressed_counts = _malware_registry_value_rows(
        db,
        case_id,
        limit=limit,
        long_value_threshold=long_value_threshold,
    )
    unusual_rows = unusual_rows[:limit]
    registry_rows = registry_rows[:limit]
    severity_counts: dict[str, int] = {}
    for item in [*unusual_rows, *registry_rows]:
        severity = str(item.get("severity") or "info")
        severity_counts[severity] = severity_counts.get(severity, 0) + 1
    source_counts: dict[str, int] = {}
    for item in unusual_rows:
        source = str(item.get("source_table") or "unknown")
        source_counts[source] = source_counts.get(source, 0) + 1
    return {
        "case_id": case_id,
        "filters": {
            "limit": limit,
            "long_value_threshold": long_value_threshold,
        },
        "summary": {
            "unusual_execution_location_count": len(unusual_rows),
            "long_or_encoded_registry_value_count": len(registry_rows),
            "severity_counts": [{"severity": key, "count": value} for key, value in sorted(severity_counts.items())],
            "unusual_execution_source_counts": [
                {"source_table": key, "count": value}
                for key, value in sorted(source_counts.items())
            ],
            "suppressed_registry_value_counts": [
                {"reason": key, "count": value}
                for key, value in sorted(registry_suppressed_counts.items())
            ],
        },
        "unusual_execution_locations": unusual_rows,
        "registry_value_indicators": registry_rows,
        "total_returned": len(unusual_rows) + len(registry_rows),
    }


def malware_hiding_places_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    unusual = report.get("unusual_execution_locations") if isinstance(report.get("unusual_execution_locations"), list) else []
    registry = report.get("registry_value_indicators") if isinstance(report.get("registry_value_indicators"), list) else []
    lines = [
        "# Potential Malware Hiding Places",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Unusual execution/persistence locations: `{summary.get('unusual_execution_location_count', 0)}`",
        f"- Long or encoded registry values: `{summary.get('long_or_encoded_registry_value_count', 0)}`",
        "",
    ]
    suppressed_counts = summary.get("suppressed_registry_value_counts")
    if isinstance(suppressed_counts, list) and suppressed_counts:
        lines.extend(["## Suppressed Registry Value Noise", ""])
        for row in suppressed_counts:
            if isinstance(row, dict):
                lines.append(f"- `{row.get('reason') or ''}`: `{row.get('count') or 0}`")
        lines.append("")
    lines.extend(["## Unusual Execution Or Persistence Locations", ""])
    if not unusual:
        lines.append("- No unusual execution or persistence locations were found by the current rules.")
    for row in unusual:
        if not isinstance(row, dict):
            continue
        lines.append(
            f"- `{row.get('timestamp_utc') or ''}` `{row.get('severity') or ''}` "
            f"`{row.get('source_table') or ''}` `{row.get('event_type') or row.get('indicator_type') or ''}` "
            f"`{row.get('application') or row.get('description') or ''}` path `{row.get('display_path') or ''}`"
        )
        detail_values = {
            "reason": row.get("reason"),
            "category": row.get("location_category"),
            "source": row.get("source_file"),
            "registry_key": row.get("registry_key"),
        }
        autostart_ref_count = len(row.get("autostart_references") or [])
        if autostart_ref_count:
            detail_values["autostart_refs"] = autostart_ref_count
        detail_bits = [f"{key}={value}" for key, value in detail_values.items() if value not in (None, "")]
        if detail_bits:
            lines.append("  - " + "; ".join(detail_bits))
    lines.extend(["", "## Long Or Encoded Registry Values", ""])
    if not registry:
        lines.append("- No long or base64-looking registry values were found by the current rules.")
    for row in registry:
        if not isinstance(row, dict):
            continue
        flags = ",".join(row.get("flags") or [])
        lines.append(
            f"- `{row.get('timestamp_utc') or ''}` `{row.get('severity') or ''}` "
            f"`{row.get('artifact') or ''}` `{row.get('value_name') or ''}` flags `{flags}`"
        )
        lines.append(
            f"  - key `{row.get('key_path') or ''}`; chars `{row.get('value_length') or 0}`; "
            f"autostart `{row.get('autostart_location') or 'not_known_autostart'}`; "
            f"preview `{row.get('value_preview') or ''}`"
        )
    return "\n".join(lines).rstrip() + "\n"


def _malware_unusual_execution_rows(
    execution: dict[str, Any],
    *,
    autostart_references: dict[str, list[dict[str, Any]]] | None = None,
) -> list[dict[str, Any]]:
    candidates: list[dict[str, Any]] = []
    autostart_references = autostart_references or {}
    for source_name in ("events", "process_activity"):
        rows = execution.get(source_name) if isinstance(execution.get(source_name), list) else []
        for row in rows:
            if not isinstance(row, dict):
                continue
            if str(row.get("event_type") or "").casefold() in MALWARE_REPORT_EXECUTION_IGNORED_EVENT_TYPES:
                continue
            path = str(row.get("display_path") or display_evidence_path(row.get("path")) or "")
            category = _unusual_execution_location(path)
            if not category:
                continue
            if not _path_looks_executable_or_script(path, row.get("application") or row.get("description")):
                continue
            benign_reason = _malware_report_benign_suppression_reason(path, row.get("application") or row.get("description"))
            if benign_reason:
                continue
            details = row.get("details") if isinstance(row.get("details"), dict) else {}
            source_table = str(row.get("source_table") or "")
            reason = f"Executable/script observed from unusual location category `{category}`."
            severity = "high" if source_table in {"prefetch_items", "registry_runmru", "evtx_events"} else "medium"
            if source_table in {"amcache_entries", "shimcache_entries"}:
                reason += " Source is presence/cache metadata, not execution proof."
            normalized_path = _normalize_artifact_path(path)
            autostart_matches = autostart_references.get(normalized_path.casefold(), [])
            candidates.append(
                {
                    "severity": severity,
                    "location_category": category,
                    "timestamp_utc": row.get("timestamp_utc"),
                    "source_table": source_table,
                    "source_row_id": row.get("source_row_id"),
                    "event_type": row.get("event_type"),
                    "indicator_type": row.get("indicator_type"),
                    "application": row.get("application"),
                    "description": row.get("description"),
                    "display_path": path,
                    "normalized_path": normalized_path,
                    "source_file": _short_case_path(display_evidence_path(details.get("source_file")) or details.get("source_file")),
                    "registry_key": details.get("key_path") or details.get("source_key"),
                    "autostart_references": autostart_matches,
                    "reason": reason,
                }
            )
    candidates.sort(
        key=lambda item: (
            {"high": 0, "medium": 1, "low": 2}.get(str(item.get("severity")), 9),
            item.get("location_category") or "",
            item.get("display_path") or "",
            item.get("timestamp_utc") or "",
        )
    )
    return _dedupe_malware_indicator_rows(candidates)


def _malware_registry_value_rows(
    db: Database,
    case_id: str,
    *,
    limit: int,
    long_value_threshold: int,
) -> tuple[list[dict[str, Any]], dict[str, int]]:
    rows = _query_report_rows(
        db,
        case_id,
        "registry_artifacts",
        """
        SELECT id, source_path, hive_type, artifact, category, key_path,
               key_last_write_utc, event_time_utc, value_name, value_type,
               value_data, display_name, normalized_path
        FROM registry_artifacts
        WHERE case_id = ?
          AND COALESCE(value_data, '') != ''
        ORDER BY COALESCE(event_time_utc, key_last_write_utc, '') DESC, artifact, key_path
        LIMIT ?
        """,
        (case_id, max(limit * 20, 1000)),
    )
    indicators: list[dict[str, Any]] = []
    suppressed_counts: dict[str, int] = {}
    for row in rows:
        suppression_reason = _malware_registry_suppression_reason(row)
        if suppression_reason:
            suppressed_counts[suppression_reason] = suppressed_counts.get(suppression_reason, 0) + 1
            continue
        value_data = str(row.get("value_data") or "")
        flags = _registry_value_indicator_flags(value_data, long_value_threshold=long_value_threshold)
        if not flags:
            continue
        if (
            "base64_decodable" not in flags
            and not _malware_registry_command_text_is_useful(row, flags)
            and not _malware_registry_long_value_name_is_command(row, flags)
        ):
            continue
        autostart_location = _malware_known_autostart_location(row)
        benign_reason = _malware_report_benign_registry_value_reason(row)
        if benign_reason:
            suppressed_counts[benign_reason] = suppressed_counts.get(benign_reason, 0) + 1
            continue
        severity = "high" if "base64_decodable" in flags and "long_value" in flags else "medium"
        indicators.append(
            {
                "severity": severity,
                "source_table": "registry_artifacts",
                "source_row_id": row.get("id"),
                "timestamp_utc": row.get("event_time_utc") or row.get("key_last_write_utc"),
                "source_path": display_evidence_path(row.get("source_path")),
                "hive_type": row.get("hive_type"),
                "artifact": row.get("artifact"),
                "category": row.get("category"),
                "key_path": row.get("key_path"),
                "value_name": row.get("value_name"),
                "value_type": row.get("value_type"),
                "value_length": len(value_data),
                "value_preview": _sanitize_report_inline(_truncate_middle(value_data, 160)),
                "flags": flags,
                "autostart_location": autostart_location,
                "known_autostart_location": autostart_location is not None,
            }
        )
    indicators.sort(
        key=lambda item: (
            {"high": 0, "medium": 1, "low": 2}.get(str(item.get("severity")), 9),
            -(item.get("value_length") or 0),
            item.get("artifact") or "",
        )
    )
    return indicators[:limit], suppressed_counts


def _malware_registry_suppression_reason(row: dict[str, Any]) -> str | None:
    artifact = str(row.get("artifact") or "").casefold()
    category = str(row.get("category") or "").casefold()
    key_path = str(row.get("key_path") or "").replace("/", "\\").casefold()
    if artifact in MALWARE_REPORT_IGNORED_REGISTRY_ARTIFACTS:
        return f"parsed_legitimate_registry_artifact:{artifact}"
    if category == "user_activity":
        return "parsed_user_activity_registry_artifact"
    if artifact in MALWARE_REPORT_REGISTRY_ARTIFACTS_OF_INTEREST:
        return None
    if any(token in key_path for token in MALWARE_REPORT_REGISTRY_KEY_TOKENS_OF_INTEREST):
        return None
    return "registry_artifact_not_persistence_or_command_source"


def _malware_known_autostart_location(row: dict[str, Any]) -> str | None:
    artifact = str(row.get("artifact") or "").casefold()
    label = MALWARE_REPORT_KNOWN_AUTOSTART_ARTIFACT_LABELS.get(artifact)
    if label:
        return label
    key_path = str(row.get("key_path") or "").replace("/", "\\").casefold()
    if "\\currentversion\\runonce" in key_path:
        return "RunOnce"
    if "\\currentversion\\run" in key_path:
        return "Run"
    if "\\schedule\\taskcache" in key_path:
        return "Scheduled Task Cache"
    if "\\services\\" in key_path:
        return "Windows service"
    if "\\image file execution options\\" in key_path:
        return "Image File Execution Options"
    if "\\windows nt\\currentversion\\winlogon" in key_path:
        return "Winlogon"
    return None


def _malware_report_benign_registry_value_reason(row: dict[str, Any]) -> str | None:
    artifact = str(row.get("artifact") or "").casefold()
    value = str(row.get("value_data") or "").casefold()
    normalized_value = value.replace("/", "\\")
    for pattern_artifact, patterns, reason in MALWARE_REPORT_BENIGN_REGISTRY_VALUE_PATTERNS:
        if artifact != pattern_artifact:
            continue
        if any(re.search(pattern, normalized_value, re.IGNORECASE) for pattern in patterns):
            return reason
    return None


def _malware_autostart_references(db: Database, case_id: str) -> dict[str, list[dict[str, Any]]]:
    artifacts = sorted(MALWARE_REPORT_KNOWN_AUTOSTART_ARTIFACT_LABELS)
    placeholders = ",".join("?" for _ in artifacts)
    rows = _query_report_rows(
        db,
        case_id,
        "registry_artifacts",
        f"""
        SELECT id, artifact, key_path, value_name, value_data, normalized_path,
               key_last_write_utc, event_time_utc
        FROM registry_artifacts
        WHERE case_id = ?
          AND artifact IN ({placeholders})
          AND (
            COALESCE(normalized_path, '') != ''
            OR COALESCE(value_data, '') != ''
          )
        """,
        [case_id, *artifacts],
    )
    refs: dict[str, list[dict[str, Any]]] = {}
    for row in rows:
        item = dict(row)
        location = _malware_known_autostart_location(item)
        paths = _candidate_paths_from_registry_value(item)
        for path in paths:
            normalized = _normalize_artifact_path(path)
            if not normalized:
                continue
            refs.setdefault(normalized.casefold(), []).append(
                {
                    "source_table": "registry_artifacts",
                    "source_row_id": item.get("id"),
                    "artifact": item.get("artifact"),
                    "autostart_location": location,
                    "key_path": item.get("key_path"),
                    "value_name": item.get("value_name"),
                    "timestamp_utc": item.get("event_time_utc") or item.get("key_last_write_utc"),
                }
            )
    return refs


def _candidate_paths_from_registry_value(row: dict[str, Any]) -> list[str]:
    candidates = [
        str(row.get("normalized_path") or ""),
        str(row.get("value_data") or ""),
    ]
    paths: list[str] = []
    for value in candidates:
        if not value:
            continue
        paths.extend(re.findall(r"[A-Za-z]:[\\/][^\"'\s|<>]+", value))
        paths.extend(re.findall(r"\\Device\\HarddiskVolume\d+\\[^\"'\s|<>]+", value, flags=re.IGNORECASE))
        if not paths and _path_looks_executable_or_script(value):
            paths.append(value)
    return paths


def _unusual_execution_location(path: str) -> str | None:
    normalized = display_evidence_path(path).replace("\\", "/").casefold()
    if not normalized:
        return None
    for pattern, category in UNUSUAL_EXECUTION_PATH_PATTERNS:
        if re.search(pattern, normalized, re.IGNORECASE):
            return category
    return None


def _path_looks_executable_or_script(path: str, fallback: Any = None) -> bool:
    text = f"{path} {fallback or ''}".casefold()
    return any(ext in text for ext in EXECUTABLE_OR_SCRIPT_EXTENSIONS)


def _malware_report_benign_suppression_reason(path: str, fallback: Any = None) -> str | None:
    text = display_evidence_path(path).replace("\\", "/").casefold()
    file_name = (_basename_from_path(text) or str(fallback or "")).casefold()
    for pattern, reason in MALWARE_REPORT_BENIGN_PATH_PATTERNS:
        if re.search(pattern, text, re.IGNORECASE):
            return reason
    if file_name in MALWARE_REPORT_BENIGN_FILE_NAMES and "microsoft" in text:
        return "known_microsoft_security_binary"
    return None


def _registry_value_indicator_flags(value: str, *, long_value_threshold: int) -> list[str]:
    flags: list[str] = []
    compact = re.sub(r"\s+", "", value)
    if len(value) >= long_value_threshold:
        flags.append("long_value")
    lowered = value.casefold()
    if any(token in lowered for token in MALWARE_REPORT_COMMAND_TEXT_TOKENS):
        flags.append("command_or_script_text")
    compact_is_hex = bool(re.fullmatch(r"[0-9a-fA-F]+", compact or "")) and len(compact) % 2 == 0
    if len(compact) >= 80 and _looks_like_base64(compact):
        flags.append("base64_decodable")
    elif len(compact) >= 80 and not compact_is_hex and re.fullmatch(r"[A-Za-z0-9+/=]+", compact or ""):
        flags.append("base64_like")
    return flags


def _looks_like_base64(value: str) -> bool:
    if re.fullmatch(r"[0-9a-fA-F]+", value or "") and len(value) % 2 == 0:
        return False
    if len(value) % 4 != 0:
        value = value + "=" * ((4 - len(value) % 4) % 4)
    try:
        decoded = base64.b64decode(value, validate=True)
    except (binascii.Error, ValueError):
        return False
    if len(decoded) < 32:
        return False
    return _decoded_base64_has_text_signal(decoded)


def _decoded_base64_has_text_signal(decoded: bytes) -> bool:
    decoded_variants: list[str] = []
    for encoding in ("utf-8", "utf-16-le", "latin-1"):
        try:
            decoded_variants.append(decoded.decode(encoding, errors="ignore"))
        except LookupError:
            continue
    for text in decoded_variants:
        lowered = text.casefold()
        if any(token.strip().casefold() in lowered for token in MALWARE_REPORT_COMMAND_TEXT_TOKENS):
            return True
        printable = sum(1 for char in text if char.isprintable() or char.isspace())
        alphabetic = sum(1 for char in text if char.isalpha())
        if text and printable / max(len(text), 1) >= 0.75 and alphabetic >= 8 and (" " in text or "\\" in text or "/" in text):
            return True
    return False


def _malware_registry_command_text_is_useful(row: dict[str, Any], flags: list[str]) -> bool:
    if "command_or_script_text" not in flags:
        return False
    artifact = str(row.get("artifact") or "").casefold()
    if artifact in {"autostart", "runmru", "scheduled_task_cache"}:
        return True
    return _malware_registry_value_name_is_command_context(row)


def _malware_registry_long_value_name_is_command(row: dict[str, Any], flags: list[str]) -> bool:
    if "long_value" not in flags:
        return False
    return _malware_registry_value_name_is_command_context(row)


def _malware_registry_value_name_is_command_context(row: dict[str, Any]) -> bool:
    value_name = str(row.get("value_name") or "").casefold()
    return value_name in {name.casefold() for name in MALWARE_REPORT_COMMAND_VALUE_NAMES}


def _truncate_middle(value: str, max_length: int) -> str:
    if len(value) <= max_length:
        return value
    half = max(1, (max_length - 5) // 2)
    return f"{value[:half]} ... {value[-half:]}"


def _sanitize_report_inline(value: Any) -> str:
    text = str(value or "")
    return "".join(char if char.isprintable() or char in "\t " else "." for char in text)


def _dedupe_malware_indicator_rows(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    deduped: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for row in rows:
        key = (
            str(row.get("source_table") or ""),
            str(row.get("source_row_id") or ""),
            str(row.get("display_path") or "").casefold(),
            str(row.get("location_category") or ""),
        )
        if key in seen:
            continue
        seen.add(key)
        deduped.append(row)
    return deduped


def suspicious_timeline_windows_report(
    db: Database,
    case_id: str,
    *,
    window_minutes: int = 30,
    limit: int = 100,
) -> dict[str, Any]:
    db.get_case(case_id)
    events = _suspicious_window_seed_events(db, case_id, limit=max(limit * 10, 500))
    windows = _cluster_suspicious_events(events, window_minutes=window_minutes)
    windows.sort(key=lambda row: (-int(row.get("score") or 0), row.get("start_utc") or ""))
    return {
        "case_id": case_id,
        "summary": {
            "seed_event_count": len(events),
            "window_count": len(windows),
            "window_minutes": window_minutes,
            "returned_windows": min(len(windows), limit),
        },
        "windows": windows[:limit],
        "events": events[: max(limit * 5, limit)],
        "total_returned": min(len(windows), limit),
    }


def suspicious_timeline_windows_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Suspicious Timeline Windows",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Seed events considered: `{summary.get('seed_event_count', 0)}`",
        f"- Suspicious windows: `{summary.get('window_count', 0)}`",
        f"- Window size: `{summary.get('window_minutes', 0)}` minutes",
        "",
        "## Windows",
        "",
    ]
    windows = report.get("windows") if isinstance(report.get("windows"), list) else []
    if not windows:
        lines.append("- No suspicious timeline windows were identified.")
    for index, window in enumerate(windows, start=1):
        categories = ", ".join(str(item) for item in window.get("categories") or [])
        lines.extend(
            [
                f"### {index}. `{window.get('start_utc') or ''}` to `{window.get('end_utc') or ''}`",
                "",
                f"- Score: `{window.get('score') or 0}`",
                f"- Event count: `{window.get('event_count') or 0}`",
                f"- Categories: `{categories}`",
                f"- Rationale: {window.get('rationale') or ''}",
                "",
            ]
        )
        for event in (window.get("events") or [])[:12]:
            lines.append(
                f"- `{event.get('timestamp_utc') or ''}` `{event.get('category') or ''}` "
                f"`{event.get('source') or ''}` {event.get('description') or ''}"
            )
        lines.append("")
    return "\n".join(lines).rstrip() + "\n"


def investigation_triage_dashboard_report(db: Database, case_id: str, *, limit: int = 25) -> dict[str, Any]:
    db.get_case(case_id)
    completeness = artifact_completeness_report(db, case_id, limit=limit)
    quality = evidence_quality_report(db, case_id, limit=limit)
    gaps = evidence_gaps_report(db, case_id, limit=limit)
    memory = memory_artifacts_report(db, case_id, limit=limit)
    suspicious = suspicious_timeline_windows_report(db, case_id, limit=limit)
    brute = brute_force_report(db, case_id, limit=limit)
    remote = remote_access_sessions_report(db, case_id, limit=limit)
    external = external_storage_report(db, case_id, limit=limit)
    malware = malware_hiding_places_report(db, case_id, limit=limit)
    interesting = interesting_executables_report(db, case_id, limit=limit)
    suspicious_exec = suspicious_executions_report(db, case_id, limit=limit)
    exfil = data_exfiltration_report(db, case_id, limit=limit)
    account = account_compromise_report(db, case_id, limit=limit)
    cards = [
        _triage_card("artifact_completeness", "Artifact Completeness", completeness.get("summary") or {}),
        _triage_card("evidence_quality", "Evidence Quality", quality.get("summary") or {}),
        _triage_card("evidence_gaps", "Evidence Gaps", gaps.get("summary") or {}),
        _triage_card("memory_artifacts", "Memory Artifacts", memory.get("summary") or {}),
        _triage_card("suspicious_windows", "Suspicious Windows", suspicious.get("summary") or {}),
        _triage_card("brute_force", "Brute Force / Password Spraying", brute.get("summary") or {}),
        _triage_card("remote_access", "Remote Access", remote.get("summary") or {}),
        _triage_card("external_storage", "External Storage", external.get("summary") or {}),
        _triage_card("malware_hiding", "Malware Hiding Places", malware.get("summary") or {}),
        _triage_card("interesting_executables", "Interesting Executables", interesting.get("summary") or {}),
        _triage_card("suspicious_executions", "Suspicious Executions", suspicious_exec.get("summary") or {}),
        _triage_card("data_exfiltration", "Data Exfiltration", exfil.get("summary") or {}),
        _triage_card("account_compromise", "Account Compromise", account.get("summary") or {}),
    ]
    return {
        "case_id": case_id,
        "summary": {
            "cards": len(cards),
            "top_suspicious_windows": len(suspicious.get("windows") or []),
            "data_exfiltration_findings": (exfil.get("summary") or {}).get("finding_count", 0),
            "account_compromise_findings": (account.get("summary") or {}).get("finding_count", 0),
            "evidence_gaps": (gaps.get("summary") or {}).get("gap_count", 0),
            "memory_artifacts": (memory.get("summary") or {}).get("artifact_count", 0),
            "suspicious_execution_findings": (suspicious_exec.get("summary") or {}).get("finding_count", 0),
        },
        "cards": cards,
        "top_evidence_gaps": (gaps.get("gaps") or [])[:10],
        "memory_artifacts": (memory.get("artifacts") or [])[:10],
        "top_windows": (suspicious.get("windows") or [])[:10],
        "top_suspicious_executions": (suspicious_exec.get("findings") or [])[:10],
        "top_data_exfiltration_findings": (exfil.get("findings") or [])[:10],
        "top_account_compromise_findings": (account.get("findings") or [])[:10],
        "recommended_reports": [
            {"report": "suspicious-timeline-windows", "reason": "Review clustered high-signal activity."},
            {"report": "suspicious-executions", "reason": "Review notable executions, suspicious command tokens, and unusual execution locations."},
            {"report": "evidence-gaps", "reason": "Review unsupported, encrypted, partial, or skipped evidence sources."},
            {"report": "memory-artifacts", "reason": "Inventory hibernation, pagefile, and swapfile candidates for later memory analysis."},
            {"report": "data-exfiltration", "reason": "Review removable media, cloud, archive, browser, and email movement leads."},
            {"report": "account-compromise", "reason": "Review logon failures, successful access, and remote-access context."},
            {"report": "program-provenance", "reason": "Review how notable executables arrived and whether they ran."},
        ],
    }


def investigation_triage_dashboard_markdown(report: dict[str, Any]) -> str:
    lines = ["# Investigation Triage Dashboard", "", f"Case: `{report.get('case_id') or ''}`", "", "## Score Cards", ""]
    for card in report.get("cards") or []:
        lines.append(
            f"- `{card.get('id')}` {card.get('title')}: severity `{card.get('severity')}`, "
            f"score `{card.get('score')}`, summary `{card.get('summary_text')}`"
        )
    lines.extend(["", "## Top Suspicious Windows", ""])
    for window in (report.get("top_windows") or [])[:10]:
        lines.append(
            f"- `{window.get('start_utc') or ''}` to `{window.get('end_utc') or ''}` "
            f"score `{window.get('score') or 0}` categories `{', '.join(window.get('categories') or [])}`"
        )
    if not report.get("top_windows"):
        lines.append("- No suspicious windows were found.")
    lines.extend(["", "## Top Suspicious Executions", ""])
    for finding in (report.get("top_suspicious_executions") or [])[:10]:
        details = finding.get("details") if isinstance(finding.get("details"), dict) else {}
        path = (
            finding.get("display_path")
            or finding.get("normalized_path")
            or details.get("path")
            or details.get("resolved_path")
            or details.get("process_path")
            or ""
        )
        app = finding.get("application") or details.get("application") or details.get("file_name") or details.get("process_name") or ""
        source = finding.get("source_table") or finding.get("source") or ""
        lines.append(
            f"- `{finding.get('severity') or ''}` `{finding.get('category') or ''}` "
            f"{app or finding.get('description') or ''} source `{source}` path `{path}`"
        )
    if not report.get("top_suspicious_executions"):
        lines.append("- No suspicious execution leads were found.")
    lines.extend(["", "## Evidence Gaps", ""])
    for gap in (report.get("top_evidence_gaps") or [])[:10]:
        lines.append(f"- `{gap.get('severity') or ''}` `{gap.get('category') or ''}` {gap.get('title') or ''}")
    if not report.get("top_evidence_gaps"):
        lines.append("- No evidence gaps were found.")
    lines.extend(["", "## Memory Artifacts", ""])
    for artifact in (report.get("memory_artifacts") or [])[:10]:
        lines.append(
            f"- `{artifact.get('artifact_type') or ''}` `{artifact.get('path') or ''}` "
            f"size `{artifact.get('size_bytes') or ''}`"
        )
    if not report.get("memory_artifacts"):
        lines.append("- No on-disk memory artifacts were found.")
    lines.extend(["", "## Top Data Movement Leads", ""])
    for finding in (report.get("top_data_exfiltration_findings") or [])[:10]:
        lines.append(
            f"- `{finding.get('severity') or ''}` `{finding.get('category') or ''}` "
            f"{finding.get('description') or ''} source `{finding.get('source') or ''}`"
        )
    if not report.get("top_data_exfiltration_findings"):
        lines.append("- No data movement leads were found.")
    lines.extend(["", "## Recommended Next Reports", ""])
    for item in report.get("recommended_reports") or []:
        lines.append(f"- `{item.get('report')}`: {item.get('reason')}")
    return "\n".join(lines).rstrip() + "\n"


def data_exfiltration_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    findings: list[dict[str, Any]] = []
    external = external_storage_report(db, case_id, limit=limit)
    for row in external.get("devices") or []:
        if row.get("file_activity_detected"):
            findings.append(_finding("medium", "external_storage_file_activity", "external-storage", row.get("serial") or row.get("friendly_name"), row))
    for row in external.get("file_activity") or []:
        findings.append(_finding("medium", "usb_file_activity", "usb_file_correlations", row.get("file_location") or row.get("file_name"), row))
    cloud = cloud_files_report(db, case_id, limit=limit)
    for row in cloud.get("cloud_files") or []:
        severity = "medium" if str(row.get("is_deleted") or "").lower() in {"1", "true", "yes"} else "low"
        findings.append(_finding(severity, "cloud_file_activity", row.get("source_table"), row.get("cloud_path") or row.get("file_name"), row))
    downloads = browser_downloads_report(db, case_id, limit=limit)
    for row in downloads.get("browser_downloads") or downloads.get("items") or []:
        findings.append(_finding("low", "browser_download", "browser_downloads", row.get("target_path") or row.get("url"), row))
    attachments = mailbox_attachments_report(db, case_id, limit=limit)
    for row in attachments.get("mailbox_attachments") or []:
        findings.append(_finding("low", "email_attachment", "mailbox_attachments", row.get("attachment_name"), row))
    for row in _archive_exfil_rows(db, case_id, limit=limit):
        findings.append(_finding("medium", "archive_staging", "archive_entries", row.get("archive_path") or row.get("member_path"), row))
    copied = copied_file_indicators_report(db, case_id, limit=limit)
    for row in copied.get("items") or copied.get("copied_file_indicators") or []:
        findings.append(_finding("medium", "copied_file_indicator", "copied_file_indicators", row.get("file_location") or row.get("file_name"), row))
    findings = _dedupe_findings(findings)
    findings.sort(key=lambda row: (_severity_rank(row.get("severity")), str(row.get("category") or ""), str(row.get("description") or "")))
    return {
        "case_id": case_id,
        "summary": {
            "finding_count": len(findings),
            "category_counts": _count_by_key(findings, "category"),
            "external_storage_devices": (external.get("summary") or {}).get("device_count", 0),
            "cloud_file_rows": len(cloud.get("cloud_files") or []),
            "email_attachment_rows": len(attachments.get("mailbox_attachments") or []),
        },
        "findings": findings[:limit],
        "external_storage_summary": external.get("summary"),
        "cloud_summary": cloud.get("summary"),
    }


def data_exfiltration_markdown(report: dict[str, Any]) -> str:
    return _findings_markdown("Data Exfiltration Report", report, "Data movement leads")


def account_compromise_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    findings: list[dict[str, Any]] = []
    brute = brute_force_report(db, case_id, limit=limit)
    for row in brute.get("source_ips") or []:
        severity = "high" if row.get("classification") in {"password_spraying", "brute_force"} else "medium"
        findings.append(_finding(severity, "failed_logon_pattern", "brute-force", row.get("source_ip"), row))
    for row in brute.get("target_accounts") or []:
        findings.append(_finding("medium", "targeted_account", "brute-force", row.get("target_account"), row))
    remote = remote_access_sessions_report(db, case_id, limit=limit)
    for row in remote.get("sessions") or remote.get("remote_access_sessions") or []:
        findings.append(_finding("high", "remote_access_session", "remote-access", row.get("remote_host") or row.get("username") or row.get("session_id"), row))
    attribution = remote_access_attribution_report(db, case_id, limit=limit)
    for row in attribution.get("windows") or []:
        if row.get("external_storage_count") or row.get("local_activity_count") or row.get("cloud_activity_count"):
            findings.append(_finding("high", "remote_access_with_local_context", "remote-access-attribution", row.get("window_label") or row.get("remote_host"), row))
    for row in _successful_logon_rows(db, case_id, limit=limit):
        findings.append(_finding("low", "successful_logon", "evtx_events", row.get("description") or row.get("remote_host") or row.get("user_name"), row))
    findings = _dedupe_findings(findings)
    findings.sort(key=lambda row: (_severity_rank(row.get("severity")), str(row.get("category") or ""), str(row.get("description") or "")))
    return {
        "case_id": case_id,
        "summary": {
            "finding_count": len(findings),
            "category_counts": _count_by_key(findings, "category"),
            "failed_logon_events": (brute.get("summary") or {}).get("failure_event_count", 0),
            "source_ip_count": (brute.get("summary") or {}).get("source_ip_count", 0),
            "remote_access_sessions": len(remote.get("sessions") or remote.get("remote_access_sessions") or []),
        },
        "findings": findings[:limit],
        "brute_force_summary": brute.get("summary"),
    }


def account_compromise_markdown(report: dict[str, Any]) -> str:
    return _findings_markdown("Account Compromise Report", report, "Account and remote-access leads")


def program_provenance_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    interesting = interesting_executables_report(db, case_id, limit=limit)
    findings: list[dict[str, Any]] = []
    for row in interesting.get("matches") or interesting.get("findings") or []:
        name = row.get("file_name") or row.get("application") or row.get("description") or row.get("path")
        payload = dict(row)
        payload["related_sources"] = _program_related_sources(db, case_id, name, limit=20)
        findings.append(_finding(row.get("severity") or "medium", "interesting_program", row.get("source_table") or "interesting-executables", name, payload))
    for row in _downloaded_executable_rows(db, case_id, limit=limit):
        name = row.get("file_name") or row.get("target_path") or row.get("url")
        payload = dict(row)
        payload["related_sources"] = _program_related_sources(db, case_id, name, limit=20)
        findings.append(_finding("medium", "downloaded_executable", "browser_downloads", name, payload))
    findings = _dedupe_findings(findings)
    findings.sort(key=lambda row: (_severity_rank(row.get("severity")), str(row.get("description") or "")))
    return {
        "case_id": case_id,
        "summary": {"finding_count": len(findings), "category_counts": _count_by_key(findings, "category")},
        "findings": findings[:limit],
    }


def program_provenance_markdown(report: dict[str, Any]) -> str:
    return _findings_markdown("Program Provenance Report", report, "Executable provenance leads")


def investigation_findings_report(
    db: Database,
    case_id: str,
    *,
    limit: int = 100,
    rebuild: bool = False,
) -> dict[str, Any]:
    db.get_case(case_id)
    rebuild_summary = rebuild_investigation_graph(db, case_id=case_id, limit=max(limit * 20, 1000)) if rebuild else None
    findings = _query_investigation_findings(db, case_id, limit=limit)
    entity_counts = _query_count_rows(db, "investigation_entities", case_id, "entity_type")
    relationship_counts = _query_count_rows(db, "investigation_relationships", case_id, "relationship_type")
    return {
        "case_id": case_id,
        "summary": {
            "finding_count": _sqlite_count(db, "investigation_findings", case_id),
            "returned_findings": len(findings),
            "entity_count": _sqlite_count(db, "investigation_entities", case_id),
            "relationship_count": _sqlite_count(db, "investigation_relationships", case_id),
            "evidence_count": _sqlite_count(db, "investigation_finding_evidence", case_id),
            "finding_type_counts": _query_count_rows(db, "investigation_findings", case_id, "finding_type"),
            "severity_counts": _query_count_rows(db, "investigation_findings", case_id, "severity"),
            "entity_type_counts": entity_counts,
            "relationship_type_counts": relationship_counts,
        },
        "findings": findings,
        "rebuild_summary": rebuild_summary,
        "methodology": {
            "principle": "Deterministic evidence-backed findings. AI/MCP may summarize these rows, but findings originate from Perceptor rules.",
            "traceability": "Each finding contains rule metadata and supporting source_table/source_row_id evidence rows.",
        },
        "limit_note": f"findings is limited to {limit}. Increase --limit or use the source tables for the full evidence set.",
    }


def investigation_findings_markdown(report: dict[str, Any]) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [
        "# Investigation Findings",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        "",
        "## Summary",
        "",
        f"- Findings: `{summary.get('finding_count', 0)}`",
        f"- Entities: `{summary.get('entity_count', 0)}`",
        f"- Relationships: `{summary.get('relationship_count', 0)}`",
        f"- Finding evidence rows: `{summary.get('evidence_count', 0)}`",
        "",
        "## Methodology",
        "",
        "- Findings are generated by deterministic Perceptor rules.",
        "- Each finding includes rule metadata and source evidence rows.",
        "- Treat confidence as a transparent scoring aid, not a hidden conclusion.",
        "",
        "## Findings",
        "",
    ]
    findings = report.get("findings") if isinstance(report.get("findings"), list) else []
    if not findings:
        lines.append("- No investigation findings were generated. Run with `--rebuild` after artifact parsing.")
    for finding in findings:
        lines.extend(
            [
                f"### {finding.get('title') or finding.get('finding_type')}",
                "",
                f"- Severity: `{finding.get('severity') or ''}`",
                f"- Confidence: `{finding.get('confidence') or ''}` (`{finding.get('confidence_score') or 0}`)",
                f"- Rule: `{finding.get('rule_id') or ''}` {finding.get('rule_name') or ''}",
                f"- Window: `{finding.get('start_time_utc') or ''}` to `{finding.get('end_time_utc') or ''}`",
                f"- Summary: {finding.get('summary') or ''}",
                "",
            ]
        )
        evidence = finding.get("evidence") if isinstance(finding.get("evidence"), list) else []
        if evidence:
            lines.append("Evidence:")
            for row in evidence[:20]:
                lines.append(
                    f"- `{row.get('role') or ''}` `{row.get('source_table') or ''}` "
                    f"`{row.get('source_row_id') or ''}` {row.get('summary') or ''}"
                )
            lines.append("")
    if report.get("limit_note"):
        lines.extend(["## Limits", "", f"- {report['limit_note']}", ""])
    return "\n".join(lines).rstrip() + "\n"


def _query_investigation_findings(db: Database, case_id: str, *, limit: int) -> list[dict[str, Any]]:
    rows = db.conn.execute(
        """
        SELECT *
        FROM investigation_findings
        WHERE case_id = ?
        ORDER BY confidence_score DESC, COALESCE(start_time_utc, '') DESC, title
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()
    output: list[dict[str, Any]] = []
    for row in rows:
        item = dict(row)
        item["details"] = _json_object(item.pop("details_json", None))
        item["evidence"] = _query_finding_evidence(db, str(item["id"]))
        output.append(item)
    return output


def _query_finding_evidence(db: Database, finding_id: str) -> list[dict[str, Any]]:
    rows = db.conn.execute(
        """
        SELECT *
        FROM investigation_finding_evidence
        WHERE finding_id = ?
        ORDER BY COALESCE(event_time_utc, ''), role, source_table
        """,
        (finding_id,),
    ).fetchall()
    output = []
    for row in rows:
        item = dict(row)
        item["details"] = _json_object(item.pop("details_json", None))
        output.append(item)
    return output


def _sqlite_count(db: Database, table: str, case_id: str) -> int:
    row = db.conn.execute(f"SELECT COUNT(*) AS count FROM {_quote_identifier(table)} WHERE case_id = ?", (case_id,)).fetchone()
    return int(row["count"] if row else 0)


def _query_count_rows(db: Database, table: str, case_id: str, key: str) -> list[dict[str, Any]]:
    rows = db.conn.execute(
        f"""
        SELECT {_quote_identifier(key)} AS value, COUNT(*) AS count
        FROM {_quote_identifier(table)}
        WHERE case_id = ?
        GROUP BY {_quote_identifier(key)}
        ORDER BY count DESC, value
        """,
        (case_id,),
    ).fetchall()
    return [dict(row) for row in rows]


def _json_object(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return value
    if not value:
        return {}
    try:
        data = json.loads(str(value))
    except Exception:
        return {}
    return data if isinstance(data, dict) else {}


def _suspicious_window_seed_events(db: Database, case_id: str, *, limit: int) -> list[dict[str, Any]]:
    events: list[dict[str, Any]] = []
    for event in (execution_report(db, case_id, limit=limit).get("events") or []):
        events.append(_seed_event(event.get("timestamp_utc"), "execution", "execution", event.get("description"), event, weight=3))
    for row in (brute_force_report(db, case_id, limit=limit).get("source_ips") or []):
        events.append(_seed_event(row.get("first_seen_utc"), "authentication", "brute-force", row.get("source_ip"), row, weight=5))
        events.append(_seed_event(row.get("last_seen_utc"), "authentication", "brute-force", row.get("source_ip"), row, weight=5))
    for row in (external_storage_report(db, case_id, limit=limit).get("timeline") or []):
        events.append(_seed_event(row.get("timestamp"), "external_storage", "external-storage", row.get("description"), row, weight=5))
    for row in (cloud_files_report(db, case_id, limit=limit).get("cloud_files") or []):
        events.append(_seed_event(row.get("event_time_utc"), "cloud", row.get("source_table"), row.get("cloud_path") or row.get("file_name"), row, weight=3))
    for row in _archive_exfil_rows(db, case_id, limit=limit):
        events.append(_seed_event(row.get("archive_modified_time_utc"), "archive", "archive_entries", row.get("archive_path"), row, weight=4))
    output = [event for event in events if event.get("timestamp_utc")]
    output.sort(key=lambda row: _timestamp_sort_key(row.get("timestamp_utc")))
    return output


def _seed_event(timestamp: Any, category: str, source: Any, description: Any, row: dict[str, Any], *, weight: int) -> dict[str, Any]:
    return {"timestamp_utc": timestamp, "category": category, "source": source, "description": description, "weight": weight, "row": row}


def _cluster_suspicious_events(events: list[dict[str, Any]], *, window_minutes: int) -> list[dict[str, Any]]:
    parsed = [(event, _parse_report_timestamp(str(event.get("timestamp_utc") or ""))) for event in events]
    parsed = [(event, ts) for event, ts in parsed if ts is not None]
    windows: list[dict[str, Any]] = []
    used: set[int] = set()
    for index, (_event, start) in enumerate(parsed):
        if index in used:
            continue
        end = start
        members: list[dict[str, Any]] = []
        for other_index, (other, other_ts) in enumerate(parsed):
            if other_index in used:
                continue
            if abs((other_ts - start).total_seconds()) <= window_minutes * 60:
                used.add(other_index)
                members.append(other)
                if other_ts > end:
                    end = other_ts
        categories = sorted({str(member.get("category") or "") for member in members if member.get("category")})
        score = sum(int(member.get("weight") or 1) for member in members) + max(0, len(categories) - 1) * 4
        if len(members) < 2 and score < 6:
            continue
        windows.append(
            {
                "start_utc": _format_report_timestamp(start),
                "end_utc": _format_report_timestamp(end),
                "event_count": len(members),
                "categories": categories,
                "score": score,
                "rationale": _suspicious_window_rationale(categories, len(members)),
                "events": members,
            }
        )
    return windows


def _suspicious_window_rationale(categories: list[str], event_count: int) -> str:
    if len(categories) > 1:
        return f"{event_count} high-signal events across {len(categories)} categories occurred in a short window."
    return f"{event_count} high-signal events occurred close together."


def _triage_card(identifier: str, title: str, summary: dict[str, Any]) -> dict[str, Any]:
    score = _triage_score(summary)
    return {
        "id": identifier,
        "title": title,
        "score": score,
        "severity": "high" if score >= 50 else "medium" if score >= 15 else "low",
        "summary_text": _triage_summary_text(summary),
        "summary": summary,
    }


def _triage_score(summary: dict[str, Any]) -> int:
    total = 0
    for key, value in summary.items():
        if isinstance(value, int) and any(token in key for token in ("count", "events", "findings", "failures", "windows")):
            total += min(value, 50)
    return total


def _triage_summary_text(summary: dict[str, Any]) -> str:
    parts = []
    for key, value in summary.items():
        if isinstance(value, (str, int, float)) and len(parts) < 4:
            parts.append(f"{key}={value}")
    return "; ".join(parts)


def _finding(severity: Any, category: Any, source: Any, description: Any, row: dict[str, Any]) -> dict[str, Any]:
    return {"severity": severity or "low", "category": category or "unknown", "source": source or "unknown", "description": description or "", "details": row}


def _dedupe_findings(findings: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, str, str]] = set()
    output = []
    for finding in findings:
        key = (str(finding.get("category") or ""), str(finding.get("source") or ""), str(finding.get("description") or "").casefold())
        if key in seen:
            continue
        seen.add(key)
        output.append(finding)
    return output


def _severity_rank(value: Any) -> int:
    return {"critical": 0, "high": 1, "medium": 2, "low": 3, "info": 4}.get(str(value or "").lower(), 5)


def _count_by_key(rows: list[dict[str, Any]], key: str) -> list[dict[str, Any]]:
    counts: dict[str, int] = {}
    for row in rows:
        value = str(row.get(key) or "unknown")
        counts[value] = counts.get(value, 0) + 1
    return [{"value": value, "count": count} for value, count in sorted(counts.items(), key=lambda item: (-item[1], item[0]))]


def _findings_markdown(title: str, report: dict[str, Any], heading: str) -> str:
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    lines = [f"# {title}", "", f"Case: `{report.get('case_id') or ''}`", "", "## Summary", "", f"- Findings: `{summary.get('finding_count', 0)}`", ""]
    counts = summary.get("category_counts") if isinstance(summary.get("category_counts"), list) else []
    if counts:
        lines.extend(["Category counts:", ""])
        for row in counts:
            lines.append(f"- `{row.get('value')}`: `{row.get('count')}`")
        lines.append("")
    lines.extend([f"## {heading}", ""])
    findings = report.get("findings") if isinstance(report.get("findings"), list) else []
    if not findings:
        lines.append("- No findings were produced.")
    for finding in findings:
        lines.append(f"- `{finding.get('severity') or ''}` `{finding.get('category') or ''}` {finding.get('description') or ''} source `{finding.get('source') or ''}`")
    return "\n".join(lines).rstrip() + "\n"


def _archive_exfil_rows(db: Database, case_id: str, *, limit: int) -> list[dict[str, Any]]:
    return _query_report_rows(
        db,
        case_id,
        "archive_entries",
        """
        SELECT *
        FROM archive_entries
        WHERE case_id = ?
          AND (member_path IS NULL OR COALESCE(member_path, '') = '')
        ORDER BY archive_modified_time_utc DESC, archive_path
        LIMIT ?
        """,
        (case_id, limit),
    )


def _successful_logon_rows(db: Database, case_id: str, *, limit: int) -> list[dict[str, Any]]:
    return _query_report_rows(
        db,
        case_id,
        "evtx_events",
        """
        SELECT *
        FROM evtx_events
        WHERE case_id = ?
          AND event_id IN ('4624', '4776', '4778')
          AND COALESCE(time_created, '') != ''
        ORDER BY time_created DESC
        LIMIT ?
        """,
        (case_id, limit),
    )


def _downloaded_executable_rows(db: Database, case_id: str, *, limit: int) -> list[dict[str, Any]]:
    columns = _report_table_columns(db, case_id, "browser_downloads")
    candidate_columns = [
        column
        for column in ("target_path", "file_name", "url", "tab_url", "site_url", "referrer")
        if column in columns
    ]
    if not candidate_columns:
        return []
    name_expr = f"COALESCE({', '.join(candidate_columns)}, '')"
    return _query_report_rows(
        db,
        case_id,
        "browser_downloads",
        f"""
        SELECT *
        FROM browser_downloads
        WHERE case_id = ?
          AND (
            lower({name_expr}) LIKE '%.exe%'
            OR lower({name_expr}) LIKE '%.dll%'
            OR lower({name_expr}) LIKE '%.ps1%'
            OR lower({name_expr}) LIKE '%.bat%'
            OR lower({name_expr}) LIKE '%.msi%'
          )
        ORDER BY COALESCE(end_time_utc, start_time_utc, '') DESC
        LIMIT ?
        """,
        (case_id, limit),
    )


def _program_related_sources(db: Database, case_id: str, name: Any, *, limit: int) -> dict[str, Any]:
    text = str(name or "").strip()
    basename = Path(text.replace("\\", "/")).name if text else ""
    if not basename:
        return {"executed": False, "sources": []}
    pattern = f"%{basename}%"
    sources: list[dict[str, Any]] = []
    for table, column in (
        ("prefetch_items", "executable_name"),
        ("browser_downloads", "target_path"),
        ("zone_identifier_ads", "file_path"),
        ("mailbox_attachments", "attachment_name"),
        ("usb_file_correlations", "file_name"),
    ):
        try:
            rows = _query_report_rows(db, case_id, table, f"SELECT * FROM {table} WHERE case_id = ? AND {column} LIKE ? LIMIT ?", (case_id, pattern, limit))
        except Exception:
            rows = []
        if rows:
            sources.append({"source_table": table, "match_count": len(rows), "examples": rows[:5]})
    return {"executed": any(source.get("source_table") == "prefetch_items" for source in sources), "sources": sources}


def shortcuts_report(db: Database, case_id: str, *, artifact_type: str | None = None, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    params: list[Any] = [case_id]
    where = "WHERE shortcut_items.case_id = ?"
    if artifact_type:
        where += " AND shortcut_items.artifact_type = ?"
        params.append(artifact_type)
    params.append(limit)
    rows = _query_report_rows(
        db,
        case_id,
        "shortcut_items",
        f"""
        SELECT shortcut_items.*, NULL AS computer_label, NULL AS image_path
        FROM shortcut_items
        {where}
        ORDER BY shortcut_items.artifact_type, shortcut_items.artifact_path, shortcut_items.row_number
        LIMIT ?
        """,
        params,
    )
    computer_labels = _computer_labels(db, case_id)
    image_paths = _image_paths(db, case_id)
    items = []
    for row in rows:
        item = dict(row)
        item["computer_label"] = item.get("computer_label") or computer_labels.get(str(item.get("computer_id")))
        item["image_path"] = item.get("image_path") or image_paths.get(str(item.get("image_id")))
        items.append(item)
    return {"case_id": case_id, "shortcuts": items, "total_returned": len(rows)}


def shortcut_droid_changes_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    columns = _report_table_columns(db, case_id, "shortcut_items")
    if not {"droid_volume_id", "droid_file_id", "birth_droid_volume_id", "birth_droid_file_id"} & columns:
        return {"case_id": case_id, "droid_changes": [], "total_returned": 0}
    rows = _query_report_rows(
        db,
        case_id,
        "shortcut_items",
        f"""
        SELECT {_shortcut_select_sql(columns)},
               case_id,
               source_scope,
               snapshot_id,
               snapshot_ids,
               snapshot_count,
               snapshot_index,
               snapshot_created_utc
        FROM shortcut_items
        WHERE case_id = ?
          AND (
            ({_droid_column_sql(columns, 'droid_volume_id')} <> '' AND {_droid_column_sql(columns, 'birth_droid_volume_id')} <> ''
             AND lower({_droid_column_sql(columns, 'droid_volume_id')}) <> lower({_droid_column_sql(columns, 'birth_droid_volume_id')}))
            OR
            ({_droid_column_sql(columns, 'droid_file_id')} <> '' AND {_droid_column_sql(columns, 'birth_droid_file_id')} <> ''
             AND lower({_droid_column_sql(columns, 'droid_file_id')}) <> lower({_droid_column_sql(columns, 'birth_droid_file_id')}))
          )
        ORDER BY COALESCE(NULLIF(target_accessed, ''), NULLIF(target_modified, ''), NULLIF(target_created, ''), NULLIF(lnk_modified, ''), NULLIF(lnk_created, '')) DESC,
                 artifact_type,
                 artifact_path
        LIMIT ?
        """,
        (case_id, limit),
    )
    computer_labels = _computer_labels(db, case_id)
    image_paths = _image_paths(db, case_id)
    items = []
    for row in rows:
        item = dict(row)
        item["computer_label"] = computer_labels.get(str(item.get("computer_id"))) if item.get("computer_id") else None
        item["image_path"] = image_paths.get(str(item.get("image_id"))) if item.get("image_id") else None
        item["droid_change_basis"] = _shortcut_droid_change_basis(item)
        item["interpretation"] = (
            "Current Droid and Birth Droid values differ. This can indicate the linked target was moved, "
            "renamed, copied, or otherwise resolved as a different tracked file/volume object after tracking began."
        )
        items.append(item)
    return {"case_id": case_id, "droid_changes": items, "total_returned": len(items)}


def shortcut_object_tracking_report(db: Database, case_id: str, *, limit: int = 100) -> dict[str, Any]:
    db.get_case(case_id)
    shortcut_columns = _report_table_columns(db, case_id, "shortcut_items")
    mft_columns = _report_table_columns(db, case_id, "mft_entries")
    if "object_id" not in mft_columns:
        return {"case_id": case_id, "matches": [], "total_returned": 0}
    rows = _query_report_rows(
        db,
        case_id,
        "shortcut_items",
        f"""
        WITH shortcuts AS (
          SELECT {_shortcut_select_sql(shortcut_columns)}
          FROM shortcut_items
          WHERE case_id = ?
        ),
        mft AS (
          SELECT id AS mft_id, computer_id AS mft_computer_id, image_id AS mft_image_id,
                 entry_number AS mft_entry_number, sequence_number AS mft_sequence_number,
                 parent_path AS mft_parent_path, file_name AS mft_file_name,
                 object_id, birth_volume_id, birth_object_id, birth_domain_id,
                 created_si AS mft_created_si, modified_si AS mft_modified_si,
                 record_changed_si AS mft_record_changed_si, accessed_si AS mft_accessed_si,
                 source_file AS mft_source_file
          FROM mft_entries
          WHERE case_id = ?
            AND COALESCE(object_id, '') <> ''
        )
        SELECT shortcuts.*,
               mft.*,
               CASE
                 WHEN {_droid_column_sql(shortcut_columns, 'droid_file_id')} <> ''
                      AND {_normalized_guid_sql(_droid_column_sql(shortcut_columns, 'droid_file_id'))} = {_normalized_guid_sql('mft.object_id')}
                   THEN 'current_droid_file_id_to_mft_object_id'
                 WHEN {_droid_column_sql(shortcut_columns, 'birth_droid_file_id')} <> ''
                      AND {_normalized_guid_sql(_droid_column_sql(shortcut_columns, 'birth_droid_file_id'))} = {_normalized_guid_sql('mft.object_id')}
                   THEN 'birth_droid_file_id_to_mft_object_id'
                 WHEN {_droid_column_sql(shortcut_columns, 'birth_droid_file_id')} <> ''
                      AND COALESCE(mft.birth_object_id, '') <> ''
                      AND {_normalized_guid_sql(_droid_column_sql(shortcut_columns, 'birth_droid_file_id'))} = {_normalized_guid_sql('mft.birth_object_id')}
                   THEN 'birth_droid_file_id_to_mft_birth_object_id'
                 ELSE 'unknown'
               END AS match_basis
        FROM shortcuts
        JOIN mft
          ON (
            ({_droid_column_sql(shortcut_columns, 'droid_file_id')} <> ''
             AND {_normalized_guid_sql(_droid_column_sql(shortcut_columns, 'droid_file_id'))} = {_normalized_guid_sql('mft.object_id')})
            OR
            ({_droid_column_sql(shortcut_columns, 'birth_droid_file_id')} <> ''
             AND {_normalized_guid_sql(_droid_column_sql(shortcut_columns, 'birth_droid_file_id'))} = {_normalized_guid_sql('mft.object_id')})
            OR
            ({_droid_column_sql(shortcut_columns, 'birth_droid_file_id')} <> ''
             AND COALESCE(mft.birth_object_id, '') <> ''
             AND {_normalized_guid_sql(_droid_column_sql(shortcut_columns, 'birth_droid_file_id'))} = {_normalized_guid_sql('mft.birth_object_id')})
          )
        ORDER BY COALESCE(NULLIF(target_accessed, ''), NULLIF(target_modified, ''), NULLIF(target_created, ''), NULLIF(lnk_modified, ''), NULLIF(lnk_created, '')) DESC,
                 artifact_path,
                 mft_parent_path,
                 mft_file_name
        LIMIT ?
        """,
        (case_id, case_id, limit),
    )
    computer_labels = _computer_labels(db, case_id)
    image_paths = _image_paths(db, case_id)
    matches = []
    for row in rows:
        item = dict(row)
        item["computer_label"] = computer_labels.get(str(item.get("computer_id"))) if item.get("computer_id") else None
        item["image_path"] = image_paths.get(str(item.get("image_id"))) if item.get("image_id") else None
        item["mft_computer_label"] = computer_labels.get(str(item.get("mft_computer_id"))) if item.get("mft_computer_id") else None
        item["mft_image_path"] = image_paths.get(str(item.get("mft_image_id"))) if item.get("mft_image_id") else None
        item["mft_full_path"] = _join_report_path(item.get("mft_parent_path"), item.get("mft_file_name"))
        matches.append(item)
    return {"case_id": case_id, "matches": matches, "total_returned": len(matches)}


