WELL_KNOWN_ADS_STREAMS = {
    "zone.identifier",
    "encryptable",
    "summaryinformation",
    "documentsummaryinformation",
    "com.dropbox.attributes",
}
ADS_PRIORITY_ORDER = {"high": 0, "medium": 1, "low": 2}


def _ads_stream_name(path_or_name: object) -> str:
    text = str(path_or_name or "")
    if ":" not in text:
        return ""
    return text.rsplit(":", 1)[-1].strip()


def _ads_stream_classification(stream: str, path: str) -> dict[str, Any]:
    stream_lower = (stream or "").casefold()
    path_lower = (path or "").casefold()
    if not stream:
        return {
            "classification": "ads_stream_name_unknown",
            "review_priority": "medium",
            "is_expected": False,
            "classification_note": "ADS row did not contain a parseable stream name.",
        }
    if re.fullmatch(r"\$\{[0-9a-f-]{36}\}\.metadata", stream_lower):
        return {
            "classification": "expected_cloud_files_metadata",
            "review_priority": "low",
            "is_expected": True,
            "classification_note": "Cloud Files/OneDrive metadata stream. Useful for cloud context but usually not hidden user content.",
        }
    if re.fullmatch(r"\$\{[0-9a-f-]{36}\}\.syncrootidentity", stream_lower):
        return {
            "classification": "expected_cloud_sync_root_identity",
            "review_priority": "low",
            "is_expected": True,
            "classification_note": "Cloud Files sync-root identity stream. Usually expected on OneDrive or similar sync roots.",
        }
    if stream_lower == "wofcompresseddata":
        return {
            "classification": "expected_windows_overlay_filter_compression",
            "review_priority": "low",
            "is_expected": True,
            "classification_note": "Windows Overlay Filter compressed data stream.",
        }
    if stream_lower == "streamedfilestate":
        return {
            "classification": "expected_streamed_file_state",
            "review_priority": "low",
            "is_expected": True,
            "classification_note": "Windows streamed-file state metadata, commonly seen on temporary files.",
        }
    if stream_lower == "smartscreen":
        return {
            "classification": "expected_smartscreen_metadata",
            "review_priority": "low",
            "is_expected": True,
            "classification_note": "Windows SmartScreen metadata stream.",
        }
    if stream_lower.startswith("cm_") and path_lower.startswith("./windows:"):
        return {
            "classification": "expected_windows_content_metadata",
            "review_priority": "low",
            "is_expected": True,
            "classification_note": "Windows content metadata stream on a system path.",
        }
    if stream_lower.startswith("cm_") and "codemeter" in path_lower:
        return {
            "classification": "expected_codemeter_license_metadata",
            "review_priority": "low",
            "is_expected": True,
            "classification_note": "CodeMeter licensing metadata stream.",
        }
    if stream_lower in {"$sds", "$sii", "$sdh", "$j", "$max", "$info", "$bad", "$bitmap", "$logfile", "$corrupt", "$verify", "$config", "$srat", "$t"}:
        return {
            "classification": "expected_ntfs_metadata_stream",
            "review_priority": "low",
            "is_expected": True,
            "classification_note": "NTFS/system metadata stream. Investigate only when the parent path or timestamps are independently relevant.",
        }
    if stream_lower.startswith("$"):
        return {
            "classification": "system_named_ads",
            "review_priority": "medium",
            "is_expected": False,
            "classification_note": "Dollar-prefixed stream not in the known expected list.",
        }
    return {
        "classification": "unclassified_non_standard_ads",
        "review_priority": "high",
        "is_expected": False,
        "classification_note": "Stream is not in the expected Cloud Files, Windows compression, SmartScreen, or NTFS metadata families.",
    }


def non_standard_ads_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    """Surface alternate data streams beyond common Zone/System ADS."""
    limit = max(1, min(int(limit), 50_000))
    rows: list[dict[str, Any]] = []
    for table in ("mft_entries",):
        if not _report_table_columns(db, case_id, table):
            continue
        selected = _query_report_rows(
            db,
            case_id,
            table,
            f"""
            SELECT id, case_id, computer_id, image_id,
                   '{table}' AS source_table,
                   parent_path,
                   file_name,
                   file_size,
                   is_ads,
                   has_ads,
                   created_si,
                   modified_si,
                   accessed_si,
                   record_changed_si
            FROM {table}
            WHERE case_id = ?
              AND LOWER(COALESCE(is_ads, '')) IN ('true', '1', 'yes')
            ORDER BY COALESCE(modified_si, record_changed_si, accessed_si, created_si) DESC
            LIMIT ?
            """,
            (case_id, limit * 3),
        )
        rows.extend(dict(row) for row in selected)
    output: list[dict[str, Any]] = []
    for row in rows:
        path = _join_path(row.get("parent_path"), row.get("file_name"))
        stream = _ads_stream_name(path or row.get("file_name"))
        if stream.casefold() in WELL_KNOWN_ADS_STREAMS:
            continue
        item = dict(row)
        item["timestamp_utc"] = row.get("modified_si") or row.get("record_changed_si") or row.get("accessed_si") or row.get("created_si")
        item["path"] = path
        item["stream_name"] = stream
        item.update(_ads_stream_classification(stream, path))
        output.append(item)
    output.sort(key=lambda item: str(item.get("timestamp_utc") or ""), reverse=True)
    output.sort(key=lambda item: ADS_PRIORITY_ORDER.get(str(item.get("review_priority") or ""), 3))
    priority_counts: dict[str, int] = {}
    classification_counts: dict[str, int] = {}
    expected_count = 0
    for item in output:
        priority = str(item.get("review_priority") or "unknown")
        classification = str(item.get("classification") or "unknown")
        priority_counts[priority] = priority_counts.get(priority, 0) + 1
        classification_counts[classification] = classification_counts.get(classification, 0) + 1
        if item.get("is_expected"):
            expected_count += 1
    total = len(output)
    output = output[:limit]
    limited = total > limit
    return {
        "case_id": case_id,
        "summary": {
            "result_count": len(output),
            "total_available": total,
            "limit": limit,
            "limited": limited,
            "expected_count": expected_count,
            "needs_review_count": total - expected_count,
            "priority_counts": priority_counts,
            "classification_counts": classification_counts,
        },
        "limited": limited,
        "limit_warning": (
            "Returned rows reached the active non-standard ADS limit; request a higher limit or export CSV/JSON for the full set."
            if limited
            else ""
        ),
        "alternate_data_streams": output,
    }


NTFS_SECURITY_DESCRIPTOR_STREAMS = {"$sds", "$sii", "$sdh"}


def ntfs_security_descriptors_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    """Surface NTFS $Secure security descriptor stream presence from MFT ADS rows."""
    limit = max(1, min(int(limit), 50_000))
    rows: list[dict[str, Any]] = []
    if _report_table_columns(db, case_id, "mft_entries"):
        selected = _query_report_rows(
            db,
            case_id,
            "mft_entries",
            """
            SELECT id, case_id, computer_id, image_id,
                   parent_path,
                   file_name,
                   file_size,
                   is_ads,
                   created_si,
                   modified_si,
                   accessed_si,
                   record_changed_si
            FROM mft_entries
            WHERE case_id = ?
              AND LOWER(COALESCE(is_ads, '')) IN ('true', '1', 'yes')
            ORDER BY COALESCE(modified_si, record_changed_si, accessed_si, created_si) DESC
            LIMIT ?
            """,
            (case_id, max(limit * 20, 1000)),
        )
        for row in selected:
            path = _join_path(row.get("parent_path"), row.get("file_name"))
            stream = _ads_stream_name(path or row.get("file_name"))
            if stream.casefold() not in NTFS_SECURITY_DESCRIPTOR_STREAMS:
                continue
            item = dict(row)
            item["source_table"] = "mft_entries"
            item["timestamp_utc"] = row.get("modified_si") or row.get("record_changed_si") or row.get("accessed_si") or row.get("created_si")
            item["path"] = path
            item["stream_name"] = stream
            item["parse_status"] = "presence_and_metadata_only"
            item["forensic_value"] = (
                "$Secure stream presence confirms NTFS security descriptor metadata is present. "
                "Structured ACL interpretation requires dedicated $Secure:$SDS parsing or MFTECmd security descriptor output."
            )
            rows.append(item)
            if len(rows) >= limit:
                break
    limited = len(rows) >= limit
    return {
        "case_id": case_id,
        "summary": {
            "result_count": len(rows),
            "limit": limit,
            "limited": limited,
            "streams": _count_by_key(rows, "stream_name"),
            "parse_status": "presence_and_metadata_only",
        },
        "limited": limited,
        "limit_warning": (
            "Returned rows reached the active ntfs-security-descriptors limit; request a higher limit or export CSV/JSON for the full set."
            if limited
            else ""
        ),
        "security_descriptor_streams": rows,
        "caveats": [
            "$Secure:$SDS records security descriptor metadata, but this report currently inventories stream presence rather than decoding ACL contents.",
            "Use MFTECmd security descriptor output or a future structured SDS parser when file/folder permission-change analysis is in scope.",
        ],
    }


REMOTE_ACCESS_TOOL_NAMES = {
    "AnyDesk",
    "TeamViewer",
    "LogMeIn",
    "GoTo",
    "ConnectWise Control",
    "BeyondTrust",
    "Splashtop",
    "RustDesk",
    "Chrome Remote Desktop",
    "RemotePC",
    "Dameware",
    "Atera",
    "NinjaOne",
    "MeshCentral",
    "DWAgent",
    "Parsec",
    "RealVNC",
    "TightVNC",
    "UltraVNC",
}


def _application_indicator_for_text(text: str) -> str | None:
    lowered = (text or "").lower()
    for indicator in APPLICATION_INDICATORS:
        application = str(indicator.get("application") or "")
        if application not in REMOTE_ACCESS_TOOL_NAMES:
            continue
        if any(str(token).lower() in lowered for token in indicator.get("tokens") or ()):
            return application
    return None


def _remote_access_candidate_application_for_path(path: str) -> str | None:
    normalized = re.sub(r"[\\/]+", "/", (path or "").lower())
    if not normalized:
        return None
    if normalized.startswith("/windows/") or "/winsxs/" in normalized or "/officefilecache/" in normalized:
        return None
    strong_tokens = {
        "AnyDesk": ("anydesk",),
        "TeamViewer": ("teamviewer", "tv_w32.exe", "tv_x64.exe"),
        "LogMeIn": ("logmein", "lmi rescue"),
        "GoTo": ("gotoassist", "goto resolve", "g2ax_"),
        "ConnectWise Control": ("screenconnect", "connectwise control"),
        "BeyondTrust": ("bomgar", "beyondtrust"),
        "Splashtop": ("splashtop",),
        "RustDesk": ("rustdesk",),
        "Chrome Remote Desktop": ("chrome remote desktop", "chromoting"),
        "RemotePC": ("remotepc",),
        "Dameware": ("dameware",),
        "Atera": ("atera",),
        "NinjaOne": ("ninjarmm", "ninjaone"),
        "MeshCentral": ("meshcentral",),
        "DWAgent": ("dwagent",),
        "Parsec": ("parsec",),
        "RealVNC": ("realvnc", "vnc viewer", "vnc server"),
        "TightVNC": ("tightvnc",),
        "UltraVNC": ("ultravnc",),
    }
    for application, tokens in strong_tokens.items():
        for token in tokens:
            token_lower = token.lower()
            if f"/{token_lower}/" in normalized or normalized.endswith(f"/{token_lower}") or normalized.endswith(f"/{token_lower}.exe"):
                return application
            if " " in token_lower and token_lower in normalized:
                return application
    return None


def remote_access_tool_logs_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    """Surface collected remote-access application logs and candidate files."""
    limit = max(1, min(int(limit), 50_000))
    rows: list[dict[str, Any]] = []
    if _report_table_columns(db, case_id, "messaging_records"):
        placeholders = ", ".join("?" for _ in REMOTE_ACCESS_TOOL_NAMES)
        rows.extend(
            _query_report_rows(
                db,
                case_id,
                "messaging_records",
                f"""
                SELECT id, case_id, computer_id, image_id,
                       application,
                       user_profile,
                       artifact_type,
                       source_path,
                       store_path,
                       record_key,
                       record_type,
                       url,
                       host,
                       email,
                       timestamp_utc,
                       message_text,
                       raw_text,
                       'messaging_records' AS source_table
                FROM messaging_records
                WHERE case_id = ?
                  AND application IN ({placeholders})
                ORDER BY timestamp_utc DESC, application, source_path
                LIMIT ?
                """,
                [case_id, *sorted(REMOTE_ACCESS_TOOL_NAMES), limit],
            )
        )
    if len(rows) < limit and _report_table_columns(db, case_id, "mft_entries"):
        app_patterns = [(app["application"], token) for app in APPLICATION_INDICATORS if app["application"] in REMOTE_ACCESS_TOOL_NAMES for token in app["tokens"]]
        pattern_sql = " OR ".join("LOWER(COALESCE(parent_path, '') || '/' || COALESCE(file_name, '')) LIKE ?" for _ in app_patterns)
        if pattern_sql:
            scan_limit = max((limit - len(rows)) * 20, 5000)
            for row in _query_report_rows(
                db,
                case_id,
                "mft_entries",
                f"""
                SELECT id, case_id, computer_id, image_id,
                       parent_path,
                       file_name,
                       file_size,
                       modified_si AS timestamp_utc,
                       created_si,
                       accessed_si,
                       'mft_entries' AS source_table
                FROM mft_entries
                WHERE case_id = ?
                  AND ({pattern_sql})
                ORDER BY modified_si DESC
                LIMIT ?
                """,
                [case_id, *[f"%{token.lower()}%" for _, token in app_patterns], scan_limit],
            ):
                item = dict(row)
                path = _join_path(item.get("parent_path"), item.get("file_name"))
                application = _remote_access_candidate_application_for_path(path)
                if not application:
                    continue
                item["source_path"] = path
                item["application"] = application
                item["artifact_type"] = "candidate_file"
                rows.append(item)
                if len(rows) >= limit:
                    break
    rows = rows[:limit]
    return {
        "case_id": case_id,
        "summary": {"result_count": len(rows), "limit": limit, "limited": len(rows) >= limit},
        "limited": len(rows) >= limit,
        "limit_warning": (
            "Returned rows reached the active remote-access-tool-logs limit; request a higher limit or export CSV/JSON for the full set."
            if len(rows) >= limit
            else ""
        ),
        "remote_access_tool_logs": rows,
    }


def mapped_network_paths_report(db: Database, case_id: str, *, user: str | None = None, limit: int = 250) -> dict[str, Any]:
    """Summarize MountPoints2 network share keys as UNC-style mapped paths."""
    limit = max(1, min(int(limit), 50_000))
    if not _report_table_columns(db, case_id, "registry_artifacts"):
        return {
            "case_id": case_id,
            "summary": {"result_count": 0, "limit": limit, "limited": False},
            "limit_warning": "",
            "mapped_network_paths": [],
        }

    params: list[Any] = [case_id, "mountpoints2", "%/mountpoints2/##%"]
    user_clause = ""
    if user:
        user_clause = " AND LOWER(COALESCE(user_profile, '')) = LOWER(?)"
        params.append(user)

    rows = _query_report_rows(
        db,
        case_id,
        "registry_artifacts",
        f"""
        SELECT id, case_id, computer_id, image_id,
               user_profile,
               source_path,
               key_path,
               key_last_write_utc,
               event_time_utc,
               value_name,
               value_type,
               value_data,
               display_name,
               normalized_path,
               notes
        FROM registry_artifacts
        WHERE case_id = ?
          AND artifact = ?
          AND LOWER(REPLACE(key_path, '\\\\', '/')) LIKE ?
          {user_clause}
        ORDER BY COALESCE(NULLIF(event_time_utc, ''), key_last_write_utc) DESC, key_path, value_name
        LIMIT ?
        """,
        [*params, limit * 50],
    )

    grouped: dict[tuple[str, str, str, str, str], dict[str, Any]] = {}
    for row in rows:
        parsed = mountpoints2_network_path_from_key(str(row.get("key_path") or ""))
        if not parsed:
            continue
        timestamp = str(row.get("event_time_utc") or row.get("key_last_write_utc") or "")
        key = (
            str(row.get("computer_id") or ""),
            str(row.get("image_id") or ""),
            str(row.get("user_profile") or ""),
            parsed["mountpoints2_key"],
            parsed["unc_path"].casefold(),
        )
        item = grouped.get(key)
        if item is None:
            item = {
                "case_id": case_id,
                "computer_id": row.get("computer_id"),
                "image_id": row.get("image_id"),
                "user_profile": row.get("user_profile"),
                "timestamp_utc": timestamp or None,
                "first_seen_utc": timestamp or None,
                "last_seen_utc": timestamp or None,
                "host": parsed["host"],
                "share": parsed["share"],
                "remote_path": parsed["remote_path"],
                "unc_path": parsed["unc_path"],
                "mountpoints2_key": parsed["mountpoints2_key"],
                "source_path": row.get("source_path"),
                "source_table": "registry_artifacts",
                "row_count": 0,
                "evidence_values": [],
                "notes": "MountPoints2 network-share key decoded from ##host#share#path registry format.",
            }
            grouped[key] = item
        item["row_count"] = int(item.get("row_count") or 0) + 1
        if timestamp:
            if not item.get("first_seen_utc") or timestamp < str(item["first_seen_utc"]):
                item["first_seen_utc"] = timestamp
            if not item.get("last_seen_utc") or timestamp > str(item["last_seen_utc"]):
                item["last_seen_utc"] = timestamp
                item["timestamp_utc"] = timestamp
        evidence_values = item["evidence_values"]
        if isinstance(evidence_values, list) and len(evidence_values) < 10:
            value_name = str(row.get("value_name") or "").strip()
            value_data = str(row.get("value_data") or row.get("display_name") or "").strip()
            if value_name or value_data:
                evidence_values.append(
                    {
                        "value_name": value_name,
                        "value_type": row.get("value_type"),
                        "value_data": value_data[:500],
                    }
                )

    mapped_paths = sorted(
        grouped.values(),
        key=lambda item: str(item.get("last_seen_utc") or item.get("timestamp_utc") or ""),
        reverse=True,
    )
    total_candidates = len(mapped_paths)
    mapped_paths = mapped_paths[:limit]
    limited = total_candidates > limit or len(rows) >= limit * 50
    return {
        "case_id": case_id,
        "summary": {
            "result_count": len(mapped_paths),
            "limit": limit,
            "limited": limited,
            "raw_registry_rows_scanned": len(rows),
        },
        "limited": limited,
        "limit_warning": (
            "Returned rows reached the active mapped-network-paths limit; request a higher limit or export CSV/JSON for the full set."
            if limited
            else ""
        ),
        "mapped_network_paths": mapped_paths,
    }


def examiner_edge_artifacts_report(db: Database, case_id: str, *, limit: int = 250) -> dict[str, Any]:
    """Surface high-value small artifacts that commonly produce examiner leads."""
    limit = max(1, min(int(limit), 5000))
    rows: list[dict[str, Any]] = []
    counts: dict[str, int] = {}

    if _report_table_columns(db, case_id, "package_artifacts"):
        placeholders = ", ".join("?" for _ in EDGE_PACKAGE_RECORD_TYPES)
        query_rows = _query_report_rows(
            db,
            case_id,
            "package_artifacts",
            f"""
            SELECT id, case_id, computer_id, image_id,
                   record_type AS artifact_type,
                   user_profile,
                   COALESCE(NULLIF(event_time_utc, ''), modified_utc) AS timestamp_utc,
                   source_name,
                   source_path,
                   file_name,
                   title,
                   artifact_value,
                   artifact_text,
                   details_json,
                   'package_artifacts' AS source_table
            FROM package_artifacts
            WHERE case_id = ?
              AND record_type IN ({placeholders})
            ORDER BY COALESCE(NULLIF(event_time_utc, ''), modified_utc) DESC, record_type, source_path
            LIMIT ?
            """,
            [case_id, *sorted(EDGE_PACKAGE_RECORD_TYPES), limit],
        )
        for row in query_rows:
            item = dict(row)
            item["category"] = _edge_category(str(item.get("artifact_type") or ""))
            item["summary"] = _edge_summary(item)
            rows.append(item)
            counts[item["category"]] = counts.get(item["category"], 0) + 1

    if _report_table_columns(db, case_id, "telemetry_artifacts"):
        query_rows = _query_report_rows(
            db,
            case_id,
            "telemetry_artifacts",
            """
            SELECT id, case_id, computer_id, image_id,
                   record_type AS artifact_type,
                   user_profile,
                   COALESCE(NULLIF(event_time_utc, ''), modified_utc) AS timestamp_utc,
                   source_name,
                   source_path,
                   file_name,
                   title,
                   value_data AS artifact_value,
                   artifact_text,
                   details_json,
                   'telemetry_artifacts' AS source_table
            FROM telemetry_artifacts
            WHERE case_id = ?
              AND artifact_group = 'notifications'
            ORDER BY COALESCE(NULLIF(event_time_utc, ''), modified_utc) DESC, record_type, source_path
            LIMIT ?
            """,
            [case_id, limit],
        )
        for row in query_rows:
            item = dict(row)
            item["category"] = "notifications"
            item["summary"] = _edge_summary(item)
            rows.append(item)
            counts["notifications"] = counts.get("notifications", 0) + 1

    if _report_table_columns(db, case_id, "registry_artifacts"):
        placeholders = ", ".join("?" for _ in EDGE_REGISTRY_ARTIFACTS)
        query_rows = _query_report_rows(
            db,
            case_id,
            "registry_artifacts",
            f"""
            SELECT id, case_id, computer_id, image_id,
                   artifact AS artifact_type,
                   user_profile,
                   COALESCE(NULLIF(event_time_utc, ''), key_last_write_utc) AS timestamp_utc,
                   category AS source_name,
                   source_path,
                   key_path AS file_name,
                   display_name AS title,
                   value_data AS artifact_value,
                   notes AS artifact_text,
                   value_name,
                   value_type,
                   'registry_artifacts' AS source_table
            FROM registry_artifacts
            WHERE case_id = ?
              AND artifact IN ({placeholders})
            ORDER BY COALESCE(NULLIF(event_time_utc, ''), key_last_write_utc) DESC, artifact, key_path
            LIMIT ?
            """,
            [case_id, *sorted(EDGE_REGISTRY_ARTIFACTS), limit],
        )
        for row in query_rows:
            item = dict(row)
            item["category"] = _edge_category(str(item.get("artifact_type") or ""))
            item["summary"] = _edge_summary(item)
            rows.append(item)
            counts[item["category"]] = counts.get(item["category"], 0) + 1

    rows.sort(key=lambda row: str(row.get("timestamp_utc") or ""), reverse=True)
    total_candidates = len(rows)
    rows = rows[:limit]
    limited = total_candidates > limit
    return {
        "case_id": case_id,
        "summary": {
            "result_count": len(rows),
            "limit": limit,
            "limited": limited,
            "category_counts": counts,
        },
        "limited": limited,
        "limit_warning": (
            "Returned rows reached the active examiner-edge-artifacts limit; absence of additional rows is not evidence of absence."
            if limited
            else ""
        ),
        "items": rows,
    }


def _edge_category(artifact_type: str) -> str:
    artifact = artifact_type.lower()
    if "sticky" in artifact:
        return "sticky_notes"
    if "notification" in artifact:
        return "notifications"
    if "eventtranscript" in artifact:
        return "diagnostic_telemetry"
    if "tokenbroker" in artifact:
        return "cloud_account_metadata"
    if "thumbs_db" in artifact:
        return "thumbnail_artifacts"
    if "network" in artifact or "rdp" in artifact or "mountpoints" in artifact:
        return "network_and_remote_access"
    if "task" in artifact:
        return "scheduled_tasks"
    if "cryptnet" in artifact or artifact == "hosts_mapping" or artifact == "hosts_file":
        return "network_resolution"
    if "credential" in artifact or "vault" in artifact:
        return "credential_metadata"
    if "wsl" in artifact:
        return "wsl"
    if "windows_update" in artifact or artifact == "installed_applications":
        return "software_inventory"
    if "bluetooth" in artifact:
        return "bluetooth"
    if "swiftkey" in artifact:
        return "typed_text_leads"
    return "other"


def _edge_summary(row: dict[str, Any]) -> str:
    for key in ("title", "artifact_value", "artifact_text", "file_name", "source_path"):
        value = str(row.get(key) or "").strip()
        if value:
            return re.sub(r"\s+", " ", value)[:500]
    return str(row.get("artifact_type") or "")


def _count(
    db: Database,
    table: str,
    case_id: str,
    *,
    user_filter: tuple[str, str | None] | None = None,
) -> int:
    where = "case_id = ?"
    params: list[Any] = [case_id]
    if user_filter and user_filter[1]:
        where += f" AND {user_filter[0]} LIKE ?"
        params.append(user_filter[1])
    rows = _query_report_rows(
        db,
        case_id,
        table,
        f"SELECT COUNT(*) AS count FROM {table} WHERE {where}",
        params,
    )
    return int((rows[0] if rows else {}).get("count") or 0)


def _table_exists(db: Database, table: str) -> bool:
    if table in ANALYTICS_TABLES and db.analytics_mode != "sqlite":
        return bool(_analytics_table_columns(db, table))
    row = db.conn.execute(
        "SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = ?",
        (table,),
    ).fetchone()
    return row is not None


def artifact_search_report(
    db: Database,
    case_id: str,
    *,
    query: str | None = None,
    user: str | None = None,
    computer: str | None = None,
    source_type: str | None = None,
    start: str | None = None,
    end: str | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    """Search common parsed artifact tables without requiring OpenSearch."""
    limit = max(1, min(int(limit), 1000))
    query_text = (query or "").strip()
    user_text = (user or "").strip()
    computer_text = (computer or "").strip()
    source_text = (source_type or "").strip().casefold()
    normalized_start = _normalize_report_timestamp(start)
    normalized_end = _normalize_report_timestamp(end)
    start_bound = _timestamp_sql_bound(start)
    end_bound = _timestamp_sql_bound(end)
    computer_labels = _case_computer_labels(db, case_id)
    image_paths = _case_image_paths(db, case_id)
    computer_ids = _matching_computer_ids(computer_labels, computer_text)
    results: list[dict[str, Any]] = []
    searched_tables = 0

    for spec in ARTIFACT_SEARCH_SPECS:
        table = str(spec["table"])
        category = str(spec["category"])
        if source_text and source_text not in {category.casefold(), table.casefold()}:
            continue
        columns = _report_table_columns(db, case_id, table)
        if not columns:
            continue
        searched_tables += 1
        searchable = [field for field in spec["fields"] if field in columns]
        display = [field for field in spec["display"] if field in columns]
        timestamp_col = str(spec.get("timestamp") or "")
        end_timestamp_col = str(spec.get("end_timestamp") or "")
        user_col = str(spec.get("user") or "")
        select_cols = _dedupe_columns(["id", "case_id", "computer_id", "image_id", timestamp_col, end_timestamp_col, user_col, *display, *searchable])
        select_cols = [column for column in select_cols if column in columns]
        if "id" not in select_cols or "case_id" not in select_cols:
            continue
        where = ["case_id = ?"]
        params: list[Any] = [case_id]
        if query_text and searchable:
            clauses = [f"LOWER(COALESCE({field}, '')) LIKE ?" for field in searchable]
            where.append("(" + " OR ".join(clauses) + ")")
            params.extend([f"%{query_text.casefold()}%" for _ in searchable])
        elif query_text and not searchable:
            continue
        if user_text and user_col and user_col in columns:
            where.append(f"LOWER(COALESCE({user_col}, '')) LIKE ?")
            params.append(f"%{user_text.casefold()}%")
        elif user_text:
            continue
        if computer_ids is not None:
            if not computer_ids:
                continue
            placeholders = ", ".join("?" for _ in computer_ids)
            where.append(f"computer_id IN ({placeholders})")
            params.extend(computer_ids)
        if (start_bound or end_bound) and timestamp_col in columns:
            timestamp_expr = _timestamp_sql_expr(timestamp_col)
            if end_timestamp_col in columns:
                end_timestamp_expr = f"COALESCE(NULLIF({_timestamp_sql_expr(end_timestamp_col)}, ''), {timestamp_expr})"
                if start_bound:
                    where.append(f"{end_timestamp_expr} >= ?")
                    params.append(start_bound)
                if end_bound:
                    where.append(f"{timestamp_expr} <= ?")
                    params.append(end_bound)
            else:
                if start_bound:
                    where.append(f"{timestamp_expr} >= ?")
                    params.append(start_bound)
                if end_bound:
                    where.append(f"{timestamp_expr} <= ?")
                    params.append(end_bound)
        order = f"ORDER BY {timestamp_col} DESC" if timestamp_col in columns else "ORDER BY id"
        remaining = limit - len(results)
        sql = f"SELECT {', '.join(select_cols)} FROM {table} WHERE {' AND '.join(where)} {order} LIMIT ?"
        rows = _query_report_rows(db, case_id, table, sql, [*params, remaining])
        for row in rows:
            item = dict(row)
            item["table"] = table
            item["category"] = category
            item["timestamp"] = item.get(timestamp_col) if timestamp_col else None
            item["end_timestamp"] = item.get(end_timestamp_col) if end_timestamp_col else None
            item["computer_label"] = computer_labels.get(str(item.get("computer_id") or ""))
            item["image_path"] = image_paths.get(str(item.get("image_id") or ""))
            item["matched_fields"] = _artifact_matched_fields(item, searchable, query_text)
            item["summary"] = _artifact_search_summary(item, display, searchable)
            score, score_reasons = _artifact_search_score(item, query_text, user_text)
            item["score"] = score
            item["score_reasons"] = score_reasons
            item["drilldown"] = _artifact_drilldown_hint(item)
            results.append(item)
            if len(results) >= limit:
                break
        if len(results) >= limit:
            break

    results.sort(key=lambda row: (int(row.get("score") or 0), str(row.get("timestamp") or "")), reverse=True)
    results = results[:limit]
    return {
        "case_id": case_id,
        "query": query_text,
        "filters": {
            "user": user_text,
            "computer": computer_text,
            "source_type": source_text,
            "start": normalized_start or "",
            "end": normalized_end or "",
        },
        "summary": {
            "searched_tables": searched_tables,
            "result_count": len(results),
            "limit": limit,
            "limited": len(results) >= limit,
        },
        "limited": len(results) >= limit,
        "limit_warning": (
            "Returned rows reached the active artifact-search limit; absence of additional rows is not evidence of absence."
            if len(results) >= limit
            else ""
        ),
        "results": results,
    }


def artifact_lead_search_report(
    db: Database,
    case_id: str,
    *,
    preset: str,
    query: str | None = None,
    user: str | None = None,
    computer: str | None = None,
    start: str | None = None,
    end: str | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    preset_key = (preset or "").strip().casefold()
    if preset_key not in ARTIFACT_LEAD_SEARCH_PRESETS:
        raise ValueError(f"Unsupported lead search preset: {preset}")
    categories = ARTIFACT_LEAD_SEARCH_PRESETS[preset_key]
    per_category_limit = max(1, min(int(limit), 1000))
    results: list[dict[str, Any]] = []
    category_summaries: list[dict[str, Any]] = []
    seen: set[tuple[str, str]] = set()
    for category in categories:
        report = artifact_search_report(
            db,
            case_id,
            query=query,
            user=user,
            computer=computer,
            source_type=category,
            start=start,
            end=end,
            limit=per_category_limit,
        )
        category_summaries.append({"category": category, **dict(report.get("summary") or {})})
        for row in report.get("results") or []:
            key = (str(row.get("table") or ""), str(row.get("id") or ""))
            if key in seen:
                continue
            seen.add(key)
            item = dict(row)
            item["lead_preset"] = preset_key
            results.append(item)
    results.sort(key=lambda row: str(row.get("timestamp") or ""), reverse=True)
    returned = results[: max(1, min(int(limit), 1000))]
    return {
        "case_id": case_id,
        "preset": preset_key,
        "query": (query or "").strip(),
        "filters": {
            "user": (user or "").strip(),
            "computer": (computer or "").strip(),
            "start": start or "",
            "end": end or "",
        },
        "summary": {
            "result_count": len(returned),
            "total_matching": len(results),
            "limit": max(1, min(int(limit), 1000)),
            "categories": categories,
        },
        "category_summaries": category_summaries,
        "results": returned,
    }


def artifact_search_source_inventory_report(db: Database, case_id: str) -> dict[str, Any]:
    """Return the tables and fields covered by artifact/lead search."""
    sources: list[dict[str, Any]] = []
    available_count = 0
    populated_count = 0
    for spec in ARTIFACT_SEARCH_SPECS:
        table = str(spec["table"])
        columns = _report_table_columns(db, case_id, table)
        searchable = [field for field in spec["fields"] if field in columns]
        display = [field for field in spec["display"] if field in columns]
        timestamp_col = str(spec.get("timestamp") or "")
        row_count = _table_count(db, table, case_id) if columns else 0
        available = bool(columns)
        populated = row_count > 0
        available_count += 1 if available else 0
        populated_count += 1 if populated else 0
        sources.append(
            {
                "table": table,
                "category": str(spec["category"]),
                "available": available,
                "populated": populated,
                "row_count": row_count,
                "searchable_fields": searchable,
                "display_fields": display,
                "timestamp_field": timestamp_col if timestamp_col in columns else "",
                "user_field": str(spec.get("user") or "") if str(spec.get("user") or "") in columns else "",
                "missing_search_fields": [field for field in spec["fields"] if field not in columns],
            }
        )
    return {
        "case_id": case_id,
        "summary": {
            "source_count": len(sources),
            "available_source_count": available_count,
            "populated_source_count": populated_count,
        },
        "sources": sources,
    }


def case_activity_digest_report(db: Database, case_id: str, *, limit: int = 25) -> dict[str, Any]:
    limit = max(1, min(int(limit), 1000))
    timeline = timeline_review_report(db, case_id, limit=limit)
    suspicious = suspicious_executions_report(db, case_id, limit=limit)
    storage = external_storage_report(db, case_id, limit=limit, rebuild_correlations=False, include_file_activity=False)
    opened_removable = opened_from_removable_media_report(db, case_id, limit=limit)
    opened_cloud = opened_from_cloud_storage_report(db, case_id, limit=limit)
    gaps = evidence_gaps_report(db, case_id, limit=limit)
    actions = case_next_actions_report(db, case_id, limit=limit)
    timeline_rows = timeline.get("events") or timeline.get("timeline") or timeline.get("items") or []
    return {
        "case_id": case_id,
        "summary": {
            "timeline_count": len(timeline_rows),
            "suspicious_execution_count": len(suspicious.get("findings") or suspicious.get("items") or []),
            "external_storage_count": len(storage.get("devices") or storage.get("storage_devices") or []),
            "opened_from_removable_count": len(opened_removable.get("items") or opened_removable.get("findings") or []),
            "opened_from_cloud_count": len(opened_cloud.get("items") or opened_cloud.get("findings") or []),
            "evidence_gap_count": len(gaps.get("gaps") or []),
            "next_action_count": len(actions.get("actions") or []),
            "limit": limit,
        },
        "recent_timeline": timeline_rows[:limit],
        "suspicious_executions": (suspicious.get("findings") or suspicious.get("items") or [])[:limit],
        "external_storage": (storage.get("devices") or storage.get("storage_devices") or [])[:limit],
        "opened_from_removable_media": (opened_removable.get("items") or opened_removable.get("findings") or [])[:limit],
        "opened_from_cloud_storage": (opened_cloud.get("items") or opened_cloud.get("findings") or [])[:limit],
        "evidence_gaps": (gaps.get("gaps") or [])[:limit],
        "next_actions": (actions.get("actions") or [])[:limit],
    }


def rerun_search_packet_report(db: Database, packet: dict[str, Any], *, limit_override: int | None = None) -> dict[str, Any]:
    case_id = str(packet.get("case_id") or "").strip()
    arguments = packet.get("arguments") if isinstance(packet.get("arguments"), dict) else {}
    search_type = str(packet.get("search_type") or ("lead" if arguments.get("preset") else "artifact"))
    limit = int(limit_override or arguments.get("limit") or 100)
    if search_type == "lead" or arguments.get("preset"):
        rerun = artifact_lead_search_report(
            db,
            case_id,
            preset=str(arguments.get("preset") or ""),
            query=str(arguments.get("query") or "") or None,
            user=str(arguments.get("user") or "") or None,
            computer=str(arguments.get("computer") or "") or None,
            start=str(arguments.get("start") or "") or None,
            end=str(arguments.get("end") or "") or None,
            limit=limit,
        )
    else:
        rerun = artifact_search_report(
            db,
            case_id,
            query=str(arguments.get("query") or "") or None,
            user=str(arguments.get("user") or "") or None,
            computer=str(arguments.get("computer") or "") or None,
            source_type=str(arguments.get("source_type") or "") or None,
            start=str(arguments.get("start") or "") or None,
            end=str(arguments.get("end") or "") or None,
            limit=limit,
        )
    previous_search = packet.get("search") if isinstance(packet.get("search"), dict) else {}
    previous_results = previous_search.get("results") if isinstance(previous_search.get("results"), list) else []
    current_results = rerun.get("results") if isinstance(rerun.get("results"), list) else []
    previous_by_key = {_search_result_key(row): row for row in previous_results if isinstance(row, dict)}
    current_by_key = {_search_result_key(row): row for row in current_results if isinstance(row, dict)}
    previous_keys = set(previous_by_key)
    current_keys = set(current_by_key)
    shared_keys = previous_keys & current_keys
    changed: list[dict[str, Any]] = []
    unchanged_count = 0
    for key in shared_keys:
        previous_hash = _search_result_hash(previous_by_key[key])
        current_hash = _search_result_hash(current_by_key[key])
        if previous_hash == current_hash:
            unchanged_count += 1
            continue
        changed.append(
            {
                "key": {"table": key[0], "id": key[1]},
                "previous_hash": previous_hash,
                "current_hash": current_hash,
                "previous": previous_by_key[key],
                "current": current_by_key[key],
            }
        )
    return {
        "case_id": case_id,
        "title": packet.get("title") or "",
        "search_type": search_type,
        "arguments": arguments,
        "previous_summary": previous_search.get("summary") if isinstance(previous_search.get("summary"), dict) else {},
        "current_summary": rerun.get("summary") if isinstance(rerun.get("summary"), dict) else {},
        "comparison": {
            "previous_count": len(previous_keys),
            "current_count": len(current_keys),
            "added_count": len(current_keys - previous_keys),
            "removed_count": len(previous_keys - current_keys),
            "changed_count": len(changed),
            "unchanged_count": unchanged_count,
            "added": [row for row in current_results if isinstance(row, dict) and _search_result_key(row) in current_keys - previous_keys],
            "removed": [row for row in previous_results if isinstance(row, dict) and _search_result_key(row) in previous_keys - current_keys],
            "changed": changed,
        },
        "search": rerun,
    }


def search_packet_metadata(db: Database, case_id: str, search: dict[str, Any], arguments: dict[str, Any], *, tool_version: str = "") -> dict[str, Any]:
    """Return defensibility metadata for saved search packets."""
    results = search.get("results") if isinstance(search.get("results"), list) else []
    result_hashes = [_search_result_hash(row) for row in results if isinstance(row, dict)]
    case_counts = _case_packet_counts(db, case_id)
    return {
        "tool": "perceptor",
        "tool_version": tool_version,
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "case_id": case_id,
        "arguments": {key: value for key, value in arguments.items() if value not in (None, "", [], {})},
        "case_counts": case_counts,
        "result_count": len(result_hashes),
        "result_hash_algorithm": "sha256",
        "result_hashes": result_hashes,
        "result_hash_set": hashlib.sha256("\n".join(sorted(result_hashes)).encode("utf-8")).hexdigest() if result_hashes else "",
    }


def changed_search_packets_report(
    db: Database,
    case_id: str,
    packets: Iterable[dict[str, Any]],
    *,
    limit: int = 50,
) -> dict[str, Any]:
    """Rerun saved search packets and summarize changed comparisons."""
    limit = max(1, min(int(limit), 1000))
    rows: list[dict[str, Any]] = []
    for packet in packets:
        if not isinstance(packet, dict) or str(packet.get("case_id") or "") != case_id:
            continue
        comparison = rerun_search_packet_report(db, packet)
        counts = comparison.get("comparison") if isinstance(comparison.get("comparison"), dict) else {}
        changed = int(counts.get("added_count") or 0) + int(counts.get("removed_count") or 0) + int(counts.get("changed_count") or 0)
        rows.append(
            {
                "case_id": case_id,
                "title": packet.get("title") or "",
                "created_at": packet.get("created_at") or "",
                "search_type": packet.get("search_type") or "",
                "changed": changed > 0,
                "change_count": changed,
                "added_count": int(counts.get("added_count") or 0),
                "removed_count": int(counts.get("removed_count") or 0),
                "changed_count": int(counts.get("changed_count") or 0),
                "unchanged_count": int(counts.get("unchanged_count") or 0),
                "previous_count": int(counts.get("previous_count") or 0),
                "current_count": int(counts.get("current_count") or 0),
                "arguments": packet.get("arguments") if isinstance(packet.get("arguments"), dict) else {},
                "comparison": comparison,
            }
        )
        if len(rows) >= limit:
            break
    rows.sort(key=lambda row: (bool(row.get("changed")), int(row.get("change_count") or 0), str(row.get("created_at") or "")), reverse=True)
    return {
        "case_id": case_id,
        "summary": {
            "packet_count": len(rows),
            "changed_packet_count": sum(1 for row in rows if row.get("changed")),
            "added_count": sum(int(row.get("added_count") or 0) for row in rows),
            "removed_count": sum(int(row.get("removed_count") or 0) for row in rows),
            "changed_result_count": sum(int(row.get("changed_count") or 0) for row in rows),
            "limit": limit,
        },
        "packets": rows,
    }


def rerun_search_packet_markdown(report: dict[str, Any]) -> str:
    comparison = report.get("comparison") if isinstance(report.get("comparison"), dict) else {}
    lines = [
        "# Search Packet Rerun",
        "",
        f"Case: `{report.get('case_id') or ''}`",
        f"Title: `{report.get('title') or ''}`",
        f"Type: `{report.get('search_type') or ''}`",
        "",
        "## Comparison",
        "",
    ]
    for key in ("previous_count", "current_count", "added_count", "removed_count", "changed_count", "unchanged_count"):
        lines.append(f"- {key.replace('_', ' ').title()}: `{comparison.get(key, 0)}`")
    _markdown_digest_rows(lines, "Added Results", comparison.get("added"), ("timestamp", "category", "table", "summary"))
    _markdown_digest_rows(lines, "Removed Results", comparison.get("removed"), ("timestamp", "category", "table", "summary"))
    changed = comparison.get("changed") if isinstance(comparison.get("changed"), list) else []
    lines.extend(["", "## Changed Results", ""])
    if not changed:
        lines.append("- None")
    for row in changed[:25]:
        if not isinstance(row, dict):
            continue
        current = row.get("current") if isinstance(row.get("current"), dict) else {}
        lines.append(
            f"- `{current.get('timestamp') or ''}` `{current.get('category') or current.get('table') or ''}` "
            f"{current.get('summary') or row.get('key') or ''}"
        )
    return "\n".join(lines).rstrip() + "\n"


