def case_next_actions_report(db: Database, case_id: str, *, limit: int = 25) -> dict[str, Any]:
    limit = max(1, min(int(limit), 1000))
    actions: list[dict[str, Any]] = []

    def add(priority: int, category: str, title: str, detail: str, command: str = "", evidence: dict[str, Any] | None = None) -> None:
        actions.append(
            {
                "priority": priority,
                "category": category,
                "title": title,
                "detail": detail,
                "suggested_command": command,
                "evidence": evidence or {},
            }
        )

    readiness = processing_readiness_report(db, case_id, limit=limit)
    for item in readiness.get("items") or readiness.get("checks") or []:
        if isinstance(item, dict) and str(item.get("status") or "").casefold() in {"needs_action", "failed", "missing"}:
            add(
                10,
                "readiness",
                str(item.get("label") or item.get("name") or "Readiness item needs action"),
                str(item.get("summary") or item.get("details") or ""),
                f"perceptor --root <workspace> report processing-readiness --case {case_id}",
                item,
            )

    gaps = evidence_gaps_report(db, case_id, limit=limit)
    for gap in gaps.get("gaps") or []:
        severity = str(gap.get("severity") or "")
        priority = 20 if severity == "error" else 30 if severity == "warning" else 60
        add(
            priority,
            "evidence_gap",
            str(gap.get("title") or "Evidence gap"),
            str(gap.get("summary") or gap.get("recommendation") or ""),
            f"perceptor --root <workspace> report evidence-gaps --case {case_id}",
            gap,
        )

    unmapped = unmapped_imports_report(db, case_id, limit=limit)
    if int((unmapped.get("summary") or {}).get("unmapped_count") or 0):
        add(
            25,
            "parser_gap",
            "Unmapped live-response CSVs need parser review",
            f"{unmapped['summary']['unmapped_count']} unsupported CSV imports were recorded.",
            f"perceptor --root <workspace> report unmapped-imports --case {case_id} --format table",
            unmapped.get("summary"),
        )

    suspicious = suspicious_executions_report(db, case_id, limit=limit)
    for finding in (suspicious.get("findings") or suspicious.get("items") or [])[:5]:
        add(
            35,
            "suspicious_execution",
            str(finding.get("application") or finding.get("display_path") or "Suspicious execution finding"),
            str(finding.get("reason") or finding.get("summary") or ""),
            f"perceptor --root <workspace> report suspicious-executions --case {case_id}",
            finding,
        )

    storage = external_storage_report(db, case_id, limit=limit, rebuild_correlations=False, include_file_activity=False)
    for device in (storage.get("devices") or storage.get("storage_devices") or [])[:5]:
        if device.get("file_activity_count") or device.get("matched_file_count") or device.get("serial_reliability") == "fake_or_generated":
            add(
                45,
                "external_storage",
                str(device.get("display_name") or device.get("serial") or "External storage lead"),
                str(device.get("summary") or device.get("serial_reliability") or ""),
                f"perceptor --root <workspace> report external-storage --case {case_id}",
                device,
            )

    actions.sort(key=lambda row: (int(row["priority"]), str(row["category"]), str(row["title"])))
    returned = actions[:limit]
    return {"case_id": case_id, "actions": returned, "summary": {"action_count": len(returned), "total_action_count": len(actions), "limit": limit}}


def _case_computer_labels(db: Database, case_id: str) -> dict[str, str]:
    rows = db.conn.execute("SELECT id, label FROM computers WHERE case_id = ?", (case_id,)).fetchall()
    return {str(row["id"]): str(row["label"] or "") for row in rows}


def _case_image_paths(db: Database, case_id: str) -> dict[str, str]:
    rows = db.conn.execute("SELECT id, path FROM images WHERE case_id = ?", (case_id,)).fetchall()
    return {str(row["id"]): str(row["path"] or "") for row in rows}


def _case_packet_counts(db: Database, case_id: str) -> dict[str, int]:
    counts: dict[str, int] = {}
    for name, sql in (
        ("computer_count", "SELECT COUNT(*) AS count FROM computers WHERE case_id = ?"),
        ("image_count", "SELECT COUNT(*) AS count FROM images WHERE case_id = ?"),
        ("tool_output_count", "SELECT COUNT(*) AS count FROM tool_outputs WHERE case_id = ?"),
    ):
        try:
            row = db.conn.execute(sql, (case_id,)).fetchone()
            counts[name] = int(row["count"] if row is not None else 0)
        except Exception:
            counts[name] = 0
    return counts


def _matching_computer_ids(labels: dict[str, str], computer: str) -> list[str] | None:
    if not computer:
        return None
    needle = computer.casefold()
    return [computer_id for computer_id, label in labels.items() if needle in computer_id.casefold() or needle in label.casefold()]


def _dedupe_columns(columns: Iterable[str]) -> list[str]:
    seen: set[str] = set()
    result: list[str] = []
    for column in columns:
        if column and column not in seen:
            seen.add(column)
            result.append(column)
    return result


def _artifact_matched_fields(row: dict[str, Any], fields: list[str], query: str) -> list[str]:
    if not query:
        return []
    needle = query.casefold()
    return [field for field in fields if needle in str(row.get(field) or "").casefold()]


def _artifact_search_summary(row: dict[str, Any], display: list[str], searchable: list[str]) -> str:
    values = []
    for field in [*display, *searchable]:
        value = row.get(field)
        if value not in (None, "") and str(value) not in values:
            values.append(str(value))
        if len(values) >= 3:
            break
    return " | ".join(values)


def _artifact_drilldown_hint(row: dict[str, Any]) -> dict[str, Any]:
    table = str(row.get("table") or "")
    category = str(row.get("category") or "")
    path = _first_present(row, ("item_path", "file_location", "target_path", "local_path", "absolute_path", "original_path", "full_path", "parent_path", "path", "file_path"))
    file_name = _first_present(row, ("file_name", "item_name", "display_name", "target_name", "name"))
    serial = _first_present(row, ("serial", "volume_serial_number", "usb_serial"))
    user = _first_present(row, ("user_profile", "user_name", "owner", "actor", "profile_path"))
    timestamp = row.get("timestamp")
    if table.startswith("registry_"):
        artifact = str(row.get("artifact") or "")
        if not artifact and table.startswith("registry_"):
            artifact = table.replace("registry_", "").replace("_", "-")
        return {"tool": "perceptor_query_registry_activity", "report": "registry-activity", "arguments": _non_empty({"artifact": artifact, "user": user})}
    if table == "srum_records":
        return {"tool": "perceptor_timeline_window", "report": "srum-context", "arguments": _non_empty({"contains": row.get("app_name") or row.get("app_path") or row.get("user_name")})}
    if table.startswith("mailbox_"):
        return {"tool": "perceptor_query_communications", "report": "communications", "arguments": _non_empty({"user": user, "contains": row.get("subject") or row.get("sender") or row.get("message_id")})}
    if table.startswith("cloud_"):
        return {"tool": "perceptor_query_cloud_artifacts", "report": "cloud-artifacts", "arguments": _non_empty({"contains": row.get("file_name") or row.get("target") or row.get("provider")})}
    if table.startswith("rdp_"):
        return {"tool": "perceptor_timeline_window", "report": "remote-access", "arguments": _non_empty({"preset": "remote_access", "contains": row.get("observed_text") or row.get("observed_path") or row.get("file_name")})}
    if table == "shortcut_items":
        return {"tool": "perceptor_query_shortcuts", "report": "shortcuts", "arguments": _non_empty({"artifact_type": row.get("artifact_type")})}
    if category == "external_storage" or table.startswith("usb_"):
        return {"tool": "perceptor_usb_dossier", "report": "usb-dossier", "arguments": _non_empty({"serial": serial, "volume_serial_number": row.get("volume_serial_number"), "volume_guid": row.get("volume_guid")})}
    if path or file_name:
        return {"tool": "perceptor_file_dossier", "report": "file-dossier", "arguments": _non_empty({"path": path, "name": file_name})}
    if user:
        return {"tool": "perceptor_user_activity", "report": "user-activity", "arguments": {"user": user}}
    if timestamp:
        return {"tool": "perceptor_timeline_window", "report": "timeline-review", "arguments": {"center": timestamp}}
    return {"tool": "perceptor_case_activity_digest", "report": "activity-digest", "arguments": {}}


def _artifact_search_score(row: dict[str, Any], query: str, user: str) -> tuple[int, list[str]]:
    score = 0
    reasons: list[str] = []
    matched = set(row.get("matched_fields") or [])
    path_fields = {"item_path", "file_location", "target_path", "local_path", "absolute_path", "original_path", "full_path", "parent_path", "path", "file_path"}
    name_fields = {"file_name", "item_name", "display_name", "target_name", "name", "executable_name"}
    if query and matched & (path_fields | name_fields):
        score += 40
        reasons.append("direct_filename_or_path_hit")
    elif query and matched:
        score += 20
        reasons.append("text_hit")
    if user and any(user.casefold() in str(row.get(key) or "").casefold() for key in ("user_profile", "user_name", "owner", "actor", "profile_path")):
        score += 20
        reasons.append("user_hit")
    category = str(row.get("category") or "")
    table = str(row.get("table") or "")
    if category in {"execution", "external_storage", "cloud", "communications", "remote_access"} or table in {"prefetch_items", "shortcut_items", "mailbox_messages"}:
        score += 15
        reasons.append("high_value_source")
    if row.get("timestamp"):
        score += 5
        reasons.append("timestamped")
    if table in {"timeline_events", "prefetch_items", "usb_connection_events", "cloud_server_events"}:
        score += 5
        reasons.append("event_source")
    return score, reasons


def _search_result_key(row: dict[str, Any]) -> tuple[str, str]:
    return (str(row.get("table") or ""), str(row.get("id") or row.get("source_record_id") or row.get("summary") or ""))


def _search_result_hash(row: dict[str, Any]) -> str:
    ignored = {"score", "score_reasons", "drilldown"}
    normalized = {key: value for key, value in row.items() if key not in ignored}
    payload = json.dumps(normalized, sort_keys=True, default=str, separators=(",", ":"))
    return hashlib.sha256(payload.encode("utf-8")).hexdigest()


def _first_present(row: dict[str, Any], keys: Iterable[str]) -> Any:
    for key in keys:
        value = row.get(key)
        if value not in (None, ""):
            return value
    return None


def _non_empty(values: dict[str, Any]) -> dict[str, Any]:
    return {key: value for key, value in values.items() if value not in (None, "", [], {})}


def _markdown_digest_rows(lines: list[str], title: str, rows: Any, columns: tuple[str, ...]) -> None:
    lines.extend(["", f"## {title}", ""])
    if not isinstance(rows, list) or not rows:
        lines.append("- None")
        return
    lines.append("| " + " | ".join(column.replace("_", " ").title() for column in columns) + " |")
    lines.append("| " + " | ".join("---" for _ in columns) + " |")
    for row in rows[:25]:
        if not isinstance(row, dict):
            continue
        values = [_markdown_table_cell(row.get(column)) for column in columns]
        if not any(values):
            fallback = json.dumps(row, default=str)
            values = [fallback[:500]] + ["" for _ in columns[1:]]
        lines.append("| " + " | ".join(values) + " |")


def _markdown_table_cell(value: Any) -> str:
    if value in (None, ""):
        return ""
    if isinstance(value, (dict, list, tuple)):
        value = json.dumps(value, default=str)
    text = str(value).replace("\r", " ").replace("\n", " ")
    text = text.replace("|", "\\|")
    return text.strip()


def _table_has_column(db: Database, table: str, column: str) -> bool:
    if table in ANALYTICS_TABLES and db.analytics_mode != "sqlite":
        return column in _analytics_table_columns(db, table)
    if not _table_exists(db, table):
        return False
    return any(row["name"] == column for row in db.conn.execute(f"PRAGMA table_info({_quote_identifier(table)})").fetchall())


def _tool_output_bytes(db: Database, case_id: str) -> dict[str, Any]:
    rows = db.conn.execute(
        """
        SELECT id, tool_name, output_type, path, row_count
        FROM tool_outputs
        WHERE case_id = ?
        ORDER BY created_at DESC
        """,
        (case_id,),
    ).fetchall()
    total_size = 0
    existing_files = 0
    missing_files = 0
    by_tool: dict[str, dict[str, Any]] = {}
    for row in rows:
        path = Path(row["path"]) if row["path"] else None
        size = path.stat().st_size if path and path.exists() and path.is_file() else 0
        if size:
            existing_files += 1
            total_size += size
        else:
            missing_files += 1
        tool = row["tool_name"] or "unknown"
        item = by_tool.setdefault(tool, {"tool_name": tool, "output_count": 0, "existing_file_count": 0, "estimated_bytes": 0, "row_count": 0})
        item["output_count"] += 1
        item["existing_file_count"] += 1 if size else 0
        item["estimated_bytes"] += size
        item["row_count"] += int(row["row_count"] or 0)
    return {
        "tool_output_count": len(rows),
        "existing_file_count": existing_files,
        "missing_or_non_file_count": missing_files,
        "estimated_bytes": total_size,
        "by_tool": sorted(by_tool.values(), key=lambda item: (-item["estimated_bytes"], item["tool_name"])),
    }


