def _browser_noise_filter_sql(host_expr: str, url_expr: str) -> str:
    noisy = [
        "doubleclick.",
        "googlesyndication.",
        "google-analytics.",
        "analytics.",
        "adnxs.",
        "adsystem.",
        "ads.",
        "adsrvr.",
        "pubmatic.",
        "mxptint.",
        "bidswitch.",
        "bidr.",
        "mathtag.",
        "rubiconproject.",
        "rlcdn.",
        "zeotap.",
        "dotomi.",
        "adform.",
        "casalemedia.",
        "openx.",
        "criteo.",
        "taboola.",
        "outbrain.",
        "scorecardresearch.",
        "facebook.net",
        "connect.facebook.",
        "yahoo.com/sync",
        "cookie",
        "usersync",
        "pixel",
    ]
    clauses = [
        f"LOWER(COALESCE({host_expr}, '')) NOT LIKE '%{needle}%'"
        for needle in noisy
        if "/" not in needle
    ]
    clauses.extend(
        f"LOWER(COALESCE({url_expr}, '')) NOT LIKE '%{needle}%'"
        for needle in noisy
    )
    return "(" + " AND ".join(clauses) + ")"


def _webcache_filtered_report(
    db: Database,
    case_id: str,
    *,
    table: str,
    key: str,
    limit: int,
    application: str | None,
    user: str | None,
    exclude_metadata: bool,
) -> dict[str, Any]:
    db.get_case(case_id)
    where = [f"{table}.case_id = ?"]
    params: list[Any] = [case_id]
    if application:
        where.append(f"LOWER(COALESCE({table}.application, '')) LIKE LOWER(?)")
        params.append(f"%{application}%")
    if user:
        where.append(f"LOWER(COALESCE({table}.user_name, '')) = LOWER(?)")
        params.append(user)
    if exclude_metadata:
        where.append(
            f"""
            COALESCE({table}.url, '') NOT LIKE 'MicrosoftEdge_iecompat:%'
            AND COALESCE({table}.url, '') NOT LIKE 'MicrosoftEdge_iecompatua:%'
            AND COALESCE({table}.url, '') NOT LIKE 'MicrosoftEdge_ieflipahead:%'
            AND COALESCE({table}.source_table, '') NOT LIKE 'MSysObjects%'
            AND COALESCE({table}.source_table, '') NOT LIKE 'CookieEntry%'
            AND COALESCE({table}.source_table, '') NOT LIKE 'BlobEntry%'
            AND COALESCE({table}.source_table, '') NOT LIKE 'DependencyEntry%'
            """
        )
    params.append(limit)
    rows = db.conn.execute(
        f"""
        SELECT {table}.*, computers.label AS computer_label, images.path AS image_path
        FROM {table}
        LEFT JOIN computers ON {table}.computer_id = computers.id
        LEFT JOIN images ON {table}.image_id = images.id
        WHERE {' AND '.join(where)}
        ORDER BY COALESCE({table}.accessed_utc, {table}.modified_utc, {table}.created_utc, {table}.created_at) DESC,
                 {table}.row_number DESC
        LIMIT ?
        """,
        params,
    ).fetchall()
    return {
        "case_id": case_id,
        "filters": {
            "application": application,
            "user": user,
            "exclude_metadata": exclude_metadata,
            "table": table,
        },
        key: [dict(row) for row in rows],
        "total_returned": len(rows),
    }


def _usb_overlaps_for_time(
    db: Database,
    case_id: str,
    image_id: str | None,
    timestamp_utc: str | None,
    local_path: str | None,
) -> list[dict[str, Any]]:
    timestamp_bound = _timestamp_sql_bound(timestamp_utc)
    if not timestamp_bound:
        return []
    params: list[Any] = [case_id]
    image_filter = ""
    if image_id:
        image_filter = "AND start_event.image_id = ?"
        params.append(image_id)
    params.append(timestamp_bound)
    params.append(timestamp_bound)
    removal_after_start_expr = (
        f"{_timestamp_sql_expr('end_event.event_time_utc')} >= "
        f"{_timestamp_sql_expr('start_event.event_time_utc')}"
    )
    session_end_expr = f"""
        COALESCE(
          (
            SELECT MIN(end_event.event_time_utc)
            FROM usb_connection_events end_event
            WHERE end_event.case_id = start_event.case_id
              AND end_event.image_id = start_event.image_id
              AND end_event.serial = start_event.serial
              AND end_event.event_type = 'removal'
              AND {removal_after_start_expr}
          ),
          start_event.event_time_utc
        )
    """
    rows = _query_report_rows(
        db,
        case_id,
        "usb_connection_events",
        f"""
        SELECT start_event.serial, start_event.volume_serial_number, start_event.volume_guid,
               start_event.drive_letter, start_event.event_time_utc AS session_start,
               {session_end_expr} AS session_end,
               usb_storage_devices.volume_name,
               usb_storage_devices.product,
               usb_storage_devices.vendor
        FROM usb_connection_events start_event
        LEFT JOIN usb_storage_devices
          ON usb_storage_devices.id = start_event.usb_device_id
        WHERE start_event.case_id = ?
          {image_filter}
          AND start_event.event_type IN ('arrival', 'first_connected', 'partition_seen')
          AND {_timestamp_sql_expr('start_event.event_time_utc')} <= ?
          AND {_timestamp_sql_expr(session_end_expr)} >= ?
        ORDER BY start_event.event_time_utc DESC
        LIMIT 10
        """,
        params,
    )
    drive = (local_path or "")[:2].upper() if re.match(r"^[A-Za-z]:", local_path or "") else None
    overlaps = []
    for row in rows:
        item = dict(row)
        item["drive_letter_match"] = bool(drive and (item.get("drive_letter") or "").upper().startswith(drive))
        overlaps.append(item)
    return overlaps


def _mft_matches_for_path(db: Database, case_id: str, image_id: str | None, target_path: str | None) -> list[dict[str, Any]]:
    normalized = _normalize_windows_path(target_path)
    filename = _basename(target_path)
    if not normalized or not filename:
        return []
    params: list[Any] = [case_id, filename]
    image_clause = ""
    if image_id:
        image_clause = "AND image_id = ?"
        params.append(image_id)
    rows = db.conn.execute(
        f"""
        SELECT id, entry_number, in_use, parent_path, file_name, file_size,
               created_si, modified_si, accessed_si
        FROM mft_entries
        WHERE case_id = ? AND LOWER(file_name) = LOWER(?) {image_clause}
        LIMIT 100
        """,
        params,
    ).fetchall()
    matches = []
    for row in rows:
        item = dict(row)
        candidate = _normalize_windows_path((item.get("parent_path") or "") + "/" + (item.get("file_name") or ""))
        if candidate and (candidate.endswith(normalized) or normalized.endswith(candidate)):
            matches.append(item)
    return matches[:10]


def _usb_matches_for_path(db: Database, case_id: str, target_path: str | None) -> list[dict[str, Any]]:
    normalized = _normalize_windows_path(target_path)
    filename = _basename(target_path)
    if not normalized or not filename:
        return []
    rows = _query_report_rows(
        db,
        case_id,
        "usb_file_correlations",
        """
        SELECT usb_serial, usb_volume_serial_number, usb_volume_name, usb_drive_letter,
               file_name, file_location, source_artifact_type, target_created, target_modified
        FROM usb_file_correlations
        WHERE case_id = ? AND LOWER(file_name) = LOWER(?)
        LIMIT 100
        """,
        (case_id, filename),
    )
    matches = []
    for row in rows:
        item = dict(row)
        candidate = _normalize_windows_path(item.get("file_location"))
        if candidate and (candidate.endswith(normalized) or normalized.endswith(candidate)):
            matches.append(item)
    return matches[:10]


def _normalize_windows_path(path: str | None) -> str | None:
    if not path:
        return None
    text = path.replace("\\", "/").strip().lower()
    text = re.sub(r"^[a-z]:/", "", text)
    text = re.sub(r"^\./", "", text)
    return text.strip("/") or None


def _basename(path: str | None) -> str | None:
    if not path:
        return None
    normalized = path.replace("\\", "/").rstrip("/")
    return normalized.rsplit("/", 1)[-1] if normalized else None


def _mounted_memory_artifacts(db: Database, case_id: str) -> list[dict[str, Any]]:
    case = db.get_case(case_id)
    rows: list[dict[str, Any]] = []
    mount_roots = [
        case.root / "mounts" / "volumes",
        Path(os.environ.get("PERCEPTOR_MOUNT_ROOT") or os.environ.get("FORENSIC_MOUNT_ROOT", "/tmp/perceptor-mounts")) / "cases" / case_id / "volumes",
    ]
    paths: list[Path] = []
    for mounts in mount_roots:
        if _path_accessible(mounts):
            paths.extend(_mounted_memory_candidate_paths(mounts))
    for path in paths:
        try:
            is_file = path.is_file()
        except OSError:
            continue
        if not is_file:
            continue
        artifact_type = _memory_artifact_type(path)
        if not artifact_type:
            continue
        try:
            size = path.stat().st_size
        except OSError:
            size = None
        hiberfil_status = None
        hiberfil_note = None
        if artifact_type == "hiberfil":
            try:
                hiberfil_status, hiberfil_note = assess_hiberfil_source(path)
            except Exception as exc:
                hiberfil_status = "assessment_failed"
                hiberfil_note = str(exc)
        rows.append(
            {
                "artifact_type": artifact_type,
                "path": display_evidence_path(path),
                "actual_path": str(path),
                "size_bytes": size,
                "source": "mounted_filesystem",
                "processed_status": "not_processed",
                "hiberfil_status": hiberfil_status,
                "hiberfil_note": hiberfil_note,
                "notes": _memory_artifact_note(artifact_type, hiberfil_status),
            }
        )
    return rows


def _mft_memory_artifacts(db: Database, case_id: str, *, limit: int) -> list[dict[str, Any]]:
    columns = _report_table_columns(db, case_id, "mft_entries")
    if not columns:
        return []
    if "file_name" not in columns:
        return []
    select_columns = [
        column
        for column in (
            "computer_id",
            "image_id",
            "entry_number",
            "sequence_number",
            "file_name",
            "parent_path",
            "extension",
            "file_size",
            "created_si",
            "modified_si",
            "accessed_si",
            "source_csv",
        )
        if column in columns
    ]
    if not select_columns:
        return []
    rows = _query_report_rows(
        db,
        case_id,
        "mft_entries",
        f"""
        SELECT {', '.join(_quote_identifier(column) for column in select_columns)}
        FROM mft_entries
        WHERE case_id = ?
          AND (
            lower(file_name) IN ('hiberfil.sys', 'pagefile.sys', 'swapfile.sys', 'memory.dmp')
            OR (
              lower(COALESCE(extension, '')) IN ('.dmp', 'dmp', '.mdmp', 'mdmp', '.dump', 'dump')
              AND (
                lower(COALESCE(parent_path, '')) LIKE '%minidump%'
                OR lower(COALESCE(parent_path, '')) LIKE '%crashdumps%'
                OR lower(COALESCE(parent_path, '')) LIKE '%windows error reporting%'
                OR lower(COALESCE(parent_path, '')) LIKE '%/wer%'
                OR lower(COALESCE(parent_path, '')) LIKE '%\\wer%'
              )
            )
          )
        LIMIT ?
        """,
        (case_id, limit),
    )
    output = []
    for row in rows:
        name = str(row.get("file_name") or "")
        parent = str(row.get("parent_path") or "").replace("\\", "/").rstrip("/")
        if parent in {"", ".", "/"}:
            parent = ""
        path = f"{parent}/{name}" if parent else f"/{name}"
        output.append(
            {
                "artifact_type": _memory_artifact_type(name),
                "path": display_evidence_path(path),
                "computer_id": row.get("computer_id"),
                "image_id": row.get("image_id"),
                "entry_number": row.get("entry_number"),
                "sequence_number": row.get("sequence_number"),
                "size_bytes": _int_or_none(row.get("file_size")),
                "source": "mft_entries",
                "processed_status": "not_processed",
                "created_time": row.get("created_si"),
                "modified_time": row.get("modified_si"),
                "accessed_time": row.get("accessed_si"),
                "source_csv": display_evidence_path(row.get("source_csv")),
                "notes": "Candidate for later memory analysis.",
            }
        )
    return output


def _memory_artifact_type(name: Any) -> str | None:
    source = Path(str(name or ""))
    classified = _classify_memory_artifact_type(source)
    if classified in {"hiberfil", "pagefile", "swapfile", "crash_dump", "process_dump", "full_memory_dump"}:
        return classified
    lowered = source.name.lower()
    if lowered == "hiberfil.sys":
        return "hiberfil"
    if lowered == "pagefile.sys":
        return "pagefile"
    if lowered == "swapfile.sys":
        return "swapfile"
    if lowered == "memory.dmp" or lowered.endswith((".dmp", ".mdmp", ".dump")):
        return "crash_dump"
    if lowered.endswith((".raw", ".vmem", ".mem")):
        return "full_memory_dump"
    return None


def _mounted_memory_candidate_paths(mounts: Path) -> list[Path]:
    paths: list[Path] = []
    for volume in sorted(path for path in mounts.glob("*") if path.is_dir()):
        for name in ("hiberfil.sys", "pagefile.sys", "swapfile.sys", "MEMORY.DMP", "memory.dmp"):
            paths.append(volume / name)
        patterns = (
            "Windows/Minidump/*",
            "Windows/LiveKernelReports/**/*",
            "ProgramData/Microsoft/Windows/WER/**/*",
            "Users/*/AppData/Local/CrashDumps/*",
            "Users/*/AppData/Local/Temp/*.dmp",
            "Users/*/AppData/Local/Temp/*.mdmp",
            "Users/*/AppData/Local/Temp/*.dump",
        )
        for pattern in patterns:
            paths.extend(path for path in volume.glob(pattern) if path.suffix.lower() in {".dmp", ".mdmp", ".dump"})
    existing = []
    for path in paths:
        try:
            if path.exists():
                existing.append(path)
        except OSError:
            continue
    return sorted(set(existing))


def _path_accessible(path: Path) -> bool:
    try:
        if not path.exists():
            return False
        # Stale FUSE mounts can report existence but fail when opened/listed.
        if path.is_dir():
            next(path.iterdir(), None)
        return True
    except OSError:
        return False


def _correlate_crash_dumps_to_wer(artifacts: list[dict[str, Any]], wer_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    correlations: list[dict[str, Any]] = []
    for artifact in artifacts:
        artifact_path = str(artifact.get("path") or artifact.get("actual_path") or "")
        artifact_name = _basename(artifact_path) or ""
        best: dict[str, Any] | None = None
        for wer in wer_rows:
            wer_text = " ".join(
                str(wer.get(field) or "")
                for field in ("source_file", "report_folder", "app_name", "original_filename", "ui_path")
            )
            if artifact_name and artifact_name.lower() in wer_text.lower():
                best = wer
                break
            if artifact_path and _basename(str(wer.get("source_file") or "")) == artifact_name:
                best = wer
                break
        correlations.append(
            {
                "dump_path": artifact_path,
                "dump_type": artifact.get("artifact_type"),
                "size_bytes": artifact.get("size_bytes"),
                "wer_report_id": best.get("id") if best else None,
                "app_name": best.get("app_name") if best else None,
                "event_time_utc": best.get("event_time_utc") if best else None,
                "exception_code": best.get("exception_code") if best else None,
            }
        )
    return correlations


def _dedupe_memory_artifacts(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, str]] = set()
    output = []
    for row in rows:
        path_key = str(row.get("path") or "").replace("\\", "/")
        path_key = re.sub(r"^\./", "/", path_key)
        key = (str(row.get("artifact_type") or ""), path_key.casefold())
        if key in seen:
            continue
        seen.add(key)
        output.append(row)
    return output


def _memory_artifact_note(artifact_type: str | None, hiberfil_status: str | None = None) -> str:
    if artifact_type == "hiberfil" and hiberfil_status:
        if hiberfil_status in {"unknown_or_compressed", "active_hibernation_header"}:
            return "Candidate for hiberfil decompression and memory string analysis."
        if hiberfil_status == "zeroed_or_inactive":
            return "Hiberfil appears zeroed or inactive in sampled regions."
        if hiberfil_status in {"empty", "unreadable", "assessment_failed"}:
            return "Hiberfil assessment produced a caveat; review status before analysis."
    if artifact_type in {"crash_dump", "process_dump", "full_memory_dump"}:
        return "Candidate for crash/full-memory string analysis and WER/process correlation."
    return "Candidate for later memory analysis."


def _processed_memory_sources(db: Database, case_id: str) -> set[str]:
    output: set[str] = set()
    if _report_table_columns(db, case_id, "memory_string_hits"):
        rows = _query_report_rows(
            db,
            case_id,
            "memory_string_hits",
            """
            SELECT DISTINCT source_path, scanned_path, decompressed_path
            FROM memory_string_hits
            WHERE case_id = ?
            """,
            (case_id,),
        )
        for row in rows:
            for key in ("source_path", "scanned_path", "decompressed_path"):
                normalized = _normalize_memory_source_key(row.get(key))
                if normalized:
                    output.add(normalized)
    for row in db.conn.execute(
        """
        SELECT details_json
        FROM activity_log
        WHERE case_id = ?
          AND event IN ('memory.strings_scanned', 'memory.profile_artifact_scanned', 'memory.crash_dump_scanned')
        """,
        (case_id,),
    ).fetchall():
        details = _json_details(row["details_json"])
        for key in ("source_path", "original_source_path", "scanned_path", "decompressed_path"):
            normalized = _normalize_memory_source_key(details.get(key))
            if normalized:
                output.add(normalized)
    return output


def _memory_scan_activity_rows(db: Database, case_id: str) -> list[dict[str, Any]]:
    rows = db.conn.execute(
        """
        SELECT created_at, event, level, message, details_json
        FROM activity_log
        WHERE case_id = ?
          AND event IN ('memory.strings_scanned', 'memory.profile_artifact_scanned', 'memory.crash_dump_scanned')
        ORDER BY created_at DESC
        """,
        (case_id,),
    ).fetchall()
    output: list[dict[str, Any]] = []
    for row in rows:
        details = _json_details(row["details_json"])
        item = {
            "created_at": row["created_at"],
            "event": row["event"],
            "level": row["level"],
            "message": row["message"],
            "status": "scanned",
            **details,
        }
        output.append(item)
    return output


def _normalize_memory_source_key(value: Any) -> str:
    text = str(value or "").replace("\\", "/").strip().casefold()
    text = re.sub(r"^\./", "", text)
    return text.rstrip("/")


def _opensearch_gap_rows(db: Database, case_id: str) -> list[dict[str, Any]]:
    rows = db.conn.execute(
        """
        SELECT created_at, level, event, message, details_json
        FROM activity_log
        WHERE case_id = ?
          AND (event LIKE 'search.opensearch%failed%' OR event = 'search.opensearch_write_failed')
        ORDER BY created_at DESC
        LIMIT 50
        """,
        (case_id,),
    ).fetchall()
    return [
        {
            "severity": "error",
            "category": "opensearch",
            "title": row["message"] or row["event"],
            "summary": row["created_at"],
            "details": dict(row),
            "recommendation": "Confirm OpenSearch availability and rerun the content-producing parser if searchable body/content is required.",
        }
        for row in rows
    ]


def _dedupe_gap_rows(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, str, str]] = set()
    output = []
    for row in rows:
        key = (str(row.get("severity") or ""), str(row.get("category") or ""), str(row.get("title") or ""))
        if key in seen:
            continue
        seen.add(key)
        output.append(row)
    return output


def _gap_severity_rank(value: Any) -> int:
    return {"error": 0, "warning": 1, "info": 2}.get(str(value or "").lower(), 3)


def _int_or_none(value: Any) -> int | None:
    try:
        return int(value)
    except (TypeError, ValueError):
        return None


def _report_table_count(db: Database, case_id: str, table: str) -> int:
    if not _safe_identifier(table):
        raise ValueError(f"Unsafe report table name: {table}")
    if table in ANALYTICS_TABLES or _duckdb_table_available(db, case_id, table):
        rows = _query_report_rows(
            db,
            case_id,
            table,
            f"SELECT COUNT(*) AS count FROM {_quote_identifier(table)} WHERE case_id = ?",
            (case_id,),
        )
        return int(rows[0].get("count") or 0) if rows else 0
    try:
        row = db.conn.execute(f"SELECT COUNT(*) AS count FROM {_quote_identifier(table)} WHERE case_id = ?", (case_id,)).fetchone()
    except Exception:
        return 0
    return int(row["count"] or 0) if row else 0


def _report_table_count_where(
    db: Database,
    case_id: str,
    table: str,
    where: str,
    params: tuple[Any, ...] | list[Any],
) -> int:
    if not _safe_identifier(table):
        raise ValueError(f"Unsafe report table name: {table}")
    rows = _query_report_rows(
        db,
        case_id,
        table,
        f"SELECT COUNT(*) AS count FROM {_quote_identifier(table)} WHERE case_id = ? AND {where}",
        (case_id, *tuple(params)),
    )
    return int(rows[0].get("count") or 0) if rows else 0


def _table_report(db: Database, case_id: str, table: str, key: str, limit: int) -> dict[str, Any]:
    db.get_case(case_id)
    duck_rows = _duckdb_table_rows(db, case_id, table, limit)
    if duck_rows is not None:
        return {"case_id": case_id, key: duck_rows, "total_returned": len(duck_rows)}
    if table in ANALYTICS_TABLES:
        return {"case_id": case_id, key: [], "total_returned": 0}

    duplicate_filter = _artifact_duplicate_filter(table)
    rows = db.conn.execute(
        f"""
        SELECT {table}.*, computers.label AS computer_label, images.path AS image_path,
               {_artifact_source_count_sql(table)} AS source_count
        FROM {table}
        LEFT JOIN computers ON {table}.computer_id = computers.id
        LEFT JOIN images ON {table}.image_id = images.id
        WHERE {table}.case_id = ?
          {duplicate_filter}
        ORDER BY {table}.created_at, {table}.row_number
        LIMIT ?
        """,
        (case_id, limit),
    ).fetchall()
    return {"case_id": case_id, key: [dict(row) for row in rows], "total_returned": len(rows)}


def _duckdb_table_rows(db: Database, case_id: str, table: str, limit: int) -> list[dict[str, Any]] | None:
    if not _safe_identifier(table):
        raise ValueError(f"Unsafe report table name: {table}")
    db_path = _duckdb_path_for_case(db, case_id)
    if not db_path.exists():
        return None
    conn, should_close = _duckdb_report_connection(db, case_id, db_path)
    try:
        if not _duckdb_table_exists(conn, table):
            return None
        duplicate_ids = _duplicate_row_ids(db, table)
        rows: list[dict[str, Any]] = []
        fetch_limit = max(limit, min(limit * 5, 5000))
        result = conn.execute(
            f"""
            SELECT *
            FROM {_quote_identifier(table)}
            WHERE case_id = ?
            ORDER BY created_at, row_number
            LIMIT ?
            """,
            [case_id, fetch_limit],
        ).fetchdf()
        computer_labels = _computer_labels(db, case_id)
        image_paths = _image_paths(db, case_id)
        source_counts = _source_counts(db, table)
        for item in result.to_dict("records"):
            row_id = str(item.get("id") or "")
            if row_id and row_id in duplicate_ids:
                continue
            computer_id = item.get("computer_id")
            image_id = item.get("image_id")
            item["computer_label"] = computer_labels.get(str(computer_id)) if computer_id else None
            item["image_path"] = image_paths.get(str(image_id)) if image_id else None
            item["source_count"] = source_counts.get(row_id, 0) if row_id else 0
            rows.append(item)
            if len(rows) >= limit:
                break
        return rows
    finally:
        if should_close:
            conn.close()


def _query_report_rows(
    db: Database,
    case_id: str,
    table: str,
    sql: str,
    params: tuple[Any, ...] | list[Any],
) -> list[dict[str, Any]]:
    if _duckdb_table_available(db, case_id, table):
        db_path = _duckdb_path_for_case(db, case_id)
        conn, should_close = _duckdb_report_connection(db, case_id, db_path)
        try:
            result = conn.execute(sql, list(params))
            names = [column[0] for column in result.description or []]
            return [dict(zip(names, row, strict=False)) for row in result.fetchall()]
        finally:
            if should_close:
                conn.close()
    if table in ANALYTICS_TABLES:
        return _analytics_query_rows(db, table, sql, params)
    rows = db.conn.execute(sql, params).fetchall()
    return [dict(row) for row in rows]


def _report_table_columns(db: Database, case_id: str, table: str) -> set[str]:
    if table in ANALYTICS_TABLES:
        return _analytics_table_columns(db, table, case_id=case_id)
    if _duckdb_table_available(db, case_id, table):
        db_path = _duckdb_path_for_case(db, case_id)
        conn, should_close = _duckdb_report_connection(db, case_id, db_path)
        try:
            return {str(row[1]) for row in conn.execute(f"PRAGMA table_info({_quote_identifier(table)})").fetchall()}
        finally:
            if should_close:
                conn.close()
    return {str(row["name"]) for row in db.conn.execute(f"PRAGMA table_info({_quote_identifier(table)})").fetchall()}


def _row_value(row: Any, key: str) -> Any:
    if isinstance(row, dict):
        return row.get(key)
    try:
        return row[key]
    except (IndexError, KeyError):
        return None


def _duckdb_table_available(db: Database, case_id: str, table: str) -> bool:
    if not _safe_identifier(table):
        raise ValueError(f"Unsafe report table name: {table}")
    db_path = _duckdb_path_for_case(db, case_id)
    if not db_path.exists():
        return False
    try:
        conn, should_close = _duckdb_report_connection(db, case_id, db_path)
    except duckdb.Error:
        return False
    try:
        return _duckdb_table_exists(conn, table)
    finally:
        if should_close:
            conn.close()


def _duckdb_path_for_case(db: Database, case_id: str) -> Path:
    case = db.get_case(case_id)
    return case.root / "analytics" / "events.duckdb"


def _duckdb_report_connection(
    db: Database,
    case_id: str,
    db_path: Path,
) -> tuple[duckdb.DuckDBPyConnection, bool]:
    analytics = getattr(db, "analytics", None)
    if analytics is not None and hasattr(analytics, "_connect"):
        key = str(db_path)
        existing_connections = getattr(analytics, "_connections", {})
        if key in existing_connections:
            return existing_connections[key], False
    return duckdb.connect(str(db_path), read_only=True), True


def _duckdb_table_exists(conn: duckdb.DuckDBPyConnection, table: str) -> bool:
    return bool(
        conn.execute(
            "SELECT 1 FROM information_schema.tables WHERE table_name = ? LIMIT 1",
            [table],
        ).fetchone()
    )


def _safe_identifier(value: str) -> bool:
    return bool(re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", value))


def _quote_identifier(value: str) -> str:
    return '"' + value.replace('"', '""') + '"'


def _duplicate_row_ids(db: Database, table: str) -> set[str]:
    rows = db.conn.execute(
        """
        SELECT duplicate_row_id
        FROM artifact_record_sources
        WHERE duplicate_table = ? AND source_scope = 'windows_old'
        """,
        (table,),
    ).fetchall()
    return {str(row["duplicate_row_id"]) for row in rows if row["duplicate_row_id"] is not None}


def _source_counts(db: Database, table: str) -> dict[str, int]:
    rows = db.conn.execute(
        """
        SELECT primary_row_id, COUNT(*) AS count
        FROM artifact_record_sources
        WHERE primary_table = ?
        GROUP BY primary_row_id
        """,
        (table,),
    ).fetchall()
    return {str(row["primary_row_id"]): int(row["count"]) for row in rows}


def _computer_labels(db: Database, case_id: str) -> dict[str, str]:
    rows = db.conn.execute("SELECT id, label FROM computers WHERE case_id = ?", (case_id,)).fetchall()
    return {str(row["id"]): row["label"] for row in rows}


def _image_paths(db: Database, case_id: str) -> dict[str, str]:
    rows = db.conn.execute("SELECT id, path FROM images WHERE case_id = ?", (case_id,)).fetchall()
    return {str(row["id"]): row["path"] for row in rows}


def _fill_computer_image_fields(db: Database, case_id: str, rows: list[dict[str, Any]]) -> None:
    labels = _computer_labels(db, case_id)
    paths = _image_paths(db, case_id)
    for row in rows:
        if not row.get("computer_label"):
            row["computer_label"] = labels.get(str(row.get("computer_id")))
        if not row.get("image_path"):
            row["image_path"] = paths.get(str(row.get("image_id")))


def _artifact_duplicate_filter(table: str) -> str:
    return f"AND {_artifact_duplicate_condition(table)}"


def _artifact_duplicate_condition(table: str) -> str:
    return (
        "NOT EXISTS ("
        "SELECT 1 FROM artifact_record_sources ars "
        f"WHERE ars.duplicate_table = '{table}' AND ars.duplicate_row_id = {table}.id "
        "AND ars.source_scope = 'windows_old'"
        ")"
    )


def _artifact_source_count_sql(table: str) -> str:
    return (
        "(SELECT COUNT(*) FROM artifact_record_sources ars "
        f"WHERE ars.primary_table = '{table}' AND ars.primary_row_id = {table}.id)"
    )


def _usn_filtered_report(
    db: Database,
    case_id: str,
    *,
    limit: int,
    path_contains: str | None = None,
    reason_contains: str | None = None,
    order: str = "DESC",
    filters: dict[str, Any] | None = None,
    key: str = "items",
) -> dict[str, Any]:
    db.get_case(case_id)
    where = ["usn_journal_entries.case_id = ?"]
    params: list[Any] = [case_id]
    if path_contains:
        where.append("(usn_journal_entries.full_path LIKE ? OR usn_journal_entries.file_name LIKE ?)")
        params.extend([f"%{path_contains}%", f"%{path_contains}%"])
    if reason_contains:
        where.append("LOWER(COALESCE(usn_journal_entries.reason, '')) LIKE LOWER(?)")
        params.append(f"%{reason_contains}%")
    direction = "ASC" if order.upper() == "ASC" else "DESC"
    params.append(limit)
    rows = _query_report_rows(
        db,
        case_id,
        "usn_journal_entries",
        f"""
        SELECT *
        FROM usn_journal_entries
        WHERE {' AND '.join(where)}
        ORDER BY usn_journal_entries.update_timestamp {direction},
                 usn_journal_entries.update_sequence_number {direction}
        LIMIT ?
        """,
        params,
    )
    _fill_computer_image_fields(db, case_id, rows)
    return {
        "case_id": case_id,
        "filters": filters or {
            "path_contains": path_contains,
            "reason": reason_contains,
        },
        key: [_compact_usn_row(row) for row in rows],
        "total_returned": len(rows),
    }


def _compact_usn_row(row: Any) -> dict[str, Any]:
    return {
        "computer_id": row["computer_id"],
        "computer_label": row["computer_label"],
        "image_id": row["image_id"],
        "image_path": row["image_path"],
        "update_timestamp": row["update_timestamp"],
        "update_sequence_number": row["update_sequence_number"],
        "file_name": row["file_name"],
        "extension": row["extension"],
        "full_path": row["full_path"],
        "reason": row["reason"],
        "file_attributes": row["file_attributes"],
        "file_reference_number": row["file_reference_number"],
        "parent_file_reference_number": row["parent_file_reference_number"],
    }


def _mft_enrichment(row: Any) -> dict[str, Any] | None:
    if "mft_entry_id" not in row.keys() or row["mft_entry_id"] is None:
        return None
    return {
        "id": row["mft_entry_id"],
        "in_use": row["mft_in_use"],
        "parent_path": row["mft_parent_path"],
        "file_size": row["mft_file_size"],
        "is_directory": row["mft_is_directory"],
        "is_ads": row["mft_is_ads"],
        "created_si": row["mft_created_si"],
        "modified_si": row["mft_modified_si"],
        "record_changed_si": row["mft_record_changed_si"],
        "accessed_si": row["mft_accessed_si"],
    }


def _mft_rows_by_reference(db: Database, case_id: str) -> dict[tuple[str, str, str], dict[str, Any]]:
    rows = _query_report_rows(
        db,
        case_id,
        "mft_entries",
        """
        SELECT id, image_id, entry_number, sequence_number, in_use, parent_path,
               file_size, is_directory, is_ads, created_si, modified_si,
               record_changed_si, accessed_si
        FROM mft_entries
        WHERE case_id = ?
        """,
        (case_id,),
    )
    output: dict[tuple[str, str, str], dict[str, Any]] = {}
    for row in rows:
        output[(str(row.get("image_id") or ""), str(row.get("entry_number") or ""), str(row.get("sequence_number") or ""))] = row
        output.setdefault((str(row.get("image_id") or ""), str(row.get("entry_number") or ""), ""), row)
    return output


def _attach_mft_enrichment(row: dict[str, Any], mft_by_ref: dict[tuple[str, str, str], dict[str, Any]]) -> None:
    key = (
        str(row.get("image_id") or ""),
        str(row.get("file_reference_number") or ""),
        str(row.get("file_reference_sequence_number") or ""),
    )
    mft = mft_by_ref.get(key) or mft_by_ref.get((key[0], key[1], ""))
    if not mft:
        return
    row["mft_entry_id"] = mft.get("id")
    row["mft_in_use"] = mft.get("in_use")
    row["mft_parent_path"] = mft.get("parent_path")
    row["mft_file_size"] = mft.get("file_size")
    row["mft_is_directory"] = mft.get("is_directory")
    row["mft_is_ads"] = mft.get("is_ads")
    row["mft_created_si"] = mft.get("created_si")
    row["mft_modified_si"] = mft.get("modified_si")
    row["mft_record_changed_si"] = mft.get("record_changed_si")
    row["mft_accessed_si"] = mft.get("accessed_si")


def _base_event(row: Any, parsed: dict[str, Any]) -> dict[str, Any]:
    return {
        "case_id": row["case_id"],
        "computer_id": row["computer_id"],
        "computer_label": row["computer_label"],
        "image_id": row["image_id"],
        "image_path": row["image_path"],
        "tool": row["tool_name"],
        "source_path": parsed.get("source_path") or row["source_path"],
        "row_number": row["row_number"],
    }


def _prefetch_events(row: Any, parsed: dict[str, Any]) -> list[dict[str, Any]]:
    timestamps = _coerce_list(parsed.get("last_run_times_utc"))
    if not timestamps and parsed.get("last_run_time_utc"):
        timestamps = [parsed["last_run_time_utc"]]
    events: list[dict[str, Any]] = []
    for index, timestamp in enumerate(timestamps, start=1):
        if not timestamp:
            continue
        events.append(
            {
                **_base_event(row, parsed),
                "timestamp_utc": timestamp,
                "event_type": "prefetch_last_run",
                "description": parsed.get("executable_name") or parsed.get("prefetch_name"),
                "details": {
                    "run_count": parsed.get("run_count"),
                    "prefetch_name": parsed.get("prefetch_name"),
                    "prefetch_hash": parsed.get("prefetch_hash"),
                    "timestamp_index": index,
                    "timestamp_count": len(timestamps),
                },
            }
        )
    return events


